(1, 3, 'Rajasthanfilings – Powered by Expert CAs & Advocates.', 'rajasthanfilings--powered-by-expert-cas--advocates', '1760444453_pngtree-accountant-doing-financial-analysis-3d-illustration-png-image_9198423.png', NULL, '[]', '<div class=\"section-title sec-title-animation animation-style2\">\r\n<div class=\"split-line\">\r\n<div class=\"section-title sec-title-animation animation-style2\">\r\n<div class=\"split-line\">\r\n<p class=\"description mt--30\"><strong data-start=\"180\" data-end=\"201\">Rajasthan Filings</strong> is not just a consultancy &mdash; it&rsquo;s a movement built to empower Indian entrepreneurs with trust, speed, and precision. From tax filings to company registration, from business loans to legal compliance, we provide end-to-end professional solutions under one roof. Our team of Chartered Accountants, Advocates, and Financial Experts is driven by one mission &mdash; to simplify compliance and strengthen every business with knowledge and confidence. Born in Rajasthan, serving across India, we are redefining professionalism with honesty, technology, and accountability. <strong data-start=\"762\" data-end=\"861\">When it comes to business compliance, Rajasthan Filings means reliability, result, and respect.</strong></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>', '<p>fdfsd</p>', 1, '2025-09-08 00:20:05', '2025-10-25 09:17:28'),
(3, NULL, 'About Rajasthan Filings', 'about-rajasthan-filings', '1760591271_accounting-typographic-header-professional-bookkeeper-concept-tax-calculating-business-character-making-financial-198420110.webp', NULL, '[\"1760590669_design-accounting-education-financial-literacy-improve-economic-growth_4968-1462.jpg\",\"1760591271_calculator-glasses-documents-table_218381-41213.jpg\"]', '<p data-start=\"419\" data-end=\"1110\"><strong data-start=\"419\" data-end=\"440\">Rajasthan Filings</strong> is not just a consultancy &mdash; it&rsquo;s a movement built to empower Indian entrepreneurs with trust, speed, and precision. From tax filings to company registration, from business loans to legal compliance, we provide end-to-end professional solutions under one roof. Our team of Chartered Accountants, Advocates, and Financial Experts is driven by one mission &mdash; to simplify compliance and strengthen every business with knowledge and confidence. Born in Rajasthan, serving across India, we are redefining professionalism with honesty, technology, and accountability. When it comes to business compliance, <strong data-start=\"1039\" data-end=\"1060\">Rajasthan Filings</strong> stands for <em data-start=\"1072\" data-end=\"1108\">reliability, results, and respect.</em></p>\r\n<p data-start=\"1112\" data-end=\"1319\">The firm has its <strong data-start=\"1129\" data-end=\"1171\">Registered Office in Jaipur, Rajasthan</strong>, with a strong network of expert professionals and consultants across various fields &mdash; delivering complete, customized solutions to every client.</p>\r\n<p data-start=\"1321\" data-end=\"1752\">Our vast client base continues to grow because of our <strong data-start=\"1375\" data-end=\"1462\">professional ethics, quality service, core competence, and long-term relationships.</strong> We provide research-based, result-oriented business solutions through a team of high-caliber and ethical individuals. We strive to lead the industry with creativity, vision, and adaptability &mdash; recognizing opportunities where others see obstacles, and taking action where others hesitate.</p>\r\n<p data-start=\"1754\" data-end=\"1774\">We truly believe &mdash;</p>\r\n<blockquote data-start=\"1775\" data-end=\"1841\">\r\n<p data-start=\"1777\" data-end=\"1841\"><strong data-start=\"1777\" data-end=\"1841\">&ldquo;The way to get started is to quit talking and begin doing.&rdquo;</strong></p>\r\n</blockquote>', NULL, 1, '2025-09-29 02:32:23', '2025-10-25 09:27:19');

