INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(2, 3, NULL, 'Revised & Updated ITR Filing', 'revised--updated-itr-filing', 'Revised & Updated ITR Filing', '<h1 data-start=\"124\" data-end=\"171\"><strong data-start=\"126\" data-end=\"169\">Revised and Updated ITR Filing in India</strong></h1>\r\n<h3 data-start=\"172\" data-end=\"279\">Correct Your Past Income Tax Returns and Stay Fully Compliant with Expert Help from Rajasthan Filings</h3>\r\n<p data-start=\"281\" data-end=\"705\">Filing your Income Tax Return (ITR) accurately and on time is the duty of every taxpayer. However, mistakes sometimes happen &mdash; an income source might be missed, a deduction left out, or a TDS not reflected properly. The Income-tax Department allows such taxpayers to <strong data-start=\"548\" data-end=\"590\">rectify their previously filed returns</strong> by filing a <strong data-start=\"603\" data-end=\"618\">Revised ITR</strong> or an <strong data-start=\"625\" data-end=\"648\">Updated ITR (ITR-U)</strong>, depending on the nature and timing of the correction.</p>\r\n<p data-start=\"707\" data-end=\"954\">At <strong data-start=\"710\" data-end=\"731\">Rajasthan Filings</strong>, we assist individuals, professionals, and businesses in reviewing, correcting, and refiling their returns seamlessly, ensuring that all details align with AIS, TIS, and 26AS data while maintaining full legal compliance.</p>\r\n<hr data-start=\"956\" data-end=\"959\">\r\n<h3 data-start=\"961\" data-end=\"1013\"><strong data-start=\"965\" data-end=\"1013\">1. Understanding Revised and Updated Returns</strong></h3>\r\n<p data-start=\"1015\" data-end=\"1282\"><strong data-start=\"1015\" data-end=\"1030\">Revised ITR</strong> &ndash; Section 139(5) of the Income-tax Act<br data-start=\"1069\" data-end=\"1072\">If a taxpayer discovers any error or omission in the original ITR, they can file a revised return before the end of the relevant <strong data-start=\"1201\" data-end=\"1220\">assessment year</strong> or before the completion of assessment, whichever is earlier.</p>\r\n<p data-start=\"1284\" data-end=\"1589\"><strong data-start=\"1284\" data-end=\"1307\">Updated ITR (ITR-U)</strong> &ndash; Section 139(8A) of the Act<br data-start=\"1336\" data-end=\"1339\">Introduced by the Finance Act, 2022, this provision allows taxpayers to voluntarily update previously missed income or correct old returns <strong data-start=\"1478\" data-end=\"1497\">up to two years</strong> after the end of the relevant assessment year, even if no revised return was filed earlier.</p>\r\n<hr data-start=\"1591\" data-end=\"1594\">\r\n<h3 data-start=\"1596\" data-end=\"1649\"><strong data-start=\"1600\" data-end=\"1649\">2. Difference Between Revised and Updated ITR</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1651\" data-end=\"2373\">\r\n<thead data-start=\"1651\" data-end=\"1729\">\r\n<tr data-start=\"1651\" data-end=\"1729\">\r\n<th data-start=\"1651\" data-end=\"1665\" data-col-size=\"sm\"><strong data-start=\"1653\" data-end=\"1664\">Feature</strong></th>\r\n<th data-start=\"1665\" data-end=\"1696\" data-col-size=\"md\"><strong data-start=\"1667\" data-end=\"1695\">Revised ITR [Sec 139(5)]</strong></th>\r\n<th data-start=\"1696\" data-end=\"1729\" data-col-size=\"md\"><strong data-start=\"1698\" data-end=\"1727\">Updated ITR [Sec 139(8A)]</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1811\" data-end=\"2373\">\r\n<tr data-start=\"1811\" data-end=\"1922\">\r\n<td data-start=\"1811\" data-end=\"1825\" data-col-size=\"sm\"><strong data-start=\"1813\" data-end=\"1824\">Purpose</strong></td>\r\n<td data-start=\"1825\" data-end=\"1878\" data-col-size=\"md\">To correct errors/omissions in the original return</td>\r\n<td data-col-size=\"md\" data-start=\"1878\" data-end=\"1922\">To disclose previously unreported income</td>\r\n</tr>\r\n<tr data-start=\"1923\" data-end=\"2023\">\r\n<td data-start=\"1923\" data-end=\"1940\" data-col-size=\"sm\"><strong data-start=\"1925\" data-end=\"1939\">Time Limit</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1940\" data-end=\"1979\">Till end of relevant assessment year</td>\r\n<td data-col-size=\"md\" data-start=\"1979\" data-end=\"2023\">Within 24 months from end of relevant AY</td>\r\n</tr>\r\n<tr data-start=\"2024\" data-end=\"2127\">\r\n<td data-start=\"2024\" data-end=\"2045\" data-col-size=\"sm\"><strong data-start=\"2026\" data-end=\"2044\">Additional Tax</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2045\" data-end=\"2079\">None (if filed within due time)</td>\r\n<td data-col-size=\"md\" data-start=\"2079\" data-end=\"2127\">25% or 50% additional tax on total liability</td>\r\n</tr>\r\n<tr data-start=\"2128\" data-end=\"2218\">\r\n<td data-start=\"2128\" data-end=\"2147\" data-col-size=\"sm\"><strong data-start=\"2130\" data-end=\"2146\">When Allowed</strong></td>\r\n<td data-start=\"2147\" data-end=\"2180\" data-col-size=\"md\">Only if original ITR was filed</td>\r\n<td data-col-size=\"md\" data-start=\"2180\" data-end=\"2218\">Even if original ITR was not filed</td>\r\n</tr>\r\n<tr data-start=\"2219\" data-end=\"2312\">\r\n<td data-start=\"2219\" data-end=\"2240\" data-col-size=\"sm\"><strong data-start=\"2221\" data-end=\"2239\">Revision Count</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2240\" data-end=\"2281\">Can revise multiple times within limit</td>\r\n<td data-col-size=\"md\" data-start=\"2281\" data-end=\"2312\">Can update only once per AY</td>\r\n</tr>\r\n<tr data-start=\"2313\" data-end=\"2373\">\r\n<td data-start=\"2313\" data-end=\"2332\" data-col-size=\"sm\"><strong data-start=\"2315\" data-end=\"2331\">Refund Claim</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2332\" data-end=\"2344\">Permitted</td>\r\n<td data-col-size=\"md\" data-start=\"2344\" data-end=\"2373\">Not allowed through ITR-U</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2375\" data-end=\"2378\">\r\n<h3 data-start=\"2380\" data-end=\"2430\"><strong data-start=\"2384\" data-end=\"2430\">3. Common Reasons for Filing a Revised ITR</strong></h3>\r\n<ul data-start=\"2432\" data-end=\"2759\">\r\n<li data-start=\"2432\" data-end=\"2481\">\r\n<p data-start=\"2434\" data-end=\"2481\">Omission of interest income from banks or FDs</p>\r\n</li>\r\n<li data-start=\"2482\" data-end=\"2523\">\r\n<p data-start=\"2484\" data-end=\"2523\">Missed salary from multiple employers</p>\r\n</li>\r\n<li data-start=\"2524\" data-end=\"2562\">\r\n<p data-start=\"2526\" data-end=\"2562\">TDS mismatch with Form 26AS or AIS</p>\r\n</li>\r\n<li data-start=\"2563\" data-end=\"2620\">\r\n<p data-start=\"2565\" data-end=\"2620\">Missed deductions under Chapter VI-A (80C, 80D, etc.)</p>\r\n</li>\r\n<li data-start=\"2621\" data-end=\"2671\">\r\n<p data-start=\"2623\" data-end=\"2671\">Correction in personal details or bank account</p>\r\n</li>\r\n<li data-start=\"2672\" data-end=\"2712\">\r\n<p data-start=\"2674\" data-end=\"2712\">Wrong regime selection (old vs. new)</p>\r\n</li>\r\n<li data-start=\"2713\" data-end=\"2759\">\r\n<p data-start=\"2715\" data-end=\"2759\">Incorrectly shown losses or carry-forwards</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2761\" data-end=\"2888\">Filing a correct revised return prevents future notices, penalties, or mismatch warnings from CPC or the Income-tax Department.</p>\r\n<hr data-start=\"2890\" data-end=\"2893\">\r\n<h3 data-start=\"2895\" data-end=\"2954\"><strong data-start=\"2899\" data-end=\"2954\">4. Common Reasons for Filing an Updated ITR (ITR-U)</strong></h3>\r\n<ul data-start=\"2956\" data-end=\"3247\">\r\n<li data-start=\"2956\" data-end=\"3027\">\r\n<p data-start=\"2958\" data-end=\"3027\">Disclosure of previously unreported business or professional income</p>\r\n</li>\r\n<li data-start=\"3028\" data-end=\"3069\">\r\n<p data-start=\"3030\" data-end=\"3069\">Missed capital gains or rental income</p>\r\n</li>\r\n<li data-start=\"3070\" data-end=\"3128\">\r\n<p data-start=\"3072\" data-end=\"3128\">Adjustment after receiving AIS/TIS mismatch intimation</p>\r\n</li>\r\n<li data-start=\"3129\" data-end=\"3190\">\r\n<p data-start=\"3131\" data-end=\"3190\">Non-filing of ITR in earlier years despite taxable income</p>\r\n</li>\r\n<li data-start=\"3191\" data-end=\"3247\">\r\n<p data-start=\"3193\" data-end=\"3247\">Voluntary correction to avoid scrutiny and penalties</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3249\" data-end=\"3252\">\r\n<h3 data-start=\"3254\" data-end=\"3287\"><strong data-start=\"3258\" data-end=\"3287\">5. Time Limits for Filing</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3289\" data-end=\"3567\">\r\n<thead data-start=\"3289\" data-end=\"3347\">\r\n<tr data-start=\"3289\" data-end=\"3347\">\r\n<th data-start=\"3289\" data-end=\"3300\" data-col-size=\"sm\"><strong data-start=\"3291\" data-end=\"3299\">Type</strong></th>\r\n<th data-start=\"3300\" data-end=\"3322\" data-col-size=\"sm\"><strong data-start=\"3302\" data-end=\"3321\">Assessment Year</strong></th>\r\n<th data-start=\"3322\" data-end=\"3347\" data-col-size=\"sm\"><strong data-start=\"3324\" data-end=\"3345\">Last Date to File</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3407\" data-end=\"3567\">\r\n<tr data-start=\"3407\" data-end=\"3471\">\r\n<td data-start=\"3407\" data-end=\"3422\" data-col-size=\"sm\">Original ITR</td>\r\n<td data-col-size=\"sm\" data-start=\"3422\" data-end=\"3441\">e.g., AY 2024-25</td>\r\n<td data-col-size=\"sm\" data-start=\"3441\" data-end=\"3471\">31 July 2024 (individuals)</td>\r\n</tr>\r\n<tr data-start=\"3472\" data-end=\"3516\">\r\n<td data-start=\"3472\" data-end=\"3486\" data-col-size=\"sm\">Revised ITR</td>\r\n<td data-col-size=\"sm\" data-start=\"3486\" data-end=\"3499\">AY 2024-25</td>\r\n<td data-col-size=\"sm\" data-start=\"3499\" data-end=\"3516\">31 March 2025</td>\r\n</tr>\r\n<tr data-start=\"3517\" data-end=\"3567\">\r\n<td data-start=\"3517\" data-end=\"3531\" data-col-size=\"sm\">Updated ITR</td>\r\n<td data-col-size=\"sm\" data-start=\"3531\" data-end=\"3544\">AY 2024-25</td>\r\n<td data-col-size=\"sm\" data-start=\"3544\" data-end=\"3567\">Up to 31 March 2027</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"3569\" data-end=\"3656\">Timely filing ensures the return is processed without additional interest or penalties.</p>\r\n<hr data-start=\"3658\" data-end=\"3661\">\r\n<h3 data-start=\"3663\" data-end=\"3706\"><strong data-start=\"3667\" data-end=\"3706\">6. Additional Tax Under Updated ITR</strong></h3>\r\n<p data-start=\"3708\" data-end=\"3792\">To discourage misuse, Section 140B prescribes an <strong data-start=\"3757\" data-end=\"3775\">additional tax</strong> on filing ITR-U:</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3794\" data-end=\"4046\">\r\n<thead data-start=\"3794\" data-end=\"3842\">\r\n<tr data-start=\"3794\" data-end=\"3842\">\r\n<th data-start=\"3794\" data-end=\"3812\" data-col-size=\"sm\"><strong data-start=\"3796\" data-end=\"3811\">Filing Time</strong></th>\r\n<th data-start=\"3812\" data-end=\"3842\" data-col-size=\"sm\"><strong data-start=\"3814\" data-end=\"3840\">Additional Tax Payable</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3893\" data-end=\"4046\">\r\n<tr data-start=\"3893\" data-end=\"3967\">\r\n<td data-start=\"3893\" data-end=\"3930\" data-col-size=\"sm\">Within 12 months after relevant AY</td>\r\n<td data-col-size=\"sm\" data-start=\"3930\" data-end=\"3967\">25% of total tax and interest due</td>\r\n</tr>\r\n<tr data-start=\"3968\" data-end=\"4046\">\r\n<td data-start=\"3968\" data-end=\"4009\" data-col-size=\"sm\">Between 12&ndash;24 months after relevant AY</td>\r\n<td data-col-size=\"sm\" data-start=\"4009\" data-end=\"4046\">50% of total tax and interest due</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"4048\" data-end=\"4132\">This additional payment ensures fair compliance and encourages voluntary disclosure.</p>\r\n<hr data-start=\"4134\" data-end=\"4137\">\r\n<h3 data-start=\"4139\" data-end=\"4189\"><strong data-start=\"4143\" data-end=\"4189\">7. Cases Where Updated ITR Cannot Be Filed</strong></h3>\r\n<p data-start=\"4191\" data-end=\"4218\">You cannot file ITR-U if:</p>\r\n<ul data-start=\"4219\" data-end=\"4502\">\r\n<li data-start=\"4219\" data-end=\"4285\">\r\n<p data-start=\"4221\" data-end=\"4285\">The updated return results in a loss or reduces tax liability.</p>\r\n</li>\r\n<li data-start=\"4286\" data-end=\"4322\">\r\n<p data-start=\"4288\" data-end=\"4322\">It claims or increases a refund.</p>\r\n</li>\r\n<li data-start=\"4323\" data-end=\"4389\">\r\n<p data-start=\"4325\" data-end=\"4389\">It is filed after a search or survey action by the department.</p>\r\n</li>\r\n<li data-start=\"4390\" data-end=\"4450\">\r\n<p data-start=\"4392\" data-end=\"4450\">Proceedings under Section 132 / 133A / 148A are pending.</p>\r\n</li>\r\n<li data-start=\"4451\" data-end=\"4502\">\r\n<p data-start=\"4453\" data-end=\"4502\">Prosecution has been initiated for the same year.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4504\" data-end=\"4507\">\r\n<h3 data-start=\"4509\" data-end=\"4538\"><strong data-start=\"4513\" data-end=\"4538\">8. Documents Required</strong></h3>\r\n<ul data-start=\"4540\" data-end=\"4780\">\r\n<li data-start=\"4540\" data-end=\"4579\">\r\n<p data-start=\"4542\" data-end=\"4579\">Copy of original ITR acknowledgment</p>\r\n</li>\r\n<li data-start=\"4580\" data-end=\"4606\">\r\n<p data-start=\"4582\" data-end=\"4606\">Form 16 / Salary slips</p>\r\n</li>\r\n<li data-start=\"4607\" data-end=\"4639\">\r\n<p data-start=\"4609\" data-end=\"4639\">Form 26AS / AIS / TIS report</p>\r\n</li>\r\n<li data-start=\"4640\" data-end=\"4659\">\r\n<p data-start=\"4642\" data-end=\"4659\">Bank statements</p>\r\n</li>\r\n<li data-start=\"4660\" data-end=\"4703\">\r\n<p data-start=\"4662\" data-end=\"4703\">Investment proofs (80C, 80D, 80G, etc.)</p>\r\n</li>\r\n<li data-start=\"4704\" data-end=\"4736\">\r\n<p data-start=\"4706\" data-end=\"4736\">Interest income certificates</p>\r\n</li>\r\n<li data-start=\"4737\" data-end=\"4780\">\r\n<p data-start=\"4739\" data-end=\"4780\">Business books of account (if applicable)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4782\" data-end=\"4785\">\r\n<h3 data-start=\"4787\" data-end=\"4818\"><strong data-start=\"4791\" data-end=\"4818\">9. Step-by-Step Process</strong></h3>\r\n<ol data-start=\"4820\" data-end=\"5330\">\r\n<li data-start=\"4820\" data-end=\"4897\">\r\n<p data-start=\"4823\" data-end=\"4897\"><strong data-start=\"4823\" data-end=\"4851\">Review of Existing Data:</strong> Reconcile your ITR with AIS, TIS, and 26AS.</p>\r\n</li>\r\n<li data-start=\"4898\" data-end=\"4990\">\r\n<p data-start=\"4901\" data-end=\"4990\"><strong data-start=\"4901\" data-end=\"4934\">Identify Omissions or Errors:</strong> Check for missing income, deductions, or wrong heads.</p>\r\n</li>\r\n<li data-start=\"4991\" data-end=\"5077\">\r\n<p data-start=\"4994\" data-end=\"5077\"><strong data-start=\"4994\" data-end=\"5023\">Prepare Corrected Return:</strong> Amend or update income details under correct heads.</p>\r\n</li>\r\n<li data-start=\"5078\" data-end=\"5167\">\r\n<p data-start=\"5081\" data-end=\"5167\"><strong data-start=\"5081\" data-end=\"5105\">Compute Tax Payable:</strong> Include late fees, interest, and additional tax (if ITR-U).</p>\r\n</li>\r\n<li data-start=\"5168\" data-end=\"5268\">\r\n<p data-start=\"5171\" data-end=\"5268\"><strong data-start=\"5171\" data-end=\"5202\">File Revised / Updated ITR:</strong> Upload via the Income Tax Portal with digital signature or EVC.</p>\r\n</li>\r\n<li data-start=\"5269\" data-end=\"5330\">\r\n<p data-start=\"5272\" data-end=\"5330\"><strong data-start=\"5272\" data-end=\"5290\">Verify Return:</strong> Complete verification within 30 days.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"5332\" data-end=\"5335\">\r\n<h3 data-start=\"5337\" data-end=\"5392\"><strong data-start=\"5341\" data-end=\"5392\">10. Importance of Filing Revised or Updated ITR</strong></h3>\r\n<ul data-start=\"5394\" data-end=\"5730\">\r\n<li data-start=\"5394\" data-end=\"5459\">\r\n<p data-start=\"5396\" data-end=\"5459\">Prevents tax notices and scrutiny under Sections 143(2) / 148</p>\r\n</li>\r\n<li data-start=\"5460\" data-end=\"5506\">\r\n<p data-start=\"5462\" data-end=\"5506\">Corrects errors before assessment or audit</p>\r\n</li>\r\n<li data-start=\"5507\" data-end=\"5557\">\r\n<p data-start=\"5509\" data-end=\"5557\">Reflects transparency and voluntary compliance</p>\r\n</li>\r\n<li data-start=\"5558\" data-end=\"5621\">\r\n<p data-start=\"5560\" data-end=\"5621\">Aligns your tax records with digital data (AIS / PAN / TDS)</p>\r\n</li>\r\n<li data-start=\"5622\" data-end=\"5668\">\r\n<p data-start=\"5624\" data-end=\"5668\">Protects credit score and loan eligibility</p>\r\n</li>\r\n<li data-start=\"5669\" data-end=\"5730\">\r\n<p data-start=\"5671\" data-end=\"5730\">Demonstrates credibility for visa and tender applications</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5732\" data-end=\"5735\">\r\n<h3 data-start=\"5737\" data-end=\"5775\"><strong data-start=\"5741\" data-end=\"5775\">11. Penalty for Non-Compliance</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5777\" data-end=\"6098\">\r\n<thead data-start=\"5777\" data-end=\"5807\">\r\n<tr data-start=\"5777\" data-end=\"5807\">\r\n<th data-start=\"5777\" data-end=\"5788\" data-col-size=\"sm\"><strong data-start=\"5779\" data-end=\"5787\">Type</strong></th>\r\n<th data-start=\"5788\" data-end=\"5807\" data-col-size=\"md\"><strong data-start=\"5790\" data-end=\"5805\">Consequence</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5840\" data-end=\"6098\">\r\n<tr data-start=\"5840\" data-end=\"5909\">\r\n<td data-start=\"5840\" data-end=\"5872\" data-col-size=\"sm\">Failure to revise or disclose</td>\r\n<td data-col-size=\"md\" data-start=\"5872\" data-end=\"5909\">Penalty up to 200% of tax avoided</td>\r\n</tr>\r\n<tr data-start=\"5910\" data-end=\"5974\">\r\n<td data-start=\"5910\" data-end=\"5934\" data-col-size=\"sm\">Filing after due date</td>\r\n<td data-start=\"5934\" data-end=\"5974\" data-col-size=\"md\">Interest @ 1% per month u/s 234A/B/C</td>\r\n</tr>\r\n<tr data-start=\"5975\" data-end=\"6024\">\r\n<td data-start=\"5975\" data-end=\"5995\" data-col-size=\"sm\">Late verification</td>\r\n<td data-start=\"5995\" data-end=\"6024\" data-col-size=\"md\">Return treated as invalid</td>\r\n</tr>\r\n<tr data-start=\"6025\" data-end=\"6098\">\r\n<td data-start=\"6025\" data-end=\"6053\" data-col-size=\"sm\">Non-filing despite income</td>\r\n<td data-col-size=\"md\" data-start=\"6053\" data-end=\"6098\">Notice under Section 148 for reassessment</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"6100\" data-end=\"6184\">Voluntary correction through a revised or updated return helps avoid such penalties.</p>\r\n<hr data-start=\"6186\" data-end=\"6189\">\r\n<h3 data-start=\"6191\" data-end=\"6231\"><strong data-start=\"6195\" data-end=\"6231\">12. Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"6233\" data-end=\"6633\">\r\n<li data-start=\"6233\" data-end=\"6288\">\r\n<p data-start=\"6235\" data-end=\"6288\">Expert review of previously filed ITRs and AIS data</p>\r\n</li>\r\n<li data-start=\"6289\" data-end=\"6338\">\r\n<p data-start=\"6291\" data-end=\"6338\">Identification of mismatches or missed income</p>\r\n</li>\r\n<li data-start=\"6339\" data-end=\"6395\">\r\n<p data-start=\"6341\" data-end=\"6395\">Accurate computation of revised or updated liability</p>\r\n</li>\r\n<li data-start=\"6396\" data-end=\"6455\">\r\n<p data-start=\"6398\" data-end=\"6455\">Filing and verification under Section 139(5) or 139(8A)</p>\r\n</li>\r\n<li data-start=\"6456\" data-end=\"6511\">\r\n<p data-start=\"6458\" data-end=\"6511\">Guidance on penalty and additional tax implications</p>\r\n</li>\r\n<li data-start=\"6512\" data-end=\"6564\">\r\n<p data-start=\"6514\" data-end=\"6564\">Professional handling of CPC / AO correspondence</p>\r\n</li>\r\n<li data-start=\"6565\" data-end=\"6633\">\r\n<p data-start=\"6567\" data-end=\"6633\">End-to-end support till acknowledgment is successfully processed</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6635\" data-end=\"6806\">Rajasthan Filings ensures your tax compliance stays accurate, updated, and legally sound &mdash; whether it&rsquo;s correction for the last year or a missed filing from two years ago.</p>\r\n<hr data-start=\"6808\" data-end=\"6811\">\r\n<h3 data-start=\"6813\" data-end=\"6835\"><strong data-start=\"6817\" data-end=\"6835\">13. Conclusion</strong></h3>\r\n<p data-start=\"6837\" data-end=\"7093\">Mistakes in tax returns are common, but ignoring them can lead to notices, penalties, and future scrutiny. The facility to file <strong data-start=\"6965\" data-end=\"6993\">Revised and Updated ITRs</strong> allows taxpayers to correct errors, disclose income voluntarily, and maintain a clean tax record.</p>\r\n<p data-start=\"7095\" data-end=\"7284\">With Rajasthan Filings&rsquo; expert guidance, every correction becomes smooth, lawful, and stress-free &mdash; safeguarding you from compliance risks and building long-term trust with tax authorities.</p>', NULL, NULL, '1758969396_pro-img-4.jpg', NULL, 1, '2025-09-03 04:13:24', '2025-11-08 00:52:24');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(3, 2, NULL, 'GST Returns', 'gst-returns-', 'GST Returns (GSTR-1, 3B, 9, 9C, R-1, R-4 etc.)', '<h1 data-start=\"515\" data-end=\"576\"><strong data-start=\"517\" data-end=\"576\">GST Returns&nbsp;</strong></h1>\r\n<p data-start=\"578\" data-end=\"1088\">The Goods and Services Tax (GST) system in India is based on the principle of self-assessment, transparency, and seamless credit flow. Every registered taxpayer is required to file periodical statements and returns containing details of outward supplies, inward supplies, tax liability, and input-tax credit. These returns are not only a legal obligation under the GST law but also the foundation for reconciliation between suppliers and recipients, ensuring the smooth functioning of the national tax network.</p>\r\n<p data-start=\"1090\" data-end=\"1622\">A GST return is a formal record submitted to the Goods and Services Tax Network (GSTN) by a registered person. It provides comprehensive data about sales, purchases, taxes collected and paid, and the eligibility for claiming input tax credit. Through these filings, the government monitors compliance, prevents evasion, and ensures accurate collection of revenue. Filing returns on time is mandatory even when there are no transactions during a particular period; in such cases, a Nil return must be filed to maintain active status.</p>\r\n<p data-start=\"1624\" data-end=\"2021\">Timely and accurate return filing is crucial for every business because the buyer&rsquo;s ability to claim input credit depends on the seller&rsquo;s timely filing of details. Any mismatch or delay may lead to blockage of credit, cash-flow disruption, and potential legal consequences. Under the GST regime, compliance discipline directly reflects a taxpayer&rsquo;s credibility and rating on the government system.</p>\r\n<p data-start=\"2023\" data-end=\"2373\">The GST law prescribes different types of returns for various categories of taxpayers such as regular dealers, composition taxpayers, non-resident persons, Input Service Distributors, e-commerce operators, and others. Among these, the most commonly filed returns are <strong data-start=\"2290\" data-end=\"2300\">GSTR-1</strong>, <strong data-start=\"2302\" data-end=\"2313\">GSTR-3B</strong>, <strong data-start=\"2315\" data-end=\"2325\">GSTR-9</strong>, <strong data-start=\"2327\" data-end=\"2338\">GSTR-9C</strong>, <strong data-start=\"2340\" data-end=\"2356\">GSTR-4 (R-4)</strong>, and <strong data-start=\"2362\" data-end=\"2372\">ITC-04</strong>.</p>\r\n<hr data-start=\"2375\" data-end=\"2378\">\r\n<h3 data-start=\"2380\" data-end=\"2425\"><strong data-start=\"2384\" data-end=\"2425\">Purpose and Importance of GST Returns</strong></h3>\r\n<p data-start=\"2427\" data-end=\"2471\">Filing GST returns serves multiple purposes:</p>\r\n<ol data-start=\"2473\" data-end=\"3107\">\r\n<li data-start=\"2473\" data-end=\"2578\">\r\n<p data-start=\"2476\" data-end=\"2578\"><strong data-start=\"2476\" data-end=\"2497\">Legal Compliance:</strong> It fulfils statutory obligations under Sections 37 to 44 of the CGST Act 2017.</p>\r\n</li>\r\n<li data-start=\"2579\" data-end=\"2674\">\r\n<p data-start=\"2582\" data-end=\"2674\"><strong data-start=\"2582\" data-end=\"2599\">Transparency:</strong> It builds a verified trail of transactions between suppliers and buyers.</p>\r\n</li>\r\n<li data-start=\"2675\" data-end=\"2789\">\r\n<p data-start=\"2678\" data-end=\"2789\"><strong data-start=\"2678\" data-end=\"2694\">Credit Flow:</strong> It enables automatic matching of invoices for input-tax credit under the matching mechanism.</p>\r\n</li>\r\n<li data-start=\"2790\" data-end=\"2884\">\r\n<p data-start=\"2793\" data-end=\"2884\"><strong data-start=\"2793\" data-end=\"2819\">Data for Policymaking:</strong> Aggregate data from returns supports national fiscal planning.</p>\r\n</li>\r\n<li data-start=\"2885\" data-end=\"3015\">\r\n<p data-start=\"2888\" data-end=\"3015\"><strong data-start=\"2888\" data-end=\"2916\">Eligibility for Refunds:</strong> Exporters and taxpayers with inverted duty structures require accurate returns to claim refunds.</p>\r\n</li>\r\n<li data-start=\"3016\" data-end=\"3107\">\r\n<p data-start=\"3019\" data-end=\"3107\"><strong data-start=\"3019\" data-end=\"3046\">Avoidance of Penalties:</strong> Timely filing prevents late-fee accumulation and interest.</p>\r\n</li>\r\n</ol>\r\n<p data-start=\"3109\" data-end=\"3252\">Failure to file returns results in suspension of GSTIN, blocking of e-way bills, denial of input credit, and even cancellation of registration.</p>\r\n<hr data-start=\"3254\" data-end=\"3257\">\r\n<h3 data-start=\"3259\" data-end=\"3292\"><strong data-start=\"3263\" data-end=\"3292\">Commonly Used GST Returns</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3294\" data-end=\"4075\">\r\n<thead data-start=\"3294\" data-end=\"3363\">\r\n<tr data-start=\"3294\" data-end=\"3363\">\r\n<th data-start=\"3294\" data-end=\"3305\" data-col-size=\"sm\"><strong data-start=\"3296\" data-end=\"3304\">Form</strong></th>\r\n<th data-start=\"3305\" data-end=\"3319\" data-col-size=\"md\"><strong data-start=\"3307\" data-end=\"3318\">Purpose</strong></th>\r\n<th data-start=\"3319\" data-end=\"3342\" data-col-size=\"sm\"><strong data-start=\"3321\" data-end=\"3341\">Filing Frequency</strong></th>\r\n<th data-start=\"3342\" data-end=\"3363\" data-col-size=\"sm\"><strong data-start=\"3344\" data-end=\"3361\">Applicability</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3435\" data-end=\"4075\">\r\n<tr data-start=\"3435\" data-end=\"3531\">\r\n<td data-start=\"3435\" data-end=\"3448\" data-col-size=\"sm\"><strong data-start=\"3437\" data-end=\"3447\">GSTR-1</strong></td>\r\n<td data-start=\"3448\" data-end=\"3488\" data-col-size=\"md\">Statement of outward supplies (sales)</td>\r\n<td data-col-size=\"sm\" data-start=\"3488\" data-end=\"3510\">Monthly / Quarterly</td>\r\n<td data-col-size=\"sm\" data-start=\"3510\" data-end=\"3531\">Regular taxpayers</td>\r\n</tr>\r\n<tr data-start=\"3532\" data-end=\"3638\">\r\n<td data-start=\"3532\" data-end=\"3546\" data-col-size=\"sm\"><strong data-start=\"3534\" data-end=\"3545\">GSTR-3B</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3546\" data-end=\"3607\">Summary of inward &amp; outward supplies, ITC, and tax payment</td>\r\n<td data-col-size=\"sm\" data-start=\"3607\" data-end=\"3617\">Monthly</td>\r\n<td data-col-size=\"sm\" data-start=\"3617\" data-end=\"3638\">Regular taxpayers</td>\r\n</tr>\r\n<tr data-start=\"3639\" data-end=\"3755\">\r\n<td data-start=\"3639\" data-end=\"3652\" data-col-size=\"sm\"><strong data-start=\"3641\" data-end=\"3651\">GSTR-9</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3652\" data-end=\"3702\">Annual summary of all monthly/quarterly returns</td>\r\n<td data-col-size=\"sm\" data-start=\"3702\" data-end=\"3713\">Annually</td>\r\n<td data-col-size=\"sm\" data-start=\"3713\" data-end=\"3755\">Taxpayers with turnover above ₹2 crore</td>\r\n</tr>\r\n<tr data-start=\"3756\" data-end=\"3874\">\r\n<td data-start=\"3756\" data-end=\"3770\" data-col-size=\"sm\"><strong data-start=\"3758\" data-end=\"3769\">GSTR-9C</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3770\" data-end=\"3821\">Reconciliation statement with audited financials</td>\r\n<td data-col-size=\"sm\" data-start=\"3821\" data-end=\"3832\">Annually</td>\r\n<td data-col-size=\"sm\" data-start=\"3832\" data-end=\"3874\">Taxpayers with turnover above ₹5 crore</td>\r\n</tr>\r\n<tr data-start=\"3875\" data-end=\"3970\">\r\n<td data-start=\"3875\" data-end=\"3894\" data-col-size=\"sm\"><strong data-start=\"3877\" data-end=\"3893\">GSTR-4 (R-4)</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3894\" data-end=\"3936\">Annual return for composition taxpayers</td>\r\n<td data-col-size=\"sm\" data-start=\"3936\" data-end=\"3947\">Annually</td>\r\n<td data-col-size=\"sm\" data-start=\"3947\" data-end=\"3970\">Composition dealers</td>\r\n</tr>\r\n<tr data-start=\"3971\" data-end=\"4075\">\r\n<td data-start=\"3971\" data-end=\"3984\" data-col-size=\"sm\"><strong data-start=\"3973\" data-end=\"3983\">ITC-04</strong></td>\r\n<td data-start=\"3984\" data-end=\"4032\" data-col-size=\"md\">Statement of goods sent/received for job-work</td>\r\n<td data-col-size=\"sm\" data-start=\"4032\" data-end=\"4044\">Quarterly</td>\r\n<td data-col-size=\"sm\" data-start=\"4044\" data-end=\"4075\">Manufacturers / Job workers</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4077\" data-end=\"4080\">\r\n<h3 data-start=\"4082\" data-end=\"4125\"><strong data-start=\"4086\" data-end=\"4125\">Detailed Explanation of Each Return</strong></h3>\r\n<h4 data-start=\"4127\" data-end=\"4174\"><strong data-start=\"4132\" data-end=\"4174\">GSTR-1 &ndash; Statement of Outward Supplies</strong></h4>\r\n<p data-start=\"4176\" data-end=\"4431\">GSTR-1 contains complete details of outward supplies made by a registered person during a tax period. It includes invoice-wise information of business-to-business (B2B) transactions, business-to-consumer (B2C) large sales, exports, and debit/credit notes.</p>\r\n<p data-start=\"4433\" data-end=\"4645\"><strong data-start=\"4433\" data-end=\"4451\">Who Must File:</strong><br data-start=\"4451\" data-end=\"4454\">All registered taxpayers making outward supplies except Input Service Distributors, composition dealers, non-resident taxable persons, and those liable to deduct or collect TDS/TCS under GST.</p>\r\n<p data-start=\"4647\" data-end=\"4677\"><strong data-start=\"4647\" data-end=\"4675\">Frequency and Due Dates:</strong></p>\r\n<ul data-start=\"4678\" data-end=\"4914\">\r\n<li data-start=\"4678\" data-end=\"4787\">\r\n<p data-start=\"4680\" data-end=\"4787\">Monthly filing for taxpayers having turnover above ₹5 crore &ndash; due by the <strong data-start=\"4753\" data-end=\"4761\">11th</strong> of the following month.</p>\r\n</li>\r\n<li data-start=\"4788\" data-end=\"4914\">\r\n<p data-start=\"4790\" data-end=\"4914\">Quarterly filing under the QRMP scheme for turnover up to ₹5 crore &ndash; due by the <strong data-start=\"4870\" data-end=\"4878\">13th</strong> of the month following the quarter.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4916\" data-end=\"5191\"><strong data-start=\"4916\" data-end=\"4929\">Contents:</strong><br data-start=\"4929\" data-end=\"4932\">B2B supplies, B2C large transactions, exports, nil/exempt supplies, and HSN-wise summary must be reported precisely. Amendments of previous months can also be included. Once filed, GSTR-1 cannot be revised; any corrections must be reported in the next period.</p>\r\n<p data-start=\"5193\" data-end=\"5414\"><strong data-start=\"5193\" data-end=\"5219\">Late Fee and Interest:</strong><br data-start=\"5219\" data-end=\"5222\">Late filing attracts ₹50 per day (₹25 CGST + ₹25 SGST) up to ₹5 000, and ₹20 per day for nil returns. Interest at 18 % p.a. applies on delayed tax payments related to corresponding 3B filings.</p>\r\n<p data-start=\"5416\" data-end=\"5608\"><strong data-start=\"5416\" data-end=\"5431\">Importance:</strong><br data-start=\"5431\" data-end=\"5434\">Details in GSTR-1 populate recipients&rsquo; auto-drafted GSTR-2A/2B. Inaccurate reporting may block buyers&rsquo; credit or trigger notices. Hence accuracy and punctuality are critical.</p>\r\n<hr data-start=\"5610\" data-end=\"5613\">\r\n<h4 data-start=\"5615\" data-end=\"5664\"><strong data-start=\"5620\" data-end=\"5664\">GSTR-3B &ndash; Summary Return and Tax Payment</strong></h4>\r\n<p data-start=\"5666\" data-end=\"5884\">GSTR-3B is a self-declaration summarising total outward supplies, eligible input-tax credit, tax liability, and payments for each tax period. It is the form through which the taxpayer actually discharges GST liability.</p>\r\n<p data-start=\"5886\" data-end=\"6021\"><strong data-start=\"5886\" data-end=\"5899\">Due Date:</strong> 20th of the succeeding month for monthly filers; for QRMP taxpayers, by the 22nd or 24th depending on the state category.</p>\r\n<p data-start=\"6023\" data-end=\"6048\"><strong data-start=\"6023\" data-end=\"6048\">Structure of GSTR-3B:</strong></p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6050\" data-end=\"6425\">\r\n<thead data-start=\"6050\" data-end=\"6083\">\r\n<tr data-start=\"6050\" data-end=\"6083\">\r\n<th data-start=\"6050\" data-end=\"6064\" data-col-size=\"sm\"><strong data-start=\"6052\" data-end=\"6063\">Section</strong></th>\r\n<th data-start=\"6064\" data-end=\"6083\" data-col-size=\"md\"><strong data-start=\"6066\" data-end=\"6081\">Particulars</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6118\" data-end=\"6425\">\r\n<tr data-start=\"6118\" data-end=\"6192\">\r\n<td data-start=\"6118\" data-end=\"6127\" data-col-size=\"sm\">3.1(a)</td>\r\n<td data-start=\"6127\" data-end=\"6192\" data-col-size=\"md\">Outward taxable supplies (other than zero-rated, nil, exempt)</td>\r\n</tr>\r\n<tr data-start=\"6193\" data-end=\"6233\">\r\n<td data-start=\"6193\" data-end=\"6202\" data-col-size=\"sm\">3.1(b)</td>\r\n<td data-col-size=\"md\" data-start=\"6202\" data-end=\"6233\">Outward supplies zero-rated</td>\r\n</tr>\r\n<tr data-start=\"6234\" data-end=\"6282\">\r\n<td data-start=\"6234\" data-end=\"6243\" data-col-size=\"sm\">3.1(c)</td>\r\n<td data-col-size=\"md\" data-start=\"6243\" data-end=\"6282\">Other outward supplies (nil/exempt)</td>\r\n</tr>\r\n<tr data-start=\"6283\" data-end=\"6317\">\r\n<td data-start=\"6283\" data-end=\"6287\" data-col-size=\"sm\">4</td>\r\n<td data-start=\"6287\" data-end=\"6317\" data-col-size=\"md\">Eligible ITC and reversals</td>\r\n</tr>\r\n<tr data-start=\"6318\" data-end=\"6372\">\r\n<td data-start=\"6318\" data-end=\"6322\" data-col-size=\"sm\">5</td>\r\n<td data-col-size=\"md\" data-start=\"6322\" data-end=\"6372\">Values of exempt, nil, non-GST inward supplies</td>\r\n</tr>\r\n<tr data-start=\"6373\" data-end=\"6425\">\r\n<td data-start=\"6373\" data-end=\"6377\" data-col-size=\"sm\">6</td>\r\n<td data-col-size=\"md\" data-start=\"6377\" data-end=\"6425\">Tax payment summary (cash + ITC utilisation)</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"6427\" data-end=\"6442\"><strong data-start=\"6427\" data-end=\"6442\">Key Points:</strong></p>\r\n<ul data-start=\"6443\" data-end=\"6667\">\r\n<li data-start=\"6443\" data-end=\"6520\">\r\n<p data-start=\"6445\" data-end=\"6520\">Taxpayer must compute net tax liability after adjusting input-tax credit.</p>\r\n</li>\r\n<li data-start=\"6521\" data-end=\"6578\">\r\n<p data-start=\"6523\" data-end=\"6578\">The balance of credit is auto-populated from GSTR-2B.</p>\r\n</li>\r\n<li data-start=\"6579\" data-end=\"6667\">\r\n<p data-start=\"6581\" data-end=\"6667\">Payment is made using the electronic cash ledger or credit ledger before submission.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6669\" data-end=\"6707\"><strong data-start=\"6669\" data-end=\"6707\">Late Fee and Interest Calculation:</strong></p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6709\" data-end=\"6953\">\r\n<thead data-start=\"6709\" data-end=\"6752\">\r\n<tr data-start=\"6709\" data-end=\"6752\">\r\n<th data-start=\"6709\" data-end=\"6725\" data-col-size=\"sm\"><strong data-start=\"6711\" data-end=\"6724\">Situation</strong></th>\r\n<th data-start=\"6725\" data-end=\"6752\" data-col-size=\"sm\"><strong data-start=\"6727\" data-end=\"6750\">Interest Rate / Fee</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6799\" data-end=\"6953\">\r\n<tr data-start=\"6799\" data-end=\"6852\">\r\n<td data-start=\"6799\" data-end=\"6822\" data-col-size=\"sm\">Delay in tax payment</td>\r\n<td data-col-size=\"sm\" data-start=\"6822\" data-end=\"6852\">18 % p.a. on net liability</td>\r\n</tr>\r\n<tr data-start=\"6853\" data-end=\"6897\">\r\n<td data-start=\"6853\" data-end=\"6882\" data-col-size=\"sm\">Delay in filing nil return</td>\r\n<td data-col-size=\"sm\" data-start=\"6882\" data-end=\"6897\">₹20 per day</td>\r\n</tr>\r\n<tr data-start=\"6898\" data-end=\"6953\">\r\n<td data-start=\"6898\" data-end=\"6938\" data-col-size=\"sm\">Delay in filing return with liability</td>\r\n<td data-col-size=\"sm\" data-start=\"6938\" data-end=\"6953\">₹50 per day</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"6955\" data-end=\"7087\"><strong data-start=\"6955\" data-end=\"6991\">Example of Interest Calculation:</strong><br data-start=\"6991\" data-end=\"6994\">If tax liability of ₹50 000 is paid 10 days late, interest = 50 000 &times; 18 % &times; 10 / 365 = ₹247.</p>\r\n<p data-start=\"7089\" data-end=\"7321\"><strong data-start=\"7089\" data-end=\"7120\">Reconciliation with GSTR-1:</strong><br data-start=\"7120\" data-end=\"7123\">The outward supply figures in 3B must match those declared in GSTR-1. Mismatch may cause system alerts or scrutiny notices. Continuous matching avoids audit issues and builds compliance credibility.</p>\r\n<hr data-start=\"7323\" data-end=\"7326\">\r\n<h4 data-start=\"7328\" data-end=\"7359\"><strong data-start=\"7333\" data-end=\"7359\">GSTR-9 &ndash; Annual Return</strong></h4>\r\n<p data-start=\"7361\" data-end=\"7565\">GSTR-9 is a consolidated statement of all monthly/quarterly returns filed during a financial year. It provides a complete picture of sales, purchases, ITC, tax paid, and any adjustments made subsequently.</p>\r\n<p data-start=\"7567\" data-end=\"7696\"><strong data-start=\"7567\" data-end=\"7585\">Applicability:</strong><br data-start=\"7585\" data-end=\"7588\">Mandatory for regular taxpayers having turnover above ₹2 crore.<br data-start=\"7651\" data-end=\"7654\">Composition taxpayers file GSTR-4 instead.</p>\r\n<p data-start=\"7698\" data-end=\"7798\"><strong data-start=\"7698\" data-end=\"7711\">Due Date:</strong> 31 December following the end of the financial year (may be extended by notification).</p>\r\n<p data-start=\"7800\" data-end=\"8018\"><strong data-start=\"7800\" data-end=\"7813\">Contents:</strong><br data-start=\"7813\" data-end=\"7816\">Details of outward and inward supplies, ITC availed/reversed, tax payable vs. paid, HSN-wise summary, and previous-year adjustments.<br data-start=\"7948\" data-end=\"7951\">Taxpayers must reconcile data with audited books before submission.</p>\r\n<p data-start=\"8020\" data-end=\"8096\"><strong data-start=\"8020\" data-end=\"8033\">Late Fee:</strong> ₹200 per day (₹100 CGST + ₹100 SGST) up to 0.25 % of turnover.</p>\r\n<p data-start=\"8098\" data-end=\"8185\">Accurate filing of GSTR-9 ensures transparency and reduces risk of departmental audits.</p>\r\n<hr data-start=\"8187\" data-end=\"8190\">\r\n<h4 data-start=\"8192\" data-end=\"8235\"><strong data-start=\"8197\" data-end=\"8235\">GSTR-9C &ndash; Reconciliation Statement</strong></h4>\r\n<p data-start=\"8237\" data-end=\"8408\">GSTR-9C is an audit-based reconciliation between the figures declared in GSTR-9 and the annual financial statements certified by a Chartered Accountant or Cost Accountant.</p>\r\n<p data-start=\"8410\" data-end=\"8504\"><strong data-start=\"8410\" data-end=\"8428\">Applicability:</strong><br data-start=\"8428\" data-end=\"8431\">Taxpayers with aggregate turnover exceeding ₹5 crore in a financial year.</p>\r\n<p data-start=\"8506\" data-end=\"8683\"><strong data-start=\"8506\" data-end=\"8518\">Purpose:</strong><br data-start=\"8518\" data-end=\"8521\">To verify correctness of turnover, tax payment, and ITC claimed. It acts as a true-up mechanism ensuring that GST data tallies with the audited books of accounts.</p>\r\n<p data-start=\"8685\" data-end=\"8702\"><strong data-start=\"8685\" data-end=\"8700\">Components:</strong></p>\r\n<ul data-start=\"8703\" data-end=\"8831\">\r\n<li data-start=\"8703\" data-end=\"8744\">\r\n<p data-start=\"8705\" data-end=\"8744\">Reconciliation of turnover and taxes.</p>\r\n</li>\r\n<li data-start=\"8745\" data-end=\"8773\">\r\n<p data-start=\"8747\" data-end=\"8773\">Auditor&rsquo;s certification.</p>\r\n</li>\r\n<li data-start=\"8774\" data-end=\"8831\">\r\n<p data-start=\"8776\" data-end=\"8831\">Reporting of additional liability if differences exist.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"8833\" data-end=\"8922\">Filing of 9C increases reliability of the taxpayer&rsquo;s records and reduces litigation risk.</p>\r\n<hr data-start=\"8924\" data-end=\"8927\">\r\n<h4 data-start=\"8929\" data-end=\"8989\"><strong data-start=\"8934\" data-end=\"8989\">GSTR-4 (R-4) &ndash; Composition Taxpayers&rsquo; Annual Return</strong></h4>\r\n<p data-start=\"8991\" data-end=\"9208\">Composition taxpayers pay tax at a fixed rate on turnover and are exempt from detailed monthly filings. They must, however, file an annual return in Form GSTR-4 by <strong data-start=\"9155\" data-end=\"9167\">30 April</strong> following the end of the financial year.</p>\r\n<p data-start=\"9210\" data-end=\"9240\"><strong data-start=\"9210\" data-end=\"9238\">Details to be Furnished:</strong></p>\r\n<ul data-start=\"9241\" data-end=\"9404\">\r\n<li data-start=\"9241\" data-end=\"9284\">\r\n<p data-start=\"9243\" data-end=\"9284\">Consolidated turnover of supplies made.</p>\r\n</li>\r\n<li data-start=\"9285\" data-end=\"9314\">\r\n<p data-start=\"9287\" data-end=\"9314\">Tax paid during the year.</p>\r\n</li>\r\n<li data-start=\"9315\" data-end=\"9361\">\r\n<p data-start=\"9317\" data-end=\"9361\">Inward supplies attracting reverse charge.</p>\r\n</li>\r\n<li data-start=\"9362\" data-end=\"9404\">\r\n<p data-start=\"9364\" data-end=\"9404\">Amendments, if any, from previous years.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"9406\" data-end=\"9482\">Failure to file attracts a late fee of ₹50 per day (₹25 + ₹25) up to ₹2 000.</p>\r\n<hr data-start=\"9484\" data-end=\"9487\">\r\n<h4 data-start=\"9489\" data-end=\"9522\"><strong data-start=\"9494\" data-end=\"9522\">ITC-04 &ndash; Job-Work Return</strong></h4>\r\n<p data-start=\"9524\" data-end=\"9749\">ITC-04 is required to be filed by manufacturers or principal suppliers who send goods to job-workers and receive them back. It records details of goods sent for job-work, received back, or sent from one job-worker to another.</p>\r\n<p data-start=\"9751\" data-end=\"9950\"><strong data-start=\"9751\" data-end=\"9765\">Frequency:</strong> Quarterly.<br data-start=\"9776\" data-end=\"9779\"><strong data-start=\"9779\" data-end=\"9792\">Due Date:</strong> 25th of the month following the quarter.<br data-start=\"9833\" data-end=\"9836\">Accurate filing ensures that goods sent for processing are duly accounted for and input-tax credit remains intact.</p>\r\n<hr data-start=\"9952\" data-end=\"9955\">\r\n<h4 data-start=\"9957\" data-end=\"9999\"><strong data-start=\"9962\" data-end=\"9999\">Late Fees and Penalties under GST</strong></h4>\r\n<p data-start=\"10001\" data-end=\"10101\">Late fees apply for each day after the due date until the return is filed. Below are general limits:</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"10103\" data-end=\"10390\">\r\n<thead data-start=\"10103\" data-end=\"10191\">\r\n<tr data-start=\"10103\" data-end=\"10191\">\r\n<th data-start=\"10103\" data-end=\"10121\" data-col-size=\"sm\"><strong data-start=\"10105\" data-end=\"10120\">Return Type</strong></th>\r\n<th data-start=\"10121\" data-end=\"10149\" data-col-size=\"sm\"><strong data-start=\"10123\" data-end=\"10148\">Normal Late Fee / Day</strong></th>\r\n<th data-start=\"10149\" data-end=\"10172\" data-col-size=\"sm\"><strong data-start=\"10151\" data-end=\"10171\">Nil Return / Day</strong></th>\r\n<th data-start=\"10172\" data-end=\"10191\" data-col-size=\"sm\"><strong data-start=\"10174\" data-end=\"10189\">Maximum Cap</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"10281\" data-end=\"10390\">\r\n<tr data-start=\"10281\" data-end=\"10312\">\r\n<td data-start=\"10281\" data-end=\"10290\" data-col-size=\"sm\">GSTR-1</td>\r\n<td data-start=\"10290\" data-end=\"10296\" data-col-size=\"sm\">₹50</td>\r\n<td data-col-size=\"sm\" data-start=\"10296\" data-end=\"10302\">₹20</td>\r\n<td data-col-size=\"sm\" data-start=\"10302\" data-end=\"10312\">₹5 000</td>\r\n</tr>\r\n<tr data-start=\"10313\" data-end=\"10345\">\r\n<td data-start=\"10313\" data-end=\"10323\" data-col-size=\"sm\">GSTR-3B</td>\r\n<td data-col-size=\"sm\" data-start=\"10323\" data-end=\"10329\">₹50</td>\r\n<td data-col-size=\"sm\" data-start=\"10329\" data-end=\"10335\">₹20</td>\r\n<td data-col-size=\"sm\" data-start=\"10335\" data-end=\"10345\">₹5 000</td>\r\n</tr>\r\n<tr data-start=\"10346\" data-end=\"10390\">\r\n<td data-start=\"10346\" data-end=\"10355\" data-col-size=\"sm\">GSTR-9</td>\r\n<td data-col-size=\"sm\" data-start=\"10355\" data-end=\"10362\">₹200</td>\r\n<td data-col-size=\"sm\" data-start=\"10362\" data-end=\"10368\">N/A</td>\r\n<td data-col-size=\"sm\" data-start=\"10368\" data-end=\"10390\">0.25 % of turnover</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"10392\" data-end=\"10492\"><strong data-start=\"10392\" data-end=\"10405\">Interest:</strong><br data-start=\"10405\" data-end=\"10408\">18 % p.a. on delayed payment of tax and 24 % p.a. for undue or excess credit claims.</p>\r\n<p data-start=\"10494\" data-end=\"10583\">Continuous default may lead to suspension or cancellation of registration under Rule 21A.</p>\r\n<hr data-start=\"10585\" data-end=\"10588\">\r\n<h4 data-start=\"10590\" data-end=\"10628\"><strong data-start=\"10595\" data-end=\"10628\">Reconciliation and Compliance</strong></h4>\r\n<p data-start=\"10630\" data-end=\"10714\">Reconciliation is the process of matching data across returns to ensure consistency:</p>\r\n<ul data-start=\"10716\" data-end=\"10877\">\r\n<li data-start=\"10716\" data-end=\"10773\">\r\n<p data-start=\"10718\" data-end=\"10773\">Outward supplies in GSTR-1 = Tax liability in GSTR-3B</p>\r\n</li>\r\n<li data-start=\"10774\" data-end=\"10823\">\r\n<p data-start=\"10776\" data-end=\"10823\">ITC in GSTR-3B = Credits reflected in GSTR-2B</p>\r\n</li>\r\n<li data-start=\"10824\" data-end=\"10877\">\r\n<p data-start=\"10826\" data-end=\"10877\">Turnover in GSTR-9 = Audited financial statements</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"10879\" data-end=\"11014\">Mismatch in any of these leads to scrutiny or demand notices. Monthly reconciliation prevents cumulative errors and financial exposure.</p>\r\n<hr data-start=\"11016\" data-end=\"11019\">\r\n<h4 data-start=\"11021\" data-end=\"11066\"><strong data-start=\"11026\" data-end=\"11066\">Amendments and Correction of Returns</strong></h4>\r\n<p data-start=\"11068\" data-end=\"11448\">GST law does not permit revision of a filed return. However, omissions or errors can be corrected in subsequent periods up to <strong data-start=\"11194\" data-end=\"11241\">30 November of the following financial year</strong>.<br data-start=\"11242\" data-end=\"11245\">Amendments include addition of missing invoices, rectification of tax head errors, and reporting of credit or debit notes.<br data-start=\"11367\" data-end=\"11370\">Any additional liability must be paid through Form DRC-03 along with interest.</p>\r\n<hr data-start=\"11450\" data-end=\"11453\">\r\n<h4 data-start=\"11455\" data-end=\"11509\"><strong data-start=\"11460\" data-end=\"11509\">GST Return Filing Calendar (Regular Taxpayer)</strong></h4>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"11511\" data-end=\"11911\">\r\n<thead data-start=\"11511\" data-end=\"11554\">\r\n<tr data-start=\"11511\" data-end=\"11554\">\r\n<th data-start=\"11511\" data-end=\"11522\" data-col-size=\"sm\"><strong data-start=\"11513\" data-end=\"11521\">Form</strong></th>\r\n<th data-start=\"11522\" data-end=\"11538\" data-col-size=\"sm\"><strong data-start=\"11524\" data-end=\"11537\">Frequency</strong></th>\r\n<th data-start=\"11538\" data-end=\"11554\" data-col-size=\"sm\"><strong data-start=\"11540\" data-end=\"11552\">Due Date</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"11601\" data-end=\"11911\">\r\n<tr data-start=\"11601\" data-end=\"11669\">\r\n<td data-start=\"11601\" data-end=\"11610\" data-col-size=\"sm\">GSTR-1</td>\r\n<td data-col-size=\"sm\" data-start=\"11610\" data-end=\"11632\">Monthly / Quarterly</td>\r\n<td data-col-size=\"sm\" data-start=\"11632\" data-end=\"11669\">11th / 13th of next month/quarter</td>\r\n</tr>\r\n<tr data-start=\"11670\" data-end=\"11712\">\r\n<td data-start=\"11670\" data-end=\"11680\" data-col-size=\"sm\">GSTR-3B</td>\r\n<td data-col-size=\"sm\" data-start=\"11680\" data-end=\"11690\">Monthly</td>\r\n<td data-col-size=\"sm\" data-start=\"11690\" data-end=\"11712\">20th of next month</td>\r\n</tr>\r\n<tr data-start=\"11713\" data-end=\"11759\">\r\n<td data-start=\"11713\" data-end=\"11722\" data-col-size=\"sm\">GSTR-9</td>\r\n<td data-start=\"11722\" data-end=\"11731\" data-col-size=\"sm\">Annual</td>\r\n<td data-start=\"11731\" data-end=\"11759\" data-col-size=\"sm\">31 December following FY</td>\r\n</tr>\r\n<tr data-start=\"11760\" data-end=\"11807\">\r\n<td data-start=\"11760\" data-end=\"11770\" data-col-size=\"sm\">GSTR-9C</td>\r\n<td data-start=\"11770\" data-end=\"11779\" data-col-size=\"sm\">Annual</td>\r\n<td data-start=\"11779\" data-end=\"11807\" data-col-size=\"sm\">31 December following FY</td>\r\n</tr>\r\n<tr data-start=\"11808\" data-end=\"11865\">\r\n<td data-start=\"11808\" data-end=\"11817\" data-col-size=\"sm\">GSTR-4</td>\r\n<td data-col-size=\"sm\" data-start=\"11817\" data-end=\"11840\">Annual (Composition)</td>\r\n<td data-col-size=\"sm\" data-start=\"11840\" data-end=\"11865\">30 April following FY</td>\r\n</tr>\r\n<tr data-start=\"11866\" data-end=\"11911\">\r\n<td data-start=\"11866\" data-end=\"11875\" data-col-size=\"sm\">ITC-04</td>\r\n<td data-col-size=\"sm\" data-start=\"11875\" data-end=\"11887\">Quarterly</td>\r\n<td data-col-size=\"sm\" data-start=\"11887\" data-end=\"11911\">25th of next quarter</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"11913\" data-end=\"11992\">Timely adherence to this calendar ensures full compliance and avoids penalties.</p>\r\n<hr data-start=\"11994\" data-end=\"11997\">\r\n<h4 data-start=\"11999\" data-end=\"12034\"><strong data-start=\"12004\" data-end=\"12034\">Consequences of Non-Filing</strong></h4>\r\n<ul data-start=\"12036\" data-end=\"12318\">\r\n<li data-start=\"12036\" data-end=\"12091\">\r\n<p data-start=\"12038\" data-end=\"12091\"><strong data-start=\"12038\" data-end=\"12062\">Suspension of GSTIN:</strong> After continuous defaults.</p>\r\n</li>\r\n<li data-start=\"12092\" data-end=\"12170\">\r\n<p data-start=\"12094\" data-end=\"12170\"><strong data-start=\"12094\" data-end=\"12122\">Blocking of e-way bills:</strong> Taxpayer cannot generate transport documents.</p>\r\n</li>\r\n<li data-start=\"12171\" data-end=\"12235\">\r\n<p data-start=\"12173\" data-end=\"12235\"><strong data-start=\"12173\" data-end=\"12189\">Loss of ITC:</strong> Buyers cannot claim credit from non-filers.</p>\r\n</li>\r\n<li data-start=\"12236\" data-end=\"12318\">\r\n<p data-start=\"12238\" data-end=\"12318\"><strong data-start=\"12238\" data-end=\"12262\">Departmental action:</strong> Assessment under Section 62 and recovery proceedings.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"12320\" data-end=\"12414\">To maintain smooth operations, returns must be filed regularly even in nil-transaction months.</p>\r\n<hr data-start=\"12416\" data-end=\"12419\">\r\n<h4 data-start=\"12421\" data-end=\"12459\"><strong data-start=\"12426\" data-end=\"12459\">Why Consistent Filing Matters</strong></h4>\r\n<ol data-start=\"12461\" data-end=\"12779\">\r\n<li data-start=\"12461\" data-end=\"12513\">\r\n<p data-start=\"12464\" data-end=\"12513\">Ensures uninterrupted flow of input-tax credit.</p>\r\n</li>\r\n<li data-start=\"12514\" data-end=\"12577\">\r\n<p data-start=\"12517\" data-end=\"12577\">Builds a strong compliance rating visible to stakeholders.</p>\r\n</li>\r\n<li data-start=\"12578\" data-end=\"12624\">\r\n<p data-start=\"12581\" data-end=\"12624\">Avoids cumulative late fees and interest.</p>\r\n</li>\r\n<li data-start=\"12625\" data-end=\"12704\">\r\n<p data-start=\"12628\" data-end=\"12704\">Enables participation in government contracts requiring active GST status.</p>\r\n</li>\r\n<li data-start=\"12705\" data-end=\"12779\">\r\n<p data-start=\"12708\" data-end=\"12779\">Demonstrates financial discipline and credibility to banks and vendors.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"12781\" data-end=\"12784\">\r\n<h4 data-start=\"12786\" data-end=\"12824\"><strong data-start=\"12791\" data-end=\"12824\">How Rajasthan Filings Assists</strong></h4>\r\n<p data-start=\"12826\" data-end=\"12892\">Rajasthan Filings provides end-to-end GST compliance management:</p>\r\n<ul data-start=\"12893\" data-end=\"13240\">\r\n<li data-start=\"12893\" data-end=\"12947\">\r\n<p data-start=\"12895\" data-end=\"12947\">Preparation of data and validation as per GST law.</p>\r\n</li>\r\n<li data-start=\"12948\" data-end=\"12997\">\r\n<p data-start=\"12950\" data-end=\"12997\">Accurate computation of liability and credit.</p>\r\n</li>\r\n<li data-start=\"12998\" data-end=\"13062\">\r\n<p data-start=\"13000\" data-end=\"13062\">Timely filing of all monthly, quarterly, and annual returns.</p>\r\n</li>\r\n<li data-start=\"13063\" data-end=\"13131\">\r\n<p data-start=\"13065\" data-end=\"13131\">Reconciliation of outward and inward data to prevent mismatches.</p>\r\n</li>\r\n<li data-start=\"13132\" data-end=\"13186\">\r\n<p data-start=\"13134\" data-end=\"13186\">Reminder systems for due dates and updates in law.</p>\r\n</li>\r\n<li data-start=\"13187\" data-end=\"13240\">\r\n<p data-start=\"13189\" data-end=\"13240\">Advisory on notices, assessments, and amendments.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"13242\" data-end=\"13370\">Our goal is to keep businesses fully compliant with minimal administrative burden while ensuring accuracy in every filing cycle.</p>\r\n<hr data-start=\"13372\" data-end=\"13375\">\r\n<h4 data-start=\"13377\" data-end=\"13396\"><strong data-start=\"13382\" data-end=\"13396\">Conclusion</strong></h4>\r\n<p data-start=\"13398\" data-end=\"13756\">The GST return filing process is the backbone of the indirect-tax framework. Each form &mdash; GSTR-1 for sales, GSTR-3B for payment, GSTR-9 for annual summary, GSTR-9C for audit, GSTR-4 for composition, and ITC-04 for job-work &mdash; serves a distinct legal purpose. Together they ensure transparency, accountability, and credit continuity throughout the supply chain.</p>\r\n<p data-start=\"13758\" data-end=\"14035\">Filing these returns accurately and on time protects a business from penalties, secures uninterrupted input-tax credit, and strengthens professional credibility.<br data-start=\"13919\" data-end=\"13922\">For Indian enterprises, GST compliance is not merely a statutory requirement but a measure of business integrity.</p>\r\n<p data-start=\"14037\" data-end=\"14211\">Rajasthan Filings helps taxpayers across India manage GST filings with confidence and precision &mdash; ensuring that every return reflects accuracy, compliance, and peace of mind.</p>', NULL, NULL, '1758969375_pro-img-3.jpg', NULL, 1, '2025-09-03 13:19:18', '2025-11-08 00:52:22'),
(4, 1, NULL, 'MSME/Udyam Registration', 'msmeudyam-registration', 'MSME/Udyam Registration', '<h1 style=\"font-size: 34px; line-height: 1.3; margin-bottom: 10px;\">🏭 <strong>MSME / Udyam Registration</strong></h1>\r\n<h2 data-start=\"290\" data-end=\"347\">🌟 Empower Your Business with Government Recognition</h2>\r\n<p data-start=\"348\" data-end=\"732\">At <strong data-start=\"351\" data-end=\"372\">Rajasthan Filings</strong>, we help e</p>\r\n<hr data-start=\"3029\" data-end=\"3032\">\r\n<h2 data-start=\"3034\" data-end=\"3075\">📞 <strong data-start=\"3040\" data-end=\"3075\">Get Your MSME Certificate Today</strong></h2>\r\n<blockquote data-start=\"3076\" data-end=\"3214\">\r\n<p data-start=\"3078\" data-end=\"3214\">Give your business the recognition it deserves.<br data-start=\"3125\" data-end=\"3128\">Get registered as a Micro, Small, or Medium Enterprise with Rajasthan Filings today.</p>\r\n</blockquote>', 'Take input tax credit\r\nMake interstate sales without restrictions', 'Having Turnover of more than 40 lakhs in case of Goods\r\nHaving Turnover of more than 20 lakhs in case of Services\r\nVoluntary Registration\r\nInter State Sales', '1758969352_pro-img-2.jpg', NULL, 1, '2025-09-06 00:35:09', '2025-11-08 02:22:36');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(6, 4, NULL, 'Loan Assistance Services', 'loan-assistance-services', '(MSME, Mudra, Business, Home, Personal & Project Loans)', '<h1 data-start=\"354\" data-end=\"440\"><strong data-start=\"356\" data-end=\"440\">Loan Assistance Services (MSME, Mudra, Business, Home, Personal &amp; Project Loans)</strong></h1>\r\n<hr data-start=\"442\" data-end=\"445\">\r\n<h3 data-start=\"447\" data-end=\"463\"><strong data-start=\"451\" data-end=\"463\">Overview</strong></h3>\r\n<p data-start=\"465\" data-end=\"736\">Finance is the foundation of every successful business and personal milestone. Whether you are starting a new enterprise, expanding your operations, purchasing property, or meeting personal needs &mdash; access to the right loan at the right time can make all the difference.</p>\r\n<p data-start=\"738\" data-end=\"1074\">At <strong data-start=\"741\" data-end=\"762\">Rajasthan Filings</strong>, we provide <strong data-start=\"775\" data-end=\"817\">comprehensive loan assistance services</strong> across India &mdash; from documentation to eligibility evaluation, project report preparation, CMA data, and liaison with banks and financial institutions.<br data-start=\"967\" data-end=\"970\">Our goal is to help you get <strong data-start=\"998\" data-end=\"1046\">fast, transparent, and hassle-free approvals</strong> for every category of loan.</p>\r\n<hr data-start=\"1076\" data-end=\"1079\">\r\n<h3 data-start=\"1081\" data-end=\"1119\"><strong data-start=\"1085\" data-end=\"1119\">Our Loan Assistance Categories</strong></h3>\r\n<h4 data-start=\"1121\" data-end=\"1142\"><strong data-start=\"1126\" data-end=\"1142\">1. MSME Loan</strong></h4>\r\n<p data-start=\"1143\" data-end=\"1280\">Loans designed for Micro, Small, and Medium Enterprises for working capital, machinery purchase, or business expansion.<br data-start=\"1262\" data-end=\"1265\"><strong data-start=\"1265\" data-end=\"1278\">Features:</strong></p>\r\n<ul data-start=\"1281\" data-end=\"1411\">\r\n<li data-start=\"1281\" data-end=\"1304\">\r\n<p data-start=\"1283\" data-end=\"1304\">Loan up to ₹5 crore</p>\r\n</li>\r\n<li data-start=\"1305\" data-end=\"1344\">\r\n<p data-start=\"1307\" data-end=\"1344\">Collateral-free under CGTMSE scheme</p>\r\n</li>\r\n<li data-start=\"1345\" data-end=\"1411\">\r\n<p data-start=\"1347\" data-end=\"1411\">Flexible repayment and interest subsidy under eligible schemes</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1413\" data-end=\"1416\">\r\n<h4 data-start=\"1418\" data-end=\"1465\"><strong data-start=\"1423\" data-end=\"1465\">2. Mudra Loan (Shishu, Kishor &amp; Tarun)</strong></h4>\r\n<p data-start=\"1466\" data-end=\"1615\">Special government-backed loans under the <strong data-start=\"1508\" data-end=\"1546\">Pradhan Mantri Mudra Yojana (PMMY)</strong> for traders, manufacturers, and service providers.<br data-start=\"1597\" data-end=\"1600\"><strong data-start=\"1600\" data-end=\"1613\">Features:</strong></p>\r\n<ul data-start=\"1616\" data-end=\"1778\">\r\n<li data-start=\"1616\" data-end=\"1658\">\r\n<p data-start=\"1618\" data-end=\"1658\">Up to ₹10 lakh loan without collateral</p>\r\n</li>\r\n<li data-start=\"1659\" data-end=\"1725\">\r\n<p data-start=\"1661\" data-end=\"1725\">Ideal for startups, small retailers, and self-employed persons</p>\r\n</li>\r\n<li data-start=\"1726\" data-end=\"1778\">\r\n<p data-start=\"1728\" data-end=\"1778\">Subsidy and support under government initiatives</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1780\" data-end=\"1783\">\r\n<h4 data-start=\"1785\" data-end=\"1810\"><strong data-start=\"1790\" data-end=\"1810\">3. Business Loan</strong></h4>\r\n<p data-start=\"1811\" data-end=\"1950\">Unsecured loans for small and medium businesses to manage daily operations, marketing, inventory, or growth requirements.<br data-start=\"1932\" data-end=\"1935\"><strong data-start=\"1935\" data-end=\"1948\">Features:</strong></p>\r\n<ul data-start=\"1951\" data-end=\"2113\">\r\n<li data-start=\"1951\" data-end=\"1983\">\r\n<p data-start=\"1953\" data-end=\"1983\">No collateral up to ₹50 lakh</p>\r\n</li>\r\n<li data-start=\"1984\" data-end=\"2042\">\r\n<p data-start=\"1986\" data-end=\"2042\">Fast approval with simplified KYC and ITR verification</p>\r\n</li>\r\n<li data-start=\"2043\" data-end=\"2113\">\r\n<p data-start=\"2045\" data-end=\"2113\">Available for proprietors, partnerships, and private limited firms</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2115\" data-end=\"2118\">\r\n<h4 data-start=\"2120\" data-end=\"2141\"><strong data-start=\"2125\" data-end=\"2141\">4. Home Loan</strong></h4>\r\n<p data-start=\"2142\" data-end=\"2231\">Loans for purchasing, constructing, or renovating residential property.<br data-start=\"2213\" data-end=\"2216\"><strong data-start=\"2216\" data-end=\"2229\">Features:</strong></p>\r\n<ul data-start=\"2232\" data-end=\"2394\">\r\n<li data-start=\"2232\" data-end=\"2271\">\r\n<p data-start=\"2234\" data-end=\"2271\">Loan up to 80&ndash;90% of property value</p>\r\n</li>\r\n<li data-start=\"2272\" data-end=\"2339\">\r\n<p data-start=\"2274\" data-end=\"2339\">Attractive interest rates with flexible tenure (up to 30 years)</p>\r\n</li>\r\n<li data-start=\"2340\" data-end=\"2394\">\r\n<p data-start=\"2342\" data-end=\"2394\">Balance transfer and top-up loan options available</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2396\" data-end=\"2399\">\r\n<h4 data-start=\"2401\" data-end=\"2426\"><strong data-start=\"2406\" data-end=\"2426\">5. Personal Loan</strong></h4>\r\n<p data-start=\"2427\" data-end=\"2561\">Quick and flexible unsecured loans for individual financial needs such as education, marriage, travel, or emergency.<br data-start=\"2543\" data-end=\"2546\"><strong data-start=\"2546\" data-end=\"2559\">Features:</strong></p>\r\n<ul data-start=\"2562\" data-end=\"2687\">\r\n<li data-start=\"2562\" data-end=\"2595\">\r\n<p data-start=\"2564\" data-end=\"2595\">Loan from ₹50,000 to ₹25 lakh</p>\r\n</li>\r\n<li data-start=\"2596\" data-end=\"2633\">\r\n<p data-start=\"2598\" data-end=\"2633\">No security or guarantor required</p>\r\n</li>\r\n<li data-start=\"2634\" data-end=\"2687\">\r\n<p data-start=\"2636\" data-end=\"2687\">Instant approval based on credit score and income</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2689\" data-end=\"2692\">\r\n<h4 data-start=\"2694\" data-end=\"2730\"><strong data-start=\"2699\" data-end=\"2730\">6. Vehicle &amp; Equipment Loan</strong></h4>\r\n<p data-start=\"2731\" data-end=\"2855\">Loans for commercial or personal vehicles, JCBs, tractors, and machinery for industrial and transport use.<br data-start=\"2837\" data-end=\"2840\"><strong data-start=\"2840\" data-end=\"2853\">Features:</strong></p>\r\n<ul data-start=\"2856\" data-end=\"2981\">\r\n<li data-start=\"2856\" data-end=\"2893\">\r\n<p data-start=\"2858\" data-end=\"2893\">Up to 85% financing of asset cost</p>\r\n</li>\r\n<li data-start=\"2894\" data-end=\"2942\">\r\n<p data-start=\"2896\" data-end=\"2942\">Fast disbursement with minimal documentation</p>\r\n</li>\r\n<li data-start=\"2943\" data-end=\"2981\">\r\n<p data-start=\"2945\" data-end=\"2981\">Flexible repayment and EMI options</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2983\" data-end=\"2986\">\r\n<h4 data-start=\"2988\" data-end=\"3024\"><strong data-start=\"2993\" data-end=\"3024\">7. Project Loan / Term Loan</strong></h4>\r\n<p data-start=\"3025\" data-end=\"3122\">Long-term funding for setting up new plants, industries, or expansion projects.<br data-start=\"3104\" data-end=\"3107\"><strong data-start=\"3107\" data-end=\"3120\">Features:</strong></p>\r\n<ul data-start=\"3123\" data-end=\"3282\">\r\n<li data-start=\"3123\" data-end=\"3178\">\r\n<p data-start=\"3125\" data-end=\"3178\">Customized financial projections &amp; CMA data support</p>\r\n</li>\r\n<li data-start=\"3179\" data-end=\"3223\">\r\n<p data-start=\"3181\" data-end=\"3223\">Collateral or project-based loan options</p>\r\n</li>\r\n<li data-start=\"3224\" data-end=\"3282\">\r\n<p data-start=\"3226\" data-end=\"3282\">Required for manufacturing and infrastructure projects</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3284\" data-end=\"3287\">\r\n<h4 data-start=\"3289\" data-end=\"3340\"><strong data-start=\"3294\" data-end=\"3340\">8. Government Subsidy &amp; Scheme-Based Loans</strong></h4>\r\n<p data-start=\"3341\" data-end=\"3441\">We help entrepreneurs benefit from all central and state government financial initiatives such as:</p>\r\n<ul data-start=\"3442\" data-end=\"3813\">\r\n<li data-start=\"3442\" data-end=\"3508\">\r\n<p data-start=\"3444\" data-end=\"3508\"><strong data-start=\"3444\" data-end=\"3459\">CGTMSE Loan</strong> &ndash; Collateral-free MSME funding up to ₹2 crore.</p>\r\n</li>\r\n<li data-start=\"3509\" data-end=\"3595\">\r\n<p data-start=\"3511\" data-end=\"3595\"><strong data-start=\"3511\" data-end=\"3541\">PMEGP (Khadi Board Scheme)</strong> &ndash; Subsidized loans for manufacturing/service units.</p>\r\n</li>\r\n<li data-start=\"3596\" data-end=\"3655\">\r\n<p data-start=\"3598\" data-end=\"3655\"><strong data-start=\"3598\" data-end=\"3616\">Stand-Up India</strong> &ndash; For women and SC/ST entrepreneurs.</p>\r\n</li>\r\n<li data-start=\"3656\" data-end=\"3728\">\r\n<p data-start=\"3658\" data-end=\"3728\"><strong data-start=\"3658\" data-end=\"3691\">Startup India &amp; SIDBI Schemes</strong> &ndash; Funding for innovative startups.</p>\r\n</li>\r\n<li data-start=\"3729\" data-end=\"3813\">\r\n<p data-start=\"3731\" data-end=\"3813\"><strong data-start=\"3731\" data-end=\"3753\">PM Svanidhi Scheme</strong> &ndash; Small loans for street vendors and micro-entrepreneurs.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3815\" data-end=\"3818\">\r\n<h3 data-start=\"3820\" data-end=\"3859\"><strong data-start=\"3824\" data-end=\"3859\">How Rajasthan Filings Helps You</strong></h3>\r\n<ol data-start=\"3861\" data-end=\"4653\">\r\n<li data-start=\"3861\" data-end=\"4014\">\r\n<p data-start=\"3864\" data-end=\"4014\"><strong data-start=\"3864\" data-end=\"3896\">Loan Eligibility Evaluation:</strong><br data-start=\"3896\" data-end=\"3899\">We assess your financial profile, credit history, and business strength to find the best loan type and scheme.</p>\r\n</li>\r\n<li data-start=\"4016\" data-end=\"4177\">\r\n<p data-start=\"4019\" data-end=\"4177\"><strong data-start=\"4019\" data-end=\"4051\">Documentation &amp; Application:</strong><br data-start=\"4051\" data-end=\"4054\">We prepare and organize all necessary papers such as ITRs, balance sheets, identity proofs, and business registration.</p>\r\n</li>\r\n<li data-start=\"4179\" data-end=\"4353\">\r\n<p data-start=\"4182\" data-end=\"4353\"><strong data-start=\"4182\" data-end=\"4224\">CMA Data &amp; Project Report Preparation:</strong><br data-start=\"4224\" data-end=\"4227\">Our financial experts prepare bank-ready CMA Data, cash flow statements, and project reports for sanctioning authorities.</p>\r\n</li>\r\n<li data-start=\"4355\" data-end=\"4517\">\r\n<p data-start=\"4358\" data-end=\"4517\"><strong data-start=\"4358\" data-end=\"4398\">Bank Coordination &amp; File Submission:</strong><br data-start=\"4398\" data-end=\"4401\">We directly liaise with nationalized, private, and NBFC banks to ensure smooth application review and approval.</p>\r\n</li>\r\n<li data-start=\"4519\" data-end=\"4653\">\r\n<p data-start=\"4522\" data-end=\"4653\"><strong data-start=\"4522\" data-end=\"4549\">Post-Approval Services:</strong><br data-start=\"4549\" data-end=\"4552\">Assistance in agreement finalization, account setup, disbursement follow-up, and subsidy claims.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"4655\" data-end=\"4658\">\r\n<h3 data-start=\"4660\" data-end=\"4686\"><strong data-start=\"4664\" data-end=\"4686\">Documents Required</strong></h3>\r\n<ul data-start=\"4688\" data-end=\"5038\">\r\n<li data-start=\"4688\" data-end=\"4757\">\r\n<p data-start=\"4690\" data-end=\"4757\">PAN, Aadhaar, and photographs of applicant / partners / directors</p>\r\n</li>\r\n<li data-start=\"4758\" data-end=\"4817\">\r\n<p data-start=\"4760\" data-end=\"4817\">Business registration proof (GST, Udyam, Incorporation)</p>\r\n</li>\r\n<li data-start=\"4818\" data-end=\"4851\">\r\n<p data-start=\"4820\" data-end=\"4851\">3 years&rsquo; ITR &amp; balance sheets</p>\r\n</li>\r\n<li data-start=\"4852\" data-end=\"4891\">\r\n<p data-start=\"4854\" data-end=\"4891\">Latest bank statement (6&ndash;12 months)</p>\r\n</li>\r\n<li data-start=\"4892\" data-end=\"4951\">\r\n<p data-start=\"4894\" data-end=\"4951\">Property / quotation / invoice of asset (if applicable)</p>\r\n</li>\r\n<li data-start=\"4952\" data-end=\"4976\">\r\n<p data-start=\"4954\" data-end=\"4976\">Address and ID proof</p>\r\n</li>\r\n<li data-start=\"4977\" data-end=\"5038\">\r\n<p data-start=\"4979\" data-end=\"5038\">Project report or CMA data (we prepare it professionally)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5040\" data-end=\"5043\">\r\n<h3 data-start=\"5045\" data-end=\"5094\"><strong data-start=\"5049\" data-end=\"5094\">Eligibility Criteria (General Guidelines)</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5096\" data-end=\"5669\">\r\n<thead data-start=\"5096\" data-end=\"5152\">\r\n<tr data-start=\"5096\" data-end=\"5152\">\r\n<th data-start=\"5096\" data-end=\"5112\" data-col-size=\"sm\"><strong data-start=\"5098\" data-end=\"5111\">Loan Type</strong></th>\r\n<th data-start=\"5112\" data-end=\"5130\" data-col-size=\"md\"><strong data-start=\"5114\" data-end=\"5129\">Eligibility</strong></th>\r\n<th data-start=\"5130\" data-end=\"5152\" data-col-size=\"sm\"><strong data-start=\"5132\" data-end=\"5150\">Maximum Amount</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5210\" data-end=\"5669\">\r\n<tr data-start=\"5210\" data-end=\"5290\">\r\n<td data-start=\"5210\" data-end=\"5226\" data-col-size=\"sm\">MSME / CGTMSE</td>\r\n<td data-col-size=\"md\" data-start=\"5226\" data-end=\"5278\">Registered business with minimum 1 year operation</td>\r\n<td data-col-size=\"sm\" data-start=\"5278\" data-end=\"5290\">₹5 crore</td>\r\n</tr>\r\n<tr data-start=\"5291\" data-end=\"5363\">\r\n<td data-start=\"5291\" data-end=\"5304\" data-col-size=\"sm\">Mudra Loan</td>\r\n<td data-start=\"5304\" data-end=\"5351\" data-col-size=\"md\">Small business / retailer / service provider</td>\r\n<td data-col-size=\"sm\" data-start=\"5351\" data-end=\"5363\">₹10 lakh</td>\r\n</tr>\r\n<tr data-start=\"5364\" data-end=\"5438\">\r\n<td data-start=\"5364\" data-end=\"5380\" data-col-size=\"sm\">Business Loan</td>\r\n<td data-start=\"5380\" data-end=\"5426\" data-col-size=\"md\">Any registered business with turnover proof</td>\r\n<td data-col-size=\"sm\" data-start=\"5426\" data-end=\"5438\">₹50 lakh</td>\r\n</tr>\r\n<tr data-start=\"5439\" data-end=\"5509\">\r\n<td data-start=\"5439\" data-end=\"5451\" data-col-size=\"sm\">Home Loan</td>\r\n<td data-start=\"5451\" data-end=\"5497\" data-col-size=\"md\">Salaried or self-employed with income proof</td>\r\n<td data-col-size=\"sm\" data-start=\"5497\" data-end=\"5509\">₹2 crore</td>\r\n</tr>\r\n<tr data-start=\"5510\" data-end=\"5581\">\r\n<td data-start=\"5510\" data-end=\"5526\" data-col-size=\"sm\">Personal Loan</td>\r\n<td data-start=\"5526\" data-end=\"5569\" data-col-size=\"md\">Individual with good credit score (700+)</td>\r\n<td data-col-size=\"sm\" data-start=\"5569\" data-end=\"5581\">₹25 lakh</td>\r\n</tr>\r\n<tr data-start=\"5582\" data-end=\"5669\">\r\n<td data-start=\"5582\" data-end=\"5604\" data-col-size=\"sm\">Project / Term Loan</td>\r\n<td data-col-size=\"md\" data-start=\"5604\" data-end=\"5646\">New or expansion projects with CMA Data</td>\r\n<td data-col-size=\"sm\" data-start=\"5646\" data-end=\"5669\">As per project cost</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5671\" data-end=\"5674\">\r\n<h3 data-start=\"5676\" data-end=\"5715\"><strong data-start=\"5680\" data-end=\"5715\">Benefits of Our Loan Assistance</strong></h3>\r\n<ul data-start=\"5717\" data-end=\"5996\">\r\n<li data-start=\"5717\" data-end=\"5767\">\r\n<p data-start=\"5719\" data-end=\"5767\">Access to multiple loan options under one roof</p>\r\n</li>\r\n<li data-start=\"5768\" data-end=\"5821\">\r\n<p data-start=\"5770\" data-end=\"5821\">Accurate and professional financial documentation</p>\r\n</li>\r\n<li data-start=\"5822\" data-end=\"5877\">\r\n<p data-start=\"5824\" data-end=\"5877\">Faster approval through bank-compliant presentation</p>\r\n</li>\r\n<li data-start=\"5878\" data-end=\"5938\">\r\n<p data-start=\"5880\" data-end=\"5938\">Guidance for subsidy, guarantee, and government benefits</p>\r\n</li>\r\n<li data-start=\"5939\" data-end=\"5996\">\r\n<p data-start=\"5941\" data-end=\"5996\">End-to-end transparency and personalized consultation</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5998\" data-end=\"6001\">\r\n<h3 data-start=\"6003\" data-end=\"6038\"><strong data-start=\"6007\" data-end=\"6038\">Our Loan Assistance Process</strong></h3>\r\n<ol data-start=\"6040\" data-end=\"6323\">\r\n<li data-start=\"6040\" data-end=\"6095\">\r\n<p data-start=\"6043\" data-end=\"6095\">Initial consultation and loan requirement analysis</p>\r\n</li>\r\n<li data-start=\"6096\" data-end=\"6144\">\r\n<p data-start=\"6099\" data-end=\"6144\">Scheme selection and eligibility evaluation</p>\r\n</li>\r\n<li data-start=\"6145\" data-end=\"6195\">\r\n<p data-start=\"6148\" data-end=\"6195\">Document collection and financial data review</p>\r\n</li>\r\n<li data-start=\"6196\" data-end=\"6233\">\r\n<p data-start=\"6199\" data-end=\"6233\">CMA / Project Report preparation</p>\r\n</li>\r\n<li data-start=\"6234\" data-end=\"6277\">\r\n<p data-start=\"6237\" data-end=\"6277\">File submission and liaison with banks</p>\r\n</li>\r\n<li data-start=\"6278\" data-end=\"6323\">\r\n<p data-start=\"6281\" data-end=\"6323\">Loan sanction and disbursement follow-up</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"6325\" data-end=\"6328\">\r\n<h3 data-start=\"6330\" data-end=\"6366\"><strong data-start=\"6334\" data-end=\"6366\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"6368\" data-end=\"6707\">\r\n<li data-start=\"6368\" data-end=\"6441\">\r\n<p data-start=\"6370\" data-end=\"6441\">Managed by Chartered Accountants, finance consultants &amp; legal experts</p>\r\n</li>\r\n<li data-start=\"6442\" data-end=\"6484\">\r\n<p data-start=\"6444\" data-end=\"6484\">100% online and PAN India loan support</p>\r\n</li>\r\n<li data-start=\"6485\" data-end=\"6557\">\r\n<p data-start=\"6487\" data-end=\"6557\">Experience with all major banks, NBFCs, and cooperative institutions</p>\r\n</li>\r\n<li data-start=\"6558\" data-end=\"6609\">\r\n<p data-start=\"6560\" data-end=\"6609\">Transparent, affordable, and time-bound service</p>\r\n</li>\r\n<li data-start=\"6610\" data-end=\"6658\">\r\n<p data-start=\"6612\" data-end=\"6658\">Confidential handling of financial documents</p>\r\n</li>\r\n<li data-start=\"6659\" data-end=\"6707\">\r\n<p data-start=\"6661\" data-end=\"6707\">Dedicated relationship manager for each case</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6709\" data-end=\"6840\">Our professional presentation and strong documentation ensure higher approval rates, better loan terms, and complete peace of mind.</p>\r\n<hr data-start=\"6842\" data-end=\"6845\">\r\n<h3 data-start=\"6847\" data-end=\"6886\"><strong data-start=\"6851\" data-end=\"6886\">Who Can Avail Our Loan Services</strong></h3>\r\n<ul data-start=\"6888\" data-end=\"7138\">\r\n<li data-start=\"6888\" data-end=\"6928\">\r\n<p data-start=\"6890\" data-end=\"6928\">MSME Entrepreneurs and Manufacturers</p>\r\n</li>\r\n<li data-start=\"6929\" data-end=\"6962\">\r\n<p data-start=\"6931\" data-end=\"6962\">Traders and Retail Businesses</p>\r\n</li>\r\n<li data-start=\"6963\" data-end=\"6993\">\r\n<p data-start=\"6965\" data-end=\"6993\">Startups and Professionals</p>\r\n</li>\r\n<li data-start=\"6994\" data-end=\"7023\">\r\n<p data-start=\"6996\" data-end=\"7023\">Self-employed Individuals</p>\r\n</li>\r\n<li data-start=\"7024\" data-end=\"7056\">\r\n<p data-start=\"7026\" data-end=\"7056\">Contractors and Transporters</p>\r\n</li>\r\n<li data-start=\"7057\" data-end=\"7096\">\r\n<p data-start=\"7059\" data-end=\"7096\">Farmers, Dairy and Agro-based Units</p>\r\n</li>\r\n<li data-start=\"7097\" data-end=\"7138\">\r\n<p data-start=\"7099\" data-end=\"7138\">Salaried and Non-Salaried Home Buyers</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7140\" data-end=\"7143\">\r\n<h3 data-start=\"7145\" data-end=\"7163\"><strong data-start=\"7149\" data-end=\"7163\">Conclusion</strong></h3>\r\n<p data-start=\"7165\" data-end=\"7476\">In today&rsquo;s competitive financial environment, the right documentation and presentation make all the difference.<br data-start=\"7276\" data-end=\"7279\">At <strong data-start=\"7282\" data-end=\"7303\">Rajasthan Filings</strong>, we help you get your loan approved faster, with less stress and more clarity &mdash; whether it&rsquo;s a business loan, home loan, personal loan, or government-backed MSME finance.</p>\r\n<p data-start=\"7478\" data-end=\"7561\">Let our experienced team handle the technicalities while you focus on your goals.</p>', NULL, NULL, '1760512382_pngtree-accountant-doing-financial-analysis-3d-illustration-png-image_9198423.png', NULL, 1, '2025-09-27 05:06:55', '2025-11-08 01:00:40');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(7, 3, NULL, 'Income Tax Return (ITR) Filing', 'income-tax-return-itr-filing-', 'Income Tax Return (ITR) Filing – ITR-1 to ITR-7', '<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" dir=\"auto\" tabindex=\"-1\" data-turn-id=\"request-68fb87f4-a264-8321-b4c7-5e36824a185a-49\" data-testid=\"conversation-turn-92\" data-scroll-anchor=\"false\" data-turn=\"assistant\">\r\n<div class=\"text-base my-auto mx-auto [--thread-content-margin:--spacing(4)] thread-sm:[--thread-content-margin:--spacing(6)] thread-lg:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\">\r\n<div class=\"[--thread-content-max-width:40rem] thread-lg:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\">\r\n<div class=\"flex max-w-full flex-col grow\">\r\n<div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" dir=\"auto\" data-message-author-role=\"assistant\" data-message-id=\"45e56281-f822-41e3-8941-bdf3b60ee1d8\" data-message-model-slug=\"gpt-5\">\r\n<div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\">\r\n<div class=\"markdown prose dark:prose-invert w-full break-words light markdown-new-styling\">\r\n<p data-start=\"1122\" data-end=\"1187\"><strong data-start=\"1122\" data-end=\"1187\">Income Tax Return (ITR) Filing under the Income-tax Act, 2025</strong></p>\r\n<p data-start=\"1189\" data-end=\"1502\">The <strong data-start=\"1193\" data-end=\"1217\">Income-tax Act, 2025</strong> marks a historic modernization of India&rsquo;s direct-tax regime. Coming into effect from <strong data-start=\"1303\" data-end=\"1319\">1 April 2026</strong>, it replaces the six-decade-old Income-tax Act, 1961 and brings a completely digital, transparent, and simplified system for income declaration, tax computation, and return filing.</p>\r\n<p data-start=\"1504\" data-end=\"1910\">In this new legal environment, <strong data-start=\"1535\" data-end=\"1569\">Income Tax Return (ITR) filing</strong> becomes not only a statutory obligation but also a fundamental mechanism for recording income and maintaining financial discipline. Every individual, partnership, LLP, company, trust, or institution earning income in India must disclose their total income, claim eligible deductions, and pay tax according to the new slabs and provisions.</p>\r\n<p data-start=\"1912\" data-end=\"2237\">The Government of India, through the Central Board of Direct Taxes (CBDT), has ensured that the new system under the Income-tax Act 2025 is fully integrated with faceless compliance, real-time data verification, and automatic reconciliation through AIS (Annual Information Statement) and TIS (Taxpayer Information Summary).</p>\r\n<p data-start=\"2239\" data-end=\"2379\">The objective is clear &mdash; to simplify the compliance journey while promoting voluntary disclosure, accuracy, and fairness for every taxpayer.</p>\r\n<hr data-start=\"2381\" data-end=\"2384\">\r\n<h3 data-start=\"2386\" data-end=\"2448\"><strong data-start=\"2390\" data-end=\"2448\">Understanding ITR Filing under the Income-tax Act 2025</strong></h3>\r\n<p data-start=\"2450\" data-end=\"2739\">Filing an Income Tax Return means submitting to the government a detailed statement of one&rsquo;s income, expenditure, deductions, and taxes paid during a financial year. The return acts as both a <strong data-start=\"2642\" data-end=\"2675\">financial disclosure document</strong> and a <strong data-start=\"2682\" data-end=\"2703\">legal declaration</strong> under Section 139 of the new Act.</p>\r\n<p data-start=\"2741\" data-end=\"3039\">The <strong data-start=\"2745\" data-end=\"2768\">Income-tax Act 2025</strong> retains the core principle of self-assessment but strengthens it through technology-driven verification and analytics. Every return filed is automatically cross-checked with third-party data (banks, GSTN, EPFO, registrars, etc.) to ensure accuracy and prevent evasion.</p>\r\n<hr data-start=\"3041\" data-end=\"3044\">\r\n<h3 data-start=\"3046\" data-end=\"3082\"><strong data-start=\"3050\" data-end=\"3082\">Key Objectives of ITR Filing</strong></h3>\r\n<ol data-start=\"3084\" data-end=\"3669\">\r\n<li data-start=\"3084\" data-end=\"3185\">\r\n<p data-start=\"3087\" data-end=\"3185\"><strong data-start=\"3087\" data-end=\"3108\">Legal Compliance:</strong> Every person whose income exceeds the basic exemption limit must file ITR.</p>\r\n</li>\r\n<li data-start=\"3186\" data-end=\"3267\">\r\n<p data-start=\"3189\" data-end=\"3267\"><strong data-start=\"3189\" data-end=\"3206\">Transparency:</strong> Returns ensure that income sources are properly disclosed.</p>\r\n</li>\r\n<li data-start=\"3268\" data-end=\"3354\">\r\n<p data-start=\"3271\" data-end=\"3354\"><strong data-start=\"3271\" data-end=\"3292\">Claiming Refunds:</strong> Excess TDS or advance tax can only be refunded through ITR.</p>\r\n</li>\r\n<li data-start=\"3355\" data-end=\"3471\">\r\n<p data-start=\"3358\" data-end=\"3471\"><strong data-start=\"3358\" data-end=\"3386\">Carrying Forward Losses:</strong> Business and capital losses can be carried forward only when ITR is filed in time.</p>\r\n</li>\r\n<li data-start=\"3472\" data-end=\"3567\">\r\n<p data-start=\"3475\" data-end=\"3567\"><strong data-start=\"3475\" data-end=\"3495\">Proof of Income:</strong> ITR serves as an official income proof for loans, visas, and tenders.</p>\r\n</li>\r\n<li data-start=\"3568\" data-end=\"3669\">\r\n<p data-start=\"3571\" data-end=\"3669\"><strong data-start=\"3571\" data-end=\"3598\">Contribution to Nation:</strong> Timely filing strengthens fiscal transparency and economic planning.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3671\" data-end=\"3674\">\r\n<h3 data-start=\"3676\" data-end=\"3726\"><strong data-start=\"3680\" data-end=\"3726\">Evolution of ITR System under the 2025 Act</strong></h3>\r\n<p data-start=\"3728\" data-end=\"3923\">Under the previous 1961 law, return filing often involved complex forms, manual verification, and long processing cycles.<br data-start=\"3849\" data-end=\"3852\">The <strong data-start=\"3856\" data-end=\"3879\">Income-tax Act 2025</strong> introduces a more compact framework with:</p>\r\n<ul data-start=\"3925\" data-end=\"4242\">\r\n<li data-start=\"3925\" data-end=\"3971\">\r\n<p data-start=\"3927\" data-end=\"3971\">Unified digital portal for all compliance.</p>\r\n</li>\r\n<li data-start=\"3972\" data-end=\"4054\">\r\n<p data-start=\"3974\" data-end=\"4054\">AI-based pre-filled data from banks, employers, mutual funds, and GST records.</p>\r\n</li>\r\n<li data-start=\"4055\" data-end=\"4111\">\r\n<p data-start=\"4057\" data-end=\"4111\">Automatic calculation of tax liability and interest.</p>\r\n</li>\r\n<li data-start=\"4112\" data-end=\"4181\">\r\n<p data-start=\"4114\" data-end=\"4181\">Faceless processing and refund issuance within defined timelines.</p>\r\n</li>\r\n<li data-start=\"4182\" data-end=\"4242\">\r\n<p data-start=\"4184\" data-end=\"4242\">Reduced number of schedules in ITR forms for simplicity.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4244\" data-end=\"4360\">The Act empowers taxpayers through automation while ensuring stronger detection of mismatched or undisclosed income.</p>\r\n<hr data-start=\"4362\" data-end=\"4365\">\r\n<h3 data-start=\"4367\" data-end=\"4406\"><strong data-start=\"4371\" data-end=\"4406\">Who Must File Income Tax Return</strong></h3>\r\n<p data-start=\"4408\" data-end=\"4501\">Under the Income-tax Act 2025, the following entities are obligated to file returns annually:</p>\r\n<ol data-start=\"4503\" data-end=\"4977\">\r\n<li data-start=\"4503\" data-end=\"4619\">\r\n<p data-start=\"4506\" data-end=\"4619\"><strong data-start=\"4506\" data-end=\"4555\">Individuals &amp; Hindu Undivided Families (HUFs)</strong> whose total income exceeds ₹ 12 lakh (basic exemption limit).</p>\r\n</li>\r\n<li data-start=\"4620\" data-end=\"4688\">\r\n<p data-start=\"4623\" data-end=\"4688\"><strong data-start=\"4623\" data-end=\"4653\">Companies, LLPs, and Firms</strong>, irrespective of income or loss.</p>\r\n</li>\r\n<li data-start=\"4689\" data-end=\"4772\">\r\n<p data-start=\"4692\" data-end=\"4772\"><strong data-start=\"4692\" data-end=\"4734\">Charitable Trusts, Societies, and NGOs</strong> registered under relevant sections.</p>\r\n</li>\r\n<li data-start=\"4773\" data-end=\"4841\">\r\n<p data-start=\"4776\" data-end=\"4841\"><strong data-start=\"4776\" data-end=\"4839\">Persons holding foreign assets or signing authority abroad.</strong></p>\r\n</li>\r\n<li data-start=\"4842\" data-end=\"4911\">\r\n<p data-start=\"4845\" data-end=\"4911\"><strong data-start=\"4845\" data-end=\"4909\">Residents with income from abroad or through digital assets.</strong></p>\r\n</li>\r\n<li data-start=\"4912\" data-end=\"4977\">\r\n<p data-start=\"4915\" data-end=\"4977\"><strong data-start=\"4915\" data-end=\"4975\">Taxpayers claiming refund, or carrying forward any loss.</strong></p>\r\n</li>\r\n</ol>\r\n<p data-start=\"4979\" data-end=\"5128\">The return must be filed <strong data-start=\"5004\" data-end=\"5022\">electronically</strong> through the official e-filing portal using digital signature (DSC) or electronic verification code (EVC).</p>\r\n<hr data-start=\"5130\" data-end=\"5133\">\r\n<h3 data-start=\"5135\" data-end=\"5200\"><strong data-start=\"5139\" data-end=\"5200\">Classification of ITR Forms under the Income-tax Act 2025</strong></h3>\r\n<p data-start=\"5202\" data-end=\"5409\">The government has retained <strong data-start=\"5230\" data-end=\"5263\">seven categories of ITR forms</strong>, aligning with different taxpayer types and income sources. Each form corresponds to a specific section of the Act and must be filed accordingly.</p>\r\n<p data-start=\"5411\" data-end=\"5461\">Let&rsquo;s understand all <strong data-start=\"5432\" data-end=\"5450\">ITR-1 to ITR-7</strong> in detail.</p>\r\n<hr data-start=\"5463\" data-end=\"5466\">\r\n<h4 data-start=\"5468\" data-end=\"5532\"><strong data-start=\"5473\" data-end=\"5532\">ITR-1 &ndash; Sahaj (For Salaried Individuals and Pensioners)</strong></h4>\r\n<p data-start=\"5534\" data-end=\"5552\"><strong data-start=\"5534\" data-end=\"5550\">Eligibility:</strong></p>\r\n<ul data-start=\"5553\" data-end=\"5705\">\r\n<li data-start=\"5553\" data-end=\"5612\">\r\n<p data-start=\"5555\" data-end=\"5612\">Resident individuals with total income up to ₹ 50 lakh.</p>\r\n</li>\r\n<li data-start=\"5613\" data-end=\"5705\">\r\n<p data-start=\"5615\" data-end=\"5705\">Income from salary/pension, one house property, and other sources (interest, dividends).</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5707\" data-end=\"5726\"><strong data-start=\"5707\" data-end=\"5724\">Not Eligible:</strong></p>\r\n<ul data-start=\"5727\" data-end=\"5818\">\r\n<li data-start=\"5727\" data-end=\"5818\">\r\n<p data-start=\"5729\" data-end=\"5818\">Income from business/profession, capital gains, multiple properties, or foreign assets.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5820\" data-end=\"5839\"><strong data-start=\"5820\" data-end=\"5837\">Key Features:</strong></p>\r\n<ul data-start=\"5840\" data-end=\"5985\">\r\n<li data-start=\"5840\" data-end=\"5891\">\r\n<p data-start=\"5842\" data-end=\"5891\">Pre-filled salary and TDS details from Form 16.</p>\r\n</li>\r\n<li data-start=\"5892\" data-end=\"5946\">\r\n<p data-start=\"5894\" data-end=\"5946\">Auto-calculation of deductions under Chapter VI-A.</p>\r\n</li>\r\n<li data-start=\"5947\" data-end=\"5985\">\r\n<p data-start=\"5949\" data-end=\"5985\">Simplified refund claim mechanism.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5987\" data-end=\"6091\"><strong data-start=\"5987\" data-end=\"6014\">Purpose under 2025 Act:</strong><br data-start=\"6014\" data-end=\"6017\">To provide a single-page, digitally verified return for small taxpayers.</p>\r\n<hr data-start=\"6093\" data-end=\"6096\">\r\n<h4 data-start=\"6098\" data-end=\"6160\"><strong data-start=\"6103\" data-end=\"6160\">ITR-2 &ndash; For Individuals and HUFs (No Business Income)</strong></h4>\r\n<p data-start=\"6162\" data-end=\"6180\"><strong data-start=\"6162\" data-end=\"6178\">Eligibility:</strong></p>\r\n<ul data-start=\"6181\" data-end=\"6294\">\r\n<li data-start=\"6181\" data-end=\"6294\">\r\n<p data-start=\"6183\" data-end=\"6294\">Individuals and HUFs having income from salary, multiple house properties, capital gains, or foreign sources.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6296\" data-end=\"6315\"><strong data-start=\"6296\" data-end=\"6313\">Not Eligible:</strong></p>\r\n<ul data-start=\"6316\" data-end=\"6352\">\r\n<li data-start=\"6316\" data-end=\"6352\">\r\n<p data-start=\"6318\" data-end=\"6352\">Business or professional income.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6354\" data-end=\"6394\"><strong data-start=\"6354\" data-end=\"6392\">Special Provisions under 2025 Act:</strong></p>\r\n<ul data-start=\"6395\" data-end=\"6563\">\r\n<li data-start=\"6395\" data-end=\"6452\">\r\n<p data-start=\"6397\" data-end=\"6452\">Declaration of digital-asset income (cryptocurrency).</p>\r\n</li>\r\n<li data-start=\"6453\" data-end=\"6504\">\r\n<p data-start=\"6455\" data-end=\"6504\">Automatic indexing of capital-gain computation.</p>\r\n</li>\r\n<li data-start=\"6505\" data-end=\"6563\">\r\n<p data-start=\"6507\" data-end=\"6563\">Disclosure of overseas assets and foreign tax credits.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6565\" data-end=\"6568\">\r\n<h4 data-start=\"6570\" data-end=\"6648\"><strong data-start=\"6575\" data-end=\"6648\">ITR-3 &ndash; For Individuals and HUFs with Business or Professional Income</strong></h4>\r\n<p data-start=\"6650\" data-end=\"6670\"><strong data-start=\"6650\" data-end=\"6668\">Applicable To:</strong></p>\r\n<ul data-start=\"6671\" data-end=\"6774\">\r\n<li data-start=\"6671\" data-end=\"6774\">\r\n<p data-start=\"6673\" data-end=\"6774\">Proprietors, freelancers, consultants, and professionals (lawyers, doctors, architects, CAs, etc.).</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6776\" data-end=\"6791\"><strong data-start=\"6776\" data-end=\"6789\">Features:</strong></p>\r\n<ul data-start=\"6792\" data-end=\"6998\">\r\n<li data-start=\"6792\" data-end=\"6871\">\r\n<p data-start=\"6794\" data-end=\"6871\">Comprehensive reporting of business turnover, gross receipts, and expenses.</p>\r\n</li>\r\n<li data-start=\"6872\" data-end=\"6948\">\r\n<p data-start=\"6874\" data-end=\"6948\">Digital balance sheet, profit &amp; loss account, and depreciation schedule.</p>\r\n</li>\r\n<li data-start=\"6949\" data-end=\"6998\">\r\n<p data-start=\"6951\" data-end=\"6998\">Integration with GST data for reconciliation.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"7000\" data-end=\"7142\"><strong data-start=\"7000\" data-end=\"7019\">Under 2025 Act:</strong><br data-start=\"7019\" data-end=\"7022\">The format has been rationalized; separate schedules for presumptive and non-presumptive income are unified for clarity.</p>\r\n<hr data-start=\"7144\" data-end=\"7147\">\r\n<h4 data-start=\"7149\" data-end=\"7199\"><strong data-start=\"7154\" data-end=\"7199\">ITR-4 &ndash; Sugam (Presumptive Income Scheme)</strong></h4>\r\n<p data-start=\"7201\" data-end=\"7219\"><strong data-start=\"7201\" data-end=\"7217\">Eligibility:</strong></p>\r\n<ul data-start=\"7220\" data-end=\"7400\">\r\n<li data-start=\"7220\" data-end=\"7321\">\r\n<p data-start=\"7222\" data-end=\"7321\">Small businesses and professionals under Sections 44AD, 44ADA, 44AE (updated under the 2025 Act).</p>\r\n</li>\r\n<li data-start=\"7322\" data-end=\"7400\">\r\n<p data-start=\"7324\" data-end=\"7400\">Individuals, HUFs, and firms with turnover up to the prescribed threshold.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"7402\" data-end=\"7421\"><strong data-start=\"7402\" data-end=\"7419\">Key Features:</strong></p>\r\n<ul data-start=\"7422\" data-end=\"7594\">\r\n<li data-start=\"7422\" data-end=\"7500\">\r\n<p data-start=\"7424\" data-end=\"7500\">Income declared at presumptive percentage (6 % for digital, 8 % for cash).</p>\r\n</li>\r\n<li data-start=\"7501\" data-end=\"7556\">\r\n<p data-start=\"7503\" data-end=\"7556\">Minimal record-keeping and single-page declaration.</p>\r\n</li>\r\n<li data-start=\"7557\" data-end=\"7594\">\r\n<p data-start=\"7559\" data-end=\"7594\">Quick filing for small taxpayers.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7596\" data-end=\"7599\">\r\n<h4 data-start=\"7601\" data-end=\"7657\"><strong data-start=\"7606\" data-end=\"7657\">ITR-5 &ndash; For Partnership Firms, LLPs, AOPs, BOIs</strong></h4>\r\n<p data-start=\"7659\" data-end=\"7679\"><strong data-start=\"7659\" data-end=\"7677\">Applicable To:</strong></p>\r\n<ul data-start=\"7680\" data-end=\"7803\">\r\n<li data-start=\"7680\" data-end=\"7734\">\r\n<p data-start=\"7682\" data-end=\"7734\">Partnership firms and LLPs not filing under ITR-7.</p>\r\n</li>\r\n<li data-start=\"7735\" data-end=\"7803\">\r\n<p data-start=\"7737\" data-end=\"7803\">Associations of Persons (AOPs) and Bodies of Individuals (BOIs).</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"7805\" data-end=\"7822\"><strong data-start=\"7805\" data-end=\"7820\">Highlights:</strong></p>\r\n<ul data-start=\"7823\" data-end=\"7993\">\r\n<li data-start=\"7823\" data-end=\"7870\">\r\n<p data-start=\"7825\" data-end=\"7870\">Mandatory digital signature for submission.</p>\r\n</li>\r\n<li data-start=\"7871\" data-end=\"7934\">\r\n<p data-start=\"7873\" data-end=\"7934\">Statement of partners&rsquo; capital, remuneration, and interest.</p>\r\n</li>\r\n<li data-start=\"7935\" data-end=\"7993\">\r\n<p data-start=\"7937\" data-end=\"7993\">Disclosure of audit details and depreciation schedule.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"7995\" data-end=\"8099\"><strong data-start=\"7995\" data-end=\"8013\">New Additions:</strong><br data-start=\"8013\" data-end=\"8016\">Automatic linkage of partner&rsquo;s income with firm&rsquo;s return for seamless verification.</p>\r\n<hr data-start=\"8101\" data-end=\"8104\">\r\n<h4 data-start=\"8106\" data-end=\"8169\"><strong data-start=\"8111\" data-end=\"8169\">ITR-6 &ndash; For Companies (Other than Section 8 Companies)</strong></h4>\r\n<p data-start=\"8171\" data-end=\"8191\"><strong data-start=\"8171\" data-end=\"8189\">Applicable To:</strong></p>\r\n<ul data-start=\"8192\" data-end=\"8268\">\r\n<li data-start=\"8192\" data-end=\"8268\">\r\n<p data-start=\"8194\" data-end=\"8268\">Private Limited and Public Limited companies liable under corporate tax.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"8270\" data-end=\"8285\"><strong data-start=\"8270\" data-end=\"8283\">Features:</strong></p>\r\n<ul data-start=\"8286\" data-end=\"8445\">\r\n<li data-start=\"8286\" data-end=\"8330\">\r\n<p data-start=\"8288\" data-end=\"8330\">Alignment with MCA financial statements.</p>\r\n</li>\r\n<li data-start=\"8331\" data-end=\"8394\">\r\n<p data-start=\"8333\" data-end=\"8394\">Reporting of dividend income, MAT/AMT, and CSR expenditure.</p>\r\n</li>\r\n<li data-start=\"8395\" data-end=\"8445\">\r\n<p data-start=\"8397\" data-end=\"8445\">Real-time validation with TDS &amp; TCS databases.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"8447\" data-end=\"8550\"><strong data-start=\"8447\" data-end=\"8470\">Under the 2025 Act:</strong><br data-start=\"8470\" data-end=\"8473\">Faceless filing, standardized depreciation rates, and mandatory audit upload.</p>\r\n<hr data-start=\"8552\" data-end=\"8555\">\r\n<h4 data-start=\"8557\" data-end=\"8632\"><strong data-start=\"8562\" data-end=\"8632\">ITR-7 &ndash; For Trusts, Charitable Institutions, and Political Parties</strong></h4>\r\n<p data-start=\"8634\" data-end=\"8654\"><strong data-start=\"8634\" data-end=\"8652\">Applicable To:</strong></p>\r\n<ul data-start=\"8655\" data-end=\"8801\">\r\n<li data-start=\"8655\" data-end=\"8727\">\r\n<p data-start=\"8657\" data-end=\"8727\">Persons claiming exemption under Sections 10, 11, 12, 13A, 13B, etc.</p>\r\n</li>\r\n<li data-start=\"8728\" data-end=\"8801\">\r\n<p data-start=\"8730\" data-end=\"8801\">Charitable Trusts, NGOs, Universities, Funds, and Political Entities.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"8803\" data-end=\"8818\"><strong data-start=\"8803\" data-end=\"8816\">Features:</strong></p>\r\n<ul data-start=\"8819\" data-end=\"8993\">\r\n<li data-start=\"8819\" data-end=\"8873\">\r\n<p data-start=\"8821\" data-end=\"8873\">Digital filing with audit report in Form 10B/10BB.</p>\r\n</li>\r\n<li data-start=\"8874\" data-end=\"8934\">\r\n<p data-start=\"8876\" data-end=\"8934\">Disclosure of corpus donations, grants, and utilization.</p>\r\n</li>\r\n<li data-start=\"8935\" data-end=\"8993\">\r\n<p data-start=\"8937\" data-end=\"8993\">Pre-validation of bank accounts for refund and grants.</p>\r\n</li>\r\n</ul>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</article>\r\n<article class=\"text-token-text-primary w-full focus:outline-none [--shadow-height:45px] has-data-writing-block:pointer-events-none has-data-writing-block:-mt-(--shadow-height) has-data-writing-block:pt-(--shadow-height) [&amp;:has([data-writing-block])&gt;*]:pointer-events-auto scroll-mt-[calc(var(--header-height)+min(200px,max(70px,20svh)))]\" dir=\"auto\" tabindex=\"-1\" data-turn-id=\"request-68fb87f4-a264-8321-b4c7-5e36824a185a-50\" data-testid=\"conversation-turn-94\" data-scroll-anchor=\"true\" data-turn=\"assistant\">\r\n<div class=\"text-base my-auto mx-auto pb-10 [--thread-content-margin:--spacing(4)] thread-sm:[--thread-content-margin:--spacing(6)] thread-lg:[--thread-content-margin:--spacing(16)] px-(--thread-content-margin)\">\r\n<div class=\"[--thread-content-max-width:40rem] thread-lg:[--thread-content-max-width:48rem] mx-auto max-w-(--thread-content-max-width) flex-1 group/turn-messages focus-visible:outline-hidden relative flex w-full min-w-0 flex-col agent-turn\" tabindex=\"-1\">\r\n<div class=\"flex max-w-full flex-col grow\">\r\n<div class=\"min-h-8 text-message relative flex w-full flex-col items-end gap-2 text-start break-words whitespace-normal [.text-message+&amp;]:mt-1\" dir=\"auto\" data-message-author-role=\"assistant\" data-message-id=\"a2466e07-ff46-42e2-b637-4db3c9e57c99\" data-message-model-slug=\"gpt-5\">\r\n<div class=\"flex w-full flex-col gap-1 empty:hidden first:pt-[1px]\">\r\n<div class=\"markdown prose dark:prose-invert w-full break-words light markdown-new-styling\">\r\n<h3 data-start=\"512\" data-end=\"589\"><strong data-start=\"516\" data-end=\"587\">Due Dates for Filing Income Tax Returns (Under Income-tax Act 2025)</strong></h3>\r\n<p data-start=\"591\" data-end=\"790\">The Income-tax Act 2025 clearly defines timelines to ensure disciplined compliance.<br data-start=\"674\" data-end=\"677\">Filing within the prescribed date helps avoid late fees, interest, and disqualification for loss carry-forward.</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"792\" data-end=\"1460\">\r\n<thead data-start=\"792\" data-end=\"870\">\r\n<tr data-start=\"792\" data-end=\"870\">\r\n<th data-start=\"792\" data-end=\"819\" data-col-size=\"md\"><strong data-start=\"794\" data-end=\"818\">Category of Taxpayer</strong></th>\r\n<th data-start=\"819\" data-end=\"855\" data-col-size=\"sm\"><strong data-start=\"821\" data-end=\"854\">Due Date (AY 2026-27 onwards)</strong></th>\r\n<th data-start=\"855\" data-end=\"870\" data-col-size=\"sm\"><strong data-start=\"857\" data-end=\"868\">Remarks</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"951\" data-end=\"1460\">\r\n<tr data-start=\"951\" data-end=\"1037\">\r\n<td data-start=\"951\" data-end=\"982\" data-col-size=\"md\">Individual / HUF (non-audit)</td>\r\n<td data-col-size=\"sm\" data-start=\"982\" data-end=\"1016\">31 July following the end of FY</td>\r\n<td data-col-size=\"sm\" data-start=\"1016\" data-end=\"1037\">Standard due date</td>\r\n</tr>\r\n<tr data-start=\"1038\" data-end=\"1136\">\r\n<td data-start=\"1038\" data-end=\"1082\" data-col-size=\"md\">Businesses / Firms / LLPs requiring audit</td>\r\n<td data-col-size=\"sm\" data-start=\"1082\" data-end=\"1095\">31 October</td>\r\n<td data-col-size=\"sm\" data-start=\"1095\" data-end=\"1136\">Includes tax audit under Section 44AB</td>\r\n</tr>\r\n<tr data-start=\"1137\" data-end=\"1199\">\r\n<td data-start=\"1137\" data-end=\"1149\" data-col-size=\"md\">Companies</td>\r\n<td data-col-size=\"sm\" data-start=\"1149\" data-end=\"1162\">31 October</td>\r\n<td data-col-size=\"sm\" data-start=\"1162\" data-end=\"1199\">Along with statutory audit report</td>\r\n</tr>\r\n<tr data-start=\"1200\" data-end=\"1291\">\r\n<td data-start=\"1200\" data-end=\"1248\" data-col-size=\"md\">Assessees covered under TP (Transfer Pricing)</td>\r\n<td data-col-size=\"sm\" data-start=\"1248\" data-end=\"1262\">30 November</td>\r\n<td data-col-size=\"sm\" data-start=\"1262\" data-end=\"1291\">With Form 3CEB submission</td>\r\n</tr>\r\n<tr data-start=\"1292\" data-end=\"1368\">\r\n<td data-start=\"1292\" data-end=\"1316\" data-col-size=\"md\">Belated / Revised ITR</td>\r\n<td data-col-size=\"sm\" data-start=\"1316\" data-end=\"1335\">31 March next AY</td>\r\n<td data-col-size=\"sm\" data-start=\"1335\" data-end=\"1368\">Last chance to file or revise</td>\r\n</tr>\r\n<tr data-start=\"1369\" data-end=\"1460\">\r\n<td data-start=\"1369\" data-end=\"1391\" data-col-size=\"md\">Updated ITR (ITR-U)</td>\r\n<td data-col-size=\"sm\" data-start=\"1391\" data-end=\"1425\">Within 24 months of relevant AY</td>\r\n<td data-col-size=\"sm\" data-start=\"1425\" data-end=\"1460\">With 25 % / 50 % additional tax</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"1462\" data-end=\"1465\">\r\n<h3 data-start=\"1467\" data-end=\"1529\"><strong data-start=\"1471\" data-end=\"1529\">Process of Filing an ITR under the Income-tax Act 2025</strong></h3>\r\n<p data-start=\"1531\" data-end=\"1731\">The new Act emphasizes a <strong data-start=\"1556\" data-end=\"1619\">digital-first, faceless, and data-verified filing mechanism</strong>.<br data-start=\"1620\" data-end=\"1623\">Every return passes through four seamless digital layers: preparation, filing, verification, and processing.</p>\r\n<ol data-start=\"1733\" data-end=\"2822\">\r\n<li data-start=\"1733\" data-end=\"1995\">\r\n<p data-start=\"1736\" data-end=\"1759\"><strong data-start=\"1736\" data-end=\"1757\">Preparation Stage</strong></p>\r\n<ul data-start=\"1763\" data-end=\"1995\">\r\n<li data-start=\"1763\" data-end=\"1839\">\r\n<p data-start=\"1765\" data-end=\"1839\">Collect Form 16, 26AS, AIS, TIS, bank statements, and investment proofs.</p>\r\n</li>\r\n<li data-start=\"1843\" data-end=\"1892\">\r\n<p data-start=\"1845\" data-end=\"1892\">Reconcile all income sources and TDS entries.</p>\r\n</li>\r\n<li data-start=\"1896\" data-end=\"1933\">\r\n<p data-start=\"1898\" data-end=\"1933\">Choose correct ITR form (1 to 7).</p>\r\n</li>\r\n<li data-start=\"1937\" data-end=\"1995\">\r\n<p data-start=\"1939\" data-end=\"1995\">Compute total income, deductions, and net tax liability.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"1997\" data-end=\"2293\">\r\n<p data-start=\"2000\" data-end=\"2018\"><strong data-start=\"2000\" data-end=\"2016\">Filing Stage</strong></p>\r\n<ul data-start=\"2022\" data-end=\"2293\">\r\n<li data-start=\"2022\" data-end=\"2085\">\r\n<p data-start=\"2024\" data-end=\"2085\">Log in to the official e-filing portal using PAN / Aadhaar.</p>\r\n</li>\r\n<li data-start=\"2089\" data-end=\"2154\">\r\n<p data-start=\"2091\" data-end=\"2154\">Upload return in XML/JSON format generated by online utility.</p>\r\n</li>\r\n<li data-start=\"2158\" data-end=\"2201\">\r\n<p data-start=\"2160\" data-end=\"2201\">Confirm bank details for refund credit.</p>\r\n</li>\r\n<li data-start=\"2205\" data-end=\"2293\">\r\n<p data-start=\"2207\" data-end=\"2293\">Submit using <strong data-start=\"2220\" data-end=\"2259\">Digital Signature Certificate (DSC)</strong> or <strong data-start=\"2263\" data-end=\"2292\">E-Verification Code (EVC)</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"2295\" data-end=\"2588\">\r\n<p data-start=\"2298\" data-end=\"2383\"><strong data-start=\"2298\" data-end=\"2320\">Verification Stage</strong><br data-start=\"2320\" data-end=\"2323\">Verification is mandatory within 30 days of submission:</p>\r\n<ul data-start=\"2387\" data-end=\"2588\">\r\n<li data-start=\"2387\" data-end=\"2438\">\r\n<p data-start=\"2389\" data-end=\"2438\"><strong data-start=\"2389\" data-end=\"2411\">Digital Signature:</strong> For firms and companies.</p>\r\n</li>\r\n<li data-start=\"2442\" data-end=\"2483\">\r\n<p data-start=\"2444\" data-end=\"2483\"><strong data-start=\"2444\" data-end=\"2464\">OTP via Aadhaar:</strong> For individuals.</p>\r\n</li>\r\n<li data-start=\"2487\" data-end=\"2588\">\r\n<p data-start=\"2489\" data-end=\"2588\"><strong data-start=\"2489\" data-end=\"2511\">Net Banking / EVC:</strong> For general taxpayers.<br data-start=\"2534\" data-end=\"2537\">Non-verification renders the return <strong data-start=\"2576\" data-end=\"2587\">invalid</strong>.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"2590\" data-end=\"2822\">\r\n<p data-start=\"2593\" data-end=\"2650\"><strong data-start=\"2593\" data-end=\"2613\">Processing Stage</strong><br data-start=\"2613\" data-end=\"2616\">The CPC system automatically:</p>\r\n<ul data-start=\"2654\" data-end=\"2822\">\r\n<li data-start=\"2654\" data-end=\"2711\">\r\n<p data-start=\"2656\" data-end=\"2711\">Cross-verifies data with AIS, TIS, and TDS databases.</p>\r\n</li>\r\n<li data-start=\"2715\" data-end=\"2751\">\r\n<p data-start=\"2717\" data-end=\"2751\">Calculates any refund or demand.</p>\r\n</li>\r\n<li data-start=\"2755\" data-end=\"2822\">\r\n<p data-start=\"2757\" data-end=\"2822\">Sends <strong data-start=\"2763\" data-end=\"2788\">Intimation u/s 143(1)</strong> to the taxpayer electronically.</p>\r\n</li>\r\n</ul>\r\n</li>\r\n</ol>\r\n<hr data-start=\"2824\" data-end=\"2827\">\r\n<h3 data-start=\"2829\" data-end=\"2864\"><strong data-start=\"2833\" data-end=\"2864\">Revised and Updated Returns</strong></h3>\r\n<p data-start=\"2866\" data-end=\"3035\">Even under the new Act, human or clerical errors can occur.<br data-start=\"2925\" data-end=\"2928\">Hence, the law retains the facility to file <strong data-start=\"2972\" data-end=\"3000\">Revised ITR (u/s 139(5))</strong> and <strong data-start=\"3005\" data-end=\"3034\">Updated ITR (u/s 139(8A))</strong>.</p>\r\n<p data-start=\"3037\" data-end=\"3058\"><strong data-start=\"3037\" data-end=\"3056\">Revised Return:</strong></p>\r\n<ul data-start=\"3059\" data-end=\"3200\">\r\n<li data-start=\"3059\" data-end=\"3135\">\r\n<p data-start=\"3061\" data-end=\"3135\">Can be filed anytime <strong data-start=\"3082\" data-end=\"3132\">before the end of the relevant assessment year</strong>.</p>\r\n</li>\r\n<li data-start=\"3136\" data-end=\"3200\">\r\n<p data-start=\"3138\" data-end=\"3200\">Allows correction of income, deduction, or personal details.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3202\" data-end=\"3231\"><strong data-start=\"3202\" data-end=\"3229\">Updated Return (ITR-U):</strong></p>\r\n<ul data-start=\"3232\" data-end=\"3456\">\r\n<li data-start=\"3232\" data-end=\"3291\">\r\n<p data-start=\"3234\" data-end=\"3291\">May be filed <strong data-start=\"3247\" data-end=\"3267\">within 24 months</strong> of the end of the AY.</p>\r\n</li>\r\n<li data-start=\"3292\" data-end=\"3353\">\r\n<p data-start=\"3294\" data-end=\"3353\">Enables voluntary disclosure of previously missed income.</p>\r\n</li>\r\n<li data-start=\"3354\" data-end=\"3456\">\r\n<p data-start=\"3356\" data-end=\"3456\">Attracts <strong data-start=\"3365\" data-end=\"3388\">25 % additional tax</strong> if filed within 12 months and <strong data-start=\"3419\" data-end=\"3427\">50 %</strong> if filed within 24 months.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3458\" data-end=\"3461\">\r\n<h3 data-start=\"3463\" data-end=\"3508\"><strong data-start=\"3467\" data-end=\"3508\">Verification, Rectification &amp; Refunds</strong></h3>\r\n<p data-start=\"3510\" data-end=\"3540\">After successful processing:</p>\r\n<ul data-start=\"3542\" data-end=\"3775\">\r\n<li data-start=\"3542\" data-end=\"3624\">\r\n<p data-start=\"3544\" data-end=\"3624\">If taxes paid &gt; tax payable &rarr; <strong data-start=\"3574\" data-end=\"3584\">Refund</strong> issued to pre-validated bank account.</p>\r\n</li>\r\n<li data-start=\"3625\" data-end=\"3705\">\r\n<p data-start=\"3627\" data-end=\"3705\">If taxes paid &lt; tax payable &rarr; <strong data-start=\"3657\" data-end=\"3692\">Intimation of Demand u/s 143(1)</strong> generated.</p>\r\n</li>\r\n<li data-start=\"3706\" data-end=\"3775\">\r\n<p data-start=\"3708\" data-end=\"3775\">Errors can be rectified through <strong data-start=\"3740\" data-end=\"3772\">online rectification u/s 154</strong>.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3777\" data-end=\"3926\">Refunds under the 2025 Act are automated through the central refund module and are expected to be credited within 7&ndash;15 working days after processing.</p>\r\n<hr data-start=\"3928\" data-end=\"3931\">\r\n<h3 data-start=\"3933\" data-end=\"3972\"><strong data-start=\"3937\" data-end=\"3972\">Faceless Assessment and Appeals</strong></h3>\r\n<p data-start=\"3974\" data-end=\"4190\">To strengthen transparency, the Income-tax Act 2025 institutionalizes a <strong data-start=\"4046\" data-end=\"4079\">faceless compliance ecosystem</strong>.<br data-start=\"4080\" data-end=\"4083\">All communications, assessments, and appeals are electronic&mdash;no personal hearings, no departmental visits.</p>\r\n<p data-start=\"4192\" data-end=\"4211\"><strong data-start=\"4192\" data-end=\"4209\">Key benefits:</strong></p>\r\n<ul data-start=\"4212\" data-end=\"4401\">\r\n<li data-start=\"4212\" data-end=\"4254\">\r\n<p data-start=\"4214\" data-end=\"4254\">Uniform assessment quality nationwide.</p>\r\n</li>\r\n<li data-start=\"4255\" data-end=\"4293\">\r\n<p data-start=\"4257\" data-end=\"4293\">Minimal discretion and harassment.</p>\r\n</li>\r\n<li data-start=\"4294\" data-end=\"4351\">\r\n<p data-start=\"4296\" data-end=\"4351\">Timely issue resolution through AI-driven allocation.</p>\r\n</li>\r\n<li data-start=\"4352\" data-end=\"4401\">\r\n<p data-start=\"4354\" data-end=\"4401\">Secure documentation and communication trail.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4403\" data-end=\"4406\">\r\n<h3 data-start=\"4408\" data-end=\"4447\"><strong data-start=\"4412\" data-end=\"4447\">Interest, Late Fees &amp; Penalties</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4449\" data-end=\"4931\">\r\n<thead data-start=\"4449\" data-end=\"4515\">\r\n<tr data-start=\"4449\" data-end=\"4515\">\r\n<th data-start=\"4449\" data-end=\"4463\" data-col-size=\"sm\"><strong data-start=\"4451\" data-end=\"4462\">Default</strong></th>\r\n<th data-start=\"4463\" data-end=\"4486\" data-col-size=\"sm\"><strong data-start=\"4465\" data-end=\"4485\">Relevant Section</strong></th>\r\n<th data-start=\"4486\" data-end=\"4515\" data-col-size=\"md\"><strong data-start=\"4488\" data-end=\"4513\">Penalty / Consequence</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4585\" data-end=\"4931\">\r\n<tr data-start=\"4585\" data-end=\"4664\">\r\n<td data-start=\"4585\" data-end=\"4606\" data-col-size=\"sm\">Late filing of ITR</td>\r\n<td data-col-size=\"sm\" data-start=\"4606\" data-end=\"4613\">234F</td>\r\n<td data-col-size=\"md\" data-start=\"4613\" data-end=\"4664\">₹ 1,000 (if income &le; ₹ 5 L) or ₹ 5,000 (others)</td>\r\n</tr>\r\n<tr data-start=\"4665\" data-end=\"4734\">\r\n<td data-start=\"4665\" data-end=\"4687\" data-col-size=\"sm\">Late payment of tax</td>\r\n<td data-col-size=\"sm\" data-start=\"4687\" data-end=\"4708\">234A / 234B / 234C</td>\r\n<td data-col-size=\"md\" data-start=\"4708\" data-end=\"4734\">1 % interest per month</td>\r\n</tr>\r\n<tr data-start=\"4735\" data-end=\"4800\">\r\n<td data-start=\"4735\" data-end=\"4757\" data-col-size=\"sm\">Failure to file ITR</td>\r\n<td data-col-size=\"sm\" data-start=\"4757\" data-end=\"4765\">276CC</td>\r\n<td data-col-size=\"md\" data-start=\"4765\" data-end=\"4800\">Prosecution + fine up to ₹ 10 L</td>\r\n</tr>\r\n<tr data-start=\"4801\" data-end=\"4866\">\r\n<td data-start=\"4801\" data-end=\"4829\" data-col-size=\"sm\">Under-reporting of income</td>\r\n<td data-col-size=\"sm\" data-start=\"4829\" data-end=\"4836\">270A</td>\r\n<td data-col-size=\"md\" data-start=\"4836\" data-end=\"4866\">50 % of tax under-reported</td>\r\n</tr>\r\n<tr data-start=\"4867\" data-end=\"4931\">\r\n<td data-start=\"4867\" data-end=\"4893\" data-col-size=\"sm\">Mis-reporting of income</td>\r\n<td data-col-size=\"sm\" data-start=\"4893\" data-end=\"4903\">270A(8)</td>\r\n<td data-col-size=\"md\" data-start=\"4903\" data-end=\"4931\">200 % of tax misreported</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4933\" data-end=\"4936\">\r\n<h3 data-start=\"4938\" data-end=\"4969\"><strong data-start=\"4942\" data-end=\"4969\">Types of Tax Assessment</strong></h3>\r\n<p data-start=\"4971\" data-end=\"5048\">The Income-tax Act 2025 preserves the classical framework with modernization:</p>\r\n<ol data-start=\"5050\" data-end=\"5403\">\r\n<li data-start=\"5050\" data-end=\"5119\">\r\n<p data-start=\"5053\" data-end=\"5119\"><strong data-start=\"5053\" data-end=\"5085\">Summary Assessment (143 (1))</strong> &ndash; automatic system-based check.</p>\r\n</li>\r\n<li data-start=\"5120\" data-end=\"5196\">\r\n<p data-start=\"5123\" data-end=\"5196\"><strong data-start=\"5123\" data-end=\"5156\">Scrutiny Assessment (143 (3))</strong> &ndash; detailed examination by department.</p>\r\n</li>\r\n<li data-start=\"5197\" data-end=\"5280\">\r\n<p data-start=\"5200\" data-end=\"5280\"><strong data-start=\"5200\" data-end=\"5234\">Best-Judgment Assessment (144)</strong> &ndash; when return not filed or non-cooperation.</p>\r\n</li>\r\n<li data-start=\"5281\" data-end=\"5338\">\r\n<p data-start=\"5284\" data-end=\"5338\"><strong data-start=\"5284\" data-end=\"5307\">Re-Assessment (147)</strong> &ndash; income escaped assessment.</p>\r\n</li>\r\n<li data-start=\"5339\" data-end=\"5403\">\r\n<p data-start=\"5342\" data-end=\"5403\"><strong data-start=\"5342\" data-end=\"5361\">Faceless Appeal</strong> &ndash; digital hearing with CIT(A) and NFAC.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"5405\" data-end=\"5408\">\r\n<h3 data-start=\"5410\" data-end=\"5450\"><strong data-start=\"5414\" data-end=\"5450\">Rectification and Appeal Process</strong></h3>\r\n<ul data-start=\"5452\" data-end=\"5727\">\r\n<li data-start=\"5452\" data-end=\"5522\">\r\n<p data-start=\"5454\" data-end=\"5522\"><strong data-start=\"5454\" data-end=\"5480\">Rectification u/s 154:</strong> Correcting mistakes apparent on record.</p>\r\n</li>\r\n<li data-start=\"5523\" data-end=\"5579\">\r\n<p data-start=\"5525\" data-end=\"5579\"><strong data-start=\"5525\" data-end=\"5546\">Appeal to CIT(A):</strong> Filed within 30 days of order.</p>\r\n</li>\r\n<li data-start=\"5580\" data-end=\"5727\">\r\n<p data-start=\"5582\" data-end=\"5727\"><strong data-start=\"5582\" data-end=\"5619\">Further Appeal to ITAT / HC / SC:</strong> If aggrieved by departmental decision.<br data-start=\"5658\" data-end=\"5661\">All filings are to be done through the <strong data-start=\"5700\" data-end=\"5724\">e-Proceedings module</strong>.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5729\" data-end=\"5732\">\r\n<h3 data-start=\"5734\" data-end=\"5775\"><strong data-start=\"5738\" data-end=\"5775\">Refund Process Under the 2025 Act</strong></h3>\r\n<ul data-start=\"5777\" data-end=\"6018\">\r\n<li data-start=\"5777\" data-end=\"5831\">\r\n<p data-start=\"5779\" data-end=\"5831\">Refunds are auto-generated post 143(1) processing.</p>\r\n</li>\r\n<li data-start=\"5832\" data-end=\"5888\">\r\n<p data-start=\"5834\" data-end=\"5888\">Credited directly to the pre-validated bank account.</p>\r\n</li>\r\n<li data-start=\"5889\" data-end=\"5939\">\r\n<p data-start=\"5891\" data-end=\"5939\">Status can be tracked on the refund dashboard.</p>\r\n</li>\r\n<li data-start=\"5940\" data-end=\"6018\">\r\n<p data-start=\"5942\" data-end=\"6018\">Interest @ 0.5 % per month is payable if refund is delayed beyond 90 days.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6020\" data-end=\"6023\">\r\n<h3 data-start=\"6025\" data-end=\"6064\"><strong data-start=\"6029\" data-end=\"6064\">Importance of Timely ITR Filing</strong></h3>\r\n<ol data-start=\"6066\" data-end=\"6432\">\r\n<li data-start=\"6066\" data-end=\"6129\">\r\n<p data-start=\"6069\" data-end=\"6129\"><strong data-start=\"6069\" data-end=\"6100\">Avoid Penalties &amp; Interest:</strong> Delay invites 234F &amp; 234A.</p>\r\n</li>\r\n<li data-start=\"6130\" data-end=\"6202\">\r\n<p data-start=\"6133\" data-end=\"6202\"><strong data-start=\"6133\" data-end=\"6163\">Ensure Refund Eligibility:</strong> Refund processed only on timely ITR.</p>\r\n</li>\r\n<li data-start=\"6203\" data-end=\"6283\">\r\n<p data-start=\"6206\" data-end=\"6283\"><strong data-start=\"6206\" data-end=\"6231\">Carry Forward Losses:</strong> Losses allowed only if ITR filed before due date.</p>\r\n</li>\r\n<li data-start=\"6284\" data-end=\"6343\">\r\n<p data-start=\"6287\" data-end=\"6343\"><strong data-start=\"6287\" data-end=\"6313\">Loan &amp; Visa Documents:</strong> ITR serves as income proof.</p>\r\n</li>\r\n<li data-start=\"6344\" data-end=\"6432\">\r\n<p data-start=\"6347\" data-end=\"6432\"><strong data-start=\"6347\" data-end=\"6381\">Reputation &amp; Creditworthiness:</strong> Regular filers are viewed as compliant citizens.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"6434\" data-end=\"6437\">\r\n<h3 data-start=\"6439\" data-end=\"6478\"><strong data-start=\"6443\" data-end=\"6478\">ITR Filing for Special Entities</strong></h3>\r\n<p data-start=\"6480\" data-end=\"6506\"><strong data-start=\"6480\" data-end=\"6504\">For Companies &amp; LLPs</strong></p>\r\n<ul data-start=\"6507\" data-end=\"6658\">\r\n<li data-start=\"6507\" data-end=\"6550\">\r\n<p data-start=\"6509\" data-end=\"6550\">Mandatory digital submission using DSC.</p>\r\n</li>\r\n<li data-start=\"6551\" data-end=\"6603\">\r\n<p data-start=\"6553\" data-end=\"6603\">Audit report u/s 44AB to be filed before 31 Oct.</p>\r\n</li>\r\n<li data-start=\"6604\" data-end=\"6658\">\r\n<p data-start=\"6606\" data-end=\"6658\">CSR, dividend, and MAT details disclosed in ITR-6.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6660\" data-end=\"6683\"><strong data-start=\"6660\" data-end=\"6681\">For Trusts &amp; NGOs</strong></p>\r\n<ul data-start=\"6684\" data-end=\"6784\">\r\n<li data-start=\"6684\" data-end=\"6731\">\r\n<p data-start=\"6686\" data-end=\"6731\">File ITR-7 with audit report Form 10B/10BB.</p>\r\n</li>\r\n<li data-start=\"6732\" data-end=\"6784\">\r\n<p data-start=\"6734\" data-end=\"6784\">Declare utilization of donations &amp; corpus funds.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6786\" data-end=\"6813\"><strong data-start=\"6786\" data-end=\"6811\">For Partnership Firms</strong></p>\r\n<ul data-start=\"6814\" data-end=\"6910\">\r\n<li data-start=\"6814\" data-end=\"6852\">\r\n<p data-start=\"6816\" data-end=\"6852\">ITR-5 mandatory even if no income.</p>\r\n</li>\r\n<li data-start=\"6853\" data-end=\"6910\">\r\n<p data-start=\"6855\" data-end=\"6910\">Partners&rsquo; share auto-reflected in individual returns.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6912\" data-end=\"6949\"><strong data-start=\"6912\" data-end=\"6947\">For Professionals &amp; Freelancers</strong></p>\r\n<ul data-start=\"6950\" data-end=\"7057\">\r\n<li data-start=\"6950\" data-end=\"7001\">\r\n<p data-start=\"6952\" data-end=\"7001\">ITR-3 or ITR-4 depending on presumptive scheme.</p>\r\n</li>\r\n<li data-start=\"7002\" data-end=\"7057\">\r\n<p data-start=\"7004\" data-end=\"7057\">Maintain digital books &amp; invoices for verification.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7059\" data-end=\"7062\">\r\n<h3 data-start=\"7064\" data-end=\"7099\"><strong data-start=\"7068\" data-end=\"7099\">Integration with Other Laws</strong></h3>\r\n<p data-start=\"7101\" data-end=\"7166\">The Income-tax Act 2025 is digitally linked with other systems:</p>\r\n<ul data-start=\"7168\" data-end=\"7465\">\r\n<li data-start=\"7168\" data-end=\"7242\">\r\n<p data-start=\"7170\" data-end=\"7242\"><strong data-start=\"7170\" data-end=\"7179\">GSTN:</strong> Sales and purchase data cross-verified for business returns.</p>\r\n</li>\r\n<li data-start=\"7243\" data-end=\"7310\">\r\n<p data-start=\"7245\" data-end=\"7310\"><strong data-start=\"7245\" data-end=\"7253\">MCA:</strong> Company financials auto-imported for audit comparison.</p>\r\n</li>\r\n<li data-start=\"7311\" data-end=\"7379\">\r\n<p data-start=\"7313\" data-end=\"7379\"><strong data-start=\"7313\" data-end=\"7329\">PAN&ndash;Aadhaar:</strong> Compulsory linkage for identity authentication.</p>\r\n</li>\r\n<li data-start=\"7380\" data-end=\"7465\">\r\n<p data-start=\"7382\" data-end=\"7465\"><strong data-start=\"7382\" data-end=\"7411\">Bank and Investment Data:</strong> AIS auto-fetches dividends, interest, mutual funds.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7467\" data-end=\"7470\">\r\n<h3 data-start=\"7472\" data-end=\"7501\"><strong data-start=\"7476\" data-end=\"7501\">Future-Ready Features</strong></h3>\r\n<ul data-start=\"7503\" data-end=\"7807\">\r\n<li data-start=\"7503\" data-end=\"7554\">\r\n<p data-start=\"7505\" data-end=\"7554\"><strong data-start=\"7505\" data-end=\"7537\">Real-Time AIS Reconciliation</strong> before filing.</p>\r\n</li>\r\n<li data-start=\"7555\" data-end=\"7602\">\r\n<p data-start=\"7557\" data-end=\"7602\"><strong data-start=\"7557\" data-end=\"7579\">Auto-refund system</strong> integrated with RBI.</p>\r\n</li>\r\n<li data-start=\"7603\" data-end=\"7661\">\r\n<p data-start=\"7605\" data-end=\"7661\"><strong data-start=\"7605\" data-end=\"7634\">AI-driven error detection</strong> for mismatch prevention.</p>\r\n</li>\r\n<li data-start=\"7662\" data-end=\"7751\">\r\n<p data-start=\"7664\" data-end=\"7751\"><strong data-start=\"7664\" data-end=\"7691\">Simplified verification</strong> via facial and biometric authentication (coming phase 2).</p>\r\n</li>\r\n<li data-start=\"7752\" data-end=\"7807\">\r\n<p data-start=\"7754\" data-end=\"7807\"><strong data-start=\"7754\" data-end=\"7805\">Integration with GST and customs for exporters.</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7809\" data-end=\"7812\">\r\n<h3 data-start=\"7814\" data-end=\"7877\"><strong data-start=\"7818\" data-end=\"7877\">Rajasthan Filings &ndash; Your Trusted Tax Compliance Partner</strong></h3>\r\n<p data-start=\"7879\" data-end=\"7965\">At <strong data-start=\"7882\" data-end=\"7903\">Rajasthan Filings</strong>, our expert Chartered Accountants and Tax Advisors provide:</p>\r\n<ul data-start=\"7966\" data-end=\"8339\">\r\n<li data-start=\"7966\" data-end=\"8028\">\r\n<p data-start=\"7968\" data-end=\"8028\">Precise analysis of your income and deduction eligibility.</p>\r\n</li>\r\n<li data-start=\"8029\" data-end=\"8107\">\r\n<p data-start=\"8031\" data-end=\"8107\">End-to-end ITR filing for Individuals, Firms, Companies, Trusts, and NGOs.</p>\r\n</li>\r\n<li data-start=\"8108\" data-end=\"8185\">\r\n<p data-start=\"8110\" data-end=\"8185\">Assistance for Revised / Updated Returns under Sections 139(5) &amp; 139(8A).</p>\r\n</li>\r\n<li data-start=\"8186\" data-end=\"8238\">\r\n<p data-start=\"8188\" data-end=\"8238\">Audit support for 44AB and faceless assessments.</p>\r\n</li>\r\n<li data-start=\"8239\" data-end=\"8288\">\r\n<p data-start=\"8241\" data-end=\"8288\">Refund tracking and rectification of notices.</p>\r\n</li>\r\n<li data-start=\"8289\" data-end=\"8339\">\r\n<p data-start=\"8291\" data-end=\"8339\">Year-round compliance monitoring and advisory.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"8341\" data-end=\"8470\">We ensure every return filed through Rajasthan Filings is accurate, compliant, and legally sound under the Income-tax Act 2025.</p>\r\n<hr data-start=\"8472\" data-end=\"8475\">\r\n<h3 data-start=\"8477\" data-end=\"8495\"><strong data-start=\"8481\" data-end=\"8495\">Conclusion</strong></h3>\r\n<p data-start=\"8497\" data-end=\"8709\">The <strong data-start=\"8501\" data-end=\"8524\">Income-tax Act 2025</strong> introduces a new era of <strong data-start=\"8549\" data-end=\"8592\">trust-based, technology-driven taxation</strong>.<br data-start=\"8593\" data-end=\"8596\">ITR filing is no longer a paper process but a real-time digital compliance statement of your financial honesty.</p>\r\n<p data-start=\"8711\" data-end=\"8841\">By filing on time and accurately, taxpayers strengthen India&rsquo;s economic transparency and secure their own financial credibility.</p>\r\n<p data-start=\"8843\" data-end=\"9032\">With <strong data-start=\"8848\" data-end=\"8869\">Rajasthan Filings</strong>, you can file your Income Tax Return under the new law confidently &mdash; accurately, on time, and fully compliant with every requirement of the Income-tax Act 2025.</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</article>', NULL, NULL, '1760512339_pngtree-accountant-doing-financial-analysis-3d-illustration-png-image_9198423.png', NULL, 0, '2025-09-27 05:07:36', '2025-11-07 00:49:04');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(8, 2, NULL, 'GST Registration', 'gst-registration-', 'GST Registration (Normal / Composition / Casual / Non-Resident)', '<h2><span lang=\"EN-US\">How to get a GST Registration?</span></h2>\r\n<p>The name Goods and Services Tax (GST) itself reflects that it is a taxation system that takes into account &ndash; the goods and the services. This means GST is applicable on both the tangible goods as well as the intangible services while maintaining the balance of both the Central and the State Government independent revenues through a dual mechanism of GST.</p>\r\n<p>On 1st July, 2017 marked the commencement of the GST regime that brought a comprehensive, multi-stage, and destination-based tax that is charged on every value addition. GST regime shall enhance transparency in the indirect tax framework and is expected to bring down the rate of inflation and cascading effect of tax. It will also be a hike to investment inflows, e-commerce and &ldquo;Make in India&rdquo; approach.</p>\r\n<p>GST is based on the &ldquo;One Nation One Tax&rdquo; theme and consists of tax rate slabs that start with a minimum of 0% and extend till the highest of 28%</p>\r\n<p>Even today, people are not very much familiar with this tax mechanism and to get acquainted with the same they avail Chartered Accountant service.</p>\r\n<p>The GST regime has made it mandatory for all the business entities engaged in buying or selling goods or services or both to get themselves registered under the provisions of the GST Act. Entities carrying out operations without GST Registrations are ineligible for GST collection from Consumers and they are not allowed to claim an input tax credit paid.</p>\r\n<p>So, to claim the ITC and to collect the GST from customers, GST registration is compulsory. GST, therefore is a destination-based tax applicable on all transactions, involving supply of goods / services for a consideration.</p>\r\n<h2><span lang=\"EN-US\">GST Turnover Timit</span></h2>\r\n<p>GST registration is mandatory for casual taxable persons or persons making supplies through e-Commerce operators and non-resident taxable persons, irrespective of turnover limit. Such dealers must avail GST Advisory Service or take help from professionals like CA, CS and lawyers to understand what exactly the Act wants to convey.</p>\r\n<p>&ldquo;Casual taxable person&rdquo; means anyone who occasionally undertakes transactions involving supply of goods or services or both in the course of business, whether as principal, agent or in any other capacity, in a State or a Union territory where he has no particular place of business.</p>\r\n<p>Turnover Limit or service providers and goods supplier for regular GST Registrations are mentioned in following points:-</p>\r\n<p>For Goods Suppliers: &ndash; As per the respective notification, registration under GST is mandatory for any person who is occupied in the exclusive supply of goods and whose aggregate turnover exceeds Rs.40 lakhs in a Financial year. The supplier must fulfill the below-mentioned conditions:-</p>\r\n<ul type=\"disc\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l0 level1 lfo1; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">It should not be engaged in the supply of any services</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l0 level1 lfo1; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Must not be engaged in intra-state (supplying goods within the same state) supplies in the States of Arunachal Pradesh, Manipur, Mizoram, Nagaland, Puducherry, Meghalaya, Sikkim, Telangana, Tripura, and Uttarakhand</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l0 level1 lfo1; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Not involved in the supply of pan masala, tobacco or ice creams.</span></li>\r\n</ul>\r\n<p>Turnover limit for GST registration falls down to Rs.20 lakhs and Rs.10 lakhs in case of non-fulfillment of the above-mentioned conditions and special category states, respectively.</p>\r\n<p>This means when the supplier does not meet the above-mentioned conditions, it becomes mandatory for him to obtain GST registration when the turnover exceeds Rs.20 lakhs. For the northeastern and other states mentioned in the Act, the GST registration limit is Rs.10 lakhs.</p>\r\n<p>GST registration consultants provide the platform for smooth &amp; easy registrations under it. They take care of the different turnover limits which mandate the registration under the Act</p>\r\n<p>Here is the list of the special category states under GST:-</p>\r\n<ul type=\"disc\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Arunachal Pradesh</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Assam</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Jammu and Kashmir</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Manipur</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Meghalaya</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Mizoram</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Nagaland</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Sikkim</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Tripura</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Himachal Pradesh</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l1 level1 lfo2; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">Uttarakhand</span></li>\r\n</ul>\r\n<p>The initial GST registration limits were raised in the 32<sup>nd</sup> GST Council meet for the supply of goods.Let&rsquo;s have a quick glance at the initial threshold limits as well as new thresholds that require the mandatory registration of a firm under the Act.</p>\r\n<table class=\"MsoNormalTable\" style=\"width: 100.0%; mso-cellspacing: 1.5pt; border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; mso-yfti-tbllook: 1184;\" border=\"1\" width=\"100%\" cellspacing=\"3\" cellpadding=\"0\">\r\n<tbody>\r\n<tr style=\"mso-yfti-irow: 0; mso-yfti-firstrow: yes;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><strong><span lang=\"EN-US\" style=\"font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi;\">Aggregate Turnover</span></strong></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><strong><span lang=\"EN-US\" style=\"font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi;\">Registration Mandatory</span></strong></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><strong><span lang=\"EN-US\" style=\"font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi;\">Applicability</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 1;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\" colspan=\"3\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><strong><span lang=\"EN-US\" style=\"font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi;\">Initial Threshold &ndash; For the supply of Goods or Services</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 2;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">More than Rs.20 lakh</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">Yes &ndash; For Normal Category States</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">Till March 31, 2019</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 3;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">More than Rs.10 lakh</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">Yes &ndash; For Special Category States</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">Till March 31, 2019</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 4;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\" colspan=\"3\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><strong><span lang=\"EN-US\" style=\"font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi;\">New Limits &ndash; For Sale of Goods</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 5;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">More than Rs.40 lakh</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">Yes &ndash; For Normal Category States</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">From April 1, 2019</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 6;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">More than Rs.20 lakh</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">Yes &ndash; For Special Category States</span></p>\r\n</td>\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">From April 1, 2019</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 7;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\" colspan=\"3\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><strong><span lang=\"EN-US\" style=\"font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi;\">New Limits &ndash; For Providing Services</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 8; mso-yfti-lastrow: yes;\">\r\n<td style=\"border: solid #DDDDDD 1.0pt; mso-border-alt: solid #DDDDDD .75pt; padding: 6.75pt 6.75pt 6.75pt 6.75pt;\" colspan=\"3\">\r\n<p class=\"MsoNormal\" style=\"margin: .75pt 0cm 15.0pt 0cm;\"><span lang=\"EN-US\">The threshold limits for Service Providers have remained unchanged.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h2><span lang=\"EN-US\">Explanation of Aggregate Turnover under GST</span></h2>\r\n<p>Aggregate Turnover under GST =(Taxable supplies + Exempt Supplies + Exports + Inter-State Supplies) &ndash; (Taxes + Value of Inward Supplies + Value of Supplies Taxable under Reverse Charge + Value of Non-Taxable Supplies).</p>\r\n<p>It is a PAN-based calculation, so even if one person has multiple places of business, all must be considered and summed to arrive at the aggregate turnover.</p>\r\n<h2><span lang=\"EN-US\">Voluntary registration under GST</span></h2>\r\n<p>Any person whether natural or artificial regardless of business turnover can obtain GST registration at any-time. Many businesses that do not meet the aggregate turnover limit also get themselves registered under it. GST registration consultants can suggest you the best advice as to whether or not it&rsquo;s beneficial to get your business registered under GST.</p>\r\n<p>Major reasons for obtaining voluntary GST registration are:</p>\r\n<ul type=\"disc\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l3 level1 lfo3; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">For improving the business credibility</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l3 level1 lfo3; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">For satisfying the requirements of B2B customers</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l3 level1 lfo3; tab-stops: list 36.0pt;\"><span lang=\"EN-US\">For claiming the input tax credit benefits.</span></li>\r\n</ul>\r\n<h2><span lang=\"EN-US\">What are the documents required under GST?</span></h2>\r\n<p>If you wish to avail services for the GST registration, you need to study the document requirements for GST registration. For now, we can have an understanding of the documents that we need:</p>\r\n<ul type=\"disc\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level1 lfo4; tab-stops: list 36.0pt;\"><strong><span lang=\"EN-US\">PAN CARD OF THE BUSINESS OR APPLICANT: </span></strong><span lang=\"EN-US\">As the GST Registration is linked to the PAN of business. Hence, PAN is the most important document to be obtained by the entity before applying for GST Registrations.</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level1 lfo4; tab-stops: list 36.0pt;\"><strong><span lang=\"EN-US\">ADDRESS AND IDENTITY PROOF ALONG WITH PHOTOGRAPHS: </span></strong><span lang=\"EN-US\">Following can be admitted and submitted as Identity Proof such as (Passport, Voter ID card, PAN, Aadhar Card, Driving License) and; In case of Address Proof (passport, Aadhar Card, Driving License, Voters Identity Card and Ration Card) Further, the persons who mandatorily need to submit the above-mentioned documents are as follows:- </span></li>\r\n<ul type=\"circle\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Company &ndash; Managing Director, Directors and the Authorized Person</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Hindu Undivided Family &ndash; Karta</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Proprietary Concern &ndash; Proprietor</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Local Authority &ndash; CEO or his equivalent</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Statutory Body &ndash; CEO or his equivalent</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Trust &ndash; Managing Trustee, Trustees, and Authorized Person</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Partnership Firm / LLP &ndash; Managing/Authorized/Designated Partners (personal details of all partners are required to be submitted but photographs of only 10 partners including that of Managing Partner is to be submitted);</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Association of Persons or Body of Individuals &ndash;Members of Managing Committee (personal details of all members are required to be submitted but photographs of only 10 members including that of Chairman is to be submitted)</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Others &ndash; persons in charge</span></li>\r\n</ul>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level1 lfo4; tab-stops: list 36.0pt;\"><strong><span lang=\"EN-US\">BUSINESS REGISTRATION DOCUMENT</span></strong><span lang=\"EN-US\"><br>All types of business entities need to provide their proof of business registration but in case of proprietorship, there is no requirement for the submission of the proof of business registration as the proprietor and proprietorship are considered the same. Also, the entities need to submit their charter document. Your GST consultant will guide you throughout the registration process and inform you whether or not you need a proof of business registration. </span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level1 lfo4; tab-stops: list 36.0pt;\"><strong><span lang=\"EN-US\">ADDRESS PROOF FOR PLACE OF BUSINESS</span></strong><span lang=\"EN-US\"><br>In the GST Registration application, an address proof for all places of business is to be submitted. An array of documents can be used as address proof for the place of your business, you can avail guidance from https://www.gst.gov.in/ in case of any doubt. Following documents are admissible for GST Registration:- </span></li>\r\n<ul type=\"circle\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">In case of Owned Premises - Copy of latest Property Tax Receipt or Municipal Khata or Electricity Bill.</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><strong><span lang=\"EN-US\">For Rented or Leased Premises- </span></strong><span lang=\"EN-US\">Copy of the valid rental agreement with a supporting document of ownership of the premises of the Lessor i.e. either copy of Latest Property Tax Receipt, Municipal Khata, Electricity Bill. In case of unavailability of the rental agreement or lease deed, an affidavit along with a supporting document in the possession of the premises like a copy of the electricity bill, etc can be used.</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><strong><span lang=\"EN-US\">SEZ Premises- </span></strong><span lang=\"EN-US\">In case the premises or the place of business is located in SEZ or the applicant is A SEZ Developer then all the necessary documents as issued and provided by the Government of India must be uploaded.</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><strong><span lang=\"EN-US\">Other Cases- </span></strong><span lang=\"EN-US\">Copy of consent letter of the owner of premises along with a supporting document of ownership of premises of the consenter like a copy of the electricity bill, Municipal Khata.</span></li>\r\n</ul>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level1 lfo4; tab-stops: list 36.0pt;\"><strong><span lang=\"EN-US\">PROOF OF BANK ACCOUNT</span></strong><span lang=\"EN-US\"><br>Scanned copy of either following documents:- </span></li>\r\n<ul type=\"circle\">\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">First and relevant page of Passbook</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">The relevant page of bank statement</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><span lang=\"EN-US\">Cancelled cheque bearing the name of Proprietor or business entity, Bank Account No., IFSC, MICR, and Bank Branch details including code.2</span></li>\r\n<li class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-list: l2 level2 lfo4; tab-stops: list 72.0pt;\"><strong><span lang=\"EN-US\">Other Cases- </span></strong><span lang=\"EN-US\">Copy of consent letter of the owner of premises along with a supporting document of ownership of premises of the consenter like a copy of the electricity bill, Municipal Khata.</span></li>\r\n</ul>\r\n</ul>', NULL, NULL, '1760512268_pngtree-accountant-doing-financial-analysis-3d-illustration-png-image_9198423.png', NULL, 0, '2025-09-27 05:07:53', '2025-11-07 00:49:05');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(9, 1, NULL, 'Company Registration & Incorporation', 'company-registration--incorporation', 'COMPANY REGISTRATION & INCORPORATION', '<p class=\"MsoNormal\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🏢</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\"> COMPANY REGISTRATION &amp; INCORPORATION</span></strong></p>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 107%;\">Establish Your Business with Legal Recognition and Long-Term Credibility</span></strong></p>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 14.0pt; mso-bidi-font-size: 12.0pt; line-height: 107%;\">&nbsp;</span>Introduction</strong></p>\r\n<p data-start=\"455\" data-end=\"724\">Starting a company is the first step toward transforming a business idea into a legally recognised organisation.<br data-start=\"567\" data-end=\"570\">A registered company builds <strong data-start=\"598\" data-end=\"645\">trust, credibility, and financial stability</strong>, allowing easy access to bank finance, investors, and government programmes.</p>\r\n<p data-start=\"726\" data-end=\"1029\"><strong data-start=\"726\" data-end=\"747\">Rajasthan Filings</strong> provides complete assistance for company incorporation under the Ministry of Corporate Affairs (MCA).<br data-start=\"849\" data-end=\"852\">Our Chartered Accountants and Legal Experts manage every stage&mdash;from documentation and digital signatures to final approvals&mdash;ensuring a seamless, accurate, and compliant process.<br><br></p>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%;\">Why Company Registration Matters</span></strong></p>\r\n<ol data-start=\"1169\" data-end=\"1626\">\r\n<li data-start=\"1169\" data-end=\"1263\">\r\n<p data-start=\"1172\" data-end=\"1263\"><strong data-start=\"1172\" data-end=\"1191\">Legal Identity:</strong> The company becomes a distinct legal person separate from its owners.</p>\r\n</li>\r\n<li data-start=\"1264\" data-end=\"1356\">\r\n<p data-start=\"1267\" data-end=\"1356\"><strong data-start=\"1267\" data-end=\"1289\">Limited Liability:</strong> Protects personal assets of directors from business obligations.</p>\r\n</li>\r\n<li data-start=\"1357\" data-end=\"1442\">\r\n<p data-start=\"1360\" data-end=\"1442\"><strong data-start=\"1360\" data-end=\"1382\">Access to Funding:</strong> Banks and investors prefer registered corporate entities.</p>\r\n</li>\r\n<li data-start=\"1443\" data-end=\"1527\">\r\n<p data-start=\"1446\" data-end=\"1527\"><strong data-start=\"1446\" data-end=\"1471\">Perpetual Succession:</strong> The organisation continues even if ownership changes.</p>\r\n</li>\r\n<li data-start=\"1528\" data-end=\"1626\">\r\n<p data-start=\"1531\" data-end=\"1626\"><strong data-start=\"1531\" data-end=\"1553\">Brand Credibility:</strong> A CIN-registered entity builds confidence among clients and suppliers.</p>\r\n</li>\r\n</ol>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%;\">Types of Companies</span></strong></p>\r\n<table class=\"MsoNormalTable\" style=\"mso-cellspacing: 1.5pt; mso-yfti-tbllook: 1184;\" border=\"0\" cellspacing=\"3\" cellpadding=\"0\">\r\n<thead>\r\n<tr style=\"mso-yfti-irow: 0; mso-yfti-firstrow: yes;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Feature</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Private Limited Company</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">LLP (Limited Liability Partnership)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">One Person Company (OPC)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Proprietorship</span></strong></p>\r\n</td>\r\n</tr>\r\n</thead>\r\n<tbody>\r\n<tr style=\"mso-yfti-irow: 1;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Legal Status</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Separate Legal Entity</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Separate Legal Entity</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Separate Legal Entity</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Not a Separate Entity</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 2;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Ownership</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Minimum 2 Shareholders</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Minimum 2 Partners</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Only 1 Director/Shareholder</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Single Owner</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 3;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Liability</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Limited to Shareholding</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Limited to Capital Contribution</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Limited to Shareholding</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Unlimited (Owner bears all risk)</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 4;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Registration Authority</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">MCA (Ministry of Corporate Affairs)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">MCA</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">MCA</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">MSME / Local Authority</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 5;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Capital Requirement</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">No Minimum Capital</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">No Minimum Capital</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">No Minimum Capital</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">No Minimum Capital</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 6;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Taxation</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">22% (Domestic Company) + Surcharge</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">30% (as Firm)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">22% (Domestic Company)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Slab rate (Individual Tax)</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 7;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Compliance Cost</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Moderate to High</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Moderate</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Moderate</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Very Low</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 8;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Annual Filings</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">ROC + ITR + Audit (if applicable)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">ROC + ITR</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">ROC + ITR</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">ITR only</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 9;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Ideal For</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Startups, Growing Businesses, Investors</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Professionals, Family Firms, Consultants</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Solo Entrepreneurs</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Small Traders, Retailers</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 10;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Funding / Investment</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Easy to raise through Equity or VC</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Difficult (Partners&rsquo; contribution only)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Limited (Single Owner)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Not eligible for equity funding</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 11;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Audit Requirement</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Mandatory (if turnover &gt; ₹1 Cr)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Mandatory (if turnover &gt; ₹40 Lakh)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Mandatory (same as Pvt Ltd)</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Not Mandatory</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 12;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Continuity / Perpetual Existence</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Exists even after owner change</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Exists even after partner change</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Exists even after owner change</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Ends with owner&rsquo;s life/business closure</span></strong></p>\r\n</td>\r\n</tr>\r\n<tr style=\"mso-yfti-irow: 13; mso-yfti-lastrow: yes;\">\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Reputation / Credibility</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">High &ndash; Preferred by banks/investors</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Moderate</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">High for freelancers / professionals</span></strong></p>\r\n</td>\r\n<td style=\"padding: .75pt .75pt .75pt .75pt;\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 12.0pt; mso-bidi-font-size: 11.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\">Low &ndash; Unregistered structure</span></strong></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p class=\"MsoNormal\">&nbsp;</p>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%; font-family: \'Calibri\',sans-serif; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: Calibri; mso-fareast-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Mangal; mso-bidi-theme-font: minor-bidi; mso-ansi-language: EN-IN; mso-fareast-language: EN-US; mso-bidi-language: HI;\">Documents Required</span></strong></p>\r\n<p data-start=\"2726\" data-end=\"2760\"><strong data-start=\"2726\" data-end=\"2758\">For Directors / Shareholders</strong></p>\r\n<ul data-start=\"2761\" data-end=\"2871\">\r\n<li data-start=\"2761\" data-end=\"2788\">\r\n<p data-start=\"2763\" data-end=\"2788\">PAN Card &amp; Aadhaar Card</p>\r\n</li>\r\n<li data-start=\"2789\" data-end=\"2817\">\r\n<p data-start=\"2791\" data-end=\"2817\">Passport-size photograph</p>\r\n</li>\r\n<li data-start=\"2818\" data-end=\"2871\">\r\n<p data-start=\"2820\" data-end=\"2871\">Email ID and mobile number (for OTP verification)</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2873\" data-end=\"2908\"><strong data-start=\"2873\" data-end=\"2906\">For Registered Office Address</strong></p>\r\n<ul data-start=\"2909\" data-end=\"3049\">\r\n<li data-start=\"2909\" data-end=\"2968\">\r\n<p data-start=\"2911\" data-end=\"2968\">Latest electricity / gas / water bill (within 2 months)</p>\r\n</li>\r\n<li data-start=\"2969\" data-end=\"3013\">\r\n<p data-start=\"2971\" data-end=\"3013\">Rent agreement (if rented) + Owner&rsquo;s NOC</p>\r\n</li>\r\n<li data-start=\"3014\" data-end=\"3049\">\r\n<p data-start=\"3016\" data-end=\"3049\">Property tax receipt (if owned)</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3051\" data-end=\"3079\"><strong data-start=\"3051\" data-end=\"3077\">Additional Information</strong></p>\r\n<ul data-start=\"3080\" data-end=\"3197\">\r\n<li data-start=\"3080\" data-end=\"3119\">\r\n<p data-start=\"3082\" data-end=\"3119\">Proposed company name (2&ndash;3 options)</p>\r\n</li>\r\n<li data-start=\"3120\" data-end=\"3156\">\r\n<p data-start=\"3122\" data-end=\"3156\">Main business activity / objects</p>\r\n</li>\r\n<li data-start=\"3157\" data-end=\"3197\">\r\n<p data-start=\"3159\" data-end=\"3197\">Share capital and shareholding ratio<br><br></p>\r\n</li>\r\n</ul>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%;\">Step-by-Step Incorporation Process</span></strong></p>\r\n<ol data-start=\"3344\" data-end=\"3934\">\r\n<li data-start=\"3344\" data-end=\"3445\">\r\n<p data-start=\"3347\" data-end=\"3445\"><strong data-start=\"3347\" data-end=\"3386\">Digital Signature Certificate (DSC)</strong> &ndash; issued for all directors to sign forms electronically.</p>\r\n</li>\r\n<li data-start=\"3446\" data-end=\"3525\">\r\n<p data-start=\"3449\" data-end=\"3525\"><strong data-start=\"3449\" data-end=\"3489\">Director Identification Number (DIN)</strong> &ndash; unique number allocated by MCA.</p>\r\n</li>\r\n<li data-start=\"3526\" data-end=\"3610\">\r\n<p data-start=\"3529\" data-end=\"3610\"><strong data-start=\"3529\" data-end=\"3571\">Name Reservation (RUN / SPICe+ Part A)</strong> &ndash; approval of proposed company name.</p>\r\n</li>\r\n<li data-start=\"3611\" data-end=\"3695\">\r\n<p data-start=\"3614\" data-end=\"3695\"><strong data-start=\"3614\" data-end=\"3636\">Drafting MOA &amp; AOA</strong> &ndash; defining objectives and internal rules of the company.</p>\r\n</li>\r\n<li data-start=\"3696\" data-end=\"3769\">\r\n<p data-start=\"3699\" data-end=\"3769\"><strong data-start=\"3699\" data-end=\"3723\">Filing SPICe+ Part B</strong> &ndash; online submission of incorporation forms.</p>\r\n</li>\r\n<li data-start=\"3770\" data-end=\"3844\">\r\n<p data-start=\"3773\" data-end=\"3844\"><strong data-start=\"3773\" data-end=\"3796\">PAN &amp; TAN Allotment</strong> &ndash; automatically generated after MCA approval.</p>\r\n</li>\r\n<li data-start=\"3845\" data-end=\"3934\">\r\n<p data-start=\"3848\" data-end=\"3934\"><strong data-start=\"3848\" data-end=\"3890\">Certificate of Incorporation (CIN No.)</strong> &ndash; final legal proof of company existence.<br><br></p>\r\n</li>\r\n</ol>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%;\">Post-Registration Compliance<br></span></strong></p>\r\n<p data-start=\"4050\" data-end=\"4154\">After receiving the Certificate of Incorporation, every company must complete certain statutory tasks:</p>\r\n<ul data-start=\"4156\" data-end=\"4446\">\r\n<li data-start=\"4156\" data-end=\"4193\">\r\n<p data-start=\"4158\" data-end=\"4193\">Opening a company current account</p>\r\n</li>\r\n<li data-start=\"4194\" data-end=\"4259\">\r\n<p data-start=\"4196\" data-end=\"4259\">Applying for GST registration, MSME (Udyam), and Shop License</p>\r\n</li>\r\n<li data-start=\"4260\" data-end=\"4306\">\r\n<p data-start=\"4262\" data-end=\"4306\">Issuing share certificates to shareholders</p>\r\n</li>\r\n<li data-start=\"4307\" data-end=\"4360\">\r\n<p data-start=\"4309\" data-end=\"4360\">Conducting the first Board Meeting within 30 days</p>\r\n</li>\r\n<li data-start=\"4361\" data-end=\"4397\">\r\n<p data-start=\"4363\" data-end=\"4397\">Appointment of Statutory Auditor</p>\r\n</li>\r\n<li data-start=\"4398\" data-end=\"4446\">\r\n<p data-start=\"4400\" data-end=\"4446\">Maintaining Registers of Members &amp; Directors<br><br></p>\r\n</li>\r\n</ul>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%;\">Benefits of Choosing Rajasthan Filings<br></span></strong></p>\r\n<table>\r\n<thead>\r\n<tr>\r\n<th>Advantage</th>\r\n<th>Description</th>\r\n</tr>\r\n</thead>\r\n<tbody>\r\n<tr>\r\n<td><strong>Expert Professionals</strong></td>\r\n<td>Incorporation handled by qualified Chartered Accountants and Advocates.</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Pan-India Reach</strong></td>\r\n<td>Fully digital process with service coverage across India.</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Transparent Process</strong></td>\r\n<td>Fixed documentation and step-wise updates&mdash;no hidden requirements.</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Fast Turnaround</strong></td>\r\n<td>End-to-end processing within statutory timelines.</td>\r\n</tr>\r\n<tr>\r\n<td><strong>Comprehensive Support</strong></td>\r\n<td>From registration to GST and bookkeeping&mdash;everything under one roof.</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p class=\"MsoNormal\">&nbsp;</p>\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 16.0pt; mso-bidi-font-size: 14.0pt; line-height: 107%;\">Conclusion</span></strong></p>\r\n<p data-start=\"5238\" data-end=\"5433\">Company incorporation is a cornerstone for building a trusted and growth-oriented organisation.<br data-start=\"5333\" data-end=\"5336\">It creates a strong legal foundation, enabling structured operations and sustainable expansion.</p>\r\n<p data-start=\"5435\" data-end=\"5703\">At <strong data-start=\"5438\" data-end=\"5459\">Rajasthan Filings</strong>, we combine professional expertise with technology-driven efficiency to make incorporation effortless and reliable.<br data-start=\"5575\" data-end=\"5578\">From name approval to post-registration compliance, our team ensures every requirement is met with precision and integrity.</p>\r\n<blockquote data-start=\"5705\" data-end=\"5796\">\r\n<p data-start=\"5707\" data-end=\"5796\"><strong data-start=\"5707\" data-end=\"5796\">&ldquo;Incorporate once, grow forever &mdash; with Rajasthan Filings as your compliance partner.&rdquo;</strong></p>\r\n<p data-start=\"5707\" data-end=\"5796\">&nbsp;</p>\r\n</blockquote>', NULL, NULL, '1760512233_pngtree-accountant-doing-financial-analysis-3d-illustration-png-image_9198423.png', NULL, 0, '2025-09-27 05:08:20', '2025-11-07 00:49:07');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(10, 1, NULL, 'Shop & Establishment Act Registration', 'shop--establishment-act-registration', 'Shop & Establishment Act Registration', '<p class=\"MsoNormal\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🏬</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Shop &amp; Establishment License Registration in India</span></strong></p>\r\n<h3 data-start=\"427\" data-end=\"511\">Legal Recognition for Your Business Premises &ndash; Simplified by Rajasthan Filings</h3>\r\n<p data-start=\"513\" data-end=\"899\">Every business that operates from a shop, commercial office, warehouse, or establishment must be registered under the <strong data-start=\"631\" data-end=\"661\">Shops &amp; Establishments Act</strong> of the respective State Government.<br data-start=\"697\" data-end=\"700\">This license is a <strong data-start=\"718\" data-end=\"744\">mandatory registration</strong> for all commercial entities &mdash; including retail shops, offices, service centers, restaurants, godowns, or any place where trade or business is carried out.</p>\r\n<p data-start=\"901\" data-end=\"1094\">At <strong data-start=\"904\" data-end=\"925\">Rajasthan Filings</strong>, we help you obtain your <strong data-start=\"951\" data-end=\"993\">Shop &amp; Establishment License (Gumasta)</strong> quickly and legally so your business complies with local labour, safety, and commercial regulations.</p>\r\n<hr data-start=\"1096\" data-end=\"1099\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">⚖️</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Objective of the Shop &amp; Establishment Act</span></strong></p>\r\n<p data-start=\"1152\" data-end=\"1329\">The Act governs the&nbsp;<strong data-start=\"1172\" data-end=\"1194\">conditions of work</strong> and <strong data-start=\"1199\" data-end=\"1220\">employment rights</strong> in commercial establishments. It ensures fair labour practices and proper registration of every workplace.</p>\r\n<h3 data-start=\"1331\" data-end=\"1355\">The Act regulates:</h3>\r\n<ul data-start=\"1356\" data-end=\"1602\">\r\n<li data-start=\"1356\" data-end=\"1393\">\r\n<p data-start=\"1358\" data-end=\"1393\">Working hours and weekly holidays</p>\r\n</li>\r\n<li data-start=\"1394\" data-end=\"1440\">\r\n<p data-start=\"1396\" data-end=\"1440\">Rest intervals and opening/closing timings</p>\r\n</li>\r\n<li data-start=\"1441\" data-end=\"1471\">\r\n<p data-start=\"1443\" data-end=\"1471\">Wages and overtime payment</p>\r\n</li>\r\n<li data-start=\"1472\" data-end=\"1513\">\r\n<p data-start=\"1474\" data-end=\"1513\">Employment of women and young workers</p>\r\n</li>\r\n<li data-start=\"1514\" data-end=\"1554\">\r\n<p data-start=\"1516\" data-end=\"1554\">Maintenance of registers and records</p>\r\n</li>\r\n<li data-start=\"1555\" data-end=\"1602\">\r\n<p data-start=\"1557\" data-end=\"1602\">Health, safety, and hygiene in the premises</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1604\" data-end=\"1783\">Each State in India has its own set of rules and online registration system, but the purpose remains the same &mdash; to provide <strong data-start=\"1727\" data-end=\"1782\">legal identity, transparency, and worker protection</strong>.</p>\r\n<hr data-start=\"1785\" data-end=\"1788\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🏢</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Applicability</span></strong></p>\r\n<p data-start=\"1813\" data-end=\"1855\">The Shop &amp; Establishment Act applies to:</p>\r\n<ul data-start=\"1856\" data-end=\"2171\">\r\n<li data-start=\"1856\" data-end=\"1886\">\r\n<p data-start=\"1858\" data-end=\"1886\">Retail and wholesale shops</p>\r\n</li>\r\n<li data-start=\"1887\" data-end=\"1920\">\r\n<p data-start=\"1889\" data-end=\"1920\">Trading outlets and showrooms</p>\r\n</li>\r\n<li data-start=\"1921\" data-end=\"1963\">\r\n<p data-start=\"1923\" data-end=\"1963\">Business offices and consultancy firms</p>\r\n</li>\r\n<li data-start=\"1964\" data-end=\"2013\">\r\n<p data-start=\"1966\" data-end=\"2013\">Educational institutions and coaching centers</p>\r\n</li>\r\n<li data-start=\"2014\" data-end=\"2048\">\r\n<p data-start=\"2016\" data-end=\"2048\">Restaurants, hotels, and caf&eacute;s</p>\r\n</li>\r\n<li data-start=\"2049\" data-end=\"2075\">\r\n<p data-start=\"2051\" data-end=\"2075\">Warehouses and godowns</p>\r\n</li>\r\n<li data-start=\"2076\" data-end=\"2118\">\r\n<p data-start=\"2078\" data-end=\"2118\">Service centers, clinics, and startups</p>\r\n</li>\r\n<li data-start=\"2119\" data-end=\"2171\">\r\n<p data-start=\"2121\" data-end=\"2171\">Freelancers or professionals with a fixed office</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2173\" data-end=\"2342\">Whether you are a <strong data-start=\"2191\" data-end=\"2256\">sole proprietor, partnership, LLP, or private limited company</strong>, registration under this Act is compulsory within <strong data-start=\"2307\" data-end=\"2318\">30 days</strong> of commencing business.</p>\r\n<hr data-start=\"2344\" data-end=\"2347\">\r\n<p class=\"MsoNormal\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">📄</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Benefits of Obtaining a Shop &amp; Establishment License</span></strong></p>\r\n<ol data-start=\"2411\" data-end=\"3279\">\r\n<li data-start=\"2411\" data-end=\"2547\">\r\n<p data-start=\"2414\" data-end=\"2547\"><strong data-start=\"2414\" data-end=\"2456\">Legal Recognition of Business Premises</strong><br data-start=\"2456\" data-end=\"2459\">Establishes your shop or office as a lawful business entity under State labour law.</p>\r\n</li>\r\n<li data-start=\"2549\" data-end=\"2653\">\r\n<p data-start=\"2552\" data-end=\"2653\"><strong data-start=\"2552\" data-end=\"2576\">Bank Account Opening</strong><br data-start=\"2576\" data-end=\"2579\">Required as proof for opening a current account in the business name.</p>\r\n</li>\r\n<li data-start=\"2655\" data-end=\"2764\">\r\n<p data-start=\"2658\" data-end=\"2764\"><strong data-start=\"2658\" data-end=\"2684\">Ease of Doing Business</strong><br data-start=\"2684\" data-end=\"2687\">Makes it easier to obtain other registrations like GST, FSSAI, or Udyam.</p>\r\n</li>\r\n<li data-start=\"2766\" data-end=\"2884\">\r\n<p data-start=\"2769\" data-end=\"2884\"><strong data-start=\"2769\" data-end=\"2793\">Business Credibility</strong><br data-start=\"2793\" data-end=\"2796\">Builds customer and supplier confidence by showing that the business is registered.</p>\r\n</li>\r\n<li data-start=\"2886\" data-end=\"3010\">\r\n<p data-start=\"2889\" data-end=\"3010\"><strong data-start=\"2889\" data-end=\"2932\">Employee Protection &amp; Labour Compliance</strong><br data-start=\"2932\" data-end=\"2935\">Helps maintain fair employee policies and avoids labour-law penalties.</p>\r\n</li>\r\n<li data-start=\"3012\" data-end=\"3147\">\r\n<p data-start=\"3015\" data-end=\"3147\"><strong data-start=\"3015\" data-end=\"3049\">Government Tenders &amp; Approvals</strong><br data-start=\"3049\" data-end=\"3052\">Many departments ask for Shop &amp; Establishment proof when issuing contracts or permissions.</p>\r\n</li>\r\n<li data-start=\"3149\" data-end=\"3279\">\r\n<p data-start=\"3152\" data-end=\"3279\"><strong data-start=\"3152\" data-end=\"3174\">Smooth Inspections</strong><br data-start=\"3174\" data-end=\"3177\">Demonstrates that your firm maintains proper working conditions and registers as required by law.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3281\" data-end=\"3284\">\r\n<p class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 2;\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🧾</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Documents Required</span></strong></p>\r\n<p data-start=\"3314\" data-end=\"3339\"><strong data-start=\"3314\" data-end=\"3337\">For Proprietorship:</strong></p>\r\n<ul data-start=\"3340\" data-end=\"3551\">\r\n<li data-start=\"3340\" data-end=\"3375\">\r\n<p data-start=\"3342\" data-end=\"3375\">PAN &amp; Aadhaar of the proprietor</p>\r\n</li>\r\n<li data-start=\"3376\" data-end=\"3399\">\r\n<p data-start=\"3378\" data-end=\"3399\">Passport-size photo</p>\r\n</li>\r\n<li data-start=\"3400\" data-end=\"3474\">\r\n<p data-start=\"3402\" data-end=\"3474\">Address proof of business location (rent agreement or property papers)</p>\r\n</li>\r\n<li data-start=\"3475\" data-end=\"3512\">\r\n<p data-start=\"3477\" data-end=\"3512\">Electricity bill / NOC from owner</p>\r\n</li>\r\n<li data-start=\"3513\" data-end=\"3551\">\r\n<p data-start=\"3515\" data-end=\"3551\">Business name and activity details</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3553\" data-end=\"3596\"><strong data-start=\"3553\" data-end=\"3594\">For Partnership Firm / LLP / Company:</strong></p>\r\n<ul data-start=\"3597\" data-end=\"3845\">\r\n<li data-start=\"3597\" data-end=\"3662\">\r\n<p data-start=\"3599\" data-end=\"3662\">Partnership Deed or Incorporation Certificate (as applicable)</p>\r\n</li>\r\n<li data-start=\"3663\" data-end=\"3703\">\r\n<p data-start=\"3665\" data-end=\"3703\">PAN of entity and partners/directors</p>\r\n</li>\r\n<li data-start=\"3704\" data-end=\"3744\">\r\n<p data-start=\"3706\" data-end=\"3744\">Proof of principal place of business</p>\r\n</li>\r\n<li data-start=\"3745\" data-end=\"3784\">\r\n<p data-start=\"3747\" data-end=\"3784\">List of employees and working hours</p>\r\n</li>\r\n<li data-start=\"3785\" data-end=\"3845\">\r\n<p data-start=\"3787\" data-end=\"3845\">Board Resolution or authorization letter (for companies)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3847\" data-end=\"3850\">\r\n<p class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 2;\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🧩</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Step-by-Step Registration Process</span></strong></p>\r\n<h3 data-start=\"3895\" data-end=\"3928\">1️⃣ Application Preparation</h3>\r\n<p data-start=\"3929\" data-end=\"4112\">Rajasthan Filings team prepares your application based on business type, activity, and address details. We collect all mandatory documents and ensure they meet State-specific formats.</p>\r\n<h3 data-start=\"4114\" data-end=\"4161\">2️⃣ Submission to Local Labour Department</h3>\r\n<p data-start=\"4162\" data-end=\"4347\">The verified form is filed on the State&rsquo;s labour registration portal or manually (depending on the district). All declarations about employees, holidays, and working hours are included.</p>\r\n<h3 data-start=\"4349\" data-end=\"4383\">3️⃣ Inspection (if required)</h3>\r\n<p data-start=\"4384\" data-end=\"4561\">Some states require an online or physical verification by the labour officer. Our team coordinates with the department and provides clarification or supporting papers if needed.</p>\r\n<h3 data-start=\"4563\" data-end=\"4609\">4️⃣ Issuance of Registration Certificate</h3>\r\n<p data-start=\"4610\" data-end=\"4783\">Once approved, the Labour Department issues a <strong data-start=\"4656\" data-end=\"4705\">Shop &amp; Establishment Registration Certificate</strong> with a unique registration number and validity period (usually 1 to 5 years).</p>\r\n<h3 data-start=\"4785\" data-end=\"4815\">5️⃣ Renewal &amp; Compliance</h3>\r\n<p data-start=\"4816\" data-end=\"4977\">Before expiry, renewal must be filed to keep the registration valid. Rajasthan Filings provides reminders and support for timely renewals and compliance filings.</p>\r\n<hr data-start=\"4979\" data-end=\"4982\">\r\n<p class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 2;\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">📘</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Post-Registration Responsibilities</span></strong></p>\r\n<p data-start=\"5028\" data-end=\"5107\">After registration, every establishment must follow certain labour-law norms.</p>\r\n<p data-start=\"5109\" data-end=\"5144\"><strong data-start=\"5109\" data-end=\"5142\">Key responsibilities include:</strong></p>\r\n<ul data-start=\"5145\" data-end=\"5519\">\r\n<li data-start=\"5145\" data-end=\"5217\">\r\n<p data-start=\"5147\" data-end=\"5217\">Displaying the registration certificate prominently at the workplace</p>\r\n</li>\r\n<li data-start=\"5218\" data-end=\"5274\">\r\n<p data-start=\"5220\" data-end=\"5274\">Maintaining employee attendance and salary registers</p>\r\n</li>\r\n<li data-start=\"5275\" data-end=\"5318\">\r\n<p data-start=\"5277\" data-end=\"5318\">Providing leave and rest as per the Act</p>\r\n</li>\r\n<li data-start=\"5319\" data-end=\"5383\">\r\n<p data-start=\"5321\" data-end=\"5383\">Ensuring workplace safety, cleanliness, and basic facilities</p>\r\n</li>\r\n<li data-start=\"5384\" data-end=\"5468\">\r\n<p data-start=\"5386\" data-end=\"5468\">Reporting any change in address, employees, or business nature to the department</p>\r\n</li>\r\n<li data-start=\"5469\" data-end=\"5519\">\r\n<p data-start=\"5471\" data-end=\"5519\">Applying for renewal before the license expiry</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5521\" data-end=\"5646\">Failure to comply can attract penalties or cancellation of the registration, which may also impact other statutory approvals.</p>\r\n<hr data-start=\"5648\" data-end=\"5651\">\r\n<p class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 2;\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🧠</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Why Shop &amp; Establishment Registration is Essential</span></strong></p>\r\n<ul data-start=\"5713\" data-end=\"6195\">\r\n<li data-start=\"5713\" data-end=\"5785\">\r\n<p data-start=\"5715\" data-end=\"5785\">Mandatory for every shop or office operating within municipal limits</p>\r\n</li>\r\n<li data-start=\"5786\" data-end=\"5855\">\r\n<p data-start=\"5788\" data-end=\"5855\">Forms the base document for all subsequent business registrations</p>\r\n</li>\r\n<li data-start=\"5856\" data-end=\"5928\">\r\n<p data-start=\"5858\" data-end=\"5928\">Helps maintain lawful employment conditions and workplace discipline</p>\r\n</li>\r\n<li data-start=\"5929\" data-end=\"6002\">\r\n<p data-start=\"5931\" data-end=\"6002\">Creates transparency in business dealings with government authorities</p>\r\n</li>\r\n<li data-start=\"6003\" data-end=\"6082\">\r\n<p data-start=\"6005\" data-end=\"6082\">Serves as proof of business existence for all official and banking purposes</p>\r\n</li>\r\n<li data-start=\"6083\" data-end=\"6148\">\r\n<p data-start=\"6085\" data-end=\"6148\">Enables participation in State and Central government tenders</p>\r\n</li>\r\n<li data-start=\"6149\" data-end=\"6195\">\r\n<p data-start=\"6151\" data-end=\"6195\">Protects both employer and employee rights</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6197\" data-end=\"6200\">\r\n<p class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 2;\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🏢</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Why Choose Rajasthan Filings</span></strong></p>\r\n<ul data-start=\"6240\" data-end=\"6813\">\r\n<li data-start=\"6240\" data-end=\"6312\">\r\n<p data-start=\"6242\" data-end=\"6312\"><strong data-start=\"6242\" data-end=\"6271\">Comprehensive Assistance:</strong> From document preparation to approval.</p>\r\n</li>\r\n<li data-start=\"6313\" data-end=\"6397\">\r\n<p data-start=\"6315\" data-end=\"6397\"><strong data-start=\"6315\" data-end=\"6341\">Professional Drafting:</strong> All declarations and employee data verified by CA/CS.</p>\r\n</li>\r\n<li data-start=\"6398\" data-end=\"6487\">\r\n<p data-start=\"6400\" data-end=\"6487\"><strong data-start=\"6400\" data-end=\"6429\">State-Specific Expertise:</strong> Experience in multiple state labour-department portals.</p>\r\n</li>\r\n<li data-start=\"6488\" data-end=\"6556\">\r\n<p data-start=\"6490\" data-end=\"6556\"><strong data-start=\"6490\" data-end=\"6514\">Transparent Process:</strong> Real-time tracking and document safety.</p>\r\n</li>\r\n<li data-start=\"6557\" data-end=\"6635\">\r\n<p data-start=\"6559\" data-end=\"6635\"><strong data-start=\"6559\" data-end=\"6592\">Renewal &amp; Compliance Support:</strong> Annual reminders and full-cycle service.</p>\r\n</li>\r\n<li data-start=\"6636\" data-end=\"6726\">\r\n<p data-start=\"6638\" data-end=\"6726\"><strong data-start=\"6638\" data-end=\"6663\">Allied Registrations:</strong> Option to add GST, Udyam, FSSAI, and trade licence together.</p>\r\n</li>\r\n<li data-start=\"6727\" data-end=\"6813\">\r\n<p data-start=\"6729\" data-end=\"6813\"><strong data-start=\"6729\" data-end=\"6753\">Nationwide Coverage:</strong> Services available across all major cities and districts.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6815\" data-end=\"6818\">\r\n<p class=\"MsoNormal\" style=\"mso-margin-top-alt: auto; mso-margin-bottom-alt: auto; line-height: normal; mso-outline-level: 2;\"><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; font-family: \'Segoe UI Emoji\',sans-serif; mso-bidi-font-family: \'Segoe UI Emoji\';\">🚀</span></strong><strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; mso-bidi-font-family: Calibri; mso-bidi-theme-font: minor-latin;\"> Start Your Registration with Confidence</span></strong></p>\r\n<p data-start=\"6869\" data-end=\"7147\">Get your Shop &amp; Establishment License registered quickly with <strong data-start=\"6931\" data-end=\"6952\">Rajasthan Filings</strong> &mdash; the trusted partner for complete business compliance solutions.<br data-start=\"7018\" data-end=\"7021\">We ensure accuracy, transparency, and timely delivery so that your business operates smoothly and confidently under the law.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:43:18', '2025-11-07 00:49:09'),
(12, 2, NULL, 'GST Audit & Annual Compliance', 'gst-audit--annual-compliance', 'GST Audit & Annual Compliance', '<h1 data-start=\"86\" data-end=\"132\"><strong data-start=\"88\" data-end=\"132\">GST Audit and Annual Compliance in India</strong></h1>\r\n<p data-start=\"134\" data-end=\"568\">Every registered business under the Goods and Services Tax (GST) regime is required not only to file monthly or quarterly returns but also to ensure proper reconciliation, accuracy, and audit of the data at the end of each financial year. <strong data-start=\"373\" data-end=\"408\">GST audit and annual compliance</strong> are essential mechanisms that ensure the correctness of returns, proper utilization of input-tax credit, and transparency between taxpayers and the government.</p>\r\n<p data-start=\"570\" data-end=\"872\">The purpose of the annual compliance process is to confirm that all outward and inward supplies, tax liabilities, and credits claimed are correctly reported. For entities crossing specific turnover thresholds, GST audit provides an independent verification of records and returns filed during the year.</p>\r\n<hr data-start=\"874\" data-end=\"877\">\r\n<h3 data-start=\"879\" data-end=\"907\"><strong data-start=\"883\" data-end=\"907\">Meaning of GST Audit</strong></h3>\r\n<p data-start=\"909\" data-end=\"1217\">A GST audit is a detailed examination of a taxpayer&rsquo;s books of accounts, returns, and other documents to verify the correctness of turnover declared, taxes paid, refunds claimed, and input-tax credit availed. The audit also ensures that the taxpayer has complied with all provisions of the GST Act and Rules.</p>\r\n<hr data-start=\"1219\" data-end=\"1222\">\r\n<h3 data-start=\"1224\" data-end=\"1252\"><strong data-start=\"1228\" data-end=\"1252\">Statutory Provisions</strong></h3>\r\n<p data-start=\"1254\" data-end=\"1306\">GST audits and annual compliances are governed by:</p>\r\n<ul data-start=\"1307\" data-end=\"1440\">\r\n<li data-start=\"1307\" data-end=\"1401\">\r\n<p data-start=\"1309\" data-end=\"1401\"><strong data-start=\"1309\" data-end=\"1326\">Section 35(5)</strong> and <strong data-start=\"1331\" data-end=\"1345\">Section 44</strong> of the Central Goods and Services Tax (CGST) Act 2017</p>\r\n</li>\r\n<li data-start=\"1402\" data-end=\"1440\">\r\n<p data-start=\"1404\" data-end=\"1440\"><strong data-start=\"1404\" data-end=\"1415\">Rule 80</strong> of the CGST Rules 2017</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1442\" data-end=\"1590\">As per current law, the requirement for audit certification applies to taxpayers whose <strong data-start=\"1529\" data-end=\"1569\">aggregate turnover exceeds ₹ 5 crore</strong> in a financial year.</p>\r\n<hr data-start=\"1592\" data-end=\"1595\">\r\n<h3 data-start=\"1597\" data-end=\"1624\"><strong data-start=\"1601\" data-end=\"1624\">Types of GST Audits</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1626\" data-end=\"2228\">\r\n<thead data-start=\"1626\" data-end=\"1693\">\r\n<tr data-start=\"1626\" data-end=\"1693\">\r\n<th data-start=\"1626\" data-end=\"1637\" data-col-size=\"sm\"><strong data-start=\"1628\" data-end=\"1636\">Type</strong></th>\r\n<th data-start=\"1637\" data-end=\"1656\" data-col-size=\"md\"><strong data-start=\"1639\" data-end=\"1655\">Conducted by</strong></th>\r\n<th data-start=\"1656\" data-end=\"1678\" data-col-size=\"sm\"><strong data-start=\"1658\" data-end=\"1677\">Applicable When</strong></th>\r\n<th data-start=\"1678\" data-end=\"1693\" data-col-size=\"md\"><strong data-start=\"1680\" data-end=\"1691\">Purpose</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1765\" data-end=\"2228\">\r\n<tr data-start=\"1765\" data-end=\"1924\">\r\n<td data-start=\"1765\" data-end=\"1792\" data-col-size=\"sm\"><strong data-start=\"1767\" data-end=\"1791\">Turnover-based audit</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1792\" data-end=\"1855\">Chartered Accountant / Cost Accountant appointed by taxpayer</td>\r\n<td data-col-size=\"sm\" data-start=\"1855\" data-end=\"1878\">Turnover &gt; ₹ 5 crore</td>\r\n<td data-col-size=\"md\" data-start=\"1878\" data-end=\"1924\">Reconciliation and verification of records</td>\r\n</tr>\r\n<tr data-start=\"1925\" data-end=\"2064\">\r\n<td data-start=\"1925\" data-end=\"1950\" data-col-size=\"sm\"><strong data-start=\"1927\" data-end=\"1949\">Departmental audit</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1950\" data-end=\"1987\">Commissioner or authorised officer</td>\r\n<td data-col-size=\"sm\" data-start=\"1987\" data-end=\"2022\">At discretion of tax authorities</td>\r\n<td data-col-size=\"md\" data-start=\"2022\" data-end=\"2064\">Verification of correctness of returns</td>\r\n</tr>\r\n<tr data-start=\"2065\" data-end=\"2228\">\r\n<td data-start=\"2065\" data-end=\"2085\" data-col-size=\"sm\"><strong data-start=\"2067\" data-end=\"2084\">Special audit</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2085\" data-end=\"2134\">Chartered Accountant nominated by Commissioner</td>\r\n<td data-col-size=\"sm\" data-start=\"2134\" data-end=\"2166\">On direction under Section 66</td>\r\n<td data-col-size=\"md\" data-start=\"2166\" data-end=\"2228\">When tax officer suspects misclassification or suppression</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2230\" data-end=\"2233\">\r\n<h3 data-start=\"2235\" data-end=\"2265\"><strong data-start=\"2239\" data-end=\"2265\">Annual Return &ndash; GSTR-9</strong></h3>\r\n<p data-start=\"2267\" data-end=\"2474\">GSTR-9 is the consolidated summary of all monthly or quarterly filings made during the year. It includes details of outward and inward supplies, input-tax credit, taxes paid, and adjustments carried forward.</p>\r\n<p data-start=\"2476\" data-end=\"2719\"><strong data-start=\"2476\" data-end=\"2494\">Applicability:</strong> All regular taxpayers with turnover above ₹ 2 crore.<br data-start=\"2547\" data-end=\"2550\"><strong data-start=\"2550\" data-end=\"2563\">Due Date:</strong> 31 December following the end of the financial year.<br data-start=\"2616\" data-end=\"2619\"><strong data-start=\"2619\" data-end=\"2641\">Penalty for Delay:</strong> ₹ 200 per day (₹ 100 CGST + ₹ 100 SGST) subject to 0.25 % of annual turnover.</p>\r\n<hr data-start=\"2721\" data-end=\"2724\">\r\n<h3 data-start=\"2726\" data-end=\"2768\"><strong data-start=\"2730\" data-end=\"2768\">Reconciliation Statement &ndash; GSTR-9C</strong></h3>\r\n<p data-start=\"2770\" data-end=\"2982\">GSTR-9C is the audit reconciliation statement that aligns data filed in GSTR-9 with the audited financial statements. It includes auditor certification confirming the accuracy of turnover, tax liability, and ITC.</p>\r\n<p data-start=\"2984\" data-end=\"3139\"><strong data-start=\"2984\" data-end=\"3002\">Mandatory for:</strong> Turnover above ₹ 5 crore.<br data-start=\"3028\" data-end=\"3031\"><strong data-start=\"3031\" data-end=\"3043\">Purpose:</strong> To detect differences between GST data and financial books and report any additional liability.</p>\r\n<hr data-start=\"3141\" data-end=\"3144\">\r\n<h3 data-start=\"3146\" data-end=\"3181\"><strong data-start=\"3150\" data-end=\"3181\">Key Components of GST Audit</strong></h3>\r\n<ol data-start=\"3183\" data-end=\"3844\">\r\n<li data-start=\"3183\" data-end=\"3325\">\r\n<p data-start=\"3186\" data-end=\"3325\"><strong data-start=\"3186\" data-end=\"3215\">Verification of Turnover:</strong><br data-start=\"3215\" data-end=\"3218\">Cross-checking sales reported in returns with audited financial statements, e-invoices, and e-way-bills.</p>\r\n</li>\r\n<li data-start=\"3327\" data-end=\"3492\">\r\n<p data-start=\"3330\" data-end=\"3492\"><strong data-start=\"3330\" data-end=\"3366\">Examination of Input-Tax Credit:</strong><br data-start=\"3366\" data-end=\"3369\">Validation of ITC claimed with purchase registers and GSTR-2B, ensuring reversals under Rule 42 / 43 are correctly made.</p>\r\n</li>\r\n<li data-start=\"3494\" data-end=\"3620\">\r\n<p data-start=\"3497\" data-end=\"3620\"><strong data-start=\"3497\" data-end=\"3529\">Tax Payment and Adjustments:</strong><br data-start=\"3529\" data-end=\"3532\">Confirmation that tax liability has been fully discharged through electronic ledgers.</p>\r\n</li>\r\n<li data-start=\"3622\" data-end=\"3734\">\r\n<p data-start=\"3625\" data-end=\"3734\"><strong data-start=\"3625\" data-end=\"3670\">Reconciliation of Taxes Paid and Payable:</strong><br data-start=\"3670\" data-end=\"3673\">Matching monthly returns (GSTR-3B) with annual statements.</p>\r\n</li>\r\n<li data-start=\"3736\" data-end=\"3844\">\r\n<p data-start=\"3739\" data-end=\"3844\"><strong data-start=\"3739\" data-end=\"3779\">Reporting of Additional Liabilities:</strong><br data-start=\"3779\" data-end=\"3782\">Declaration and payment of any shortfall using Form DRC-03.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3846\" data-end=\"3849\">\r\n<h3 data-start=\"3851\" data-end=\"3891\"><strong data-start=\"3855\" data-end=\"3891\">Documents Required for GST Audit</strong></h3>\r\n<ul data-start=\"3893\" data-end=\"4283\">\r\n<li data-start=\"3893\" data-end=\"3925\">\r\n<p data-start=\"3895\" data-end=\"3925\">GST registration certificate</p>\r\n</li>\r\n<li data-start=\"3926\" data-end=\"3970\">\r\n<p data-start=\"3928\" data-end=\"3970\">GSTR-1, GSTR-3B, and GSTR-9 for the year</p>\r\n</li>\r\n<li data-start=\"3971\" data-end=\"4003\">\r\n<p data-start=\"3973\" data-end=\"4003\">Audited financial statements</p>\r\n</li>\r\n<li data-start=\"4004\" data-end=\"4040\">\r\n<p data-start=\"4006\" data-end=\"4040\">Trial balance and general ledger</p>\r\n</li>\r\n<li data-start=\"4041\" data-end=\"4073\">\r\n<p data-start=\"4043\" data-end=\"4073\">Purchase and sales registers</p>\r\n</li>\r\n<li data-start=\"4074\" data-end=\"4120\">\r\n<p data-start=\"4076\" data-end=\"4120\">Input-tax credit computation and reversals</p>\r\n</li>\r\n<li data-start=\"4121\" data-end=\"4145\">\r\n<p data-start=\"4123\" data-end=\"4145\">E-way bill summaries</p>\r\n</li>\r\n<li data-start=\"4146\" data-end=\"4184\">\r\n<p data-start=\"4148\" data-end=\"4184\">Bank statements and payment proofs</p>\r\n</li>\r\n<li data-start=\"4185\" data-end=\"4227\">\r\n<p data-start=\"4187\" data-end=\"4227\">Expense schedules with tax segregation</p>\r\n</li>\r\n<li data-start=\"4228\" data-end=\"4283\">\r\n<p data-start=\"4230\" data-end=\"4283\">Reconciliation statements between books and returns</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4285\" data-end=\"4288\">\r\n<h3 data-start=\"4290\" data-end=\"4343\"><strong data-start=\"4294\" data-end=\"4343\">Procedure for GST Audit and Annual Compliance</strong></h3>\r\n<ol data-start=\"4345\" data-end=\"4966\">\r\n<li data-start=\"4345\" data-end=\"4426\">\r\n<p data-start=\"4348\" data-end=\"4426\"><strong data-start=\"4348\" data-end=\"4369\">Pre-Audit Review:</strong> Collect all GST returns, ledgers, and reconciliations.</p>\r\n</li>\r\n<li data-start=\"4427\" data-end=\"4522\">\r\n<p data-start=\"4430\" data-end=\"4522\"><strong data-start=\"4430\" data-end=\"4452\">Data Verification:</strong> Compare turnover and ITC between GST returns and books of accounts.</p>\r\n</li>\r\n<li data-start=\"4523\" data-end=\"4614\">\r\n<p data-start=\"4526\" data-end=\"4614\"><strong data-start=\"4526\" data-end=\"4550\">Audit Documentation:</strong> Prepare audit working papers for outward and inward supplies.</p>\r\n</li>\r\n<li data-start=\"4615\" data-end=\"4706\">\r\n<p data-start=\"4618\" data-end=\"4706\"><strong data-start=\"4618\" data-end=\"4659\">Reconciliation Statement Preparation:</strong> Draft GSTR-9C linking financials and GSTR-9.</p>\r\n</li>\r\n<li data-start=\"4707\" data-end=\"4793\">\r\n<p data-start=\"4710\" data-end=\"4793\"><strong data-start=\"4710\" data-end=\"4736\">Auditor Certification:</strong> Obtain certification from Chartered / Cost Accountant.</p>\r\n</li>\r\n<li data-start=\"4794\" data-end=\"4879\">\r\n<p data-start=\"4797\" data-end=\"4879\"><strong data-start=\"4797\" data-end=\"4826\">Submission to GST Portal:</strong> File both GSTR-9 and GSTR-9C online using DSC/EVC.</p>\r\n</li>\r\n<li data-start=\"4880\" data-end=\"4966\">\r\n<p data-start=\"4883\" data-end=\"4966\"><strong data-start=\"4883\" data-end=\"4912\">Payment of Discrepancies:</strong> Deposit any short tax through DRC-03 before filing.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"4968\" data-end=\"4971\">\r\n<h3 data-start=\"4973\" data-end=\"5016\"><strong data-start=\"4977\" data-end=\"5016\">Importance of GST Annual Compliance</strong></h3>\r\n<ul data-start=\"5018\" data-end=\"5283\">\r\n<li data-start=\"5018\" data-end=\"5071\">\r\n<p data-start=\"5020\" data-end=\"5071\">Ensures data consistency across returns and books</p>\r\n</li>\r\n<li data-start=\"5072\" data-end=\"5134\">\r\n<p data-start=\"5074\" data-end=\"5134\">Prevents future demand notices or audits by the department</p>\r\n</li>\r\n<li data-start=\"5135\" data-end=\"5187\">\r\n<p data-start=\"5137\" data-end=\"5187\">Enhances creditworthiness for banks and partners</p>\r\n</li>\r\n<li data-start=\"5188\" data-end=\"5226\">\r\n<p data-start=\"5190\" data-end=\"5226\">Identifies unclaimed or excess ITC</p>\r\n</li>\r\n<li data-start=\"5227\" data-end=\"5283\">\r\n<p data-start=\"5229\" data-end=\"5283\">Builds long-term credibility as a compliant taxpayer</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5285\" data-end=\"5288\">\r\n<h3 data-start=\"5290\" data-end=\"5328\"><strong data-start=\"5294\" data-end=\"5328\">Consequences of Non-Compliance</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5330\" data-end=\"5728\">\r\n<thead data-start=\"5330\" data-end=\"5384\">\r\n<tr data-start=\"5330\" data-end=\"5384\">\r\n<th data-start=\"5330\" data-end=\"5351\" data-col-size=\"sm\"><strong data-start=\"5332\" data-end=\"5350\">Non-Compliance</strong></th>\r\n<th data-start=\"5351\" data-end=\"5384\" data-col-size=\"md\"><strong data-start=\"5353\" data-end=\"5382\">Possible Action / Penalty</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5441\" data-end=\"5728\">\r\n<tr data-start=\"5441\" data-end=\"5520\">\r\n<td data-start=\"5441\" data-end=\"5469\" data-col-size=\"sm\">Non-filing of GSTR-9 / 9C</td>\r\n<td data-start=\"5469\" data-end=\"5520\" data-col-size=\"md\">Late fee ₹ 200 per day up to 0.25 % of turnover</td>\r\n</tr>\r\n<tr data-start=\"5521\" data-end=\"5591\">\r\n<td data-start=\"5521\" data-end=\"5552\" data-col-size=\"sm\">Under-reporting of liability</td>\r\n<td data-col-size=\"md\" data-start=\"5552\" data-end=\"5591\">Demand notice under Section 73 / 74</td>\r\n</tr>\r\n<tr data-start=\"5592\" data-end=\"5659\">\r\n<td data-start=\"5592\" data-end=\"5622\" data-col-size=\"sm\">Mismatch in ITC or turnover</td>\r\n<td data-start=\"5622\" data-end=\"5659\" data-col-size=\"md\">Scrutiny and interest @ 18 % p.a.</td>\r\n</tr>\r\n<tr data-start=\"5660\" data-end=\"5728\">\r\n<td data-start=\"5660\" data-end=\"5691\" data-col-size=\"sm\">Non-cooperation during audit</td>\r\n<td data-start=\"5691\" data-end=\"5728\" data-col-size=\"md\">Assessment based on best judgment</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"5730\" data-end=\"5733\">\r\n<h3 data-start=\"5735\" data-end=\"5766\"><strong data-start=\"5739\" data-end=\"5766\">Checklist for Taxpayers</strong></h3>\r\n<ul data-start=\"5768\" data-end=\"6108\">\r\n<li data-start=\"5768\" data-end=\"5833\">\r\n<p data-start=\"5770\" data-end=\"5833\">Verify reconciliation between GSTR-1, GSTR-3B, and financials</p>\r\n</li>\r\n<li data-start=\"5834\" data-end=\"5891\">\r\n<p data-start=\"5836\" data-end=\"5891\">Ensure ITC claimed is supported by valid tax invoices</p>\r\n</li>\r\n<li data-start=\"5892\" data-end=\"5943\">\r\n<p data-start=\"5894\" data-end=\"5943\">Cross-check e-way-bill data with sales register</p>\r\n</li>\r\n<li data-start=\"5944\" data-end=\"5984\">\r\n<p data-start=\"5946\" data-end=\"5984\">Report credit/debit notes accurately</p>\r\n</li>\r\n<li data-start=\"5985\" data-end=\"6032\">\r\n<p data-start=\"5987\" data-end=\"6032\">Reverse ineligible ITC before filing GSTR-9</p>\r\n</li>\r\n<li data-start=\"6033\" data-end=\"6108\">\r\n<p data-start=\"6035\" data-end=\"6108\">Retain all invoices and records for <strong data-start=\"6071\" data-end=\"6084\">72 months</strong> as required under law</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6110\" data-end=\"6113\">\r\n<h3 data-start=\"6115\" data-end=\"6139\"><strong data-start=\"6119\" data-end=\"6139\">Due-Date Summary</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6141\" data-end=\"6433\">\r\n<thead data-start=\"6141\" data-end=\"6182\">\r\n<tr data-start=\"6141\" data-end=\"6182\">\r\n<th data-start=\"6141\" data-end=\"6152\" data-col-size=\"sm\"><strong data-start=\"6143\" data-end=\"6151\">Form</strong></th>\r\n<th data-start=\"6152\" data-end=\"6166\" data-col-size=\"sm\"><strong data-start=\"6154\" data-end=\"6165\">Purpose</strong></th>\r\n<th data-start=\"6166\" data-end=\"6182\" data-col-size=\"sm\"><strong data-start=\"6168\" data-end=\"6180\">Due Date</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6226\" data-end=\"6433\">\r\n<tr data-start=\"6226\" data-end=\"6283\">\r\n<td data-start=\"6226\" data-end=\"6239\" data-col-size=\"sm\"><strong data-start=\"6228\" data-end=\"6238\">GSTR-9</strong></td>\r\n<td data-start=\"6239\" data-end=\"6255\" data-col-size=\"sm\">Annual Return</td>\r\n<td data-start=\"6255\" data-end=\"6283\" data-col-size=\"sm\">31 December following FY</td>\r\n</tr>\r\n<tr data-start=\"6284\" data-end=\"6361\">\r\n<td data-start=\"6284\" data-end=\"6298\" data-col-size=\"sm\"><strong data-start=\"6286\" data-end=\"6297\">GSTR-9C</strong></td>\r\n<td data-start=\"6298\" data-end=\"6333\" data-col-size=\"sm\">Reconciliation Statement / Audit</td>\r\n<td data-col-size=\"sm\" data-start=\"6333\" data-end=\"6361\">31 December following FY</td>\r\n</tr>\r\n<tr data-start=\"6362\" data-end=\"6433\">\r\n<td data-start=\"6362\" data-end=\"6375\" data-col-size=\"sm\"><strong data-start=\"6364\" data-end=\"6374\">DRC-03</strong></td>\r\n<td data-start=\"6375\" data-end=\"6409\" data-col-size=\"sm\">Additional tax payment (if any)</td>\r\n<td data-col-size=\"sm\" data-start=\"6409\" data-end=\"6433\">Before filing 9 / 9C</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"6435\" data-end=\"6438\">\r\n<h3 data-start=\"6440\" data-end=\"6479\"><strong data-start=\"6444\" data-end=\"6479\">Best Practices for Smooth Audit</strong></h3>\r\n<ul data-start=\"6481\" data-end=\"6745\">\r\n<li data-start=\"6481\" data-end=\"6538\">\r\n<p data-start=\"6483\" data-end=\"6538\">Maintain consistent naming and numbering in invoices.</p>\r\n</li>\r\n<li data-start=\"6539\" data-end=\"6577\">\r\n<p data-start=\"6541\" data-end=\"6577\">Update HSN and SAC codes properly.</p>\r\n</li>\r\n<li data-start=\"6578\" data-end=\"6624\">\r\n<p data-start=\"6580\" data-end=\"6624\">Keep proof of export and SEZ transactions.</p>\r\n</li>\r\n<li data-start=\"6625\" data-end=\"6682\">\r\n<p data-start=\"6627\" data-end=\"6682\">Track ITC on capital goods and reverse when required.</p>\r\n</li>\r\n<li data-start=\"6683\" data-end=\"6745\">\r\n<p data-start=\"6685\" data-end=\"6745\">Reconcile advances, credit notes, and adjustments monthly.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6747\" data-end=\"6750\">\r\n<h3 data-start=\"6752\" data-end=\"6791\"><strong data-start=\"6756\" data-end=\"6791\">Role of Professional Assistance</strong></h3>\r\n<p data-start=\"6793\" data-end=\"6859\">A qualified GST consultant or Chartered Accountant ensures that:</p>\r\n<ul data-start=\"6860\" data-end=\"7064\">\r\n<li data-start=\"6860\" data-end=\"6912\">\r\n<p data-start=\"6862\" data-end=\"6912\">All filings are accurate and compliant with law.</p>\r\n</li>\r\n<li data-start=\"6913\" data-end=\"6964\">\r\n<p data-start=\"6915\" data-end=\"6964\">Reconciliations are performed without variance.</p>\r\n</li>\r\n<li data-start=\"6965\" data-end=\"7010\">\r\n<p data-start=\"6967\" data-end=\"7010\">Audit queries are handled professionally.</p>\r\n</li>\r\n<li data-start=\"7011\" data-end=\"7064\">\r\n<p data-start=\"7013\" data-end=\"7064\">Documentation is maintained for future reference.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"7066\" data-end=\"7158\">Professional assistance minimises risk and provides confidence during departmental scrutiny.</p>\r\n<hr data-start=\"7160\" data-end=\"7163\">\r\n<h3 data-start=\"7165\" data-end=\"7201\"><strong data-start=\"7169\" data-end=\"7201\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"7203\" data-end=\"7547\">\r\n<li data-start=\"7203\" data-end=\"7276\">\r\n<p data-start=\"7205\" data-end=\"7276\">Expertise in GST audits and annual reconciliations across industries.</p>\r\n</li>\r\n<li data-start=\"7277\" data-end=\"7344\">\r\n<p data-start=\"7279\" data-end=\"7344\">End-to-end assistance &mdash; from data preparation to portal filing.</p>\r\n</li>\r\n<li data-start=\"7345\" data-end=\"7412\">\r\n<p data-start=\"7347\" data-end=\"7412\">Detailed verification of turnover, ITC, and compliance records.</p>\r\n</li>\r\n<li data-start=\"7413\" data-end=\"7478\">\r\n<p data-start=\"7415\" data-end=\"7478\">Transparent processes and timely completion before due dates.</p>\r\n</li>\r\n<li data-start=\"7479\" data-end=\"7547\">\r\n<p data-start=\"7481\" data-end=\"7547\">Advisory support for notices, refunds, and litigation follow-up.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"7549\" data-end=\"7729\">Rajasthan Filings ensures that every client meets the highest standards of GST compliance, reducing exposure to interest and penalties while maintaining flawless statutory records.</p>\r\n<hr data-start=\"7731\" data-end=\"7734\">\r\n<h3 data-start=\"7736\" data-end=\"7754\"><strong data-start=\"7740\" data-end=\"7754\">Conclusion</strong></h3>\r\n<p data-start=\"7756\" data-end=\"8106\">GST Audit and Annual Compliance represent the final stage of each financial year&rsquo;s GST journey. They validate the integrity of every return filed and ensure harmony between financial statements and tax data.<br data-start=\"7963\" data-end=\"7966\">Accurate and timely compliance not only fulfils a legal duty but also enhances business credibility, financial hygiene, and trustworthiness.</p>\r\n<p data-start=\"8108\" data-end=\"8303\">For seamless GST audits, reconciliations, and annual compliance support across India,<br data-start=\"8193\" data-end=\"8196\"><strong data-start=\"8196\" data-end=\"8217\">Rajasthan Filings</strong> provides professional expertise backed by accuracy, transparency, and accountability.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:49:09', '2025-11-07 00:49:11');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(13, 2, NULL, 'E-Invoicing & E-Way Bill Solutions', 'e-invoicing--e-way-bill-solutions', 'E-Invoicing & E-Way Bill Solutions', '<h1 data-start=\"86\" data-end=\"137\"><strong data-start=\"88\" data-end=\"137\">E-Invoicing and E-Way Bill Solutions in India</strong></h1>\r\n<p data-start=\"139\" data-end=\"393\">The Indian Goods and Services Tax (GST) system is designed around technology-driven compliance. Two of its most significant reforms &mdash; <strong data-start=\"273\" data-end=\"288\">E-Invoicing</strong> and <strong data-start=\"293\" data-end=\"307\">E-Way Bill</strong> &mdash; have transformed how businesses record, report, and transport goods and services.</p>\r\n<p data-start=\"395\" data-end=\"714\">Both mechanisms aim to create transparency, reduce tax evasion, and automate data reporting directly to the government portal. <strong data-start=\"522\" data-end=\"543\">Rajasthan Filings</strong> assists businesses of all sizes in implementing e-invoicing and e-way bill solutions, ensuring seamless integration and 100% compliance with the latest GST regulations.</p>\r\n<hr data-start=\"716\" data-end=\"719\">\r\n<h3 data-start=\"721\" data-end=\"749\"><strong data-start=\"725\" data-end=\"749\">What Is E-Invoicing?</strong></h3>\r\n<p data-start=\"751\" data-end=\"1062\"><strong data-start=\"751\" data-end=\"789\">E-Invoicing (Electronic Invoicing)</strong> refers to the system under which all B2B and export invoices are authenticated electronically by the GST Network (GSTN). Each invoice is assigned a unique <strong data-start=\"945\" data-end=\"979\">Invoice Reference Number (IRN)</strong> and a <strong data-start=\"986\" data-end=\"997\">QR code</strong> after validation from the <strong data-start=\"1024\" data-end=\"1061\">Invoice Registration Portal (IRP)</strong>.</p>\r\n<p data-start=\"1064\" data-end=\"1199\">The e-invoice replaces traditional paper or manually uploaded invoices, ensuring real-time data flow to the GST and e-way bill systems.</p>\r\n<hr data-start=\"1201\" data-end=\"1204\">\r\n<h3 data-start=\"1206\" data-end=\"1239\"><strong data-start=\"1210\" data-end=\"1239\">Objectives of E-Invoicing</strong></h3>\r\n<ol data-start=\"1241\" data-end=\"1610\">\r\n<li data-start=\"1241\" data-end=\"1314\">\r\n<p data-start=\"1244\" data-end=\"1314\"><strong data-start=\"1244\" data-end=\"1261\">Authenticity:</strong> Prevents fake invoicing and fraudulent ITC claims.</p>\r\n</li>\r\n<li data-start=\"1315\" data-end=\"1374\">\r\n<p data-start=\"1318\" data-end=\"1374\"><strong data-start=\"1318\" data-end=\"1333\">Automation:</strong> Auto-populates GSTR-1 and e-way bills.</p>\r\n</li>\r\n<li data-start=\"1375\" data-end=\"1442\">\r\n<p data-start=\"1378\" data-end=\"1442\"><strong data-start=\"1378\" data-end=\"1398\">Standardization:</strong> Uniform invoice format for all taxpayers.</p>\r\n</li>\r\n<li data-start=\"1443\" data-end=\"1542\">\r\n<p data-start=\"1446\" data-end=\"1542\"><strong data-start=\"1446\" data-end=\"1462\">Integration:</strong> Real-time synchronization between suppliers, recipients, and tax authorities.</p>\r\n</li>\r\n<li data-start=\"1543\" data-end=\"1610\">\r\n<p data-start=\"1546\" data-end=\"1610\"><strong data-start=\"1546\" data-end=\"1563\">Transparency:</strong> Reduces audit queries and compliance disputes.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"1612\" data-end=\"1615\">\r\n<h3 data-start=\"1617\" data-end=\"1653\"><strong data-start=\"1621\" data-end=\"1653\">Applicability of E-Invoicing</strong></h3>\r\n<p data-start=\"1655\" data-end=\"1726\">The government has implemented e-invoicing in phases based on turnover:</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1728\" data-end=\"2033\">\r\n<thead data-start=\"1728\" data-end=\"1771\">\r\n<tr data-start=\"1728\" data-end=\"1771\">\r\n<th data-start=\"1728\" data-end=\"1749\" data-col-size=\"sm\"><strong data-start=\"1730\" data-end=\"1748\">Turnover Limit</strong></th>\r\n<th data-start=\"1749\" data-end=\"1771\" data-col-size=\"sm\"><strong data-start=\"1751\" data-end=\"1769\">Effective Date</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1816\" data-end=\"2033\">\r\n<tr data-start=\"1816\" data-end=\"1853\">\r\n<td data-start=\"1816\" data-end=\"1835\" data-col-size=\"sm\">Above ₹500 crore</td>\r\n<td data-col-size=\"sm\" data-start=\"1835\" data-end=\"1853\">1 October 2020</td>\r\n</tr>\r\n<tr data-start=\"1854\" data-end=\"1891\">\r\n<td data-start=\"1854\" data-end=\"1873\" data-col-size=\"sm\">Above ₹100 crore</td>\r\n<td data-col-size=\"sm\" data-start=\"1873\" data-end=\"1891\">1 January 2021</td>\r\n</tr>\r\n<tr data-start=\"1892\" data-end=\"1926\">\r\n<td data-start=\"1892\" data-end=\"1910\" data-col-size=\"sm\">Above ₹50 crore</td>\r\n<td data-col-size=\"sm\" data-start=\"1910\" data-end=\"1926\">1 April 2021</td>\r\n</tr>\r\n<tr data-start=\"1927\" data-end=\"1961\">\r\n<td data-start=\"1927\" data-end=\"1945\" data-col-size=\"sm\">Above ₹20 crore</td>\r\n<td data-start=\"1945\" data-end=\"1961\" data-col-size=\"sm\">1 April 2022</td>\r\n</tr>\r\n<tr data-start=\"1962\" data-end=\"1998\">\r\n<td data-start=\"1962\" data-end=\"1980\" data-col-size=\"sm\">Above ₹10 crore</td>\r\n<td data-col-size=\"sm\" data-start=\"1980\" data-end=\"1998\">1 October 2022</td>\r\n</tr>\r\n<tr data-start=\"1999\" data-end=\"2033\">\r\n<td data-start=\"1999\" data-end=\"2016\" data-col-size=\"sm\">Above ₹5 crore</td>\r\n<td data-col-size=\"sm\" data-start=\"2016\" data-end=\"2033\">1 August 2023</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"2035\" data-end=\"2197\">Any taxpayer whose <strong data-start=\"2054\" data-end=\"2093\">aggregate turnover exceeds ₹5 crore</strong> in any financial year (from 2017&ndash;18 onwards) must issue e-invoices for all B2B and export transactions.</p>\r\n<hr data-start=\"2199\" data-end=\"2202\">\r\n<h3 data-start=\"2204\" data-end=\"2233\"><strong data-start=\"2208\" data-end=\"2233\">How E-Invoicing Works</strong></h3>\r\n<ol data-start=\"2235\" data-end=\"2700\">\r\n<li data-start=\"2235\" data-end=\"2336\">\r\n<p data-start=\"2238\" data-end=\"2336\"><strong data-start=\"2238\" data-end=\"2261\">Invoice Generation:</strong> The seller creates the invoice in the government-prescribed JSON format.</p>\r\n</li>\r\n<li data-start=\"2337\" data-end=\"2420\">\r\n<p data-start=\"2340\" data-end=\"2420\"><strong data-start=\"2340\" data-end=\"2358\">Upload to IRP:</strong> The invoice is uploaded to the Invoice Registration Portal.</p>\r\n</li>\r\n<li data-start=\"2421\" data-end=\"2515\">\r\n<p data-start=\"2424\" data-end=\"2515\"><strong data-start=\"2424\" data-end=\"2443\">Authentication:</strong> IRP validates details and generates a <strong data-start=\"2482\" data-end=\"2496\">unique IRN</strong> and <strong data-start=\"2501\" data-end=\"2512\">QR code</strong>.</p>\r\n</li>\r\n<li data-start=\"2516\" data-end=\"2609\">\r\n<p data-start=\"2519\" data-end=\"2609\"><strong data-start=\"2519\" data-end=\"2542\">Return Integration:</strong> The validated e-invoice automatically updates the GSTR-1 return.</p>\r\n</li>\r\n<li data-start=\"2610\" data-end=\"2700\">\r\n<p data-start=\"2613\" data-end=\"2700\"><strong data-start=\"2613\" data-end=\"2636\">Sharing with Buyer:</strong> The seller prints or emails the invoice containing the QR code.</p>\r\n</li>\r\n</ol>\r\n<p data-start=\"2702\" data-end=\"2804\">This system eliminates manual data entry and reduces chances of mismatch between invoices and returns.</p>\r\n<hr data-start=\"2806\" data-end=\"2809\">\r\n<h3 data-start=\"2811\" data-end=\"2842\"><strong data-start=\"2815\" data-end=\"2842\">Benefits of E-Invoicing</strong></h3>\r\n<ul data-start=\"2844\" data-end=\"3122\">\r\n<li data-start=\"2844\" data-end=\"2883\">\r\n<p data-start=\"2846\" data-end=\"2883\">Real-time invoice reporting to GSTN</p>\r\n</li>\r\n<li data-start=\"2884\" data-end=\"2933\">\r\n<p data-start=\"2886\" data-end=\"2933\">Automatic generation of GSTR-1 and e-way bill</p>\r\n</li>\r\n<li data-start=\"2934\" data-end=\"2976\">\r\n<p data-start=\"2936\" data-end=\"2976\">Reduction in input-tax credit disputes</p>\r\n</li>\r\n<li data-start=\"2977\" data-end=\"3024\">\r\n<p data-start=\"2979\" data-end=\"3024\">Fraud prevention through digital validation</p>\r\n</li>\r\n<li data-start=\"3025\" data-end=\"3071\">\r\n<p data-start=\"3027\" data-end=\"3071\">Streamlined accounting and audit readiness</p>\r\n</li>\r\n<li data-start=\"3072\" data-end=\"3122\">\r\n<p data-start=\"3074\" data-end=\"3122\">Greater trust between suppliers and recipients</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3124\" data-end=\"3127\">\r\n<h3 data-start=\"3129\" data-end=\"3169\"><strong data-start=\"3133\" data-end=\"3169\">E-Invoicing for B2C Transactions</strong></h3>\r\n<p data-start=\"3171\" data-end=\"3409\">Currently, e-invoicing is <strong data-start=\"3197\" data-end=\"3222\">not mandatory for B2C</strong> (Business-to-Consumer) transactions.<br data-start=\"3259\" data-end=\"3262\">However, taxpayers must print a <strong data-start=\"3294\" data-end=\"3313\">dynamic QR code</strong> on such invoices if turnover exceeds ₹500 crore, enabling digital payments and record tracking.</p>\r\n<hr data-start=\"3411\" data-end=\"3414\">\r\n<h3 data-start=\"3416\" data-end=\"3446\"><strong data-start=\"3420\" data-end=\"3446\">What Is an E-Way Bill?</strong></h3>\r\n<p data-start=\"3448\" data-end=\"3657\">An <strong data-start=\"3451\" data-end=\"3487\">E-Way Bill (Electronic Way Bill)</strong> is a document generated online for the movement of goods worth more than ₹50,000 within or outside a state. It serves as proof of valid transportation under the GST law.</p>\r\n<p data-start=\"3659\" data-end=\"3782\">E-way bills ensure that every consignment is traceable and legitimate, minimizing tax evasion during the movement of goods.</p>\r\n<hr data-start=\"3784\" data-end=\"3787\">\r\n<h3 data-start=\"3789\" data-end=\"3828\"><strong data-start=\"3793\" data-end=\"3828\">When Is an E-Way Bill Required?</strong></h3>\r\n<p data-start=\"3830\" data-end=\"3891\">An e-way bill must be generated before the movement of goods:</p>\r\n<ul data-start=\"3893\" data-end=\"4122\">\r\n<li data-start=\"3893\" data-end=\"3954\">\r\n<p data-start=\"3895\" data-end=\"3954\">When goods are transported for supply, sale, or transfer.</p>\r\n</li>\r\n<li data-start=\"3955\" data-end=\"3992\">\r\n<p data-start=\"3957\" data-end=\"3992\">For job work or branch transfers.</p>\r\n</li>\r\n<li data-start=\"3993\" data-end=\"4028\">\r\n<p data-start=\"3995\" data-end=\"4028\">For import/export transactions.</p>\r\n</li>\r\n<li data-start=\"4029\" data-end=\"4077\">\r\n<p data-start=\"4031\" data-end=\"4077\">When goods are returned or sent for repairs.</p>\r\n</li>\r\n<li data-start=\"4078\" data-end=\"4122\">\r\n<p data-start=\"4080\" data-end=\"4122\">When the value of goods exceeds ₹50,000.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4124\" data-end=\"4127\">\r\n<h3 data-start=\"4129\" data-end=\"4186\"><strong data-start=\"4133\" data-end=\"4186\">Who Is Responsible for Generating the E-Way Bill?</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4188\" data-end=\"4496\">\r\n<thead data-start=\"4188\" data-end=\"4225\">\r\n<tr data-start=\"4188\" data-end=\"4225\">\r\n<th data-start=\"4188\" data-end=\"4204\" data-col-size=\"md\"><strong data-start=\"4190\" data-end=\"4203\">Situation</strong></th>\r\n<th data-start=\"4204\" data-end=\"4225\" data-col-size=\"sm\"><strong data-start=\"4206\" data-end=\"4223\">Person Liable</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4264\" data-end=\"4496\">\r\n<tr data-start=\"4264\" data-end=\"4315\">\r\n<td data-start=\"4264\" data-end=\"4303\" data-col-size=\"md\">Supply of goods by registered dealer</td>\r\n<td data-col-size=\"sm\" data-start=\"4303\" data-end=\"4315\">Supplier</td>\r\n</tr>\r\n<tr data-start=\"4316\" data-end=\"4377\">\r\n<td data-start=\"4316\" data-end=\"4368\" data-col-size=\"md\">Supply by unregistered dealer to registered buyer</td>\r\n<td data-col-size=\"sm\" data-start=\"4368\" data-end=\"4377\">Buyer</td>\r\n</tr>\r\n<tr data-start=\"4378\" data-end=\"4439\">\r\n<td data-start=\"4378\" data-end=\"4424\" data-col-size=\"md\">Transport by road (third-party transporter)</td>\r\n<td data-col-size=\"sm\" data-start=\"4424\" data-end=\"4439\">Transporter</td>\r\n</tr>\r\n<tr data-start=\"4440\" data-end=\"4496\">\r\n<td data-start=\"4440\" data-end=\"4470\" data-col-size=\"md\">Own vehicle / hired vehicle</td>\r\n<td data-col-size=\"sm\" data-start=\"4470\" data-end=\"4496\">Consignor or consignee</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4498\" data-end=\"4501\">\r\n<h3 data-start=\"4503\" data-end=\"4533\"><strong data-start=\"4507\" data-end=\"4533\">Validity of E-Way Bill</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4535\" data-end=\"4724\">\r\n<thead data-start=\"4535\" data-end=\"4573\">\r\n<tr data-start=\"4535\" data-end=\"4573\">\r\n<th data-start=\"4535\" data-end=\"4550\" data-col-size=\"sm\"><strong data-start=\"4537\" data-end=\"4549\">Distance</strong></th>\r\n<th data-start=\"4550\" data-end=\"4573\" data-col-size=\"sm\"><strong data-start=\"4552\" data-end=\"4571\">Validity Period</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4614\" data-end=\"4724\">\r\n<tr data-start=\"4614\" data-end=\"4638\">\r\n<td data-start=\"4614\" data-end=\"4629\" data-col-size=\"sm\">Up to 100 km</td>\r\n<td data-col-size=\"sm\" data-start=\"4629\" data-end=\"4638\">1 day</td>\r\n</tr>\r\n<tr data-start=\"4639\" data-end=\"4679\">\r\n<td data-start=\"4639\" data-end=\"4669\" data-col-size=\"sm\">For every additional 100 km</td>\r\n<td data-col-size=\"sm\" data-start=\"4669\" data-end=\"4679\">+1 day</td>\r\n</tr>\r\n<tr data-start=\"4680\" data-end=\"4724\">\r\n<td data-start=\"4680\" data-end=\"4705\" data-col-size=\"sm\">Over-dimensional cargo</td>\r\n<td data-col-size=\"sm\" data-start=\"4705\" data-end=\"4724\">1 day per 20 km</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"4726\" data-end=\"4833\">The validity can be extended before expiry in exceptional cases like vehicle breakdown or natural calamity.</p>\r\n<hr data-start=\"4835\" data-end=\"4838\">\r\n<h3 data-start=\"4840\" data-end=\"4876\"><strong data-start=\"4844\" data-end=\"4876\">Key Components of E-Way Bill</strong></h3>\r\n<ul data-start=\"4878\" data-end=\"5100\">\r\n<li data-start=\"4878\" data-end=\"4913\">\r\n<p data-start=\"4880\" data-end=\"4913\">GSTIN of supplier and recipient</p>\r\n</li>\r\n<li data-start=\"4914\" data-end=\"4941\">\r\n<p data-start=\"4916\" data-end=\"4941\">Invoice number and date</p>\r\n</li>\r\n<li data-start=\"4942\" data-end=\"4960\">\r\n<p data-start=\"4944\" data-end=\"4960\">Value of goods</p>\r\n</li>\r\n<li data-start=\"4961\" data-end=\"4986\">\r\n<p data-start=\"4963\" data-end=\"4986\">HSN code and tax rate</p>\r\n</li>\r\n<li data-start=\"4987\" data-end=\"5024\">\r\n<p data-start=\"4989\" data-end=\"5024\">Quantity and description of goods</p>\r\n</li>\r\n<li data-start=\"5025\" data-end=\"5065\">\r\n<p data-start=\"5027\" data-end=\"5065\">Vehicle number and mode of transport</p>\r\n</li>\r\n<li data-start=\"5066\" data-end=\"5100\">\r\n<p data-start=\"5068\" data-end=\"5100\">Place of dispatch and delivery</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5102\" data-end=\"5105\">\r\n<h3 data-start=\"5107\" data-end=\"5153\"><strong data-start=\"5111\" data-end=\"5153\">E-Invoicing and E-Way Bill Integration</strong></h3>\r\n<p data-start=\"5155\" data-end=\"5356\">The government has seamlessly integrated both systems. Once an <strong data-start=\"5218\" data-end=\"5244\">e-invoice is generated</strong>, the <strong data-start=\"5250\" data-end=\"5264\">e-way bill</strong> can be automatically created using the same data &mdash; eliminating duplication and saving time.</p>\r\n<p data-start=\"5358\" data-end=\"5476\">This integration ensures that invoice authenticity, transport documentation, and tax compliance happen simultaneously.</p>\r\n<hr data-start=\"5478\" data-end=\"5481\">\r\n<h3 data-start=\"5483\" data-end=\"5519\"><strong data-start=\"5487\" data-end=\"5519\">Penalties for Non-Compliance</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"5521\" data-end=\"5910\">\r\n<thead data-start=\"5521\" data-end=\"5566\">\r\n<tr data-start=\"5521\" data-end=\"5566\">\r\n<th data-start=\"5521\" data-end=\"5537\" data-col-size=\"sm\"><strong data-start=\"5523\" data-end=\"5536\">Violation</strong></th>\r\n<th data-start=\"5537\" data-end=\"5566\" data-col-size=\"md\"><strong data-start=\"5539\" data-end=\"5564\">Penalty / Consequence</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"5614\" data-end=\"5910\">\r\n<tr data-start=\"5614\" data-end=\"5695\">\r\n<td data-start=\"5614\" data-end=\"5643\" data-col-size=\"sm\">Failure to issue e-invoice</td>\r\n<td data-col-size=\"md\" data-start=\"5643\" data-end=\"5695\">₹10,000 or 100% of tax due (whichever is higher)</td>\r\n</tr>\r\n<tr data-start=\"5696\" data-end=\"5774\">\r\n<td data-start=\"5696\" data-end=\"5727\" data-col-size=\"sm\">Transport without e-way bill</td>\r\n<td data-col-size=\"md\" data-start=\"5727\" data-end=\"5774\">₹10,000 or tax amount (whichever is higher)</td>\r\n</tr>\r\n<tr data-start=\"5775\" data-end=\"5830\">\r\n<td data-start=\"5775\" data-end=\"5796\" data-col-size=\"sm\">Goods confiscation</td>\r\n<td data-col-size=\"md\" data-start=\"5796\" data-end=\"5830\">Detention of goods and vehicle</td>\r\n</tr>\r\n<tr data-start=\"5831\" data-end=\"5910\">\r\n<td data-start=\"5831\" data-end=\"5863\" data-col-size=\"sm\">Wrong or fake invoice details</td>\r\n<td data-start=\"5863\" data-end=\"5910\" data-col-size=\"md\">Penalty under Section 122 / 125 of CGST Act</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"5912\" data-end=\"6009\">Non-compliance can lead to seizure, delay in supply chain, and disallowance of ITC to recipients.</p>\r\n<hr data-start=\"6011\" data-end=\"6014\">\r\n<h3 data-start=\"6016\" data-end=\"6042\"><strong data-start=\"6020\" data-end=\"6042\">Documents Required</strong></h3>\r\n<ul data-start=\"6044\" data-end=\"6268\">\r\n<li data-start=\"6044\" data-end=\"6076\">\r\n<p data-start=\"6046\" data-end=\"6076\">GST registration certificate</p>\r\n</li>\r\n<li data-start=\"6077\" data-end=\"6112\">\r\n<p data-start=\"6079\" data-end=\"6112\">Latest GST returns (GSTR-1, 3B)</p>\r\n</li>\r\n<li data-start=\"6113\" data-end=\"6147\">\r\n<p data-start=\"6115\" data-end=\"6147\">Business PAN and address proof</p>\r\n</li>\r\n<li data-start=\"6148\" data-end=\"6185\">\r\n<p data-start=\"6150\" data-end=\"6185\">Transporter ID or vehicle details</p>\r\n</li>\r\n<li data-start=\"6186\" data-end=\"6268\">\r\n<p data-start=\"6188\" data-end=\"6268\">Invoice details for e-invoicing (supplier &amp; buyer GSTIN, HSN, quantity, value)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6270\" data-end=\"6273\">\r\n<h3 data-start=\"6275\" data-end=\"6335\"><strong data-start=\"6279\" data-end=\"6335\">Rajasthan Filings&rsquo; E-Invoicing &amp; E-Way Bill Services</strong></h3>\r\n<ul data-start=\"6337\" data-end=\"6771\">\r\n<li data-start=\"6337\" data-end=\"6409\">\r\n<p data-start=\"6339\" data-end=\"6409\">Complete assistance in e-invoicing registration and IRP integration.</p>\r\n</li>\r\n<li data-start=\"6410\" data-end=\"6478\">\r\n<p data-start=\"6412\" data-end=\"6478\">Creation of compliant invoice formats with all mandatory fields.</p>\r\n</li>\r\n<li data-start=\"6479\" data-end=\"6539\">\r\n<p data-start=\"6481\" data-end=\"6539\">Real-time validation of invoices and QR code generation.</p>\r\n</li>\r\n<li data-start=\"6540\" data-end=\"6615\">\r\n<p data-start=\"6542\" data-end=\"6615\">Assistance in generating and managing e-way bills for all transactions.</p>\r\n</li>\r\n<li data-start=\"6616\" data-end=\"6678\">\r\n<p data-start=\"6618\" data-end=\"6678\">Guidance on turnover applicability and threshold tracking.</p>\r\n</li>\r\n<li data-start=\"6679\" data-end=\"6771\">\r\n<p data-start=\"6681\" data-end=\"6771\">Training and implementation for staff and businesses to handle compliance independently.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6773\" data-end=\"6776\">\r\n<h3 data-start=\"6778\" data-end=\"6840\"><strong data-start=\"6782\" data-end=\"6840\">Advantages of Availing Services from Rajasthan Filings</strong></h3>\r\n<ul data-start=\"6842\" data-end=\"7175\">\r\n<li data-start=\"6842\" data-end=\"6893\">\r\n<p data-start=\"6844\" data-end=\"6893\">100% compliance with GST law and notifications.</p>\r\n</li>\r\n<li data-start=\"6894\" data-end=\"6945\">\r\n<p data-start=\"6896\" data-end=\"6945\">Error-free invoice and transport documentation.</p>\r\n</li>\r\n<li data-start=\"6946\" data-end=\"7000\">\r\n<p data-start=\"6948\" data-end=\"7000\">Fast resolution of validation or rejection errors.</p>\r\n</li>\r\n<li data-start=\"7001\" data-end=\"7060\">\r\n<p data-start=\"7003\" data-end=\"7060\">Real-time monitoring of e-way bill expiry and renewals.</p>\r\n</li>\r\n<li data-start=\"7061\" data-end=\"7118\">\r\n<p data-start=\"7063\" data-end=\"7118\">Advisory support for departmental queries and audits.</p>\r\n</li>\r\n<li data-start=\"7119\" data-end=\"7175\">\r\n<p data-start=\"7121\" data-end=\"7175\">Complete confidentiality and secure data management.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7177\" data-end=\"7180\">\r\n<h3 data-start=\"7182\" data-end=\"7200\"><strong data-start=\"7186\" data-end=\"7200\">Conclusion</strong></h3>\r\n<p data-start=\"7202\" data-end=\"7404\">E-Invoicing and E-Way Bill systems are the cornerstones of India&rsquo;s digital GST infrastructure. They ensure efficiency, transparency, and authenticity in every transaction &mdash; from invoicing to delivery.</p>\r\n<p data-start=\"7406\" data-end=\"7569\">By adopting e-invoicing and e-way bill compliance, businesses can reduce manual errors, eliminate duplication, and build credibility with buyers and authorities.</p>\r\n<p data-start=\"7571\" data-end=\"7765\"><strong data-start=\"7571\" data-end=\"7592\">Rajasthan Filings</strong> offers trusted end-to-end support to implement these systems smoothly, ensuring you stay fully compliant with government regulations while focusing on your business growth</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:49:31', '2025-11-07 00:49:18'),
(14, 3, NULL, 'Tax Audit Reports', 'tax-audit-reports', 'Tax Audit Reports (Form 3CA/3CB/3CD)', '<p><span lang=\"EN-US\" style=\"font-size: 11.0pt; line-height: 115%; font-family: \'Cambria\',\'serif\'; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: \'MS Mincho\'; mso-fareast-theme-font: minor-fareast; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: \'Times New Roman\'; mso-bidi-theme-font: minor-bidi; mso-ansi-language: EN-US; mso-fareast-language: EN-US; mso-bidi-language: AR-SA;\">Tax Audit Reports (Form 3CA/3CB/3CD)</span></p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:50:04', '2025-11-07 00:49:20'),
(15, 3, NULL, 'TDS/TCS Return Filing', 'tdstcs-return-filing-', 'TDS/TCS Return Filing (24Q, 26Q, 27Q, 27EQ)', '<h1 data-start=\"368\" data-end=\"397\"><strong data-start=\"370\" data-end=\"397\">TDS / TCS Return Filing</strong></h1>\r\n<p data-start=\"399\" data-end=\"807\">Every business, company, or government organization responsible for making payments such as salary, commission, rent, interest, or professional fees is required to deduct or collect tax at source and file regular returns.<br data-start=\"620\" data-end=\"623\">Tax Deducted at Source (TDS) and Tax Collected at Source (TCS) are vital parts of India&rsquo;s modern tax compliance system, ensuring that tax is collected at the very point of transaction.</p>\r\n<p data-start=\"809\" data-end=\"1088\">At <strong data-start=\"812\" data-end=\"833\">Rajasthan Filings</strong>, we provide complete TDS and TCS return filing solutions with accuracy, transparency, and timely submission. Our expert team ensures that every return is filed correctly, challans are matched, and credits are reflected in Form 26AS and AIS without error.</p>\r\n<hr data-start=\"1090\" data-end=\"1093\">\r\n<h3 data-start=\"1095\" data-end=\"1122\"><strong data-start=\"1099\" data-end=\"1122\">Meaning and Purpose</strong></h3>\r\n<ul data-start=\"1124\" data-end=\"1560\">\r\n<li data-start=\"1124\" data-end=\"1321\">\r\n<p data-start=\"1126\" data-end=\"1321\"><strong data-start=\"1126\" data-end=\"1159\">TDS (Tax Deducted at Source):</strong><br data-start=\"1159\" data-end=\"1162\">A specific percentage of tax deducted by the payer at the time of making payments such as salary, interest, contractor bills, rent, or professional services.</p>\r\n</li>\r\n<li data-start=\"1323\" data-end=\"1560\">\r\n<p data-start=\"1325\" data-end=\"1560\"><strong data-start=\"1325\" data-end=\"1359\">TCS (Tax Collected at Source):</strong><br data-start=\"1359\" data-end=\"1362\">A small percentage of tax collected by the seller from the buyer at the time of sale of specified goods or services like scrap, motor vehicles, foreign travel packages, or e-commerce transactions.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1562\" data-end=\"1700\">These systems help maintain transparency, prevent tax evasion, and ensure that tax is collected in advance before the final return filing.</p>\r\n<hr data-start=\"1702\" data-end=\"1705\">\r\n<h3 data-start=\"1707\" data-end=\"1730\"><strong data-start=\"1711\" data-end=\"1730\">Who Should File</strong></h3>\r\n<ul data-start=\"1732\" data-end=\"2049\">\r\n<li data-start=\"1732\" data-end=\"1823\">\r\n<p data-start=\"1734\" data-end=\"1823\">All registered businesses, LLPs, firms, and companies making payments that attract TDS.</p>\r\n</li>\r\n<li data-start=\"1824\" data-end=\"1898\">\r\n<p data-start=\"1826\" data-end=\"1898\">Sellers or service providers collecting TCS on specified transactions.</p>\r\n</li>\r\n<li data-start=\"1899\" data-end=\"1986\">\r\n<p data-start=\"1901\" data-end=\"1986\">Government departments, local authorities, and institutions required to deduct tax.</p>\r\n</li>\r\n<li data-start=\"1987\" data-end=\"2049\">\r\n<p data-start=\"1989\" data-end=\"2049\">E-commerce operators, banks, NBFCs, and payment aggregators.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2051\" data-end=\"2054\">\r\n<h3 data-start=\"2056\" data-end=\"2086\"><strong data-start=\"2060\" data-end=\"2086\">TDS / TCS Return Forms</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2088\" data-end=\"2506\">\r\n<thead data-start=\"2088\" data-end=\"2138\">\r\n<tr data-start=\"2088\" data-end=\"2138\">\r\n<th data-start=\"2088\" data-end=\"2103\" data-col-size=\"sm\"><strong data-start=\"2090\" data-end=\"2102\">Form No.</strong></th>\r\n<th data-start=\"2103\" data-end=\"2117\" data-col-size=\"md\"><strong data-start=\"2105\" data-end=\"2116\">Purpose</strong></th>\r\n<th data-start=\"2117\" data-end=\"2138\" data-col-size=\"sm\"><strong data-start=\"2119\" data-end=\"2136\">Applicable To</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2191\" data-end=\"2506\">\r\n<tr data-start=\"2191\" data-end=\"2226\">\r\n<td data-start=\"2191\" data-end=\"2197\" data-col-size=\"sm\">24Q</td>\r\n<td data-start=\"2197\" data-end=\"2213\" data-col-size=\"md\">TDS on Salary</td>\r\n<td data-start=\"2213\" data-end=\"2226\" data-col-size=\"sm\">Employers</td>\r\n</tr>\r\n<tr data-start=\"2227\" data-end=\"2283\">\r\n<td data-start=\"2227\" data-end=\"2233\" data-col-size=\"sm\">26Q</td>\r\n<td data-start=\"2233\" data-end=\"2262\" data-col-size=\"md\">TDS on Non-Salary Payments</td>\r\n<td data-col-size=\"sm\" data-start=\"2262\" data-end=\"2283\">Businesses, Firms</td>\r\n</tr>\r\n<tr data-start=\"2284\" data-end=\"2352\">\r\n<td data-start=\"2284\" data-end=\"2290\" data-col-size=\"sm\">27Q</td>\r\n<td data-start=\"2290\" data-end=\"2325\" data-col-size=\"md\">TDS on Payments to Non-Residents</td>\r\n<td data-start=\"2325\" data-end=\"2352\" data-col-size=\"sm\">Foreign or NRI Payments</td>\r\n</tr>\r\n<tr data-start=\"2353\" data-end=\"2399\">\r\n<td data-start=\"2353\" data-end=\"2360\" data-col-size=\"sm\">27EQ</td>\r\n<td data-col-size=\"md\" data-start=\"2360\" data-end=\"2373\">TCS Return</td>\r\n<td data-col-size=\"sm\" data-start=\"2373\" data-end=\"2399\">Sellers Collecting Tax</td>\r\n</tr>\r\n<tr data-start=\"2400\" data-end=\"2506\">\r\n<td data-start=\"2400\" data-end=\"2421\" data-col-size=\"sm\">26QB / 26QC / 26QD</td>\r\n<td data-col-size=\"md\" data-start=\"2421\" data-end=\"2469\">TDS on Property, Rent, or Contractor Payments</td>\r\n<td data-col-size=\"sm\" data-start=\"2469\" data-end=\"2506\">Individuals / Non-Business Payees</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2508\" data-end=\"2511\">\r\n<h3 data-start=\"2513\" data-end=\"2540\"><strong data-start=\"2517\" data-end=\"2540\">Quarterly Due Dates</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2542\" data-end=\"2851\">\r\n<thead data-start=\"2542\" data-end=\"2609\">\r\n<tr data-start=\"2542\" data-end=\"2609\">\r\n<th data-start=\"2542\" data-end=\"2556\" data-col-size=\"sm\"><strong data-start=\"2544\" data-end=\"2555\">Quarter</strong></th>\r\n<th data-start=\"2556\" data-end=\"2582\" data-col-size=\"sm\"><strong data-start=\"2558\" data-end=\"2581\">TDS Return Due Date</strong></th>\r\n<th data-start=\"2582\" data-end=\"2609\" data-col-size=\"sm\"><strong data-start=\"2584\" data-end=\"2607\">TCS Return Due Date</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2681\" data-end=\"2851\">\r\n<tr data-start=\"2681\" data-end=\"2717\">\r\n<td data-start=\"2681\" data-end=\"2696\" data-col-size=\"sm\">April &ndash; June</td>\r\n<td data-start=\"2696\" data-end=\"2706\" data-col-size=\"sm\">31 July</td>\r\n<td data-col-size=\"sm\" data-start=\"2706\" data-end=\"2717\">15 July</td>\r\n</tr>\r\n<tr data-start=\"2718\" data-end=\"2764\">\r\n<td data-start=\"2718\" data-end=\"2737\" data-col-size=\"sm\">July &ndash; September</td>\r\n<td data-start=\"2737\" data-end=\"2750\" data-col-size=\"sm\">31 October</td>\r\n<td data-start=\"2750\" data-end=\"2764\" data-col-size=\"sm\">15 October</td>\r\n</tr>\r\n<tr data-start=\"2765\" data-end=\"2813\">\r\n<td data-start=\"2765\" data-end=\"2786\" data-col-size=\"sm\">October &ndash; December</td>\r\n<td data-start=\"2786\" data-end=\"2799\" data-col-size=\"sm\">31 January</td>\r\n<td data-start=\"2799\" data-end=\"2813\" data-col-size=\"sm\">15 January</td>\r\n</tr>\r\n<tr data-start=\"2814\" data-end=\"2851\">\r\n<td data-start=\"2814\" data-end=\"2832\" data-col-size=\"sm\">January &ndash; March</td>\r\n<td data-start=\"2832\" data-end=\"2841\" data-col-size=\"sm\">31 May</td>\r\n<td data-col-size=\"sm\" data-start=\"2841\" data-end=\"2851\">15 May</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"2853\" data-end=\"2969\">Timely filing ensures that TDS credits appear correctly in the deductee&rsquo;s Form 26AS and avoids penalties or notices.</p>\r\n<hr data-start=\"2971\" data-end=\"2974\">\r\n<h3 data-start=\"2976\" data-end=\"3004\"><strong data-start=\"2980\" data-end=\"3004\">Key Compliance Steps</strong></h3>\r\n<ol data-start=\"3006\" data-end=\"3594\">\r\n<li data-start=\"3006\" data-end=\"3117\">\r\n<p data-start=\"3009\" data-end=\"3117\"><strong data-start=\"3009\" data-end=\"3054\">Obtain TAN (Tax Deduction Account Number)</strong><br data-start=\"3054\" data-end=\"3057\">Mandatory for all entities deducting or collecting tax.</p>\r\n</li>\r\n<li data-start=\"3119\" data-end=\"3214\">\r\n<p data-start=\"3122\" data-end=\"3214\"><strong data-start=\"3122\" data-end=\"3147\">Deduct or Collect Tax</strong><br data-start=\"3147\" data-end=\"3150\">Apply the prescribed rate at the time of payment or credit.</p>\r\n</li>\r\n<li data-start=\"3216\" data-end=\"3305\">\r\n<p data-start=\"3219\" data-end=\"3305\"><strong data-start=\"3219\" data-end=\"3234\">Deposit Tax</strong><br data-start=\"3234\" data-end=\"3237\">Pay through challan ITNS-281 by the 7th of the following month.</p>\r\n</li>\r\n<li data-start=\"3307\" data-end=\"3403\">\r\n<p data-start=\"3310\" data-end=\"3403\"><strong data-start=\"3310\" data-end=\"3335\">File Quarterly Return</strong><br data-start=\"3335\" data-end=\"3338\">Upload return file (FVU format) through the official portal.</p>\r\n</li>\r\n<li data-start=\"3405\" data-end=\"3485\">\r\n<p data-start=\"3408\" data-end=\"3432\"><strong data-start=\"3408\" data-end=\"3430\">Issue Certificates</strong></p>\r\n<ul data-start=\"3436\" data-end=\"3485\">\r\n<li data-start=\"3436\" data-end=\"3461\">\r\n<p data-start=\"3438\" data-end=\"3461\">Form 16 / 16A for TDS</p>\r\n</li>\r\n<li data-start=\"3465\" data-end=\"3485\">\r\n<p data-start=\"3467\" data-end=\"3485\">Form 27D for TCS</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li data-start=\"3487\" data-end=\"3594\">\r\n<p data-start=\"3490\" data-end=\"3594\"><strong data-start=\"3490\" data-end=\"3514\">Reconcile and Verify</strong><br data-start=\"3514\" data-end=\"3517\">Match all deductions and deposits with Form 26AS / AIS to ensure accuracy.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3596\" data-end=\"3599\">\r\n<h3 data-start=\"3601\" data-end=\"3632\"><strong data-start=\"3605\" data-end=\"3632\">Commonly Used TDS Rates</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3634\" data-end=\"4018\">\r\n<thead data-start=\"3634\" data-end=\"3683\">\r\n<tr data-start=\"3634\" data-end=\"3683\">\r\n<th data-start=\"3634\" data-end=\"3653\" data-col-size=\"sm\"><strong data-start=\"3636\" data-end=\"3652\">Payment Type</strong></th>\r\n<th data-start=\"3653\" data-end=\"3668\" data-col-size=\"sm\"><strong data-start=\"3655\" data-end=\"3667\">Rate (%)</strong></th>\r\n<th data-start=\"3668\" data-end=\"3683\" data-col-size=\"sm\"><strong data-start=\"3670\" data-end=\"3681\">Section</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3736\" data-end=\"4018\">\r\n<tr data-start=\"3736\" data-end=\"3777\">\r\n<td data-start=\"3736\" data-end=\"3745\" data-col-size=\"sm\">Salary</td>\r\n<td data-start=\"3745\" data-end=\"3770\" data-col-size=\"sm\">As per applicable slab</td>\r\n<td data-start=\"3770\" data-end=\"3777\" data-col-size=\"sm\">192</td>\r\n</tr>\r\n<tr data-start=\"3778\" data-end=\"3814\">\r\n<td data-start=\"3778\" data-end=\"3801\" data-col-size=\"sm\">Interest on Deposits</td>\r\n<td data-col-size=\"sm\" data-start=\"3801\" data-end=\"3806\">10</td>\r\n<td data-col-size=\"sm\" data-start=\"3806\" data-end=\"3814\">194A</td>\r\n</tr>\r\n<tr data-start=\"3815\" data-end=\"3853\">\r\n<td data-start=\"3815\" data-end=\"3837\" data-col-size=\"sm\">Contractor Payments</td>\r\n<td data-start=\"3837\" data-end=\"3845\" data-col-size=\"sm\">1 &ndash; 2</td>\r\n<td data-start=\"3845\" data-end=\"3853\" data-col-size=\"sm\">194C</td>\r\n</tr>\r\n<tr data-start=\"3854\" data-end=\"3874\">\r\n<td data-start=\"3854\" data-end=\"3861\" data-col-size=\"sm\">Rent</td>\r\n<td data-start=\"3861\" data-end=\"3866\" data-col-size=\"sm\">10</td>\r\n<td data-col-size=\"sm\" data-start=\"3866\" data-end=\"3874\">194I</td>\r\n</tr>\r\n<tr data-start=\"3875\" data-end=\"3912\">\r\n<td data-start=\"3875\" data-end=\"3900\" data-col-size=\"sm\">Commission / Brokerage</td>\r\n<td data-start=\"3900\" data-end=\"3904\" data-col-size=\"sm\">5</td>\r\n<td data-start=\"3904\" data-end=\"3912\" data-col-size=\"sm\">194H</td>\r\n</tr>\r\n<tr data-start=\"3913\" data-end=\"3946\">\r\n<td data-start=\"3913\" data-end=\"3933\" data-col-size=\"sm\">Professional Fees</td>\r\n<td data-col-size=\"sm\" data-start=\"3933\" data-end=\"3938\">10</td>\r\n<td data-col-size=\"sm\" data-start=\"3938\" data-end=\"3946\">194J</td>\r\n</tr>\r\n<tr data-start=\"3947\" data-end=\"3983\">\r\n<td data-start=\"3947\" data-end=\"3970\" data-col-size=\"sm\">Purchase of Property</td>\r\n<td data-col-size=\"sm\" data-start=\"3970\" data-end=\"3974\">1</td>\r\n<td data-col-size=\"sm\" data-start=\"3974\" data-end=\"3983\">194IA</td>\r\n</tr>\r\n<tr data-start=\"3984\" data-end=\"4018\">\r\n<td data-start=\"3984\" data-end=\"4006\" data-col-size=\"sm\">E-commerce Receipts</td>\r\n<td data-col-size=\"sm\" data-start=\"4006\" data-end=\"4010\">1</td>\r\n<td data-col-size=\"sm\" data-start=\"4010\" data-end=\"4018\">194O</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4020\" data-end=\"4023\">\r\n<h3 data-start=\"4025\" data-end=\"4067\"><strong data-start=\"4029\" data-end=\"4067\">Late Fees, Interest, and Penalties</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"4069\" data-end=\"4487\">\r\n<thead data-start=\"4069\" data-end=\"4117\">\r\n<tr data-start=\"4069\" data-end=\"4117\">\r\n<th data-start=\"4069\" data-end=\"4091\" data-col-size=\"sm\"><strong data-start=\"4071\" data-end=\"4090\">Type of Default</strong></th>\r\n<th data-start=\"4091\" data-end=\"4117\" data-col-size=\"sm\"><strong data-start=\"4093\" data-end=\"4115\">Applicable Penalty</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"4168\" data-end=\"4487\">\r\n<tr data-start=\"4168\" data-end=\"4228\">\r\n<td data-start=\"4168\" data-end=\"4193\" data-col-size=\"sm\">Delay in return filing</td>\r\n<td data-col-size=\"sm\" data-start=\"4193\" data-end=\"4228\">₹200 per day under Section 234E</td>\r\n</tr>\r\n<tr data-start=\"4229\" data-end=\"4295\">\r\n<td data-start=\"4229\" data-end=\"4254\" data-col-size=\"sm\">Failure to file return</td>\r\n<td data-start=\"4254\" data-end=\"4295\" data-col-size=\"sm\">Penalty between ₹10,000 and ₹1,00,000</td>\r\n</tr>\r\n<tr data-start=\"4296\" data-end=\"4362\">\r\n<td data-start=\"4296\" data-end=\"4328\" data-col-size=\"sm\">Non-deduction or late deposit</td>\r\n<td data-col-size=\"sm\" data-start=\"4328\" data-end=\"4362\">Interest @1% or 1.5% per month</td>\r\n</tr>\r\n<tr data-start=\"4363\" data-end=\"4424\">\r\n<td data-start=\"4363\" data-end=\"4392\" data-col-size=\"sm\">Delay in certificate issue</td>\r\n<td data-col-size=\"sm\" data-start=\"4392\" data-end=\"4424\">₹100 per day per certificate</td>\r\n</tr>\r\n<tr data-start=\"4425\" data-end=\"4487\">\r\n<td data-start=\"4425\" data-end=\"4463\" data-col-size=\"sm\">False information or non-compliance</td>\r\n<td data-col-size=\"sm\" data-start=\"4463\" data-end=\"4487\">Fine and prosecution</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"4489\" data-end=\"4492\">\r\n<h3 data-start=\"4494\" data-end=\"4520\"><strong data-start=\"4498\" data-end=\"4520\">Documents Required</strong></h3>\r\n<ul data-start=\"4522\" data-end=\"4740\">\r\n<li data-start=\"4522\" data-end=\"4553\">\r\n<p data-start=\"4524\" data-end=\"4553\">TAN and PAN of the deductor</p>\r\n</li>\r\n<li data-start=\"4554\" data-end=\"4586\">\r\n<p data-start=\"4556\" data-end=\"4586\">PAN details of all deductees</p>\r\n</li>\r\n<li data-start=\"4587\" data-end=\"4639\">\r\n<p data-start=\"4589\" data-end=\"4639\">TDS challan details (BSR code, amount, and date)</p>\r\n</li>\r\n<li data-start=\"4640\" data-end=\"4685\">\r\n<p data-start=\"4642\" data-end=\"4685\">Nature of payment and corresponding rates</p>\r\n</li>\r\n<li data-start=\"4686\" data-end=\"4740\">\r\n<p data-start=\"4688\" data-end=\"4740\">Digital Signature Certificate (DSC) for submission</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4742\" data-end=\"4745\">\r\n<h3 data-start=\"4747\" data-end=\"4786\"><strong data-start=\"4751\" data-end=\"4786\">Advantages of Proper Compliance</strong></h3>\r\n<ul data-start=\"4788\" data-end=\"5006\">\r\n<li data-start=\"4788\" data-end=\"4823\">\r\n<p data-start=\"4790\" data-end=\"4823\">Prevents penalties and interest</p>\r\n</li>\r\n<li data-start=\"4824\" data-end=\"4872\">\r\n<p data-start=\"4826\" data-end=\"4872\">Ensures smooth reconciliation of tax credits</p>\r\n</li>\r\n<li data-start=\"4873\" data-end=\"4906\">\r\n<p data-start=\"4875\" data-end=\"4906\">Enhances business credibility</p>\r\n</li>\r\n<li data-start=\"4907\" data-end=\"4961\">\r\n<p data-start=\"4909\" data-end=\"4961\">Facilitates faster refund processing for deductees</p>\r\n</li>\r\n<li data-start=\"4962\" data-end=\"5006\">\r\n<p data-start=\"4964\" data-end=\"5006\">Strengthens audit and accounting records</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5008\" data-end=\"5011\">\r\n<h3 data-start=\"5013\" data-end=\"5049\"><strong data-start=\"5017\" data-end=\"5049\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"5051\" data-end=\"5360\">\r\n<li data-start=\"5051\" data-end=\"5098\">\r\n<p data-start=\"5053\" data-end=\"5098\">Professional TDS and TCS compliance experts</p>\r\n</li>\r\n<li data-start=\"5099\" data-end=\"5164\">\r\n<p data-start=\"5101\" data-end=\"5164\">Accurate preparation and quarterly filing of all return forms</p>\r\n</li>\r\n<li data-start=\"5165\" data-end=\"5214\">\r\n<p data-start=\"5167\" data-end=\"5214\">Real-time error correction and reconciliation</p>\r\n</li>\r\n<li data-start=\"5215\" data-end=\"5259\">\r\n<p data-start=\"5217\" data-end=\"5259\">Timely issuance of Form 16, 16A, and 27D</p>\r\n</li>\r\n<li data-start=\"5260\" data-end=\"5313\">\r\n<p data-start=\"5262\" data-end=\"5313\">Seamless coordination with TRACES and AIS systems</p>\r\n</li>\r\n<li data-start=\"5314\" data-end=\"5360\">\r\n<p data-start=\"5316\" data-end=\"5360\">Transparent service and nationwide support</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5362\" data-end=\"5495\">We ensure that your TDS and TCS obligations are met on time &mdash; accurately, efficiently, and completely in line with current tax rules.</p>\r\n<hr data-start=\"5497\" data-end=\"5500\">\r\n<h3 data-start=\"5502\" data-end=\"5520\"><strong data-start=\"5506\" data-end=\"5520\">Conclusion</strong></h3>\r\n<p data-start=\"5522\" data-end=\"5790\">TDS and TCS return filing is not just a procedural task &mdash; it&rsquo;s a critical part of a business&rsquo;s tax and financial ecosystem.<br data-start=\"5645\" data-end=\"5648\">Accurate deduction, timely deposit, and correct filing protect both the payer and the payee from compliance risks and departmental scrutiny.</p>\r\n<p data-start=\"5792\" data-end=\"6011\">With <strong data-start=\"5797\" data-end=\"5818\">Rajasthan Filings</strong>, you get a reliable partner to manage the entire compliance process &mdash; from TAN registration to return submission &mdash; so you can focus on your business while we handle the accuracy and deadlines.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:50:23', '2025-11-07 00:49:21');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(16, 4, NULL, 'Project Report & CMA Data Preparation', 'project-report--cma-data-preparation', 'Project Report & CMA Data Preparation', '<h1 data-start=\"124\" data-end=\"167\"><strong data-start=\"126\" data-end=\"167\">Project Report &amp; CMA Data Preparation</strong></h1>\r\n<hr data-start=\"169\" data-end=\"172\">\r\n<h3 data-start=\"174\" data-end=\"190\"><strong data-start=\"178\" data-end=\"190\">Overview</strong></h3>\r\n<p data-start=\"192\" data-end=\"442\">Every business &mdash; whether it&rsquo;s a new startup, MSME, or growing enterprise &mdash; needs a <strong data-start=\"275\" data-end=\"352\">well-prepared Project Report and CMA Data (Credit Monitoring Arrangement)</strong> while applying for loans or financial assistance from banks and financial institutions.</p>\r\n<p data-start=\"444\" data-end=\"775\">At <strong data-start=\"447\" data-end=\"468\">Rajasthan Filings</strong>, we specialize in preparing accurate, bank-ready, and professionally formatted reports that clearly represent your business model, projected financial performance, and repayment capability. Our CMA Data and Project Reports are structured according to RBI, NABARD, and all major public/private bank formats.</p>\r\n<hr data-start=\"777\" data-end=\"780\">\r\n<h3 data-start=\"782\" data-end=\"815\"><strong data-start=\"786\" data-end=\"815\">What is a Project Report?</strong></h3>\r\n<p data-start=\"817\" data-end=\"1080\">A <strong data-start=\"819\" data-end=\"837\">Project Report</strong> is a detailed written document that outlines your business plan, proposed activities, financial projections, and loan requirements. It provides the bank or investor with a complete understanding of your business &mdash; from concept to cash flow.</p>\r\n<p data-start=\"1082\" data-end=\"1221\">A well-drafted report highlights your financial stability, profitability, and repayment capacity, increasing your chances of loan approval.</p>\r\n<hr data-start=\"1223\" data-end=\"1226\">\r\n<h3 data-start=\"1228\" data-end=\"1253\"><strong data-start=\"1232\" data-end=\"1253\">What is CMA Data?</strong></h3>\r\n<p data-start=\"1255\" data-end=\"1564\"><strong data-start=\"1255\" data-end=\"1299\">CMA Data (Credit Monitoring Arrangement)</strong> is a structured financial statement format prescribed by the Reserve Bank of India (RBI) to evaluate the creditworthiness of borrowers. It includes historical and projected financial statements to assess how efficiently the business manages funds and repays loans.</p>\r\n<p data-start=\"1566\" data-end=\"1629\">CMA Data is mandatory for all business entities applying for:</p>\r\n<ul data-start=\"1630\" data-end=\"1766\">\r\n<li data-start=\"1630\" data-end=\"1656\">\r\n<p data-start=\"1632\" data-end=\"1656\">Cash Credit (CC) Limit</p>\r\n</li>\r\n<li data-start=\"1657\" data-end=\"1671\">\r\n<p data-start=\"1659\" data-end=\"1671\">Term Loans</p>\r\n</li>\r\n<li data-start=\"1672\" data-end=\"1701\">\r\n<p data-start=\"1674\" data-end=\"1701\">Overdraft (OD) Facilities</p>\r\n</li>\r\n<li data-start=\"1702\" data-end=\"1729\">\r\n<p data-start=\"1704\" data-end=\"1729\">Working Capital Finance</p>\r\n</li>\r\n<li data-start=\"1730\" data-end=\"1766\">\r\n<p data-start=\"1732\" data-end=\"1766\">MSME or Business Expansion Loans</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1768\" data-end=\"1771\">\r\n<h3 data-start=\"1773\" data-end=\"1831\"><strong data-start=\"1777\" data-end=\"1831\">Importance of a Proper Project Report and CMA Data</strong></h3>\r\n<ol data-start=\"1833\" data-end=\"2163\">\r\n<li data-start=\"1833\" data-end=\"1894\">\r\n<p data-start=\"1836\" data-end=\"1894\">Helps banks assess loan viability and repayment ability.</p>\r\n</li>\r\n<li data-start=\"1895\" data-end=\"1963\">\r\n<p data-start=\"1898\" data-end=\"1963\">Reflects the financial health and credibility of your business.</p>\r\n</li>\r\n<li data-start=\"1964\" data-end=\"2028\">\r\n<p data-start=\"1967\" data-end=\"2028\">Essential for securing MSME, Startup India, or Mudra loans.</p>\r\n</li>\r\n<li data-start=\"2029\" data-end=\"2094\">\r\n<p data-start=\"2032\" data-end=\"2094\">Demonstrates accurate fund utilization and growth potential.</p>\r\n</li>\r\n<li data-start=\"2095\" data-end=\"2163\">\r\n<p data-start=\"2098\" data-end=\"2163\">Required by both private and government financial institutions.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"2165\" data-end=\"2168\">\r\n<h3 data-start=\"2170\" data-end=\"2212\"><strong data-start=\"2174\" data-end=\"2212\">Key Components of a Project Report</strong></h3>\r\n<ol data-start=\"2214\" data-end=\"2865\">\r\n<li data-start=\"2214\" data-end=\"2291\">\r\n<p data-start=\"2217\" data-end=\"2291\"><strong data-start=\"2217\" data-end=\"2238\">Executive Summary</strong> &ndash; Brief overview of the business and loan purpose.</p>\r\n</li>\r\n<li data-start=\"2292\" data-end=\"2372\">\r\n<p data-start=\"2295\" data-end=\"2372\"><strong data-start=\"2295\" data-end=\"2315\">Promoter Details</strong> &ndash; Qualification, experience, and background of owners.</p>\r\n</li>\r\n<li data-start=\"2373\" data-end=\"2459\">\r\n<p data-start=\"2376\" data-end=\"2459\"><strong data-start=\"2376\" data-end=\"2396\">Business Profile</strong> &ndash; Nature of business, products, services, and target market.</p>\r\n</li>\r\n<li data-start=\"2460\" data-end=\"2530\">\r\n<p data-start=\"2463\" data-end=\"2530\"><strong data-start=\"2463\" data-end=\"2484\">Industry Overview</strong> &ndash; Market analysis, demand, and competition.</p>\r\n</li>\r\n<li data-start=\"2531\" data-end=\"2617\">\r\n<p data-start=\"2534\" data-end=\"2617\"><strong data-start=\"2534\" data-end=\"2553\">Project Details</strong> &ndash; Cost of project, means of finance, and implementation plan.</p>\r\n</li>\r\n<li data-start=\"2618\" data-end=\"2705\">\r\n<p data-start=\"2621\" data-end=\"2705\"><strong data-start=\"2621\" data-end=\"2646\">Financial Projections</strong> &ndash; Profit &amp; Loss statement, Balance Sheet, and Cash Flow.</p>\r\n</li>\r\n<li data-start=\"2706\" data-end=\"2781\">\r\n<p data-start=\"2709\" data-end=\"2781\"><strong data-start=\"2709\" data-end=\"2731\">Repayment Schedule</strong> &ndash; Loan tenure, EMI calculation, and DSCR ratio.</p>\r\n</li>\r\n<li data-start=\"2782\" data-end=\"2865\">\r\n<p data-start=\"2785\" data-end=\"2865\"><strong data-start=\"2785\" data-end=\"2809\">Supporting Documents</strong> &ndash; Licenses, registrations, and quotations for assets.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"2867\" data-end=\"2870\">\r\n<h3 data-start=\"2872\" data-end=\"2906\"><strong data-start=\"2876\" data-end=\"2906\">Key Components of CMA Data</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2908\" data-end=\"3488\">\r\n<thead data-start=\"2908\" data-end=\"2945\">\r\n<tr data-start=\"2908\" data-end=\"2945\">\r\n<th data-start=\"2908\" data-end=\"2926\" data-col-size=\"sm\"><strong data-start=\"2910\" data-end=\"2925\">Particulars</strong></th>\r\n<th data-start=\"2926\" data-end=\"2945\" data-col-size=\"md\"><strong data-start=\"2928\" data-end=\"2943\">Description</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2985\" data-end=\"3488\">\r\n<tr data-start=\"2985\" data-end=\"3074\">\r\n<td data-start=\"2985\" data-end=\"3008\" data-col-size=\"sm\"><strong data-start=\"2987\" data-end=\"3007\">Past Performance</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3008\" data-end=\"3074\">Previous 3 years&rsquo; audited financial data (Balance Sheet, P&amp;L).</td>\r\n</tr>\r\n<tr data-start=\"3075\" data-end=\"3153\">\r\n<td data-start=\"3075\" data-end=\"3104\" data-col-size=\"sm\"><strong data-start=\"3077\" data-end=\"3103\">Current Year Estimates</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3104\" data-end=\"3153\">Ongoing performance up to the latest quarter.</td>\r\n</tr>\r\n<tr data-start=\"3154\" data-end=\"3244\">\r\n<td data-start=\"3154\" data-end=\"3178\" data-col-size=\"sm\"><strong data-start=\"3156\" data-end=\"3177\">Projected Figures</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3178\" data-end=\"3244\">Next 2 to 5 years&rsquo; projections based on realistic assumptions.</td>\r\n</tr>\r\n<tr data-start=\"3245\" data-end=\"3317\">\r\n<td data-start=\"3245\" data-end=\"3271\" data-col-size=\"sm\"><strong data-start=\"3247\" data-end=\"3270\">Fund Flow Statement</strong></td>\r\n<td data-start=\"3271\" data-end=\"3317\" data-col-size=\"md\">Movement of funds during a financial year.</td>\r\n</tr>\r\n<tr data-start=\"3318\" data-end=\"3408\">\r\n<td data-start=\"3318\" data-end=\"3351\" data-col-size=\"sm\"><strong data-start=\"3320\" data-end=\"3350\">Working Capital Assessment</strong></td>\r\n<td data-start=\"3351\" data-end=\"3408\" data-col-size=\"md\">Analysis of current assets, liabilities, and margins.</td>\r\n</tr>\r\n<tr data-start=\"3409\" data-end=\"3488\">\r\n<td data-start=\"3409\" data-end=\"3430\" data-col-size=\"sm\"><strong data-start=\"3411\" data-end=\"3429\">Ratio Analysis</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3430\" data-end=\"3488\">Key financial ratios &ndash; Current Ratio, DSCR, ROCE, etc.</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3490\" data-end=\"3493\">\r\n<h3 data-start=\"3495\" data-end=\"3521\"><strong data-start=\"3499\" data-end=\"3521\">Documents Required</strong></h3>\r\n<ul data-start=\"3523\" data-end=\"3824\">\r\n<li data-start=\"3523\" data-end=\"3575\">\r\n<p data-start=\"3525\" data-end=\"3575\">PAN and Aadhaar of proprietor/partners/directors</p>\r\n</li>\r\n<li data-start=\"3576\" data-end=\"3617\">\r\n<p data-start=\"3578\" data-end=\"3617\">GST Registration and MSME Certificate</p>\r\n</li>\r\n<li data-start=\"3618\" data-end=\"3661\">\r\n<p data-start=\"3620\" data-end=\"3661\">Previous 3 years&rsquo; Balance Sheet and ITR</p>\r\n</li>\r\n<li data-start=\"3662\" data-end=\"3701\">\r\n<p data-start=\"3664\" data-end=\"3701\">Latest bank statement (6&ndash;12 months)</p>\r\n</li>\r\n<li data-start=\"3702\" data-end=\"3765\">\r\n<p data-start=\"3704\" data-end=\"3765\">Quotation or estimate for machinery, vehicles, or equipment</p>\r\n</li>\r\n<li data-start=\"3766\" data-end=\"3824\">\r\n<p data-start=\"3768\" data-end=\"3824\">Details of proposed project or business expansion plan</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3826\" data-end=\"3829\">\r\n<h3 data-start=\"3831\" data-end=\"3874\"><strong data-start=\"3835\" data-end=\"3874\">Types of Project Reports We Prepare</strong></h3>\r\n<ol data-start=\"3876\" data-end=\"4207\">\r\n<li data-start=\"3876\" data-end=\"3918\">\r\n<p data-start=\"3879\" data-end=\"3918\"><strong data-start=\"3879\" data-end=\"3916\">MSME / Mudra Loan Project Reports</strong></p>\r\n</li>\r\n<li data-start=\"3919\" data-end=\"3966\">\r\n<p data-start=\"3922\" data-end=\"3966\"><strong data-start=\"3922\" data-end=\"3964\">Bank Term Loan and CC/OD Limit Reports</strong></p>\r\n</li>\r\n<li data-start=\"3967\" data-end=\"4016\">\r\n<p data-start=\"3970\" data-end=\"4016\"><strong data-start=\"3970\" data-end=\"4014\">Machinery or Equipment Purchase Projects</strong></p>\r\n</li>\r\n<li data-start=\"4017\" data-end=\"4065\">\r\n<p data-start=\"4020\" data-end=\"4065\"><strong data-start=\"4020\" data-end=\"4063\">Startup India / Stand-Up India Projects</strong></p>\r\n</li>\r\n<li data-start=\"4066\" data-end=\"4110\">\r\n<p data-start=\"4069\" data-end=\"4110\"><strong data-start=\"4069\" data-end=\"4108\">FSSAI / Manufacturing Plant Reports</strong></p>\r\n</li>\r\n<li data-start=\"4111\" data-end=\"4160\">\r\n<p data-start=\"4114\" data-end=\"4160\"><strong data-start=\"4114\" data-end=\"4158\">Retail and Service Sector Business Plans</strong></p>\r\n</li>\r\n<li data-start=\"4161\" data-end=\"4207\">\r\n<p data-start=\"4164\" data-end=\"4207\"><strong data-start=\"4164\" data-end=\"4205\">Agriculture and Dairy Sector Projects</strong></p>\r\n</li>\r\n</ol>\r\n<p data-start=\"4209\" data-end=\"4338\">Each report is customized as per your industry, bank requirements, and loan purpose &mdash; ensuring accuracy, compliance, and clarity.</p>\r\n<hr data-start=\"4340\" data-end=\"4343\">\r\n<h3 data-start=\"4345\" data-end=\"4391\"><strong data-start=\"4349\" data-end=\"4391\">Financial Ratios and Analysis Included</strong></h3>\r\n<ul data-start=\"4393\" data-end=\"4602\">\r\n<li data-start=\"4393\" data-end=\"4414\">\r\n<p data-start=\"4395\" data-end=\"4414\">Debt-Equity Ratio</p>\r\n</li>\r\n<li data-start=\"4415\" data-end=\"4432\">\r\n<p data-start=\"4417\" data-end=\"4432\">Current Ratio</p>\r\n</li>\r\n<li data-start=\"4433\" data-end=\"4469\">\r\n<p data-start=\"4435\" data-end=\"4469\">Gross Profit &amp; Net Profit Margin</p>\r\n</li>\r\n<li data-start=\"4470\" data-end=\"4497\">\r\n<p data-start=\"4472\" data-end=\"4497\">Interest Coverage Ratio</p>\r\n</li>\r\n<li data-start=\"4498\" data-end=\"4536\">\r\n<p data-start=\"4500\" data-end=\"4536\">DSCR (Debt Service Coverage Ratio)</p>\r\n</li>\r\n<li data-start=\"4537\" data-end=\"4567\">\r\n<p data-start=\"4539\" data-end=\"4567\">Return on Investment (ROI)</p>\r\n</li>\r\n<li data-start=\"4568\" data-end=\"4602\">\r\n<p data-start=\"4570\" data-end=\"4602\">Working Capital Turnover Ratio</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4604\" data-end=\"4688\">These ratios help bankers evaluate your repayment capacity and financial discipline.</p>\r\n<hr data-start=\"4690\" data-end=\"4693\">\r\n<h3 data-start=\"4695\" data-end=\"4748\"><strong data-start=\"4699\" data-end=\"4748\">Benefits of Professional CMA Data Preparation</strong></h3>\r\n<ul data-start=\"4750\" data-end=\"5022\">\r\n<li data-start=\"4750\" data-end=\"4794\">\r\n<p data-start=\"4752\" data-end=\"4794\">Enhances your loan approval probability.</p>\r\n</li>\r\n<li data-start=\"4795\" data-end=\"4848\">\r\n<p data-start=\"4797\" data-end=\"4848\">Projects true profitability and growth potential.</p>\r\n</li>\r\n<li data-start=\"4849\" data-end=\"4911\">\r\n<p data-start=\"4851\" data-end=\"4911\">Reflects efficient financial planning and fund management.</p>\r\n</li>\r\n<li data-start=\"4912\" data-end=\"4963\">\r\n<p data-start=\"4914\" data-end=\"4963\">Meets all RBI and bank documentation standards.</p>\r\n</li>\r\n<li data-start=\"4964\" data-end=\"5022\">\r\n<p data-start=\"4966\" data-end=\"5022\">Avoids rejection due to incomplete or inaccurate data.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5024\" data-end=\"5027\">\r\n<h3 data-start=\"5029\" data-end=\"5065\"><strong data-start=\"5033\" data-end=\"5065\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"5067\" data-end=\"5364\">\r\n<li data-start=\"5067\" data-end=\"5124\">\r\n<p data-start=\"5069\" data-end=\"5124\">Team of Chartered Accountants and Financial Analysts.</p>\r\n</li>\r\n<li data-start=\"5125\" data-end=\"5161\">\r\n<p data-start=\"5127\" data-end=\"5161\">100% bank-compliant CMA formats.</p>\r\n</li>\r\n<li data-start=\"5162\" data-end=\"5209\">\r\n<p data-start=\"5164\" data-end=\"5209\">Customized reports for every loan category.</p>\r\n</li>\r\n<li data-start=\"5210\" data-end=\"5267\">\r\n<p data-start=\"5212\" data-end=\"5267\">Support for all major nationalized and private banks.</p>\r\n</li>\r\n<li data-start=\"5268\" data-end=\"5322\">\r\n<p data-start=\"5270\" data-end=\"5322\">Guidance on DSCR improvement and financial ratios.</p>\r\n</li>\r\n<li data-start=\"5323\" data-end=\"5364\">\r\n<p data-start=\"5325\" data-end=\"5364\">Confidential and data-secure service.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5366\" data-end=\"5506\">We not only prepare your CMA Data and Project Report but also help you understand your financial strengths and weaknesses before submission.</p>\r\n<hr data-start=\"5508\" data-end=\"5511\">\r\n<h3 data-start=\"5513\" data-end=\"5532\"><strong data-start=\"5517\" data-end=\"5532\">Our Process</strong></h3>\r\n<ol data-start=\"5534\" data-end=\"5823\">\r\n<li data-start=\"5534\" data-end=\"5584\">\r\n<p data-start=\"5537\" data-end=\"5584\">Collect basic business and financial details.</p>\r\n</li>\r\n<li data-start=\"5585\" data-end=\"5640\">\r\n<p data-start=\"5588\" data-end=\"5640\">Analyze existing performance and loan requirement.</p>\r\n</li>\r\n<li data-start=\"5641\" data-end=\"5689\">\r\n<p data-start=\"5644\" data-end=\"5689\">Prepare projections and cash flow analysis.</p>\r\n</li>\r\n<li data-start=\"5690\" data-end=\"5747\">\r\n<p data-start=\"5693\" data-end=\"5747\">Finalize CMA Data and Project Report in bank format.</p>\r\n</li>\r\n<li data-start=\"5748\" data-end=\"5823\">\r\n<p data-start=\"5751\" data-end=\"5823\">Deliver both soft copy (Excel + PDF) and editable file for submission.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"5825\" data-end=\"5828\">\r\n<h3 data-start=\"5830\" data-end=\"5857\"><strong data-start=\"5834\" data-end=\"5857\">Industries We Serve</strong></h3>\r\n<ul data-start=\"5859\" data-end=\"6081\">\r\n<li data-start=\"5859\" data-end=\"5894\">\r\n<p data-start=\"5861\" data-end=\"5894\">Manufacturing and Trading Units</p>\r\n</li>\r\n<li data-start=\"5895\" data-end=\"5930\">\r\n<p data-start=\"5897\" data-end=\"5930\">Retail and Wholesale Businesses</p>\r\n</li>\r\n<li data-start=\"5931\" data-end=\"5963\">\r\n<p data-start=\"5933\" data-end=\"5963\">Construction and Real Estate</p>\r\n</li>\r\n<li data-start=\"5964\" data-end=\"5991\">\r\n<p data-start=\"5966\" data-end=\"5991\">Transport and Logistics</p>\r\n</li>\r\n<li data-start=\"5992\" data-end=\"6038\">\r\n<p data-start=\"5994\" data-end=\"6038\">Dairy, Poultry, and Agro-based Enterprises</p>\r\n</li>\r\n<li data-start=\"6039\" data-end=\"6081\">\r\n<p data-start=\"6041\" data-end=\"6081\">IT, Consultancy, and Service Providers</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6083\" data-end=\"6086\">\r\n<h3 data-start=\"6088\" data-end=\"6106\"><strong data-start=\"6092\" data-end=\"6106\">Conclusion</strong></h3>\r\n<p data-start=\"6108\" data-end=\"6320\">A well-prepared Project Report and CMA Data can make the difference between <strong data-start=\"6184\" data-end=\"6215\">loan rejection and approval</strong>. Banks now rely heavily on financial transparency and data-based evaluation before sanctioning credit.</p>\r\n<p data-start=\"6322\" data-end=\"6482\">With <strong data-start=\"6327\" data-end=\"6348\">Rajasthan Filings</strong>, you get precise, data-backed, and professional reports that speak the language bankers understand &mdash; clarity, numbers, and viability.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:51:09', '2025-11-07 00:49:29'),
(17, 4, NULL, 'Accounting & Bookkeeping Services', 'accounting--bookkeeping-services', 'Accounting & Bookkeeping Services', '<h1 data-start=\"144\" data-end=\"183\"><strong data-start=\"146\" data-end=\"183\">Accounting &amp; Bookkeeping Services</strong></h1>\r\n<hr data-start=\"185\" data-end=\"188\">\r\n<h3 data-start=\"190\" data-end=\"206\"><strong data-start=\"194\" data-end=\"206\">Overview</strong></h3>\r\n<p data-start=\"208\" data-end=\"441\">Accurate accounting is the foundation of every successful business. Whether you are a startup, small enterprise, or growing company, maintaining clear and compliant financial records is essential for long-term stability and growth.</p>\r\n<p data-start=\"443\" data-end=\"747\">At <strong data-start=\"446\" data-end=\"467\">Rajasthan Filings</strong>, we provide complete Accounting &amp; Bookkeeping solutions designed to simplify your finances and keep your business fully compliant with Indian tax and regulatory laws. Our goal is to give you real-time control over your accounts &mdash; without the complexity of managing them in-house.</p>\r\n<hr data-start=\"749\" data-end=\"752\">\r\n<h3 data-start=\"754\" data-end=\"795\"><strong data-start=\"758\" data-end=\"795\">What Is Accounting &amp; Bookkeeping?</strong></h3>\r\n<ul data-start=\"797\" data-end=\"1083\">\r\n<li data-start=\"797\" data-end=\"915\">\r\n<p data-start=\"799\" data-end=\"915\"><strong data-start=\"799\" data-end=\"814\">Bookkeeping</strong> means recording day-to-day business transactions such as sales, purchases, receipts, and payments.</p>\r\n</li>\r\n<li data-start=\"916\" data-end=\"1083\">\r\n<p data-start=\"918\" data-end=\"1083\"><strong data-start=\"918\" data-end=\"932\">Accounting</strong> involves interpreting that data, preparing financial statements, analyzing performance, and ensuring compliance with tax and statutory requirements.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1085\" data-end=\"1250\">Together, they provide an accurate picture of your business&rsquo;s financial position &mdash; enabling better decision-making, cash-flow management, and profitability tracking.</p>\r\n<hr data-start=\"1252\" data-end=\"1255\">\r\n<h3 data-start=\"1257\" data-end=\"1300\"><strong data-start=\"1261\" data-end=\"1300\">Why Accounting &amp; Bookkeeping Matter</strong></h3>\r\n<ol data-start=\"1302\" data-end=\"1589\">\r\n<li data-start=\"1302\" data-end=\"1365\">\r\n<p data-start=\"1305\" data-end=\"1365\">Keeps your business financially organized and audit-ready.</p>\r\n</li>\r\n<li data-start=\"1366\" data-end=\"1426\">\r\n<p data-start=\"1369\" data-end=\"1426\">Helps you monitor income, expenses, and profit margins.</p>\r\n</li>\r\n<li data-start=\"1427\" data-end=\"1486\">\r\n<p data-start=\"1430\" data-end=\"1486\">Ensures accurate tax calculations and on-time filings.</p>\r\n</li>\r\n<li data-start=\"1487\" data-end=\"1530\">\r\n<p data-start=\"1490\" data-end=\"1530\">Builds investor and lender confidence.</p>\r\n</li>\r\n<li data-start=\"1531\" data-end=\"1589\">\r\n<p data-start=\"1534\" data-end=\"1589\">Provides financial insights for expansion or funding.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"1591\" data-end=\"1594\">\r\n<h3 data-start=\"1596\" data-end=\"1621\"><strong data-start=\"1600\" data-end=\"1621\">Services We Offer</strong></h3>\r\n<ol data-start=\"1623\" data-end=\"2588\">\r\n<li data-start=\"1623\" data-end=\"1715\">\r\n<p data-start=\"1626\" data-end=\"1715\"><strong data-start=\"1626\" data-end=\"1647\">Daily Bookkeeping</strong> &ndash; Recording of all sales, purchase, payment, and receipt entries.</p>\r\n</li>\r\n<li data-start=\"1716\" data-end=\"1809\">\r\n<p data-start=\"1719\" data-end=\"1809\"><strong data-start=\"1719\" data-end=\"1741\">Ledger Maintenance</strong> &ndash; Complete management of customer, supplier, and general ledgers.</p>\r\n</li>\r\n<li data-start=\"1810\" data-end=\"1901\">\r\n<p data-start=\"1813\" data-end=\"1901\"><strong data-start=\"1813\" data-end=\"1836\">Bank Reconciliation</strong> &ndash; Monthly matching of bank statements with accounting records.</p>\r\n</li>\r\n<li data-start=\"1902\" data-end=\"1996\">\r\n<p data-start=\"1905\" data-end=\"1996\"><strong data-start=\"1905\" data-end=\"1949\">Accounts Payable / Receivable Management</strong> &ndash; Tracking dues and collections efficiently.</p>\r\n</li>\r\n<li data-start=\"1997\" data-end=\"2089\">\r\n<p data-start=\"2000\" data-end=\"2089\"><strong data-start=\"2000\" data-end=\"2029\">Monthly Financial Reports</strong> &ndash; Profit &amp; Loss, Balance Sheet, and Cash-Flow statements.</p>\r\n</li>\r\n<li data-start=\"2090\" data-end=\"2197\">\r\n<p data-start=\"2093\" data-end=\"2197\"><strong data-start=\"2093\" data-end=\"2125\">Inventory &amp; Asset Accounting</strong> &ndash; Recording depreciation, fixed-asset schedules, and stock valuation.</p>\r\n</li>\r\n<li data-start=\"2198\" data-end=\"2293\">\r\n<p data-start=\"2201\" data-end=\"2293\"><strong data-start=\"2201\" data-end=\"2225\">GST &amp; TDS Accounting</strong> &ndash; Integration of indirect-tax transactions for smooth compliance.</p>\r\n</li>\r\n<li data-start=\"2294\" data-end=\"2389\">\r\n<p data-start=\"2297\" data-end=\"2389\"><strong data-start=\"2297\" data-end=\"2328\">Payroll &amp; Salary Processing</strong> &ndash; Managing employee pay, PF/ESI, and statutory deductions.</p>\r\n</li>\r\n<li data-start=\"2390\" data-end=\"2485\">\r\n<p data-start=\"2393\" data-end=\"2485\"><strong data-start=\"2393\" data-end=\"2421\">MIS &amp; Management Reports</strong> &ndash; Customized analytical reports for internal decision-making.</p>\r\n</li>\r\n<li data-start=\"2486\" data-end=\"2588\">\r\n<p data-start=\"2490\" data-end=\"2588\"><strong data-start=\"2490\" data-end=\"2524\">Final Accounts &amp; Audit Support</strong> &ndash; Preparation of annual accounts for CA audit and ITR filing.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"2590\" data-end=\"2593\">\r\n<h3 data-start=\"2595\" data-end=\"2645\"><strong data-start=\"2599\" data-end=\"2645\">Who Needs Professional Accounting Services</strong></h3>\r\n<ul data-start=\"2647\" data-end=\"2832\">\r\n<li data-start=\"2647\" data-end=\"2688\">\r\n<p data-start=\"2649\" data-end=\"2688\">Proprietorships and Partnership Firms</p>\r\n</li>\r\n<li data-start=\"2689\" data-end=\"2727\">\r\n<p data-start=\"2691\" data-end=\"2727\">LLPs and Private Limited Companies</p>\r\n</li>\r\n<li data-start=\"2728\" data-end=\"2777\">\r\n<p data-start=\"2730\" data-end=\"2777\">Traders, Manufacturers, and Service Providers</p>\r\n</li>\r\n<li data-start=\"2778\" data-end=\"2800\">\r\n<p data-start=\"2780\" data-end=\"2800\">Startups and MSMEs</p>\r\n</li>\r\n<li data-start=\"2801\" data-end=\"2832\">\r\n<p data-start=\"2803\" data-end=\"2832\">NGOs, Trusts, and Societies</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2834\" data-end=\"2955\">Even freelancers, professionals, and small businesses benefit from structured bookkeeping and periodic financial reports.</p>\r\n<hr data-start=\"2957\" data-end=\"2960\">\r\n<h3 data-start=\"2962\" data-end=\"3025\"><strong data-start=\"2966\" data-end=\"3025\">Benefits of Outsourcing Accounting to Rajasthan Filings</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3027\" data-end=\"3514\">\r\n<thead data-start=\"3027\" data-end=\"3060\">\r\n<tr data-start=\"3027\" data-end=\"3060\">\r\n<th data-start=\"3027\" data-end=\"3041\" data-col-size=\"sm\"><strong data-start=\"3029\" data-end=\"3040\">Benefit</strong></th>\r\n<th data-start=\"3041\" data-end=\"3060\" data-col-size=\"md\"><strong data-start=\"3043\" data-end=\"3058\">Description</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3095\" data-end=\"3514\">\r\n<tr data-start=\"3095\" data-end=\"3175\">\r\n<td data-start=\"3095\" data-end=\"3124\" data-col-size=\"sm\"><strong data-start=\"3097\" data-end=\"3123\">Time &amp; Cost Efficiency</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3124\" data-end=\"3175\">Saves the cost of hiring full-time accountants.</td>\r\n</tr>\r\n<tr data-start=\"3176\" data-end=\"3279\">\r\n<td data-start=\"3176\" data-end=\"3204\" data-col-size=\"sm\"><strong data-start=\"3178\" data-end=\"3203\">Accuracy &amp; Compliance</strong></td>\r\n<td data-start=\"3204\" data-end=\"3279\" data-col-size=\"md\">Eliminates manual errors and ensures adherence to accounting standards.</td>\r\n</tr>\r\n<tr data-start=\"3280\" data-end=\"3364\">\r\n<td data-start=\"3280\" data-end=\"3300\" data-col-size=\"sm\"><strong data-start=\"3282\" data-end=\"3299\">Data Security</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3300\" data-end=\"3364\">All data handled confidentially with secure digital systems.</td>\r\n</tr>\r\n<tr data-start=\"3365\" data-end=\"3424\">\r\n<td data-start=\"3365\" data-end=\"3383\" data-col-size=\"sm\"><strong data-start=\"3367\" data-end=\"3382\">Scalability</strong></td>\r\n<td data-start=\"3383\" data-end=\"3424\" data-col-size=\"md\">Services can grow with your business.</td>\r\n</tr>\r\n<tr data-start=\"3425\" data-end=\"3514\">\r\n<td data-start=\"3425\" data-end=\"3445\" data-col-size=\"sm\"><strong data-start=\"3427\" data-end=\"3444\">Expert Review</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3445\" data-end=\"3514\">Every statement cross-checked by experienced accountants and CAs.</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3516\" data-end=\"3519\">\r\n<h3 data-start=\"3521\" data-end=\"3546\"><strong data-start=\"3525\" data-end=\"3546\">Our Work Approach</strong></h3>\r\n<ol data-start=\"3548\" data-end=\"3994\">\r\n<li data-start=\"3548\" data-end=\"3631\">\r\n<p data-start=\"3551\" data-end=\"3631\"><strong data-start=\"3551\" data-end=\"3571\">Data Collection:</strong> You share invoices, bills, and bank statements digitally.</p>\r\n</li>\r\n<li data-start=\"3632\" data-end=\"3720\">\r\n<p data-start=\"3635\" data-end=\"3720\"><strong data-start=\"3635\" data-end=\"3666\">Recording &amp; Reconciliation:</strong> Our team records transactions and matches accounts.</p>\r\n</li>\r\n<li data-start=\"3721\" data-end=\"3808\">\r\n<p data-start=\"3724\" data-end=\"3808\"><strong data-start=\"3724\" data-end=\"3747\">Review &amp; Reporting:</strong> We generate detailed MIS and monthly financial statements.</p>\r\n</li>\r\n<li data-start=\"3809\" data-end=\"3904\">\r\n<p data-start=\"3812\" data-end=\"3904\"><strong data-start=\"3812\" data-end=\"3836\">Compliance &amp; Filing:</strong> All reports are integrated with GST, TDS, and Income-Tax returns.</p>\r\n</li>\r\n<li data-start=\"3905\" data-end=\"3994\">\r\n<p data-start=\"3908\" data-end=\"3994\"><strong data-start=\"3908\" data-end=\"3929\">Advisory Support:</strong> Regular review meetings for performance insights and planning.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3996\" data-end=\"3999\">\r\n<h3 data-start=\"4001\" data-end=\"4027\"><strong data-start=\"4005\" data-end=\"4027\">Documents Required</strong></h3>\r\n<ul data-start=\"4029\" data-end=\"4259\">\r\n<li data-start=\"4029\" data-end=\"4081\">\r\n<p data-start=\"4031\" data-end=\"4081\">Business registration documents (GST, PAN, etc.)</p>\r\n</li>\r\n<li data-start=\"4082\" data-end=\"4113\">\r\n<p data-start=\"4084\" data-end=\"4113\">Sales and purchase invoices</p>\r\n</li>\r\n<li data-start=\"4114\" data-end=\"4144\">\r\n<p data-start=\"4116\" data-end=\"4144\">Expense bills and vouchers</p>\r\n</li>\r\n<li data-start=\"4145\" data-end=\"4183\">\r\n<p data-start=\"4147\" data-end=\"4183\">Bank statements and cheque details</p>\r\n</li>\r\n<li data-start=\"4184\" data-end=\"4213\">\r\n<p data-start=\"4186\" data-end=\"4213\">Employee and payroll data</p>\r\n</li>\r\n<li data-start=\"4214\" data-end=\"4259\">\r\n<p data-start=\"4216\" data-end=\"4259\">Previous financial records (if available)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4261\" data-end=\"4264\">\r\n<h3 data-start=\"4266\" data-end=\"4293\"><strong data-start=\"4270\" data-end=\"4293\">Industries We Serve</strong></h3>\r\n<ul data-start=\"4295\" data-end=\"4479\">\r\n<li data-start=\"4295\" data-end=\"4323\">\r\n<p data-start=\"4297\" data-end=\"4323\">Retail &amp; Wholesale Trade</p>\r\n</li>\r\n<li data-start=\"4324\" data-end=\"4356\">\r\n<p data-start=\"4326\" data-end=\"4356\">Manufacturing &amp; Construction</p>\r\n</li>\r\n<li data-start=\"4357\" data-end=\"4382\">\r\n<p data-start=\"4359\" data-end=\"4382\">Transport &amp; Logistics</p>\r\n</li>\r\n<li data-start=\"4383\" data-end=\"4409\">\r\n<p data-start=\"4385\" data-end=\"4409\">IT &amp; Consultancy Firms</p>\r\n</li>\r\n<li data-start=\"4410\" data-end=\"4434\">\r\n<p data-start=\"4412\" data-end=\"4434\">Hotels &amp; Restaurants</p>\r\n</li>\r\n<li data-start=\"4435\" data-end=\"4461\">\r\n<p data-start=\"4437\" data-end=\"4461\">Healthcare &amp; Education</p>\r\n</li>\r\n<li data-start=\"4462\" data-end=\"4479\">\r\n<p data-start=\"4464\" data-end=\"4479\">NGOs &amp; Trusts</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4481\" data-end=\"4577\">Each industry follows specific accounting patterns &mdash; and our experts tailor systems accordingly.</p>\r\n<hr data-start=\"4579\" data-end=\"4582\">\r\n<h3 data-start=\"4584\" data-end=\"4610\"><strong data-start=\"4588\" data-end=\"4610\">Compliance Support</strong></h3>\r\n<p data-start=\"4612\" data-end=\"4680\">Our accounting services are designed to integrate seamlessly with:</p>\r\n<ul data-start=\"4681\" data-end=\"4884\">\r\n<li data-start=\"4681\" data-end=\"4722\">\r\n<p data-start=\"4683\" data-end=\"4722\"><strong data-start=\"4683\" data-end=\"4720\">GST Return Filing (GSTR-1, 3B, 9)</strong></p>\r\n</li>\r\n<li data-start=\"4723\" data-end=\"4750\">\r\n<p data-start=\"4725\" data-end=\"4750\"><strong data-start=\"4725\" data-end=\"4748\">TDS &amp; TCS Reporting</strong></p>\r\n</li>\r\n<li data-start=\"4751\" data-end=\"4794\">\r\n<p data-start=\"4753\" data-end=\"4794\"><strong data-start=\"4753\" data-end=\"4792\">Income-Tax Computation &amp; ITR Filing</strong></p>\r\n</li>\r\n<li data-start=\"4795\" data-end=\"4835\">\r\n<p data-start=\"4797\" data-end=\"4835\"><strong data-start=\"4797\" data-end=\"4833\">ROC Filings for Companies &amp; LLPs</strong></p>\r\n</li>\r\n<li data-start=\"4836\" data-end=\"4884\">\r\n<p data-start=\"4838\" data-end=\"4884\"><strong data-start=\"4838\" data-end=\"4884\">Audit and Statutory Reporting Requirements</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4886\" data-end=\"4889\">\r\n<h3 data-start=\"4891\" data-end=\"4927\"><strong data-start=\"4895\" data-end=\"4927\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"4929\" data-end=\"5206\">\r\n<li data-start=\"4929\" data-end=\"4987\">\r\n<p data-start=\"4931\" data-end=\"4987\">Experienced Chartered Accountants and Finance Experts.</p>\r\n</li>\r\n<li data-start=\"4988\" data-end=\"5046\">\r\n<p data-start=\"4990\" data-end=\"5046\">End-to-end online support for businesses across India.</p>\r\n</li>\r\n<li data-start=\"5047\" data-end=\"5093\">\r\n<p data-start=\"5049\" data-end=\"5093\">Transparent pricing and monthly reporting.</p>\r\n</li>\r\n<li data-start=\"5094\" data-end=\"5154\">\r\n<p data-start=\"5096\" data-end=\"5154\">Regular compliance reminders and real-time coordination.</p>\r\n</li>\r\n<li data-start=\"5155\" data-end=\"5206\">\r\n<p data-start=\"5157\" data-end=\"5206\">Dedicated relationship manager for each client.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5208\" data-end=\"5346\">We ensure your accounts are updated, compliant, and audit-ready &mdash; giving you peace of mind and a clear picture of your financial progress.</p>\r\n<hr data-start=\"5348\" data-end=\"5351\">\r\n<h3 data-start=\"5353\" data-end=\"5371\"><strong data-start=\"5357\" data-end=\"5371\">Conclusion</strong></h3>\r\n<p data-start=\"5373\" data-end=\"5626\">Reliable accounting isn&rsquo;t just about numbers &mdash; it&rsquo;s about clarity, control, and compliance.<br data-start=\"5464\" data-end=\"5467\">At <strong data-start=\"5470\" data-end=\"5491\">Rajasthan Filings</strong>, we handle your accounting and bookkeeping professionally so that you can focus on running your business, not managing spreadsheets.</p>\r\n<p data-start=\"5628\" data-end=\"5716\">Partner with us for accurate books, timely reports, and complete financial discipline.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:51:31', '2025-11-08 00:52:14');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(18, 4, NULL, 'Net-Worth / Turnover Certificates', 'net-worth--turnover-certificates', 'Net-Worth / Turnover Certificates', '<h1 data-start=\"140\" data-end=\"179\"><strong data-start=\"142\" data-end=\"179\">Net Worth / Turnover Certificates</strong></h1>\r\n<hr data-start=\"181\" data-end=\"184\">\r\n<h3 data-start=\"186\" data-end=\"202\"><strong data-start=\"190\" data-end=\"202\">Overview</strong></h3>\r\n<p data-start=\"204\" data-end=\"584\">A <strong data-start=\"206\" data-end=\"231\">Net Worth Certificate</strong> or <strong data-start=\"235\" data-end=\"259\">Turnover Certificate</strong> is an official financial document that reflects the true financial position and business strength of an individual, firm, or company.<br data-start=\"393\" data-end=\"396\">These certificates are often required by <strong data-start=\"437\" data-end=\"525\">banks, financial institutions, government departments, tenders, and visa authorities</strong> to verify your economic capability and creditworthiness.</p>\r\n<p data-start=\"586\" data-end=\"808\">At <strong data-start=\"589\" data-end=\"610\">Rajasthan Filings</strong>, our team of Chartered Accountants and financial professionals prepare accurate and authentic certificates that are accepted by all banks, tendering authorities, and government bodies across India.</p>\r\n<hr data-start=\"810\" data-end=\"813\">\r\n<h3 data-start=\"815\" data-end=\"855\"><strong data-start=\"819\" data-end=\"855\">What is a Net Worth Certificate?</strong></h3>\r\n<p data-start=\"857\" data-end=\"1056\">A <strong data-start=\"859\" data-end=\"884\">Net Worth Certificate</strong> represents the total value of an individual&rsquo;s or entity&rsquo;s assets after deducting all liabilities. It is the measure of your <strong data-start=\"1009\" data-end=\"1037\">overall financial health</strong> at a given date.</p>\r\n<p data-start=\"1058\" data-end=\"1287\">It includes the valuation of all movable and immovable assets such as land, buildings, vehicles, cash, bank balances, fixed deposits, investments, gold, and business assets &mdash; minus liabilities like loans, overdrafts, or payables.</p>\r\n<p data-start=\"1289\" data-end=\"1303\"><strong data-start=\"1289\" data-end=\"1301\">Formula:</strong></p>\r\n<blockquote data-start=\"1304\" data-end=\"1354\">\r\n<p data-start=\"1306\" data-end=\"1354\"><strong data-start=\"1306\" data-end=\"1354\">Net Worth = Total Assets &ndash; Total Liabilities</strong></p>\r\n</blockquote>\r\n<p data-start=\"1356\" data-end=\"1497\">This certificate is generally issued by a Chartered Accountant based on verified financial records, balance sheets, and supporting documents.</p>\r\n<hr data-start=\"1499\" data-end=\"1502\">\r\n<h3 data-start=\"1504\" data-end=\"1543\"><strong data-start=\"1508\" data-end=\"1543\">What is a Turnover Certificate?</strong></h3>\r\n<p data-start=\"1545\" data-end=\"1762\">A <strong data-start=\"1547\" data-end=\"1571\">Turnover Certificate</strong> certifies the total sales or business turnover of an entity during a specific financial period.<br data-start=\"1667\" data-end=\"1670\">It is commonly required by government departments, contractors, or private clients during:</p>\r\n<ul data-start=\"1763\" data-end=\"1905\">\r\n<li data-start=\"1763\" data-end=\"1786\">\r\n<p data-start=\"1765\" data-end=\"1786\">Tender applications</p>\r\n</li>\r\n<li data-start=\"1787\" data-end=\"1811\">\r\n<p data-start=\"1789\" data-end=\"1811\">Bank loan processing</p>\r\n</li>\r\n<li data-start=\"1812\" data-end=\"1831\">\r\n<p data-start=\"1814\" data-end=\"1831\">Project bidding</p>\r\n</li>\r\n<li data-start=\"1832\" data-end=\"1866\">\r\n<p data-start=\"1834\" data-end=\"1866\">Visa and embassy documentation</p>\r\n</li>\r\n<li data-start=\"1867\" data-end=\"1905\">\r\n<p data-start=\"1869\" data-end=\"1905\">Franchise and dealership approvals</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1907\" data-end=\"2016\">The certificate provides a clear picture of your business operations and performance during a financial year.</p>\r\n<hr data-start=\"2018\" data-end=\"2021\">\r\n<h3 data-start=\"2023\" data-end=\"2080\"><strong data-start=\"2027\" data-end=\"2080\">Importance of Net Worth and Turnover Certificates</strong></h3>\r\n<ol data-start=\"2082\" data-end=\"2478\">\r\n<li data-start=\"2082\" data-end=\"2156\">\r\n<p data-start=\"2085\" data-end=\"2156\"><strong data-start=\"2085\" data-end=\"2104\">For Bank Loans:</strong> Proves financial capacity and repayment strength.</p>\r\n</li>\r\n<li data-start=\"2157\" data-end=\"2240\">\r\n<p data-start=\"2160\" data-end=\"2240\"><strong data-start=\"2160\" data-end=\"2187\">For Government Tenders:</strong> Demonstrates eligibility based on turnover limits.</p>\r\n</li>\r\n<li data-start=\"2241\" data-end=\"2316\">\r\n<p data-start=\"2244\" data-end=\"2316\"><strong data-start=\"2244\" data-end=\"2271\">For Visa / Immigration:</strong> Serves as a proof of financial background.</p>\r\n</li>\r\n<li data-start=\"2317\" data-end=\"2391\">\r\n<p data-start=\"2320\" data-end=\"2391\"><strong data-start=\"2320\" data-end=\"2347\">For Company Evaluation:</strong> Shows stability and business credibility.</p>\r\n</li>\r\n<li data-start=\"2392\" data-end=\"2478\">\r\n<p data-start=\"2395\" data-end=\"2478\"><strong data-start=\"2395\" data-end=\"2420\">For Personal Finance:</strong> Reflects real-time wealth position for future planning.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"2480\" data-end=\"2483\">\r\n<h3 data-start=\"2485\" data-end=\"2534\"><strong data-start=\"2489\" data-end=\"2534\">Key Components of a Net Worth Certificate</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2536\" data-end=\"3042\">\r\n<thead data-start=\"2536\" data-end=\"2600\">\r\n<tr data-start=\"2536\" data-end=\"2600\">\r\n<th data-start=\"2536\" data-end=\"2551\" data-col-size=\"sm\"><strong data-start=\"2538\" data-end=\"2550\">Category</strong></th>\r\n<th data-start=\"2551\" data-end=\"2600\" data-col-size=\"md\"><strong data-start=\"2553\" data-end=\"2598\">Examples of Assets / Liabilities Included</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2667\" data-end=\"3042\">\r\n<tr data-start=\"2667\" data-end=\"2743\">\r\n<td data-start=\"2667\" data-end=\"2688\" data-col-size=\"sm\"><strong data-start=\"2669\" data-end=\"2687\">Movable Assets</strong></td>\r\n<td data-start=\"2688\" data-end=\"2743\" data-col-size=\"md\">Bank Balance, FDs, Shares, Mutual Funds, Cash, Gold</td>\r\n</tr>\r\n<tr data-start=\"2744\" data-end=\"2820\">\r\n<td data-start=\"2744\" data-end=\"2767\" data-col-size=\"sm\"><strong data-start=\"2746\" data-end=\"2766\">Immovable Assets</strong></td>\r\n<td data-start=\"2767\" data-end=\"2820\" data-col-size=\"md\">Land, Building, Residential / Commercial Property</td>\r\n</tr>\r\n<tr data-start=\"2821\" data-end=\"2898\">\r\n<td data-start=\"2821\" data-end=\"2848\" data-col-size=\"sm\"><strong data-start=\"2823\" data-end=\"2847\">Business Investments</strong></td>\r\n<td data-start=\"2848\" data-end=\"2898\" data-col-size=\"md\">Capital in Firm, Machinery, Stock, Receivables</td>\r\n</tr>\r\n<tr data-start=\"2899\" data-end=\"2966\">\r\n<td data-start=\"2899\" data-end=\"2921\" data-col-size=\"sm\"><strong data-start=\"2901\" data-end=\"2920\">Personal Assets</strong></td>\r\n<td data-start=\"2921\" data-end=\"2966\" data-col-size=\"md\">Vehicles, Jewellery, Furniture, Art, etc.</td>\r\n</tr>\r\n<tr data-start=\"2967\" data-end=\"3042\">\r\n<td data-start=\"2967\" data-end=\"2985\" data-col-size=\"sm\"><strong data-start=\"2969\" data-end=\"2984\">Liabilities</strong></td>\r\n<td data-start=\"2985\" data-end=\"3042\" data-col-size=\"md\">Bank Loans, OD/CC Limits, Creditors, Outstanding EMIs</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"3044\" data-end=\"3162\">After evaluating all details, a Chartered Accountant certifies the <strong data-start=\"3111\" data-end=\"3137\">net financial position</strong> as of a particular date.</p>\r\n<hr data-start=\"3164\" data-end=\"3167\">\r\n<h3 data-start=\"3169\" data-end=\"3217\"><strong data-start=\"3173\" data-end=\"3217\">Key Components of a Turnover Certificate</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"3219\" data-end=\"3676\">\r\n<thead data-start=\"3219\" data-end=\"3273\">\r\n<tr data-start=\"3219\" data-end=\"3273\">\r\n<th data-start=\"3219\" data-end=\"3237\" data-col-size=\"sm\"><strong data-start=\"3221\" data-end=\"3236\">Particulars</strong></th>\r\n<th data-start=\"3237\" data-end=\"3273\" data-col-size=\"md\"><strong data-start=\"3239\" data-end=\"3271\">Details Shown in Certificate</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3330\" data-end=\"3676\">\r\n<tr data-start=\"3330\" data-end=\"3378\">\r\n<td data-start=\"3330\" data-end=\"3353\" data-col-size=\"sm\">Business / Firm Name</td>\r\n<td data-start=\"3353\" data-end=\"3378\" data-col-size=\"md\">Registered Legal Name</td>\r\n</tr>\r\n<tr data-start=\"3379\" data-end=\"3433\">\r\n<td data-start=\"3379\" data-end=\"3396\" data-col-size=\"sm\">Financial Year</td>\r\n<td data-start=\"3396\" data-end=\"3433\" data-col-size=\"md\">Period Covered (e.g., FY 2023&ndash;24)</td>\r\n</tr>\r\n<tr data-start=\"3434\" data-end=\"3481\">\r\n<td data-start=\"3434\" data-end=\"3455\" data-col-size=\"sm\">Nature of Business</td>\r\n<td data-start=\"3455\" data-end=\"3481\" data-col-size=\"md\">Product / Service Type</td>\r\n</tr>\r\n<tr data-start=\"3482\" data-end=\"3530\">\r\n<td data-start=\"3482\" data-end=\"3502\" data-col-size=\"sm\">Total Sales Value</td>\r\n<td data-start=\"3502\" data-end=\"3530\" data-col-size=\"md\">As per Books of Accounts</td>\r\n</tr>\r\n<tr data-start=\"3531\" data-end=\"3600\">\r\n<td data-start=\"3531\" data-end=\"3552\" data-col-size=\"sm\">Verification Basis</td>\r\n<td data-start=\"3552\" data-end=\"3600\" data-col-size=\"md\">GST Returns, P&amp;L Account, and Ledger Summary</td>\r\n</tr>\r\n<tr data-start=\"3601\" data-end=\"3676\">\r\n<td data-start=\"3601\" data-end=\"3619\" data-col-size=\"sm\">CA Verification</td>\r\n<td data-start=\"3619\" data-end=\"3676\" data-col-size=\"md\">Signed and Stamped by Practicing Chartered Accountant</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"3678\" data-end=\"3681\">\r\n<h3 data-start=\"3683\" data-end=\"3709\"><strong data-start=\"3687\" data-end=\"3709\">Documents Required</strong></h3>\r\n<h4 data-start=\"3711\" data-end=\"3742\">For Net Worth Certificate:</h4>\r\n<ul data-start=\"3743\" data-end=\"3996\">\r\n<li data-start=\"3743\" data-end=\"3786\">\r\n<p data-start=\"3745\" data-end=\"3786\">PAN and Aadhaar of individual or entity</p>\r\n</li>\r\n<li data-start=\"3787\" data-end=\"3819\">\r\n<p data-start=\"3789\" data-end=\"3819\">Latest ITR and Balance Sheet</p>\r\n</li>\r\n<li data-start=\"3820\" data-end=\"3865\">\r\n<p data-start=\"3822\" data-end=\"3865\">Bank Statements and Fixed Deposit Details</p>\r\n</li>\r\n<li data-start=\"3866\" data-end=\"3911\">\r\n<p data-start=\"3868\" data-end=\"3911\">Property Valuation Reports (if available)</p>\r\n</li>\r\n<li data-start=\"3912\" data-end=\"3967\">\r\n<p data-start=\"3914\" data-end=\"3967\">Investment proofs (Shares, Mutual Funds, LIC, etc.)</p>\r\n</li>\r\n<li data-start=\"3968\" data-end=\"3996\">\r\n<p data-start=\"3970\" data-end=\"3996\">Loan / Liability details</p>\r\n</li>\r\n</ul>\r\n<h4 data-start=\"3998\" data-end=\"4028\">For Turnover Certificate:</h4>\r\n<ul data-start=\"4029\" data-end=\"4284\">\r\n<li data-start=\"4029\" data-end=\"4082\">\r\n<p data-start=\"4031\" data-end=\"4082\">Audited Financial Statements or Books of Accounts</p>\r\n</li>\r\n<li data-start=\"4083\" data-end=\"4139\">\r\n<p data-start=\"4085\" data-end=\"4139\">GSTR-3B and GSTR-1 Summary (if registered under GST)</p>\r\n</li>\r\n<li data-start=\"4140\" data-end=\"4178\">\r\n<p data-start=\"4142\" data-end=\"4178\">Bank Statement reflecting receipts</p>\r\n</li>\r\n<li data-start=\"4179\" data-end=\"4222\">\r\n<p data-start=\"4181\" data-end=\"4222\">Income Tax Return for the relevant year</p>\r\n</li>\r\n<li data-start=\"4223\" data-end=\"4284\">\r\n<p data-start=\"4225\" data-end=\"4284\">Any tender / project requirement document (if applicable)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4286\" data-end=\"4289\">\r\n<h3 data-start=\"4291\" data-end=\"4331\"><strong data-start=\"4295\" data-end=\"4331\">When You Need These Certificates</strong></h3>\r\n<ul data-start=\"4333\" data-end=\"4663\">\r\n<li data-start=\"4333\" data-end=\"4389\">\r\n<p data-start=\"4335\" data-end=\"4389\">Applying for <strong data-start=\"4348\" data-end=\"4387\">Bank Loan / Cash Credit / OD Limits</strong></p>\r\n</li>\r\n<li data-start=\"4390\" data-end=\"4444\">\r\n<p data-start=\"4392\" data-end=\"4444\">Participating in <strong data-start=\"4409\" data-end=\"4442\">Government or Private Tenders</strong></p>\r\n</li>\r\n<li data-start=\"4445\" data-end=\"4489\">\r\n<p data-start=\"4447\" data-end=\"4489\">Seeking <strong data-start=\"4455\" data-end=\"4487\">Visa or Immigration Approval</strong></p>\r\n</li>\r\n<li data-start=\"4490\" data-end=\"4546\">\r\n<p data-start=\"4492\" data-end=\"4546\">Establishing <strong data-start=\"4505\" data-end=\"4544\">Business Partnerships or Franchises</strong></p>\r\n</li>\r\n<li data-start=\"4547\" data-end=\"4604\">\r\n<p data-start=\"4549\" data-end=\"4604\">Submitting to <strong data-start=\"4563\" data-end=\"4602\">Financial Institutions or Investors</strong></p>\r\n</li>\r\n<li data-start=\"4605\" data-end=\"4663\">\r\n<p data-start=\"4607\" data-end=\"4663\">Filing documents for <strong data-start=\"4628\" data-end=\"4661\">Company Evaluation or Mergers</strong></p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4665\" data-end=\"4668\">\r\n<h3 data-start=\"4670\" data-end=\"4715\"><strong data-start=\"4674\" data-end=\"4715\">Process Followed by Rajasthan Filings</strong></h3>\r\n<ol data-start=\"4717\" data-end=\"5136\">\r\n<li data-start=\"4717\" data-end=\"4793\">\r\n<p data-start=\"4720\" data-end=\"4793\"><strong data-start=\"4720\" data-end=\"4740\">Data Collection:</strong> We collect financial statements and asset details.</p>\r\n</li>\r\n<li data-start=\"4794\" data-end=\"4876\">\r\n<p data-start=\"4797\" data-end=\"4876\"><strong data-start=\"4797\" data-end=\"4814\">Verification:</strong> Our CA team verifies ownership, valuation, and liabilities.</p>\r\n</li>\r\n<li data-start=\"4877\" data-end=\"4945\">\r\n<p data-start=\"4880\" data-end=\"4945\"><strong data-start=\"4880\" data-end=\"4896\">Computation:</strong> Accurate calculation of net worth or turnover.</p>\r\n</li>\r\n<li data-start=\"4946\" data-end=\"5014\">\r\n<p data-start=\"4949\" data-end=\"5014\"><strong data-start=\"4949\" data-end=\"4974\">Certificate Drafting:</strong> Professionally prepared in CA format.</p>\r\n</li>\r\n<li data-start=\"5015\" data-end=\"5136\">\r\n<p data-start=\"5018\" data-end=\"5136\"><strong data-start=\"5018\" data-end=\"5040\">Review &amp; Delivery:</strong> Digitally signed and sealed certificate delivered in PDF format (and physical copy on request).</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"5138\" data-end=\"5141\">\r\n<h3 data-start=\"5143\" data-end=\"5207\"><strong data-start=\"5147\" data-end=\"5207\">Benefits of Getting a Certificate from Rajasthan Filings</strong></h3>\r\n<ul data-start=\"5209\" data-end=\"5523\">\r\n<li data-start=\"5209\" data-end=\"5256\">\r\n<p data-start=\"5211\" data-end=\"5256\">100% CA-certified and bank-accepted format.</p>\r\n</li>\r\n<li data-start=\"5257\" data-end=\"5308\">\r\n<p data-start=\"5259\" data-end=\"5308\">Accurate valuation and transparent computation.</p>\r\n</li>\r\n<li data-start=\"5309\" data-end=\"5359\">\r\n<p data-start=\"5311\" data-end=\"5359\">Fast preparation (usually within 24&ndash;48 hours).</p>\r\n</li>\r\n<li data-start=\"5360\" data-end=\"5416\">\r\n<p data-start=\"5362\" data-end=\"5416\">Accepted by all government and private institutions.</p>\r\n</li>\r\n<li data-start=\"5417\" data-end=\"5473\">\r\n<p data-start=\"5419\" data-end=\"5473\">Useful for multiple official and financial purposes.</p>\r\n</li>\r\n<li data-start=\"5474\" data-end=\"5523\">\r\n<p data-start=\"5476\" data-end=\"5523\">Both digital and hard copy formats available.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5525\" data-end=\"5528\">\r\n<h3 data-start=\"5530\" data-end=\"5566\"><strong data-start=\"5534\" data-end=\"5566\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"5568\" data-end=\"5891\">\r\n<li data-start=\"5568\" data-end=\"5637\">\r\n<p data-start=\"5570\" data-end=\"5637\">Experienced team of Chartered Accountants and financial analysts.</p>\r\n</li>\r\n<li data-start=\"5638\" data-end=\"5709\">\r\n<p data-start=\"5640\" data-end=\"5709\">Trusted by thousands of businesses, professionals, and individuals.</p>\r\n</li>\r\n<li data-start=\"5710\" data-end=\"5771\">\r\n<p data-start=\"5712\" data-end=\"5771\">PAN India service with simple online document submission.</p>\r\n</li>\r\n<li data-start=\"5772\" data-end=\"5825\">\r\n<p data-start=\"5774\" data-end=\"5825\">High accuracy, confidentiality, and authenticity.</p>\r\n</li>\r\n<li data-start=\"5826\" data-end=\"5891\">\r\n<p data-start=\"5828\" data-end=\"5891\">Free consultation for selecting the correct certificate type.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5893\" data-end=\"6064\">Our certificates are professionally drafted, legally valid, and tailored to your specific requirement &mdash; whether for personal finance, tenders, or institutional compliance.</p>\r\n<hr data-start=\"6066\" data-end=\"6069\">\r\n<h3 data-start=\"6071\" data-end=\"6089\"><strong data-start=\"6075\" data-end=\"6089\">Conclusion</strong></h3>\r\n<p data-start=\"6091\" data-end=\"6392\">A <strong data-start=\"6093\" data-end=\"6118\">Net Worth Certificate</strong> or <strong data-start=\"6122\" data-end=\"6146\">Turnover Certificate</strong> is more than a document &mdash; it&rsquo;s a reflection of your financial strength and business credibility.<br data-start=\"6243\" data-end=\"6246\">Having a professionally verified certificate ensures trust, transparency, and confidence when dealing with banks, embassies, or corporate clients.</p>\r\n<p data-start=\"6394\" data-end=\"6585\">At <strong data-start=\"6397\" data-end=\"6418\">Rajasthan Filings</strong>, we make the process fast, simple, and fully compliant with accounting and audit standards.<br data-start=\"6510\" data-end=\"6513\">Get your CA-certified certificate delivered quickly &mdash; anywhere in India.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:51:51', '2025-11-08 00:52:11'),
(20, 1, NULL, 'Digital Signature Certificate (DSC) – Class 3', 'digital-signature-certificate-dsc--class-3', 'Digital Signature Certificate (DSC) – Class 3', '<h1 data-start=\"251\" data-end=\"302\"><strong data-start=\"253\" data-end=\"302\">Digital Signature Certificate (DSC) &ndash; Class 3</strong></h1>\r\n<hr data-start=\"304\" data-end=\"307\">\r\n<h3 data-start=\"309\" data-end=\"325\"><strong data-start=\"313\" data-end=\"325\">Overview</strong></h3>\r\n<p data-start=\"327\" data-end=\"674\">In today&rsquo;s digital era, security and authenticity are everything.<br data-start=\"392\" data-end=\"395\">A <strong data-start=\"397\" data-end=\"436\">Digital Signature Certificate (DSC)</strong> is an encrypted electronic key that verifies your identity online and validates your digital documents. It works as the <strong data-start=\"557\" data-end=\"603\">electronic version of a physical signature</strong> and is legally valid under the <strong data-start=\"635\" data-end=\"671\">Information Technology Act, 2000</strong>.</p>\r\n<p data-start=\"676\" data-end=\"875\">At <strong data-start=\"679\" data-end=\"700\">Rajasthan Filings</strong>, we provide <strong data-start=\"713\" data-end=\"729\">Class 3 DSCs</strong> for individuals, organizations, directors, and professionals &mdash; with fast online processing, eKYC verification, and doorstep delivery of tokens.</p>\r\n<hr data-start=\"877\" data-end=\"880\">\r\n<h3 data-start=\"882\" data-end=\"938\"><strong data-start=\"886\" data-end=\"938\">What Is a Class 3 Digital Signature Certificate?</strong></h3>\r\n<p data-start=\"940\" data-end=\"1130\">A <strong data-start=\"942\" data-end=\"957\">Class 3 DSC</strong> is the <strong data-start=\"965\" data-end=\"1007\">highest level of digital certification</strong> available in India.<br data-start=\"1027\" data-end=\"1030\">It provides enhanced security for online transactions and document signing.<br data-start=\"1105\" data-end=\"1108\">It is mandatory for:</p>\r\n<ul data-start=\"1132\" data-end=\"1435\">\r\n<li data-start=\"1132\" data-end=\"1183\">\r\n<p data-start=\"1134\" data-end=\"1183\">Filing of <strong data-start=\"1144\" data-end=\"1174\">GST, Income-Tax, MCA &amp; ROC</strong> forms.</p>\r\n</li>\r\n<li data-start=\"1184\" data-end=\"1237\">\r\n<p data-start=\"1186\" data-end=\"1237\">Participation in <strong data-start=\"1203\" data-end=\"1234\">e-Tendering &amp; e-Procurement</strong>.</p>\r\n</li>\r\n<li data-start=\"1238\" data-end=\"1291\">\r\n<p data-start=\"1240\" data-end=\"1291\">Filing <strong data-start=\"1247\" data-end=\"1275\">EPFO, DGFT, ICEGATE, GeM</strong> applications.</p>\r\n</li>\r\n<li data-start=\"1292\" data-end=\"1349\">\r\n<p data-start=\"1294\" data-end=\"1349\">Signing <strong data-start=\"1302\" data-end=\"1346\">legal, banking, and government contracts</strong>.</p>\r\n</li>\r\n<li data-start=\"1350\" data-end=\"1435\">\r\n<p data-start=\"1352\" data-end=\"1435\">Directors, authorized signatories, and professionals handling digital compliance.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1437\" data-end=\"1440\">\r\n<h3 data-start=\"1442\" data-end=\"1470\"><strong data-start=\"1446\" data-end=\"1470\">Types of Class 3 DSC</strong></h3>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"1472\" data-end=\"1850\">\r\n<thead data-start=\"1472\" data-end=\"1518\">\r\n<tr data-start=\"1472\" data-end=\"1518\">\r\n<th data-start=\"1472\" data-end=\"1483\" data-col-size=\"sm\"><strong data-start=\"1474\" data-end=\"1482\">Type</strong></th>\r\n<th data-start=\"1483\" data-end=\"1503\" data-col-size=\"md\"><strong data-start=\"1485\" data-end=\"1502\">User Category</strong></th>\r\n<th data-start=\"1503\" data-end=\"1518\" data-col-size=\"sm\"><strong data-start=\"1505\" data-end=\"1516\">Purpose</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"1567\" data-end=\"1850\">\r\n<tr data-start=\"1567\" data-end=\"1665\">\r\n<td data-start=\"1567\" data-end=\"1588\" data-col-size=\"sm\"><strong data-start=\"1569\" data-end=\"1587\">Individual DSC</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1588\" data-end=\"1640\">Used by professionals, directors, and individuals</td>\r\n<td data-col-size=\"sm\" data-start=\"1640\" data-end=\"1665\">GST, ITR, MCA filings</td>\r\n</tr>\r\n<tr data-start=\"1666\" data-end=\"1764\">\r\n<td data-start=\"1666\" data-end=\"1689\" data-col-size=\"sm\"><strong data-start=\"1668\" data-end=\"1688\">Organization DSC</strong></td>\r\n<td data-start=\"1689\" data-end=\"1731\" data-col-size=\"md\">Issued in the name of a company or firm</td>\r\n<td data-col-size=\"sm\" data-start=\"1731\" data-end=\"1764\">ROC, Tenders, Legal Contracts</td>\r\n</tr>\r\n<tr data-start=\"1765\" data-end=\"1850\">\r\n<td data-start=\"1765\" data-end=\"1780\" data-col-size=\"sm\"><strong data-start=\"1767\" data-end=\"1779\">DGFT DSC</strong></td>\r\n<td data-col-size=\"md\" data-start=\"1780\" data-end=\"1824\">Specifically for Export-Import businesses</td>\r\n<td data-col-size=\"sm\" data-start=\"1824\" data-end=\"1850\">DGFT / ICEGATE filings</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"1852\" data-end=\"1855\">\r\n<h3 data-start=\"1857\" data-end=\"1877\"><strong data-start=\"1861\" data-end=\"1877\">Key Features</strong></h3>\r\n<ul data-start=\"1879\" data-end=\"2253\">\r\n<li data-start=\"1879\" data-end=\"1942\">\r\n<p data-start=\"1881\" data-end=\"1942\"><strong data-start=\"1881\" data-end=\"1917\">High-level encryption (2048-bit)</strong> ensuring data security</p>\r\n</li>\r\n<li data-start=\"1943\" data-end=\"2016\">\r\n<p data-start=\"1945\" data-end=\"2016\"><strong data-start=\"1945\" data-end=\"1975\">Legally valid across India</strong> for all government and private portals</p>\r\n</li>\r\n<li data-start=\"2017\" data-end=\"2104\">\r\n<p data-start=\"2019\" data-end=\"2104\"><strong data-start=\"2019\" data-end=\"2064\">Issued by licensed Certifying Authorities</strong> (like eMudhra, Capricorn, Sify, etc.)</p>\r\n</li>\r\n<li data-start=\"2105\" data-end=\"2156\">\r\n<p data-start=\"2107\" data-end=\"2156\"><strong data-start=\"2107\" data-end=\"2139\">Stored in a secure USB token</strong> for safe usage</p>\r\n</li>\r\n<li data-start=\"2157\" data-end=\"2209\">\r\n<p data-start=\"2159\" data-end=\"2209\"><strong data-start=\"2159\" data-end=\"2180\">Validity options:</strong> 1 year / 2 years / 3 years</p>\r\n</li>\r\n<li data-start=\"2210\" data-end=\"2253\">\r\n<p data-start=\"2212\" data-end=\"2253\"><strong data-start=\"2212\" data-end=\"2237\">Can be renewed online</strong> before expiry</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2255\" data-end=\"2258\">\r\n<h3 data-start=\"2260\" data-end=\"2287\"><strong data-start=\"2264\" data-end=\"2287\">Uses of Class 3 DSC</strong></h3>\r\n<ol data-start=\"2289\" data-end=\"3056\">\r\n<li data-start=\"2289\" data-end=\"2391\">\r\n<p data-start=\"2292\" data-end=\"2391\"><strong data-start=\"2292\" data-end=\"2307\">GST Filing:</strong><br data-start=\"2307\" data-end=\"2310\">Compulsory for companies and LLPs to sign GSTR-1, 3B, 9, 9C and other forms.</p>\r\n</li>\r\n<li data-start=\"2393\" data-end=\"2512\">\r\n<p data-start=\"2396\" data-end=\"2512\"><strong data-start=\"2396\" data-end=\"2418\">Income-Tax Filing:</strong><br data-start=\"2418\" data-end=\"2421\">Used by professionals, firms, and corporates to digitally sign ITRs and audit reports.</p>\r\n</li>\r\n<li data-start=\"2514\" data-end=\"2656\">\r\n<p data-start=\"2517\" data-end=\"2656\"><strong data-start=\"2517\" data-end=\"2539\">MCA / ROC Filings:</strong><br data-start=\"2539\" data-end=\"2542\">Directors, partners, and company secretaries must use DSCs to submit forms like INC-32, DIR-12, AOC-4, MGT-7.</p>\r\n</li>\r\n<li data-start=\"2658\" data-end=\"2804\">\r\n<p data-start=\"2661\" data-end=\"2804\"><strong data-start=\"2661\" data-end=\"2693\">e-Tendering &amp; e-Procurement:</strong><br data-start=\"2693\" data-end=\"2696\">Class 3 DSC is mandatory for vendors, suppliers, and contractors bidding on government and PSU portals.</p>\r\n</li>\r\n<li data-start=\"2806\" data-end=\"2921\">\r\n<p data-start=\"2809\" data-end=\"2921\"><strong data-start=\"2809\" data-end=\"2843\">GeM, PF, EPFO &amp; Other Portals:</strong><br data-start=\"2843\" data-end=\"2846\">For vendor registration, compliance submissions, and online approvals.</p>\r\n</li>\r\n<li data-start=\"2923\" data-end=\"3056\">\r\n<p data-start=\"2926\" data-end=\"3056\"><strong data-start=\"2926\" data-end=\"2954\">Signing Legal Documents:</strong><br data-start=\"2954\" data-end=\"2957\">DSCs ensure the signer&rsquo;s identity and document integrity for digital contracts and agreements.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3058\" data-end=\"3061\">\r\n<h3 data-start=\"3063\" data-end=\"3089\"><strong data-start=\"3067\" data-end=\"3089\">Documents Required</strong></h3>\r\n<p data-start=\"3091\" data-end=\"3113\"><strong data-start=\"3091\" data-end=\"3111\">For Individuals:</strong></p>\r\n<ul data-start=\"3114\" data-end=\"3217\">\r\n<li data-start=\"3114\" data-end=\"3126\">\r\n<p data-start=\"3116\" data-end=\"3126\">PAN Card</p>\r\n</li>\r\n<li data-start=\"3127\" data-end=\"3164\">\r\n<p data-start=\"3129\" data-end=\"3164\">Aadhaar Card (linked with mobile)</p>\r\n</li>\r\n<li data-start=\"3165\" data-end=\"3188\">\r\n<p data-start=\"3167\" data-end=\"3188\">Passport-size photo</p>\r\n</li>\r\n<li data-start=\"3189\" data-end=\"3217\">\r\n<p data-start=\"3191\" data-end=\"3217\">Email ID &amp; mobile number</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3219\" data-end=\"3249\"><strong data-start=\"3219\" data-end=\"3247\">For Organization / Firm:</strong></p>\r\n<ul data-start=\"3250\" data-end=\"3401\">\r\n<li data-start=\"3250\" data-end=\"3294\">\r\n<p data-start=\"3252\" data-end=\"3294\">PAN &amp; Registration Certificate of Entity</p>\r\n</li>\r\n<li data-start=\"3295\" data-end=\"3328\">\r\n<p data-start=\"3297\" data-end=\"3328\">Authorized Signatory ID Proof</p>\r\n</li>\r\n<li data-start=\"3329\" data-end=\"3372\">\r\n<p data-start=\"3331\" data-end=\"3372\">Board Resolution / Authorization Letter</p>\r\n</li>\r\n<li data-start=\"3373\" data-end=\"3401\">\r\n<p data-start=\"3375\" data-end=\"3401\">Email ID &amp; mobile number</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3403\" data-end=\"3406\">\r\n<h3 data-start=\"3408\" data-end=\"3434\"><strong data-start=\"3412\" data-end=\"3434\">Validity &amp; Renewal</strong></h3>\r\n<ul data-start=\"3436\" data-end=\"3610\">\r\n<li data-start=\"3436\" data-end=\"3482\">\r\n<p data-start=\"3438\" data-end=\"3482\">Class 3 DSC is valid for <strong data-start=\"3463\" data-end=\"3479\">1 to 3 years</strong>.</p>\r\n</li>\r\n<li data-start=\"3483\" data-end=\"3538\">\r\n<p data-start=\"3485\" data-end=\"3538\">Renewal can be initiated <strong data-start=\"3510\" data-end=\"3535\">30 days before expiry</strong>.</p>\r\n</li>\r\n<li data-start=\"3539\" data-end=\"3610\">\r\n<p data-start=\"3541\" data-end=\"3610\">Existing USB token can be reused for renewal, saving time and cost.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3612\" data-end=\"3615\">\r\n<h3 data-start=\"3617\" data-end=\"3640\"><strong data-start=\"3621\" data-end=\"3640\">Benefits of DSC</strong></h3>\r\n<ul data-start=\"3642\" data-end=\"3895\">\r\n<li data-start=\"3642\" data-end=\"3701\">\r\n<p data-start=\"3644\" data-end=\"3701\">Legally recognized by all Indian government departments</p>\r\n</li>\r\n<li data-start=\"3702\" data-end=\"3748\">\r\n<p data-start=\"3704\" data-end=\"3748\">Ensures data confidentiality and integrity</p>\r\n</li>\r\n<li data-start=\"3749\" data-end=\"3797\">\r\n<p data-start=\"3751\" data-end=\"3797\">Saves time &mdash; no need for physical signatures</p>\r\n</li>\r\n<li data-start=\"3798\" data-end=\"3844\">\r\n<p data-start=\"3800\" data-end=\"3844\">Prevents forgery or tampering of documents</p>\r\n</li>\r\n<li data-start=\"3845\" data-end=\"3895\">\r\n<p data-start=\"3847\" data-end=\"3895\">Enables paperless, end-to-end digital workflow</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3897\" data-end=\"3900\">\r\n<h3 data-start=\"3902\" data-end=\"3921\"><strong data-start=\"3906\" data-end=\"3921\">Our Process</strong></h3>\r\n<ol data-start=\"3923\" data-end=\"4214\">\r\n<li data-start=\"3923\" data-end=\"3988\">\r\n<p data-start=\"3926\" data-end=\"3988\"><strong data-start=\"3926\" data-end=\"3947\">Submit Documents:</strong> Upload PAN, Aadhaar, and photo online.</p>\r\n</li>\r\n<li data-start=\"3989\" data-end=\"4064\">\r\n<p data-start=\"3992\" data-end=\"4064\"><strong data-start=\"3992\" data-end=\"4014\">eKYC Verification:</strong> Complete quick video or OTP-based verification.</p>\r\n</li>\r\n<li data-start=\"4065\" data-end=\"4124\">\r\n<p data-start=\"4068\" data-end=\"4124\"><strong data-start=\"4068\" data-end=\"4089\">Digital Approval:</strong> DSC issued within 15&ndash;30 minutes.</p>\r\n</li>\r\n<li data-start=\"4125\" data-end=\"4214\">\r\n<p data-start=\"4128\" data-end=\"4214\"><strong data-start=\"4128\" data-end=\"4147\">Token Delivery:</strong> Secure USB token dispatched to your address or handed in-person.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"4216\" data-end=\"4219\">\r\n<h3 data-start=\"4221\" data-end=\"4257\"><strong data-start=\"4225\" data-end=\"4257\">Why Choose Rajasthan Filings</strong></h3>\r\n<ul data-start=\"4259\" data-end=\"4569\">\r\n<li data-start=\"4259\" data-end=\"4318\">\r\n<p data-start=\"4261\" data-end=\"4318\">Authorized partner with licensed Certifying Authorities</p>\r\n</li>\r\n<li data-start=\"4319\" data-end=\"4355\">\r\n<p data-start=\"4321\" data-end=\"4355\">100 % paperless &amp; secure process</p>\r\n</li>\r\n<li data-start=\"4356\" data-end=\"4393\">\r\n<p data-start=\"4358\" data-end=\"4393\">Same-day DSC issuance (with eKYC)</p>\r\n</li>\r\n<li data-start=\"4394\" data-end=\"4464\">\r\n<p data-start=\"4396\" data-end=\"4464\">Valid for all government portals (GST, MCA, Income-Tax, GeM, DGFT)</p>\r\n</li>\r\n<li data-start=\"4465\" data-end=\"4515\">\r\n<p data-start=\"4467\" data-end=\"4515\">PAN-India service with doorstep token delivery</p>\r\n</li>\r\n<li data-start=\"4516\" data-end=\"4569\">\r\n<p data-start=\"4518\" data-end=\"4569\">Dedicated expert support for activation and usage</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4571\" data-end=\"4694\">We make obtaining a Digital Signature <strong data-start=\"4609\" data-end=\"4639\">simple, safe, and seamless</strong> &mdash; so you can file, sign, and approve without delays.</p>\r\n<hr data-start=\"4696\" data-end=\"4699\">\r\n<h3 data-start=\"4701\" data-end=\"4719\"><strong data-start=\"4705\" data-end=\"4719\">Conclusion</strong></h3>\r\n<p data-start=\"4721\" data-end=\"4922\">In the world of online compliance, a <strong data-start=\"4758\" data-end=\"4797\">Digital Signature Certificate (DSC)</strong> is your <strong data-start=\"4806\" data-end=\"4826\">digital identity</strong> &mdash; it protects your business, verifies your authority, and ensures trust in every transaction.</p>\r\n<p data-start=\"4924\" data-end=\"5081\">With <strong data-start=\"4929\" data-end=\"4950\">Rajasthan Filings</strong>, get your Class 3 DSC issued quickly and confidently &mdash; fully verified, government-approved, and ready for all professional uses.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-17 06:52:47', '2025-11-08 00:52:09');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(21, 1, NULL, 'Partnership Firm & Proprietorship Registration', 'partnership-firm--proprietorship-registration', 'Partnership Firm & Proprietorship Registration in India', '<h3 data-start=\"386\" data-end=\"456\">Simplest Way to Start Your Business Legally with Rajasthan Filings</h3>\r\n<p data-start=\"458\" data-end=\"644\">Starting a business begins with structure. For beginners, <strong data-start=\"516\" data-end=\"536\">Partnership Firm</strong> and <strong data-start=\"541\" data-end=\"564\">Sole Proprietorship</strong> are the most convenient, cost-effective and flexible business forms in India.</p>\r\n<p data-start=\"646\" data-end=\"932\">At <strong data-start=\"649\" data-end=\"670\">Rajasthan Filings</strong>, we assist small traders, shopkeepers, consultants, and professionals in registering their business under official frameworks such as <strong data-start=\"805\" data-end=\"821\">Udyam (MSME)</strong>, <strong data-start=\"823\" data-end=\"830\">GST</strong>, and <strong data-start=\"836\" data-end=\"864\">Shop &amp; Establishment Act</strong>&mdash;making your business <strong data-start=\"886\" data-end=\"931\">legally valid, tax-compliant, and trusted</strong>.</p>\r\n<hr data-start=\"934\" data-end=\"937\">\r\n<h2 data-start=\"939\" data-end=\"989\">🔹 1. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Understanding Basic Business Structures</span></strong></h2>\r\n<h3 data-start=\"991\" data-end=\"1019\">🧾 Sole Proprietorship</h3>\r\n<p data-start=\"1020\" data-end=\"1134\">A business owned and managed by one person. There is <strong data-start=\"1073\" data-end=\"1096\">no legal separation</strong> between the owner and the business.</p>\r\n<p data-start=\"1136\" data-end=\"1153\"><strong data-start=\"1136\" data-end=\"1151\">Key Points:</strong></p>\r\n<ul data-start=\"1154\" data-end=\"1408\">\r\n<li data-start=\"1154\" data-end=\"1208\">\r\n<p data-start=\"1156\" data-end=\"1208\">Complete ownership and control with one individual</p>\r\n</li>\r\n<li data-start=\"1209\" data-end=\"1259\">\r\n<p data-start=\"1211\" data-end=\"1259\">Minimal registration and reporting formalities</p>\r\n</li>\r\n<li data-start=\"1260\" data-end=\"1304\">\r\n<p data-start=\"1262\" data-end=\"1304\">Business income taxed as personal income</p>\r\n</li>\r\n<li data-start=\"1305\" data-end=\"1361\">\r\n<p data-start=\"1307\" data-end=\"1361\">Quick bank-account opening and easy GST registration</p>\r\n</li>\r\n<li data-start=\"1362\" data-end=\"1408\">\r\n<p data-start=\"1364\" data-end=\"1408\">Best suited for micro and local businesses</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1410\" data-end=\"1489\"><strong data-start=\"1410\" data-end=\"1430\">Common Examples:</strong> Retail shops &bull; Freelancers &bull; Consultants &bull; Small traders</p>\r\n<hr data-start=\"1491\" data-end=\"1494\">\r\n<h3 data-start=\"1496\" data-end=\"1521\">🤝 Partnership Firm</h3>\r\n<p data-start=\"1522\" data-end=\"1675\">Two or more people join to carry on a business and share profits under an agreed <strong data-start=\"1603\" data-end=\"1623\">Partnership Deed</strong> governed by the <strong data-start=\"1640\" data-end=\"1672\">Indian Partnership Act, 1932</strong>.</p>\r\n<p data-start=\"1677\" data-end=\"1694\"><strong data-start=\"1677\" data-end=\"1692\">Key Points:</strong></p>\r\n<ul data-start=\"1695\" data-end=\"1982\">\r\n<li data-start=\"1695\" data-end=\"1753\">\r\n<p data-start=\"1697\" data-end=\"1753\">Minimum 2 partners required (no statutory upper limit)</p>\r\n</li>\r\n<li data-start=\"1754\" data-end=\"1815\">\r\n<p data-start=\"1756\" data-end=\"1815\">Partners decide profit ratios and duties through the deed</p>\r\n</li>\r\n<li data-start=\"1816\" data-end=\"1882\">\r\n<p data-start=\"1818\" data-end=\"1882\">Option to register with the Registrar of Firms for legal proof</p>\r\n</li>\r\n<li data-start=\"1883\" data-end=\"1933\">\r\n<p data-start=\"1885\" data-end=\"1933\">Collective management and shared risk / reward</p>\r\n</li>\r\n<li data-start=\"1934\" data-end=\"1982\">\r\n<p data-start=\"1936\" data-end=\"1982\">Separate PAN and bank account in firm&rsquo;s name</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1984\" data-end=\"2067\"><strong data-start=\"1984\" data-end=\"2004\">Common Examples:</strong> Family businesses &bull; Small manufacturers &bull; Professional firms</p>\r\n<hr data-start=\"2069\" data-end=\"2072\">\r\n<h2 data-start=\"2074\" data-end=\"2107\">⚖️ 2. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Comparison at a Glance</span></strong></h2>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2109\" data-end=\"2771\">\r\n<thead data-start=\"2109\" data-end=\"2172\">\r\n<tr data-start=\"2109\" data-end=\"2172\">\r\n<th data-start=\"2109\" data-end=\"2122\" data-col-size=\"sm\"><strong data-start=\"2111\" data-end=\"2121\">Aspect</strong></th>\r\n<th data-start=\"2122\" data-end=\"2148\" data-col-size=\"sm\"><strong data-start=\"2124\" data-end=\"2147\">Sole Proprietorship</strong></th>\r\n<th data-start=\"2148\" data-end=\"2172\" data-col-size=\"sm\"><strong data-start=\"2150\" data-end=\"2170\">Partnership Firm</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2238\" data-end=\"2771\">\r\n<tr data-start=\"2238\" data-end=\"2304\">\r\n<td data-start=\"2238\" data-end=\"2255\" data-col-size=\"sm\">Legal Identity</td>\r\n<td data-col-size=\"sm\" data-start=\"2255\" data-end=\"2271\">Same as owner</td>\r\n<td data-col-size=\"sm\" data-start=\"2271\" data-end=\"2304\">Same as partners collectively</td>\r\n</tr>\r\n<tr data-start=\"2305\" data-end=\"2361\">\r\n<td data-start=\"2305\" data-end=\"2317\" data-col-size=\"sm\">Ownership</td>\r\n<td data-col-size=\"sm\" data-start=\"2317\" data-end=\"2337\">Single individual</td>\r\n<td data-col-size=\"sm\" data-start=\"2337\" data-end=\"2361\">Two or more partners</td>\r\n</tr>\r\n<tr data-start=\"2362\" data-end=\"2417\">\r\n<td data-start=\"2362\" data-end=\"2374\" data-col-size=\"sm\">Liability</td>\r\n<td data-col-size=\"sm\" data-start=\"2374\" data-end=\"2386\">Unlimited</td>\r\n<td data-col-size=\"sm\" data-start=\"2386\" data-end=\"2417\">Unlimited (joint &amp; several)</td>\r\n</tr>\r\n<tr data-start=\"2418\" data-end=\"2481\">\r\n<td data-start=\"2418\" data-end=\"2434\" data-col-size=\"sm\">Governing Law</td>\r\n<td data-col-size=\"sm\" data-start=\"2434\" data-end=\"2450\">None specific</td>\r\n<td data-col-size=\"sm\" data-start=\"2450\" data-end=\"2481\">Indian Partnership Act 1932</td>\r\n</tr>\r\n<tr data-start=\"2482\" data-end=\"2532\">\r\n<td data-start=\"2482\" data-end=\"2492\" data-col-size=\"sm\">Control</td>\r\n<td data-col-size=\"sm\" data-start=\"2492\" data-end=\"2506\">Independent</td>\r\n<td data-col-size=\"sm\" data-start=\"2506\" data-end=\"2532\">Shared decision making</td>\r\n</tr>\r\n<tr data-start=\"2533\" data-end=\"2593\">\r\n<td data-start=\"2533\" data-end=\"2550\" data-col-size=\"sm\">Profit Sharing</td>\r\n<td data-col-size=\"sm\" data-start=\"2550\" data-end=\"2566\">100% to owner</td>\r\n<td data-col-size=\"sm\" data-start=\"2566\" data-end=\"2593\">As per Partnership Deed</td>\r\n</tr>\r\n<tr data-start=\"2594\" data-end=\"2630\">\r\n<td data-start=\"2594\" data-end=\"2607\" data-col-size=\"sm\">Compliance</td>\r\n<td data-col-size=\"sm\" data-start=\"2607\" data-end=\"2618\">Very Low</td>\r\n<td data-col-size=\"sm\" data-start=\"2618\" data-end=\"2630\">Moderate</td>\r\n</tr>\r\n<tr data-start=\"2631\" data-end=\"2690\">\r\n<td data-start=\"2631\" data-end=\"2647\" data-col-size=\"sm\">Tax Treatment</td>\r\n<td data-col-size=\"sm\" data-start=\"2647\" data-end=\"2671\">Individual slab rates</td>\r\n<td data-col-size=\"sm\" data-start=\"2671\" data-end=\"2690\">Flat 30% + cess</td>\r\n</tr>\r\n<tr data-start=\"2691\" data-end=\"2771\">\r\n<td data-start=\"2691\" data-end=\"2703\" data-col-size=\"sm\">Ideal For</td>\r\n<td data-col-size=\"sm\" data-start=\"2703\" data-end=\"2739\">Solo operators &amp; micro businesses</td>\r\n<td data-col-size=\"sm\" data-start=\"2739\" data-end=\"2771\">Small teams &amp; joint ventures</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"2773\" data-end=\"2776\">\r\n<h2 data-start=\"2778\" data-end=\"2808\">🗂️ 3. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Documents Required</span></strong></h2>\r\n<h3 data-start=\"2810\" data-end=\"2839\">For Sole Proprietorship</h3>\r\n<ul data-start=\"2840\" data-end=\"3086\">\r\n<li data-start=\"2840\" data-end=\"2873\">\r\n<p data-start=\"2842\" data-end=\"2873\">PAN and Aadhaar of Proprietor</p>\r\n</li>\r\n<li data-start=\"2874\" data-end=\"2909\">\r\n<p data-start=\"2876\" data-end=\"2909\">Recent passport-size photograph</p>\r\n</li>\r\n<li data-start=\"2910\" data-end=\"2948\">\r\n<p data-start=\"2912\" data-end=\"2948\">Address proof of business location</p>\r\n</li>\r\n<li data-start=\"2949\" data-end=\"2998\">\r\n<p data-start=\"2951\" data-end=\"2998\">Electricity bill / Rent agreement / Owner NOC</p>\r\n</li>\r\n<li data-start=\"2999\" data-end=\"3036\">\r\n<p data-start=\"3001\" data-end=\"3036\">Udyam (MSME) registration details</p>\r\n</li>\r\n<li data-start=\"3037\" data-end=\"3086\">\r\n<p data-start=\"3039\" data-end=\"3086\">Bank account application supporting documents</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3088\" data-end=\"3114\">For Partnership Firm</h3>\r\n<ul data-start=\"3115\" data-end=\"3395\">\r\n<li data-start=\"3115\" data-end=\"3148\">\r\n<p data-start=\"3117\" data-end=\"3148\">PAN &amp; Aadhaar of all Partners</p>\r\n</li>\r\n<li data-start=\"3149\" data-end=\"3205\">\r\n<p data-start=\"3151\" data-end=\"3205\">Address proof of Partners (Voter ID / DL / Passport)</p>\r\n</li>\r\n<li data-start=\"3206\" data-end=\"3266\">\r\n<p data-start=\"3208\" data-end=\"3266\">Office address proof with utility bill or rent agreement</p>\r\n</li>\r\n<li data-start=\"3267\" data-end=\"3310\">\r\n<p data-start=\"3269\" data-end=\"3310\">Drafted Partnership Deed on stamp paper</p>\r\n</li>\r\n<li data-start=\"3311\" data-end=\"3353\">\r\n<p data-start=\"3313\" data-end=\"3353\">Firm name &amp; business objective details</p>\r\n</li>\r\n<li data-start=\"3354\" data-end=\"3395\">\r\n<p data-start=\"3356\" data-end=\"3395\">Digital signatures (if filing online)</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3397\" data-end=\"3400\">\r\n<h2 data-start=\"3402\" data-end=\"3433\">🧩 4. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Step-by-Step Process</span></strong></h2>\r\n<p data-start=\"3435\" data-end=\"3479\"><strong data-start=\"3435\" data-end=\"3477\">1️⃣ Consultation &amp; Structure Selection</strong></p>\r\n<ul data-start=\"3480\" data-end=\"3643\">\r\n<li data-start=\"3480\" data-end=\"3564\">\r\n<p data-start=\"3482\" data-end=\"3564\">Understand your business model and choose between Proprietorship or Partnership.</p>\r\n</li>\r\n<li data-start=\"3565\" data-end=\"3643\">\r\n<p data-start=\"3567\" data-end=\"3643\">Identify licences or registrations required (GST, FSSAI, Shops Act, etc.).</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3645\" data-end=\"3690\"><strong data-start=\"3645\" data-end=\"3688\">2️⃣ Document Preparation &amp; Verification</strong></p>\r\n<ul data-start=\"3691\" data-end=\"3802\">\r\n<li data-start=\"3691\" data-end=\"3743\">\r\n<p data-start=\"3693\" data-end=\"3743\">Collect identity, address, and ownership proofs.</p>\r\n</li>\r\n<li data-start=\"3744\" data-end=\"3802\">\r\n<p data-start=\"3746\" data-end=\"3802\">Verify name availability and draft business objective.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3804\" data-end=\"3837\"><strong data-start=\"3804\" data-end=\"3835\">3️⃣ Legal Drafting &amp; Filing</strong></p>\r\n<ul data-start=\"3838\" data-end=\"4017\">\r\n<li data-start=\"3838\" data-end=\"3939\">\r\n<p data-start=\"3840\" data-end=\"3939\">Create Partnership Deed with all terms of capital, profit sharing, duties and dispute resolution.</p>\r\n</li>\r\n<li data-start=\"3940\" data-end=\"4017\">\r\n<p data-start=\"3942\" data-end=\"4017\">For Proprietorship, file Udyam (MSME) registration and GST if applicable.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4019\" data-end=\"4058\"><strong data-start=\"4019\" data-end=\"4056\">4️⃣ Registration with Authorities</strong></p>\r\n<ul data-start=\"4059\" data-end=\"4211\">\r\n<li data-start=\"4059\" data-end=\"4156\">\r\n<p data-start=\"4061\" data-end=\"4156\">File application to Registrar of Firms (for Partnership) or MSME portal (for Proprietorship).</p>\r\n</li>\r\n<li data-start=\"4157\" data-end=\"4211\">\r\n<p data-start=\"4159\" data-end=\"4211\">Obtain PAN, TAN and business licences as required.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4213\" data-end=\"4260\"><strong data-start=\"4213\" data-end=\"4258\">5️⃣ Delivery of Certificates &amp; Activation</strong></p>\r\n<ul data-start=\"4261\" data-end=\"4392\">\r\n<li data-start=\"4261\" data-end=\"4330\">\r\n<p data-start=\"4263\" data-end=\"4330\">Receive digital registration certificate within 2&ndash;5 working days.</p>\r\n</li>\r\n<li data-start=\"4331\" data-end=\"4392\">\r\n<p data-start=\"4333\" data-end=\"4392\">Open current account and commence operations immediately.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4394\" data-end=\"4397\">\r\n<h2 data-start=\"4399\" data-end=\"4445\">📘 5. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Calibri\',sans-serif; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: Calibri; mso-fareast-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Mangal; mso-bidi-theme-font: minor-bidi; mso-ansi-language: EN-IN; mso-fareast-language: EN-US; mso-bidi-language: HI;\">Importance of Official Registration</span></strong></h2>\r\n<ul data-start=\"4447\" data-end=\"4887\">\r\n<li data-start=\"4447\" data-end=\"4497\">\r\n<p data-start=\"4449\" data-end=\"4497\">Provides <strong data-start=\"4458\" data-end=\"4473\">legal proof</strong> of business existence</p>\r\n</li>\r\n<li data-start=\"4498\" data-end=\"4550\">\r\n<p data-start=\"4500\" data-end=\"4550\">Builds <strong data-start=\"4507\" data-end=\"4548\">trust with banks, clients and vendors</strong></p>\r\n</li>\r\n<li data-start=\"4551\" data-end=\"4602\">\r\n<p data-start=\"4553\" data-end=\"4602\">Enables <strong data-start=\"4561\" data-end=\"4600\">GST compliance and invoice issuance</strong></p>\r\n</li>\r\n<li data-start=\"4603\" data-end=\"4664\">\r\n<p data-start=\"4605\" data-end=\"4664\">Grants <strong data-start=\"4612\" data-end=\"4662\">eligibility for MSME benefits and loan schemes</strong></p>\r\n</li>\r\n<li data-start=\"4665\" data-end=\"4714\">\r\n<p data-start=\"4667\" data-end=\"4714\">Protects the business name and brand identity</p>\r\n</li>\r\n<li data-start=\"4715\" data-end=\"4775\">\r\n<p data-start=\"4717\" data-end=\"4775\">Allows participation in government tenders and contracts</p>\r\n</li>\r\n<li data-start=\"4776\" data-end=\"4822\">\r\n<p data-start=\"4778\" data-end=\"4822\">Simplifies tax filing and audit procedures</p>\r\n</li>\r\n<li data-start=\"4823\" data-end=\"4887\">\r\n<p data-start=\"4825\" data-end=\"4887\">Helps in future conversion to LLP or Private Limited Company</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4889\" data-end=\"4892\">\r\n<h2 data-start=\"4894\" data-end=\"4966\">📄 6. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Partnership Deed &mdash; Core Clauses Included by Rajasthan Filings</span></strong></h2>\r\n<ul data-start=\"4968\" data-end=\"5407\">\r\n<li data-start=\"4968\" data-end=\"4997\">\r\n<p data-start=\"4970\" data-end=\"4997\">Business Name and Address</p>\r\n</li>\r\n<li data-start=\"4998\" data-end=\"5051\">\r\n<p data-start=\"5000\" data-end=\"5051\">Details of Each Partner (Name, Age, Address, PAN)</p>\r\n</li>\r\n<li data-start=\"5052\" data-end=\"5093\">\r\n<p data-start=\"5054\" data-end=\"5093\">Nature and Scope of Business Activity</p>\r\n</li>\r\n<li data-start=\"5094\" data-end=\"5143\">\r\n<p data-start=\"5096\" data-end=\"5143\">Capital Contribution and Profit Sharing Ratio</p>\r\n</li>\r\n<li data-start=\"5144\" data-end=\"5182\">\r\n<p data-start=\"5146\" data-end=\"5182\">Duties and Obligations of Partners</p>\r\n</li>\r\n<li data-start=\"5183\" data-end=\"5224\">\r\n<p data-start=\"5185\" data-end=\"5224\">Rights of Partners in Decision Making</p>\r\n</li>\r\n<li data-start=\"5225\" data-end=\"5269\">\r\n<p data-start=\"5227\" data-end=\"5269\">Interest on Capital or Drawings (if any)</p>\r\n</li>\r\n<li data-start=\"5270\" data-end=\"5309\">\r\n<p data-start=\"5272\" data-end=\"5309\">Admission or Retirement of Partners</p>\r\n</li>\r\n<li data-start=\"5310\" data-end=\"5360\">\r\n<p data-start=\"5312\" data-end=\"5360\">Method for Settlement of Accounts and Disputes</p>\r\n</li>\r\n<li data-start=\"5361\" data-end=\"5407\">\r\n<p data-start=\"5363\" data-end=\"5407\">Duration of Partnership (Fixed or At Will)</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5409\" data-end=\"5538\">All deeds drafted by Rajasthan Filings are <strong data-start=\"5452\" data-end=\"5538\">legally sound, digitally signed, and accepted by banks and government departments.</strong></p>\r\n<hr data-start=\"5540\" data-end=\"5543\">\r\n<h2 data-start=\"5545\" data-end=\"5583\">🧠 7. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Tax &amp; Compliance Highlights</span></strong></h2>\r\n<ul data-start=\"5585\" data-end=\"6073\">\r\n<li data-start=\"5585\" data-end=\"5657\">\r\n<p data-start=\"5587\" data-end=\"5657\">Proprietor files business income in individual ITR (ITR-3 or ITR-4).</p>\r\n</li>\r\n<li data-start=\"5658\" data-end=\"5725\">\r\n<p data-start=\"5660\" data-end=\"5725\">Partnership Firm files separate ITR-5 under the Income Tax Act.</p>\r\n</li>\r\n<li data-start=\"5726\" data-end=\"5805\">\r\n<p data-start=\"5728\" data-end=\"5805\">Both entities must maintain books of accounts and preserve bills for audit.</p>\r\n</li>\r\n<li data-start=\"5806\" data-end=\"5901\">\r\n<p data-start=\"5808\" data-end=\"5901\">Registration under GST mandatory if turnover exceeds ₹20 lakh (service) / ₹40 lakh (goods).</p>\r\n</li>\r\n<li data-start=\"5902\" data-end=\"5991\">\r\n<p data-start=\"5904\" data-end=\"5991\">Partnership Firms must deduct TDS on salaries and contract payments where applicable.</p>\r\n</li>\r\n<li data-start=\"5992\" data-end=\"6073\">\r\n<p data-start=\"5994\" data-end=\"6073\">Annual renewal of MSME and business licence recommended to maintain validity.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6075\" data-end=\"6078\">\r\n<h2 data-start=\"6080\" data-end=\"6130\">💼 8. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%; font-family: \'Calibri\',sans-serif; mso-ascii-theme-font: minor-latin; mso-fareast-font-family: Calibri; mso-fareast-theme-font: minor-latin; mso-hansi-theme-font: minor-latin; mso-bidi-font-family: Mangal; mso-bidi-theme-font: minor-bidi; mso-ansi-language: EN-IN; mso-fareast-language: EN-US; mso-bidi-language: HI;\">Why Businesses Prefer Rajasthan Filings</span></strong></h2>\r\n<ul data-start=\"6132\" data-end=\"6570\">\r\n<li data-start=\"6132\" data-end=\"6186\">\r\n<p data-start=\"6134\" data-end=\"6186\">End-to-end service from registration to tax filing</p>\r\n</li>\r\n<li data-start=\"6187\" data-end=\"6241\">\r\n<p data-start=\"6189\" data-end=\"6241\">Experienced team of CA, CS and legal professionals</p>\r\n</li>\r\n<li data-start=\"6242\" data-end=\"6292\">\r\n<p data-start=\"6244\" data-end=\"6292\">Nationwide service coverage and online process</p>\r\n</li>\r\n<li data-start=\"6293\" data-end=\"6341\">\r\n<p data-start=\"6295\" data-end=\"6341\">Transparent documentation and status updates</p>\r\n</li>\r\n<li data-start=\"6342\" data-end=\"6398\">\r\n<p data-start=\"6344\" data-end=\"6398\">Ready drafts for bank accounts and loan applications</p>\r\n</li>\r\n<li data-start=\"6399\" data-end=\"6463\">\r\n<p data-start=\"6401\" data-end=\"6463\">Option to upgrade to LLP / Private Limited without fresh PAN</p>\r\n</li>\r\n<li data-start=\"6464\" data-end=\"6514\">\r\n<p data-start=\"6466\" data-end=\"6514\">Dedicated relationship manager for each client</p>\r\n</li>\r\n<li data-start=\"6515\" data-end=\"6570\">\r\n<p data-start=\"6517\" data-end=\"6570\">Free post-registration consultation for GST and ITR</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"6572\" data-end=\"6575\">\r\n<h2 data-start=\"6577\" data-end=\"6606\">🚀 9. <strong><span style=\"font-size: 18.0pt; mso-bidi-font-size: 16.0pt; line-height: 107%;\">Take the Next Step</span></strong></h2>\r\n<p data-start=\"6608\" data-end=\"6778\">Make your business official today with <strong data-start=\"6647\" data-end=\"6668\">Rajasthan Filings</strong>.<br data-start=\"6669\" data-end=\"6672\">We streamline the entire process&mdash;from paperwork to certificates&mdash;so you can focus on growing your business.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-25 04:02:56', '2025-11-08 00:52:08'),
(22, 1, NULL, 'Ngo Registration', 'ngo-regis', 'NGO Registration', '<h1 data-start=\"428\" data-end=\"459\"><strong data-start=\"430\" data-end=\"459\">NGO Registration in India</strong></h1>\r\n<p data-start=\"461\" data-end=\"967\">Non-Governmental Organizations (NGOs) play a vital role in India&rsquo;s social, economic, and cultural development. They operate independently of government control, working to promote education, health, environment, skill development, and social justice. Legal registration of an NGO gives it identity, credibility, and long-term sustainability. In India, NGOs can be registered as a <strong data-start=\"841\" data-end=\"850\">Trust</strong>, <strong data-start=\"852\" data-end=\"863\">Society</strong>, or <strong data-start=\"868\" data-end=\"889\">Section 8 Company</strong>, depending on their objectives, governance structure, and scale of operation.</p>\r\n<p data-start=\"969\" data-end=\"1466\">The purpose of NGO registration is to give a non-profit organization a legal framework for functioning and accountability. Registered NGOs can open bank accounts, receive donations, apply for grants, and avail tax exemptions under the Income Tax Act. Moreover, registration is mandatory for obtaining CSR funding from companies and foreign contributions under the FCRA Act. Without registration, an organization cannot legally represent itself as a recognized entity before any authority or donor.</p>\r\n<hr data-start=\"1468\" data-end=\"1471\">\r\n<h2 data-start=\"1473\" data-end=\"1510\"><strong data-start=\"1476\" data-end=\"1510\">Understanding NGO Registration</strong></h2>\r\n<p data-start=\"1512\" data-end=\"2008\">An NGO is any voluntary group of individuals or institutions that works for the welfare of society without a profit motive. These organizations focus on public benefit activities like education, health, women empowerment, rural development, skill training, disaster relief, and environment protection. The Indian legal system provides three main frameworks for establishing an NGO &mdash; as a <strong data-start=\"1900\" data-end=\"1927\">Public Charitable Trust</strong>, <strong data-start=\"1929\" data-end=\"1951\">Registered Society</strong>, or <strong data-start=\"1956\" data-end=\"1977\">Section 8 Company</strong> under the Companies Act, 2013.</p>\r\n<p data-start=\"2010\" data-end=\"2274\">Each structure differs in formation procedure, management system, and level of government oversight. Trusts and societies are governed by state-level authorities, while Section 8 Companies are regulated by the Ministry of Corporate Affairs at the national level.</p>\r\n<hr data-start=\"2276\" data-end=\"2279\">\r\n<h2 data-start=\"2281\" data-end=\"2324\"><strong data-start=\"2284\" data-end=\"2324\">Legal Framework for NGO Registration</strong></h2>\r\n<ol data-start=\"2326\" data-end=\"2785\">\r\n<li data-start=\"2326\" data-end=\"2476\">\r\n<p data-start=\"2329\" data-end=\"2476\"><strong data-start=\"2329\" data-end=\"2379\">The Indian Trusts Act, 1882 / State Trust Acts</strong> &mdash; applicable to public charitable trusts formed to promote philanthropy or welfare activities.</p>\r\n</li>\r\n<li data-start=\"2477\" data-end=\"2629\">\r\n<p data-start=\"2480\" data-end=\"2629\"><strong data-start=\"2480\" data-end=\"2520\">The Societies Registration Act, 1860</strong> &mdash; applicable to organizations formed for promoting literature, science, fine arts, or charitable purposes.</p>\r\n</li>\r\n<li data-start=\"2630\" data-end=\"2785\">\r\n<p data-start=\"2633\" data-end=\"2785\"><strong data-start=\"2633\" data-end=\"2672\">The Companies Act, 2013 (Section 8)</strong> &mdash; applicable to non-profit companies formed for charitable purposes with national or international operations.</p>\r\n</li>\r\n</ol>\r\n<p data-start=\"2787\" data-end=\"3153\">The basic eligibility for NGO registration includes at least two individuals (for Trust or Section 8 Company) or seven individuals (for Society) who are above 18 years of age and share a common objective of working for social good. Each organization must have a fixed registered office, clear objectives, and a lawful purpose that falls within the charitable domain.</p>\r\n<hr data-start=\"3155\" data-end=\"3158\">\r\n<h2 data-start=\"3160\" data-end=\"3190\"><strong data-start=\"3163\" data-end=\"3190\">Types of NGO Structures</strong></h2>\r\n<h3 data-start=\"3192\" data-end=\"3218\"><strong data-start=\"3196\" data-end=\"3218\">Trust Registration</strong></h3>\r\n<p data-start=\"3219\" data-end=\"3585\">A Public Charitable Trust is established when one or more persons (the settlors) transfer property or funds to trustees for public benefit. The objectives may include education, medical relief, or social upliftment. The legal instrument used to form a trust is called the <strong data-start=\"3491\" data-end=\"3505\">Trust Deed</strong>, which outlines the name, objectives, powers, and responsibilities of trustees.</p>\r\n<p data-start=\"3587\" data-end=\"3909\">Trust registration is done at the office of the Sub-Registrar in the district where the trust operates. Once registered, the trust becomes a legal entity with perpetual existence. It can acquire property, open bank accounts, and receive grants. The trustees manage the trust and are bound by the clauses of the trust deed.</p>\r\n<h3 data-start=\"3911\" data-end=\"3939\"><strong data-start=\"3915\" data-end=\"3939\">Society Registration</strong></h3>\r\n<p data-start=\"3940\" data-end=\"4256\">A Society is a voluntary association of persons who work together for a common charitable, literary, or cultural objective. It is governed by the <strong data-start=\"4086\" data-end=\"4122\">Societies Registration Act, 1860</strong>. A society must have a minimum of seven members; if it wishes to operate nationwide, it must include members from different states.</p>\r\n<p data-start=\"4258\" data-end=\"4607\">The governing structure of a society includes a <strong data-start=\"4306\" data-end=\"4322\">General Body</strong> and an <strong data-start=\"4330\" data-end=\"4353\">Executive Committee</strong> (President, Secretary, Treasurer). The Memorandum of Association (MOA) defines the objectives, while the Rules &amp; Regulations describe the operational procedures. Societies must hold annual meetings, file returns, and maintain transparency in operations.</p>\r\n<h3 data-start=\"4609\" data-end=\"4647\"><strong data-start=\"4613\" data-end=\"4647\">Section 8 Company Registration</strong></h3>\r\n<p data-start=\"4648\" data-end=\"5081\">A Section 8 Company is a non-profit entity incorporated under the <strong data-start=\"4714\" data-end=\"4737\">Companies Act, 2013</strong>, with permission from the Ministry of Corporate Affairs. Unlike regular companies, its profits cannot be distributed to members; they must be used solely for charitable purposes. It enjoys the highest credibility and regulatory recognition, making it ideal for large NGOs, corporate foundations, or institutions seeking CSR or foreign funding.</p>\r\n<p data-start=\"5083\" data-end=\"5433\">A Section 8 Company requires at least two directors and two shareholders. The registration process involves applying through the <strong data-start=\"5212\" data-end=\"5233\">MCA SPICe+ portal</strong>, obtaining Digital Signature Certificates (DSCs), Director Identification Numbers (DINs), and approval from the Registrar of Companies. It operates like a company but without the objective of profit.</p>\r\n<hr data-start=\"5435\" data-end=\"5438\">\r\n<h2 data-start=\"5440\" data-end=\"5465\"><strong data-start=\"5443\" data-end=\"5465\">Documents Required</strong></h2>\r\n<ul data-start=\"5467\" data-end=\"5854\">\r\n<li data-start=\"5467\" data-end=\"5526\">\r\n<p data-start=\"5469\" data-end=\"5526\">PAN and Aadhaar of all founders, trustees, or directors</p>\r\n</li>\r\n<li data-start=\"5527\" data-end=\"5556\">\r\n<p data-start=\"5529\" data-end=\"5556\">Passport-size photographs</p>\r\n</li>\r\n<li data-start=\"5557\" data-end=\"5641\">\r\n<p data-start=\"5559\" data-end=\"5641\">Proof of registered office (electricity bill, rent agreement, or property paper)</p>\r\n</li>\r\n<li data-start=\"5642\" data-end=\"5694\">\r\n<p data-start=\"5644\" data-end=\"5694\">No Objection Certificate from the property owner</p>\r\n</li>\r\n<li data-start=\"5695\" data-end=\"5751\">\r\n<p data-start=\"5697\" data-end=\"5751\">Memorandum of Association or Trust Deed or MOA &amp; AOA</p>\r\n</li>\r\n<li data-start=\"5752\" data-end=\"5793\">\r\n<p data-start=\"5754\" data-end=\"5793\">Identity and address proof of members</p>\r\n</li>\r\n<li data-start=\"5794\" data-end=\"5854\">\r\n<p data-start=\"5796\" data-end=\"5854\">Digital Signature Certificates (for Section 8 Companies)</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5856\" data-end=\"6001\">All documents must be self-attested and filed along with the registration application in the prescribed format depending on the chosen structure.</p>\r\n<hr data-start=\"6003\" data-end=\"6006\">\r\n<h2 data-start=\"6008\" data-end=\"6048\"><strong data-start=\"6011\" data-end=\"6048\">Step-by-Step Registration Process</strong></h2>\r\n<ol data-start=\"6050\" data-end=\"7252\">\r\n<li data-start=\"6050\" data-end=\"6239\">\r\n<p data-start=\"6053\" data-end=\"6239\"><strong data-start=\"6053\" data-end=\"6094\">Consultation and Structure Selection:</strong><br data-start=\"6094\" data-end=\"6097\">Determine whether the organization should be registered as a Trust, Society, or Section 8 Company based on its size, scope, and objectives.</p>\r\n</li>\r\n<li data-start=\"6241\" data-end=\"6370\">\r\n<p data-start=\"6244\" data-end=\"6370\"><strong data-start=\"6244\" data-end=\"6262\">Name Approval:</strong><br data-start=\"6262\" data-end=\"6265\">The proposed name must be unique and not violate any existing registered names under the relevant act.</p>\r\n</li>\r\n<li data-start=\"6372\" data-end=\"6572\">\r\n<p data-start=\"6375\" data-end=\"6572\"><strong data-start=\"6375\" data-end=\"6407\">Drafting of Legal Documents:</strong><br data-start=\"6407\" data-end=\"6410\">A Trust Deed, Memorandum of Association, and Rules &amp; Regulations are prepared by professionals specifying aims, management structure, and operating principles.</p>\r\n</li>\r\n<li data-start=\"6574\" data-end=\"6806\">\r\n<p data-start=\"6577\" data-end=\"6806\"><strong data-start=\"6577\" data-end=\"6602\">Execution and Filing:</strong><br data-start=\"6602\" data-end=\"6605\">Documents are executed on non-judicial stamp paper (for Trusts) or filed digitally (for Section 8) with the respective authorities &mdash; Sub-Registrar, Registrar of Societies, or Registrar of Companies.</p>\r\n</li>\r\n<li data-start=\"6808\" data-end=\"6955\">\r\n<p data-start=\"6811\" data-end=\"6955\"><strong data-start=\"6811\" data-end=\"6843\">Verification by Authorities:</strong><br data-start=\"6843\" data-end=\"6846\">The concerned registrar verifies details, inspects premises if required, and reviews supporting documents.</p>\r\n</li>\r\n<li data-start=\"6957\" data-end=\"7093\">\r\n<p data-start=\"6960\" data-end=\"7093\"><strong data-start=\"6960\" data-end=\"6988\">Issuance of Certificate:</strong><br data-start=\"6988\" data-end=\"6991\">Once approved, the authority issues a <strong data-start=\"7032\" data-end=\"7063\">Certificate of Registration</strong>, legally recognizing the NGO.</p>\r\n</li>\r\n<li data-start=\"7095\" data-end=\"7252\">\r\n<p data-start=\"7098\" data-end=\"7252\"><strong data-start=\"7098\" data-end=\"7132\">Post-Registration Compliances:</strong><br data-start=\"7132\" data-end=\"7135\">Application for PAN, TAN, bank account, and other tax or regulatory registrations such as 12A, 80G, CSR, and FCRA.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"7254\" data-end=\"7257\">\r\n<h2 data-start=\"7259\" data-end=\"7294\"><strong data-start=\"7262\" data-end=\"7294\">Tax Exemption and Compliance</strong></h2>\r\n<p data-start=\"7296\" data-end=\"7444\">Registered NGOs can apply for tax exemptions under the Income Tax Act, which enhances their credibility and allows donors to contribute confidently.</p>\r\n<p data-start=\"7446\" data-end=\"7604\"><strong data-start=\"7446\" data-end=\"7467\">12A Registration:</strong> Grants the NGO exemption from paying income tax on its surplus funds. It is mandatory for NGOs that wish to receive grants or donations.</p>\r\n<p data-start=\"7606\" data-end=\"7791\"><strong data-start=\"7606\" data-end=\"7628\">80G Certification:</strong> Allows donors to claim tax deduction on the amount donated to the NGO. Both certificates are issued by the Income Tax Department and must be renewed periodically.</p>\r\n<p data-start=\"7793\" data-end=\"7994\">To obtain these, the NGO must submit audited financial statements, an activity report, and the details of trustees or directors. 12A and 80G status make an NGO eligible for government and CSR projects.</p>\r\n<hr data-start=\"7996\" data-end=\"7999\">\r\n<h2 data-start=\"8001\" data-end=\"8032\"><strong data-start=\"8004\" data-end=\"8032\">Foreign Funding and FCRA</strong></h2>\r\n<p data-start=\"8034\" data-end=\"8344\">Foreign funding to NGOs in India is regulated under the <strong data-start=\"8090\" data-end=\"8144\">Foreign Contribution (Regulation) Act (FCRA), 2010</strong>, amended in 2020. Any NGO receiving donations from outside India must be registered under FCRA. The Ministry of Home Affairs grants FCRA registration after verifying activities and financial records.</p>\r\n<p data-start=\"8346\" data-end=\"8736\">Eligibility conditions include three years of active operation, consistent audited accounts, and 12A registration. All foreign contributions must be received in a designated bank account at the State Bank of India, New Delhi. NGOs must maintain separate accounts for foreign funds and file annual returns (Form FC-4). Non-compliance can result in suspension or cancellation of registration.</p>\r\n<hr data-start=\"8738\" data-end=\"8741\">\r\n<h2 data-start=\"8743\" data-end=\"8778\"><strong data-start=\"8746\" data-end=\"8778\">Post-Registration Governance</strong></h2>\r\n<p data-start=\"8780\" data-end=\"8985\">Once registered, an NGO must maintain transparency and comply with statutory obligations. These include maintaining books of accounts, conducting annual audits, holding meetings, and filing annual reports.</p>\r\n<p data-start=\"8987\" data-end=\"9242\">Trusts must maintain trustee meeting minutes and accounts. Societies must submit an annual list of members and audited reports to the Registrar of Societies. Section 8 Companies must file ROC returns (AOC-4, MGT-7) and get their accounts audited annually.</p>\r\n<p data-start=\"9244\" data-end=\"9454\">Regular meetings of the Board of Trustees, Governing Body, or Directors help ensure accountability and effectiveness. NGOs must also adhere to their bylaws and avoid diverting funds for non-charitable purposes.</p>\r\n<hr data-start=\"9456\" data-end=\"9459\">\r\n<h2 data-start=\"9461\" data-end=\"9516\"><strong data-start=\"9464\" data-end=\"9516\">Case Study: Education for All Foundation, Jaipur</strong></h2>\r\n<p data-start=\"9518\" data-end=\"9768\">A group of teachers in Jaipur decided to start an organization to provide free evening classes for underprivileged students. After consulting with professionals, they registered their entity as a <strong data-start=\"9714\" data-end=\"9735\">Section 8 Company</strong> under the Companies Act, 2013.</p>\r\n<p data-start=\"9770\" data-end=\"10330\">The application process included name approval, drafting of Memorandum and Articles of Association, and filing SPICe+ forms through the MCA portal. Within 12 days, they received the Certificate of Incorporation.<br data-start=\"9981\" data-end=\"9984\">The NGO subsequently applied for PAN, TAN, 12A, and 80G registration. With these in place, they secured CSR funding from a local IT company to install digital classrooms.<br data-start=\"10154\" data-end=\"10157\">Within two years, the organization expanded to five centres teaching 350+ students &mdash; a perfect example of how proper legal registration leads to growth and donor confidence.</p>\r\n<hr data-start=\"10332\" data-end=\"10335\">\r\n<h2 data-start=\"10337\" data-end=\"10368\"><strong data-start=\"10340\" data-end=\"10368\">Comparison of Structures</strong></h2>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"10370\" data-end=\"11139\">\r\n<thead data-start=\"10370\" data-end=\"10419\">\r\n<tr data-start=\"10370\" data-end=\"10419\">\r\n<th data-start=\"10370\" data-end=\"10380\" data-col-size=\"sm\">Feature</th>\r\n<th data-start=\"10380\" data-end=\"10388\" data-col-size=\"sm\">Trust</th>\r\n<th data-start=\"10388\" data-end=\"10398\" data-col-size=\"sm\">Society</th>\r\n<th data-start=\"10398\" data-end=\"10419\" data-col-size=\"sm\">Section 8 Company</th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"10472\" data-end=\"11139\">\r\n<tr data-start=\"10472\" data-end=\"10556\">\r\n<td data-start=\"10472\" data-end=\"10488\" data-col-size=\"sm\">Governing Law</td>\r\n<td data-col-size=\"sm\" data-start=\"10488\" data-end=\"10513\">Indian Trusts Act 1882</td>\r\n<td data-col-size=\"sm\" data-start=\"10513\" data-end=\"10534\">Societies Act 1860</td>\r\n<td data-col-size=\"sm\" data-start=\"10534\" data-end=\"10556\">Companies Act 2013</td>\r\n</tr>\r\n<tr data-start=\"10557\" data-end=\"10615\">\r\n<td data-start=\"10557\" data-end=\"10575\" data-col-size=\"sm\">Minimum Members</td>\r\n<td data-col-size=\"sm\" data-start=\"10575\" data-end=\"10588\">2 Trustees</td>\r\n<td data-col-size=\"sm\" data-start=\"10588\" data-end=\"10600\">7 Members</td>\r\n<td data-col-size=\"sm\" data-start=\"10600\" data-end=\"10615\">2 Directors</td>\r\n</tr>\r\n<tr data-start=\"10616\" data-end=\"10697\">\r\n<td data-start=\"10616\" data-end=\"10633\" data-col-size=\"sm\">Governing Body</td>\r\n<td data-col-size=\"sm\" data-start=\"10633\" data-end=\"10653\">Board of Trustees</td>\r\n<td data-col-size=\"sm\" data-start=\"10653\" data-end=\"10675\">Executive Committee</td>\r\n<td data-col-size=\"sm\" data-start=\"10675\" data-end=\"10697\">Board of Directors</td>\r\n</tr>\r\n<tr data-start=\"10698\" data-end=\"10790\">\r\n<td data-start=\"10698\" data-end=\"10723\" data-col-size=\"sm\">Registration Authority</td>\r\n<td data-col-size=\"sm\" data-start=\"10723\" data-end=\"10739\">Sub-Registrar</td>\r\n<td data-col-size=\"sm\" data-start=\"10739\" data-end=\"10764\">Registrar of Societies</td>\r\n<td data-col-size=\"sm\" data-start=\"10764\" data-end=\"10790\">Registrar of Companies</td>\r\n</tr>\r\n<tr data-start=\"10791\" data-end=\"10833\">\r\n<td data-start=\"10791\" data-end=\"10810\" data-col-size=\"sm\">Compliance Level</td>\r\n<td data-col-size=\"sm\" data-start=\"10810\" data-end=\"10816\">Low</td>\r\n<td data-col-size=\"sm\" data-start=\"10816\" data-end=\"10825\">Medium</td>\r\n<td data-col-size=\"sm\" data-start=\"10825\" data-end=\"10833\">High</td>\r\n</tr>\r\n<tr data-start=\"10834\" data-end=\"10885\">\r\n<td data-start=\"10834\" data-end=\"10849\" data-col-size=\"sm\">Annual Audit</td>\r\n<td data-col-size=\"sm\" data-start=\"10849\" data-end=\"10860\">Optional</td>\r\n<td data-col-size=\"sm\" data-start=\"10860\" data-end=\"10872\">Mandatory</td>\r\n<td data-col-size=\"sm\" data-start=\"10872\" data-end=\"10885\">Mandatory</td>\r\n</tr>\r\n<tr data-start=\"10886\" data-end=\"10938\">\r\n<td data-start=\"10886\" data-end=\"10901\" data-col-size=\"sm\">Legal Status</td>\r\n<td data-col-size=\"sm\" data-start=\"10901\" data-end=\"10909\">Local</td>\r\n<td data-col-size=\"sm\" data-start=\"10909\" data-end=\"10926\">State/National</td>\r\n<td data-col-size=\"sm\" data-start=\"10926\" data-end=\"10938\">National</td>\r\n</tr>\r\n<tr data-start=\"10939\" data-end=\"10995\">\r\n<td data-start=\"10939\" data-end=\"10961\" data-col-size=\"sm\">Eligibility for CSR</td>\r\n<td data-col-size=\"sm\" data-start=\"10961\" data-end=\"10971\">Limited</td>\r\n<td data-col-size=\"sm\" data-start=\"10971\" data-end=\"10982\">Moderate</td>\r\n<td data-col-size=\"sm\" data-start=\"10982\" data-end=\"10995\">Excellent</td>\r\n</tr>\r\n<tr data-start=\"10996\" data-end=\"11048\">\r\n<td data-start=\"10996\" data-end=\"11017\" data-col-size=\"sm\">FCRA Applicability</td>\r\n<td data-col-size=\"sm\" data-start=\"11017\" data-end=\"11029\">Difficult</td>\r\n<td data-col-size=\"sm\" data-start=\"11029\" data-end=\"11039\">Average</td>\r\n<td data-col-size=\"sm\" data-start=\"11039\" data-end=\"11048\">Ideal</td>\r\n</tr>\r\n<tr data-start=\"11049\" data-end=\"11139\">\r\n<td data-start=\"11049\" data-end=\"11061\" data-col-size=\"sm\">Ideal For</td>\r\n<td data-col-size=\"sm\" data-start=\"11061\" data-end=\"11087\">Local charitable causes</td>\r\n<td data-col-size=\"sm\" data-start=\"11087\" data-end=\"11112\">Cultural/social groups</td>\r\n<td data-col-size=\"sm\" data-start=\"11112\" data-end=\"11139\">Large NGOs, foundations</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<hr data-start=\"11141\" data-end=\"11144\">\r\n<h2 data-start=\"11146\" data-end=\"11186\"><strong data-start=\"11149\" data-end=\"11186\">Common Issues in NGO Registration</strong></h2>\r\n<ul data-start=\"11188\" data-end=\"11498\">\r\n<li data-start=\"11188\" data-end=\"11245\">\r\n<p data-start=\"11190\" data-end=\"11245\">Improper drafting of objectives leading to rejection.</p>\r\n</li>\r\n<li data-start=\"11246\" data-end=\"11286\">\r\n<p data-start=\"11248\" data-end=\"11286\">Use of existing or restricted names.</p>\r\n</li>\r\n<li data-start=\"11287\" data-end=\"11328\">\r\n<p data-start=\"11289\" data-end=\"11328\">Missing signatures or address proofs.</p>\r\n</li>\r\n<li data-start=\"11329\" data-end=\"11386\">\r\n<p data-start=\"11331\" data-end=\"11386\">Failure to maintain accounts and file annual reports.</p>\r\n</li>\r\n<li data-start=\"11387\" data-end=\"11430\">\r\n<p data-start=\"11389\" data-end=\"11430\">Not renewing 12A, 80G, or FCRA on time.</p>\r\n</li>\r\n<li data-start=\"11431\" data-end=\"11498\">\r\n<p data-start=\"11433\" data-end=\"11498\">Inadequate record-keeping of meetings and utilization of funds.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"11500\" data-end=\"11604\">Professional guidance helps avoid these mistakes, ensuring smooth registration and long-term compliance.</p>\r\n<hr data-start=\"11606\" data-end=\"11609\">\r\n<h2 data-start=\"11611\" data-end=\"11657\"><strong data-start=\"11614\" data-end=\"11657\">Rajasthan Filings&rsquo; Professional Support</strong></h2>\r\n<p data-start=\"11659\" data-end=\"11777\">Rajasthan Filings provides a complete solution for NGO registration and compliance across India. The process includes:</p>\r\n<ol data-start=\"11779\" data-end=\"12222\">\r\n<li data-start=\"11779\" data-end=\"11869\">\r\n<p data-start=\"11782\" data-end=\"11869\"><strong data-start=\"11782\" data-end=\"11799\">Consultation:</strong> Understanding your cause and recommending the best legal structure.</p>\r\n</li>\r\n<li data-start=\"11870\" data-end=\"11963\">\r\n<p data-start=\"11873\" data-end=\"11963\"><strong data-start=\"11873\" data-end=\"11891\">Documentation:</strong> Drafting Trust Deed, MOA, AOA, and legal affidavits by CA/CS experts.</p>\r\n</li>\r\n<li data-start=\"11964\" data-end=\"12056\">\r\n<p data-start=\"11967\" data-end=\"12056\"><strong data-start=\"11967\" data-end=\"11989\">Filing &amp; Approval:</strong> Handling all government liaison until the certificate is issued.</p>\r\n</li>\r\n<li data-start=\"12057\" data-end=\"12148\">\r\n<p data-start=\"12060\" data-end=\"12148\"><strong data-start=\"12060\" data-end=\"12082\">Post-Registration:</strong> Support in PAN, TAN, GST, 12A, 80G, CSR, and FCRA registration.</p>\r\n</li>\r\n<li data-start=\"12149\" data-end=\"12222\">\r\n<p data-start=\"12152\" data-end=\"12222\"><strong data-start=\"12152\" data-end=\"12175\">Compliance Support:</strong> Annual filing, audit, and renewal reminders.</p>\r\n</li>\r\n</ol>\r\n<p data-start=\"12224\" data-end=\"12394\">Our experienced team ensures zero rejection and timely delivery. We handle end-to-end documentation, legal drafting, and representation before registrars and departments.</p>\r\n<hr data-start=\"12396\" data-end=\"12399\">\r\n<h2 data-start=\"12401\" data-end=\"12418\"><strong data-start=\"12404\" data-end=\"12418\">Conclusion</strong></h2>\r\n<p data-start=\"12420\" data-end=\"12808\">NGOs are essential agents of social change. By obtaining proper registration, they gain legal recognition, transparency, and access to funding that helps them serve society effectively.<br data-start=\"12605\" data-end=\"12608\">Whether you wish to form a Trust for local welfare, a Society for cultural promotion, or a Section 8 Company for large-scale development projects, legal compliance is the foundation of sustainability.</p>\r\n<p data-start=\"12810\" data-end=\"13082\">Rajasthan Filings offers a single-window solution for all forms of NGO registration &mdash; from planning to post-approval compliance. Our goal is to empower changemakers with legal clarity and administrative simplicity so they can focus on what truly matters &mdash; creating impact.</p>\r\n<p data-start=\"13084\" data-end=\"13181\">For professional NGO registration support and expert legal drafting, connect with our team today.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-25 04:45:23', '2025-11-08 00:52:07');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(23, 1, NULL, 'FSSAI License / Renewal', 'fssai-license--renewal', 'FSSAI Food License / Renewal in India', '<h1 data-start=\"374\" data-end=\"419\"><strong data-start=\"376\" data-end=\"417\">FSSAI Food License / Renewal in India</strong></h1>\r\n<h3 data-start=\"420\" data-end=\"499\">Legal Approval for Every Food Business &ndash; Made Simple by Rajasthan Filings</h3>\r\n<p data-start=\"501\" data-end=\"833\">Food safety and hygiene are critical aspects of running a food business in India. The <strong data-start=\"587\" data-end=\"643\">Food Safety and Standards Authority of India (FSSAI)</strong>, established under the <strong data-start=\"667\" data-end=\"706\">Food Safety and Standards Act, 2006</strong>, regulates all food-related businesses to ensure that the food consumed by the public is safe, healthy, and of high quality.</p>\r\n<p data-start=\"835\" data-end=\"1193\">Every business involved in the <strong data-start=\"866\" data-end=\"958\">manufacture, processing, storage, distribution, transportation, or sale of food products</strong> must obtain an FSSAI license or registration before starting operations. Whether you run a small bakery, dairy plant, restaurant, retail shop, food truck, catering unit, or export company &mdash; FSSAI registration is a legal requirement.</p>\r\n<p data-start=\"1195\" data-end=\"1431\">At <strong data-start=\"1198\" data-end=\"1219\">Rajasthan Filings</strong>, we help businesses obtain, renew, and upgrade their FSSAI licenses with complete documentation, accurate compliance, and expert consultation, ensuring your business stays legally protected and consumer-ready.</p>\r\n<hr data-start=\"1433\" data-end=\"1436\">\r\n<h2 data-start=\"1438\" data-end=\"1477\"><strong data-start=\"1441\" data-end=\"1477\">Importance of FSSAI Registration</strong></h2>\r\n<p data-start=\"1479\" data-end=\"1596\">Obtaining an FSSAI registration is not just about legal compliance &mdash; it&rsquo;s about <strong data-start=\"1559\" data-end=\"1593\">building trust and credibility</strong>.</p>\r\n<ul data-start=\"1598\" data-end=\"2132\">\r\n<li data-start=\"1598\" data-end=\"1700\">\r\n<p data-start=\"1600\" data-end=\"1700\">✅ <strong data-start=\"1602\" data-end=\"1623\">Mandatory by Law:</strong> Every food business operator (FBO) in India must be registered with FSSAI.</p>\r\n</li>\r\n<li data-start=\"1701\" data-end=\"1823\">\r\n<p data-start=\"1703\" data-end=\"1823\">✅ <strong data-start=\"1705\" data-end=\"1729\">Consumer Confidence:</strong> The FSSAI logo on packaging signals that your products meet national food safety standards.</p>\r\n</li>\r\n<li data-start=\"1824\" data-end=\"1928\">\r\n<p data-start=\"1826\" data-end=\"1928\">✅ <strong data-start=\"1828\" data-end=\"1851\">Business Expansion:</strong> Essential for retail tie-ups, e-commerce listings, and government tenders.</p>\r\n</li>\r\n<li data-start=\"1929\" data-end=\"2029\">\r\n<p data-start=\"1931\" data-end=\"2029\">✅ <strong data-start=\"1933\" data-end=\"1956\">Avoiding Penalties:</strong> Operating without an FSSAI license can lead to heavy fines or closure.</p>\r\n</li>\r\n<li data-start=\"2030\" data-end=\"2132\">\r\n<p data-start=\"2032\" data-end=\"2132\">✅ <strong data-start=\"2034\" data-end=\"2061\">Food Quality Assurance:</strong> It ensures adherence to scientific standards and hygiene benchmarks.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"2134\" data-end=\"2137\">\r\n<h2 data-start=\"2139\" data-end=\"2172\"><strong data-start=\"2142\" data-end=\"2172\">Who Needs an FSSAI License</strong></h2>\r\n<p data-start=\"2174\" data-end=\"2260\">The FSSAI registration is mandatory for all types of food business operators (FBOs):</p>\r\n<ul data-start=\"2262\" data-end=\"2687\">\r\n<li data-start=\"2262\" data-end=\"2309\">\r\n<p data-start=\"2264\" data-end=\"2309\">Food manufacturers, processors, and packers</p>\r\n</li>\r\n<li data-start=\"2310\" data-end=\"2360\">\r\n<p data-start=\"2312\" data-end=\"2360\">Restaurants, hotels, caf&eacute;s, and cloud kitchens</p>\r\n</li>\r\n<li data-start=\"2361\" data-end=\"2405\">\r\n<p data-start=\"2363\" data-end=\"2405\">Retailers, wholesalers, and distributors</p>\r\n</li>\r\n<li data-start=\"2406\" data-end=\"2443\">\r\n<p data-start=\"2408\" data-end=\"2443\">Food storage and cold-chain units</p>\r\n</li>\r\n<li data-start=\"2444\" data-end=\"2496\">\r\n<p data-start=\"2446\" data-end=\"2496\">Online food aggregators (Swiggy, Zomato vendors)</p>\r\n</li>\r\n<li data-start=\"2497\" data-end=\"2545\">\r\n<p data-start=\"2499\" data-end=\"2545\">Dairy, meat, bakery, and confectionery units</p>\r\n</li>\r\n<li data-start=\"2546\" data-end=\"2606\">\r\n<p data-start=\"2548\" data-end=\"2606\">Caterers and canteens in schools, hospitals, and offices</p>\r\n</li>\r\n<li data-start=\"2607\" data-end=\"2651\">\r\n<p data-start=\"2609\" data-end=\"2651\">Importers and exporters of food products</p>\r\n</li>\r\n<li data-start=\"2652\" data-end=\"2687\">\r\n<p data-start=\"2654\" data-end=\"2687\">Food transporters or warehouses</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2689\" data-end=\"2801\">Even small street vendors, tea stalls, and home-based bakers must obtain a <strong data-start=\"2764\" data-end=\"2786\">Basic Registration</strong> under FSSAI.</p>\r\n<hr data-start=\"2803\" data-end=\"2806\">\r\n<h2 data-start=\"2808\" data-end=\"2837\"><strong data-start=\"2811\" data-end=\"2837\">Types of FSSAI License</strong></h2>\r\n<p data-start=\"2839\" data-end=\"2938\">FSSAI issues three categories of registration depending on the size and turnover of the business:</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2940\" data-end=\"3515\">\r\n<thead data-start=\"2940\" data-end=\"3024\">\r\n<tr data-start=\"2940\" data-end=\"3024\">\r\n<th data-start=\"2940\" data-end=\"2951\" data-col-size=\"sm\"><strong data-start=\"2942\" data-end=\"2950\">Type</strong></th>\r\n<th data-start=\"2951\" data-end=\"2987\" data-col-size=\"sm\"><strong data-start=\"2953\" data-end=\"2986\">Eligibility / Annual Turnover</strong></th>\r\n<th data-start=\"2987\" data-end=\"3003\" data-col-size=\"sm\"><strong data-start=\"2989\" data-end=\"3002\">Issued By</strong></th>\r\n<th data-start=\"3003\" data-end=\"3024\" data-col-size=\"md\"><strong data-start=\"3005\" data-end=\"3022\">Applicable To</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"3113\" data-end=\"3515\">\r\n<tr data-start=\"3113\" data-end=\"3230\">\r\n<td data-start=\"3113\" data-end=\"3138\" data-col-size=\"sm\"><strong data-start=\"3115\" data-end=\"3137\">Basic Registration</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"3138\" data-end=\"3155\">Upto ₹12 lakhs</td>\r\n<td data-col-size=\"sm\" data-start=\"3155\" data-end=\"3173\">Local Authority</td>\r\n<td data-col-size=\"md\" data-start=\"3173\" data-end=\"3230\">Small retailers, petty food businesses, home kitchens</td>\r\n</tr>\r\n<tr data-start=\"3231\" data-end=\"3363\">\r\n<td data-start=\"3231\" data-end=\"3251\" data-col-size=\"sm\"><strong data-start=\"3233\" data-end=\"3250\">State License</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"3251\" data-end=\"3276\">₹12 lakhs &ndash; ₹20 crores</td>\r\n<td data-col-size=\"sm\" data-start=\"3276\" data-end=\"3307\">State Food Safety Department</td>\r\n<td data-col-size=\"md\" data-start=\"3307\" data-end=\"3363\">Medium-scale units, restaurants, small manufacturers</td>\r\n</tr>\r\n<tr data-start=\"3364\" data-end=\"3515\">\r\n<td data-start=\"3364\" data-end=\"3386\" data-col-size=\"sm\"><strong data-start=\"3366\" data-end=\"3385\">Central License</strong></td>\r\n<td data-col-size=\"sm\" data-start=\"3386\" data-end=\"3429\">Above ₹20 crores / interstate operations</td>\r\n<td data-col-size=\"sm\" data-start=\"3429\" data-end=\"3452\">Central FSSAI Office</td>\r\n<td data-col-size=\"md\" data-start=\"3452\" data-end=\"3515\">Large manufacturers, exporters, importers, central kitchens</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"3517\" data-end=\"3631\">Every food business must prominently display its <strong data-start=\"3566\" data-end=\"3599\">14-digit FSSAI License Number</strong> at premises and on packaging.</p>\r\n<hr data-start=\"3633\" data-end=\"3636\">\r\n<h2 data-start=\"3638\" data-end=\"3663\"><strong data-start=\"3641\" data-end=\"3663\">Documents Required</strong></h2>\r\n<h3 data-start=\"3665\" data-end=\"3691\">For Basic Registration</h3>\r\n<ul data-start=\"3692\" data-end=\"3872\">\r\n<li data-start=\"3692\" data-end=\"3732\">\r\n<p data-start=\"3694\" data-end=\"3732\">Passport-size photo of the applicant</p>\r\n</li>\r\n<li data-start=\"3733\" data-end=\"3778\">\r\n<p data-start=\"3735\" data-end=\"3778\">Identity proof (Aadhaar / PAN / Voter ID)</p>\r\n</li>\r\n<li data-start=\"3779\" data-end=\"3817\">\r\n<p data-start=\"3781\" data-end=\"3817\">Address proof of business premises</p>\r\n</li>\r\n<li data-start=\"3818\" data-end=\"3851\">\r\n<p data-start=\"3820\" data-end=\"3851\">Details of food items handled</p>\r\n</li>\r\n<li data-start=\"3852\" data-end=\"3872\">\r\n<p data-start=\"3854\" data-end=\"3872\">Declaration Form</p>\r\n</li>\r\n</ul>\r\n<h3 data-start=\"3874\" data-end=\"3906\">For State or Central License</h3>\r\n<ul data-start=\"3907\" data-end=\"4404\">\r\n<li data-start=\"3907\" data-end=\"3940\">\r\n<p data-start=\"3909\" data-end=\"3940\">Form-B duly filled and signed</p>\r\n</li>\r\n<li data-start=\"3941\" data-end=\"3990\">\r\n<p data-start=\"3943\" data-end=\"3990\">Photo ID of proprietor / partners / directors</p>\r\n</li>\r\n<li data-start=\"3991\" data-end=\"4062\">\r\n<p data-start=\"3993\" data-end=\"4062\">Proof of possession of premises (rent agreement / ownership papers)</p>\r\n</li>\r\n<li data-start=\"4063\" data-end=\"4110\">\r\n<p data-start=\"4065\" data-end=\"4110\">Blueprint or layout of food processing unit</p>\r\n</li>\r\n<li data-start=\"4111\" data-end=\"4146\">\r\n<p data-start=\"4113\" data-end=\"4146\">List of machinery and equipment</p>\r\n</li>\r\n<li data-start=\"4147\" data-end=\"4203\">\r\n<p data-start=\"4149\" data-end=\"4203\">List of food categories to be manufactured or traded</p>\r\n</li>\r\n<li data-start=\"4204\" data-end=\"4249\">\r\n<p data-start=\"4206\" data-end=\"4249\">Water analysis report (for manufacturers)</p>\r\n</li>\r\n<li data-start=\"4250\" data-end=\"4304\">\r\n<p data-start=\"4252\" data-end=\"4304\">Proof of turnover (Balance Sheet / CA certificate)</p>\r\n</li>\r\n<li data-start=\"4305\" data-end=\"4355\">\r\n<p data-start=\"4307\" data-end=\"4355\">Nomination of responsible person under FSS Act</p>\r\n</li>\r\n<li data-start=\"4356\" data-end=\"4404\">\r\n<p data-start=\"4358\" data-end=\"4404\">NOC from the local municipality or panchayat</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"4406\" data-end=\"4409\">\r\n<h2 data-start=\"4411\" data-end=\"4454\"><strong data-start=\"4414\" data-end=\"4454\">FSSAI Registration / License Process</strong></h2>\r\n<p data-start=\"4456\" data-end=\"4617\">1️⃣ <strong data-start=\"4460\" data-end=\"4504\">Consultation and Category Identification</strong><br data-start=\"4504\" data-end=\"4507\">Our experts assess your business model and determine whether you need a Basic, State, or Central license.</p>\r\n<p data-start=\"4619\" data-end=\"4772\">2️⃣ <strong data-start=\"4623\" data-end=\"4663\">Document Collection and Verification</strong><br data-start=\"4663\" data-end=\"4666\">We prepare all required documents, application forms, and declarations according to FSSAI guidelines.</p>\r\n<p data-start=\"4774\" data-end=\"4945\">3️⃣ <strong data-start=\"4778\" data-end=\"4826\">Online Application Filing (Form-A or Form-B)</strong><br data-start=\"4826\" data-end=\"4829\">The application is submitted on the <strong data-start=\"4868\" data-end=\"4917\">Food Licensing and Registration System (FLRS)</strong> or the <strong data-start=\"4925\" data-end=\"4942\">FoSCoS portal</strong>.</p>\r\n<p data-start=\"4947\" data-end=\"5104\">4️⃣ <strong data-start=\"4951\" data-end=\"4994\">Departmental Inspection (if applicable)</strong><br data-start=\"4994\" data-end=\"4997\">In some cases, the food safety officer inspects the premises for hygiene and infrastructure standards.</p>\r\n<p data-start=\"5106\" data-end=\"5272\">5️⃣ <strong data-start=\"5110\" data-end=\"5143\">License Approval and Issuance</strong><br data-start=\"5143\" data-end=\"5146\">Once verified, FSSAI issues a digitally signed license or registration certificate, generally valid for <strong data-start=\"5253\" data-end=\"5269\">1 to 5 years</strong>.</p>\r\n<p data-start=\"5274\" data-end=\"5404\">6️⃣ <strong data-start=\"5278\" data-end=\"5302\">Post-License Support</strong><br data-start=\"5302\" data-end=\"5305\">Rajasthan Filings assists in logo usage, compliance maintenance, and annual renewal reminders.</p>\r\n<hr data-start=\"5406\" data-end=\"5409\">\r\n<h2 data-start=\"5411\" data-end=\"5442\"><strong data-start=\"5414\" data-end=\"5442\">Renewal of FSSAI License</strong></h2>\r\n<p data-start=\"5444\" data-end=\"5678\">An FSSAI license must be renewed before its expiry date to maintain business continuity. Renewal can be done <strong data-start=\"5553\" data-end=\"5583\">120 days before expiration</strong> on the same portal. Late renewal attracts penalties of ₹100 per day or license cancellation.</p>\r\n<p data-start=\"5680\" data-end=\"5704\"><strong data-start=\"5680\" data-end=\"5702\">Steps for Renewal:</strong></p>\r\n<ul data-start=\"5705\" data-end=\"5936\">\r\n<li data-start=\"5705\" data-end=\"5755\">\r\n<p data-start=\"5707\" data-end=\"5755\">Review current license details and activities.</p>\r\n</li>\r\n<li data-start=\"5756\" data-end=\"5807\">\r\n<p data-start=\"5758\" data-end=\"5807\">File renewal application online through FoSCoS.</p>\r\n</li>\r\n<li data-start=\"5808\" data-end=\"5866\">\r\n<p data-start=\"5810\" data-end=\"5866\">Pay renewal fee and upload updated documents (if any).</p>\r\n</li>\r\n<li data-start=\"5867\" data-end=\"5902\">\r\n<p data-start=\"5869\" data-end=\"5902\">Conduct inspection if required.</p>\r\n</li>\r\n<li data-start=\"5903\" data-end=\"5936\">\r\n<p data-start=\"5905\" data-end=\"5936\">Download renewed certificate.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5938\" data-end=\"6065\">Rajasthan Filings monitors renewal timelines and sends reminders well before the due date, ensuring uninterrupted compliance.</p>\r\n<hr data-start=\"6067\" data-end=\"6070\">\r\n<h2 data-start=\"6072\" data-end=\"6116\"><strong data-start=\"6075\" data-end=\"6116\">FSSAI License Validity and Conditions</strong></h2>\r\n<ul data-start=\"6118\" data-end=\"6467\">\r\n<li data-start=\"6118\" data-end=\"6176\">\r\n<p data-start=\"6120\" data-end=\"6176\">Valid for <strong data-start=\"6130\" data-end=\"6146\">1 to 5 years</strong>, depending on the fee paid.</p>\r\n</li>\r\n<li data-start=\"6177\" data-end=\"6221\">\r\n<p data-start=\"6179\" data-end=\"6221\">Renewal to be applied for before expiry.</p>\r\n</li>\r\n<li data-start=\"6222\" data-end=\"6286\">\r\n<p data-start=\"6224\" data-end=\"6286\">License must be displayed prominently at the business place.</p>\r\n</li>\r\n<li data-start=\"6287\" data-end=\"6385\">\r\n<p data-start=\"6289\" data-end=\"6385\">Any change in business address, ownership, or product category must be updated within 30 days.</p>\r\n</li>\r\n<li data-start=\"6386\" data-end=\"6467\">\r\n<p data-start=\"6388\" data-end=\"6467\">Food products must comply with all FSSAI packaging and labelling regulations.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6469\" data-end=\"6584\">Failure to comply can result in suspension or cancellation under Section 32 of the Food Safety and Standards Act.</p>\r\n<hr data-start=\"6586\" data-end=\"6589\">\r\n<h2 data-start=\"6591\" data-end=\"6629\"><strong data-start=\"6594\" data-end=\"6629\">Hygiene and Safety Requirements</strong></h2>\r\n<p data-start=\"6631\" data-end=\"6790\">FBOs are required to maintain proper <strong data-start=\"6668\" data-end=\"6714\">hygiene, cleanliness, and safety standards</strong> under Schedule 4 of the FSS (Licensing &amp; Registration) Regulations, 2011.</p>\r\n<p data-start=\"6792\" data-end=\"6819\">Key requirements include:</p>\r\n<ul data-start=\"6820\" data-end=\"7098\">\r\n<li data-start=\"6820\" data-end=\"6865\">\r\n<p data-start=\"6822\" data-end=\"6865\">Clean surroundings and pest-free premises</p>\r\n</li>\r\n<li data-start=\"6866\" data-end=\"6916\">\r\n<p data-start=\"6868\" data-end=\"6916\">Use of safe, potable water in food preparation</p>\r\n</li>\r\n<li data-start=\"6917\" data-end=\"6964\">\r\n<p data-start=\"6919\" data-end=\"6964\">Proper waste disposal and sanitation system</p>\r\n</li>\r\n<li data-start=\"6965\" data-end=\"7006\">\r\n<p data-start=\"6967\" data-end=\"7006\">Periodic medical check-ups of workers</p>\r\n</li>\r\n<li data-start=\"7007\" data-end=\"7056\">\r\n<p data-start=\"7009\" data-end=\"7056\">Maintenance of temperature-controlled storage</p>\r\n</li>\r\n<li data-start=\"7057\" data-end=\"7098\">\r\n<p data-start=\"7059\" data-end=\"7098\">Compliance with FSSAI labelling norms</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7100\" data-end=\"7103\">\r\n<h2 data-start=\"7105\" data-end=\"7141\"><strong data-start=\"7108\" data-end=\"7141\">Annual Returns and Compliance</strong></h2>\r\n<p data-start=\"7143\" data-end=\"7319\">Every food manufacturer and importer must file <strong data-start=\"7190\" data-end=\"7225\">annual returns (Form D-1 / D-2)</strong> by May 31 each year. Separate returns are required for milk, dairy, or perishable products.</p>\r\n<p data-start=\"7321\" data-end=\"7440\">Regular audits and inspections ensure that hygiene and safety standards are maintained. Rajasthan Filings assists in:</p>\r\n<ul data-start=\"7441\" data-end=\"7619\">\r\n<li data-start=\"7441\" data-end=\"7490\">\r\n<p data-start=\"7443\" data-end=\"7490\">Filing annual returns and maintaining reports</p>\r\n</li>\r\n<li data-start=\"7491\" data-end=\"7525\">\r\n<p data-start=\"7493\" data-end=\"7525\">Renewing or upgrading licenses</p>\r\n</li>\r\n<li data-start=\"7526\" data-end=\"7568\">\r\n<p data-start=\"7528\" data-end=\"7568\">Responding to FSSAI notices or queries</p>\r\n</li>\r\n<li data-start=\"7569\" data-end=\"7619\">\r\n<p data-start=\"7571\" data-end=\"7619\">Updating changes in food category or ownership</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7621\" data-end=\"7624\">\r\n<h2 data-start=\"7626\" data-end=\"7661\"><strong data-start=\"7629\" data-end=\"7661\">Penalties for Non-Compliance</strong></h2>\r\n<p data-start=\"7663\" data-end=\"7743\">Operating without a valid license or registration can attract heavy penalties:</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"7745\" data-end=\"8109\">\r\n<thead data-start=\"7745\" data-end=\"7774\">\r\n<tr data-start=\"7745\" data-end=\"7774\">\r\n<th data-start=\"7745\" data-end=\"7759\" data-col-size=\"sm\"><strong data-start=\"7747\" data-end=\"7758\">Offence</strong></th>\r\n<th data-start=\"7759\" data-end=\"7774\" data-col-size=\"sm\"><strong data-start=\"7761\" data-end=\"7772\">Penalty</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"7806\" data-end=\"8109\">\r\n<tr data-start=\"7806\" data-end=\"7877\">\r\n<td data-start=\"7806\" data-end=\"7834\" data-col-size=\"sm\">Operating without license</td>\r\n<td data-col-size=\"sm\" data-start=\"7834\" data-end=\"7877\">Up to ₹5,00,000 and closure of business</td>\r\n</tr>\r\n<tr data-start=\"7878\" data-end=\"7937\">\r\n<td data-start=\"7878\" data-end=\"7900\" data-col-size=\"sm\">Selling unsafe food</td>\r\n<td data-col-size=\"sm\" data-start=\"7900\" data-end=\"7937\">Up to ₹10,00,000 and imprisonment</td>\r\n</tr>\r\n<tr data-start=\"7938\" data-end=\"7992\">\r\n<td data-start=\"7938\" data-end=\"7973\" data-col-size=\"sm\">Misbranding or misleading claims</td>\r\n<td data-col-size=\"sm\" data-start=\"7973\" data-end=\"7992\">Up to ₹3,00,000</td>\r\n</tr>\r\n<tr data-start=\"7993\" data-end=\"8051\">\r\n<td data-start=\"7993\" data-end=\"8032\" data-col-size=\"sm\">Substandard or unhygienic conditions</td>\r\n<td data-col-size=\"sm\" data-start=\"8032\" data-end=\"8051\">Up to ₹2,00,000</td>\r\n</tr>\r\n<tr data-start=\"8052\" data-end=\"8109\">\r\n<td data-start=\"8052\" data-end=\"8079\" data-col-size=\"sm\">Delay in license renewal</td>\r\n<td data-col-size=\"sm\" data-start=\"8079\" data-end=\"8109\">₹100 per day until renewed</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"8111\" data-end=\"8200\">Proper registration and renewal help avoid these penalties and maintain consumer trust.</p>\r\n<hr data-start=\"8202\" data-end=\"8205\">\r\n<h2 data-start=\"8207\" data-end=\"8239\"><strong data-start=\"8210\" data-end=\"8239\">Benefits of FSSAI License</strong></h2>\r\n<ul data-start=\"8241\" data-end=\"8611\">\r\n<li data-start=\"8241\" data-end=\"8291\">\r\n<p data-start=\"8243\" data-end=\"8291\">Legal authorization to operate a food business</p>\r\n</li>\r\n<li data-start=\"8292\" data-end=\"8343\">\r\n<p data-start=\"8294\" data-end=\"8343\">Builds brand reputation and consumer confidence</p>\r\n</li>\r\n<li data-start=\"8344\" data-end=\"8395\">\r\n<p data-start=\"8346\" data-end=\"8395\">Access to government loans and trade facilities</p>\r\n</li>\r\n<li data-start=\"8396\" data-end=\"8444\">\r\n<p data-start=\"8398\" data-end=\"8444\">Facilitates business expansion across states</p>\r\n</li>\r\n<li data-start=\"8445\" data-end=\"8506\">\r\n<p data-start=\"8447\" data-end=\"8506\">Eligible for e-commerce listing (Amazon, BigBasket, etc.)</p>\r\n</li>\r\n<li data-start=\"8507\" data-end=\"8557\">\r\n<p data-start=\"8509\" data-end=\"8557\">Ensures compliance with food quality standards</p>\r\n</li>\r\n<li data-start=\"8558\" data-end=\"8611\">\r\n<p data-start=\"8560\" data-end=\"8611\">Reduces risk of legal disputes or product seizure</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"8613\" data-end=\"8616\">\r\n<h2 data-start=\"8618\" data-end=\"8656\"><strong data-start=\"8621\" data-end=\"8656\">Rajasthan Filings Support Model</strong></h2>\r\n<p data-start=\"8658\" data-end=\"8770\">Rajasthan Filings offers an end-to-end solution for FSSAI registration, renewal, modification, and compliance:</p>\r\n<ul data-start=\"8772\" data-end=\"9168\">\r\n<li data-start=\"8772\" data-end=\"8829\">\r\n<p data-start=\"8774\" data-end=\"8829\">Expert analysis of business type and license category</p>\r\n</li>\r\n<li data-start=\"8830\" data-end=\"8877\">\r\n<p data-start=\"8832\" data-end=\"8877\">Preparation of all documents and affidavits</p>\r\n</li>\r\n<li data-start=\"8878\" data-end=\"8928\">\r\n<p data-start=\"8880\" data-end=\"8928\">Filing of applications on FoSCoS / FLRS portal</p>\r\n</li>\r\n<li data-start=\"8929\" data-end=\"8989\">\r\n<p data-start=\"8931\" data-end=\"8989\">Coordination with food safety departments for inspection</p>\r\n</li>\r\n<li data-start=\"8990\" data-end=\"9040\">\r\n<p data-start=\"8992\" data-end=\"9040\">Delivery of final certificate and FSSAI number</p>\r\n</li>\r\n<li data-start=\"9041\" data-end=\"9103\">\r\n<p data-start=\"9043\" data-end=\"9103\">Renewal and modification tracking with automated reminders</p>\r\n</li>\r\n<li data-start=\"9104\" data-end=\"9168\">\r\n<p data-start=\"9106\" data-end=\"9168\">Guidance on labelling, packaging, and product category codes</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"9170\" data-end=\"9253\">Our team of experienced professionals ensures zero rejection and timely approval.</p>\r\n<hr data-start=\"9255\" data-end=\"9258\">\r\n<h2 data-start=\"9260\" data-end=\"9287\"><strong data-start=\"9263\" data-end=\"9287\">Illustrative Example</strong></h2>\r\n<p data-start=\"9289\" data-end=\"9716\">A small dairy business in Jaipur wanted to expand from local milk distribution to packaged dairy products. Rajasthan Filings helped the owner upgrade from a <strong data-start=\"9446\" data-end=\"9474\">Basic FSSAI Registration</strong> to a <strong data-start=\"9480\" data-end=\"9497\">State License</strong> by preparing new machinery lists, water testing reports, and updated balance sheets. Within 10 days, the license was approved, enabling the company to supply products across Rajasthan supermarkets legally and safely.</p>\r\n<hr data-start=\"9718\" data-end=\"9721\">\r\n<h2 data-start=\"9723\" data-end=\"9767\"><strong data-start=\"9726\" data-end=\"9767\">Common Mistakes in FSSAI Registration</strong></h2>\r\n<ul data-start=\"9769\" data-end=\"10042\">\r\n<li data-start=\"9769\" data-end=\"9842\">\r\n<p data-start=\"9771\" data-end=\"9842\">Applying under the wrong category (Basic instead of State or Central)</p>\r\n</li>\r\n<li data-start=\"9843\" data-end=\"9890\">\r\n<p data-start=\"9845\" data-end=\"9890\">Submitting incomplete or outdated documents</p>\r\n</li>\r\n<li data-start=\"9891\" data-end=\"9935\">\r\n<p data-start=\"9893\" data-end=\"9935\">Delay in renewal leading to cancellation</p>\r\n</li>\r\n<li data-start=\"9936\" data-end=\"9990\">\r\n<p data-start=\"9938\" data-end=\"9990\">Ignoring inspection reports and corrective actions</p>\r\n</li>\r\n<li data-start=\"9991\" data-end=\"10042\">\r\n<p data-start=\"9993\" data-end=\"10042\">Misuse of FSSAI logo without valid registration</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"10044\" data-end=\"10122\">Professional filing avoids such issues and ensures uninterrupted operations.</p>\r\n<hr data-start=\"10124\" data-end=\"10127\">\r\n<h2 data-start=\"10129\" data-end=\"10146\"><strong data-start=\"10132\" data-end=\"10146\">Conclusion</strong></h2>\r\n<p data-start=\"10148\" data-end=\"10448\">In India&rsquo;s fast-growing food industry, compliance with FSSAI regulations is both a <strong data-start=\"10231\" data-end=\"10285\">legal requirement and a mark of quality assurance.</strong> Whether you are running a small food stall or a nationwide manufacturing unit, having a valid FSSAI license builds trust and opens new opportunities for growth.</p>\r\n<p data-start=\"10450\" data-end=\"10697\">Rajasthan Filings offers complete assistance for <strong data-start=\"10499\" data-end=\"10587\">FSSAI registration, renewal, modification, annual returns, and compliance management</strong> under one roof. Our experts handle all technical and legal aspects, saving you time, effort, and penalties.</p>\r\n<p data-start=\"10699\" data-end=\"10784\">Ensure your food business is 100% compliant &mdash; partner with Rajasthan Filings today.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-25 05:06:15', '2025-11-08 00:52:03'),
(24, 1, NULL, 'Import-Export Code (IEC)', 'import-export-code-iec', 'Import-Export Code (IEC)', '<h1 data-start=\"319\" data-end=\"373\"><strong data-start=\"321\" data-end=\"371\">Import-Export Code (IEC) Registration in India</strong></h1>\r\n<h3 data-start=\"374\" data-end=\"436\">Unlock Global Trade Opportunities with Rajasthan Filings</h3>\r\n<p data-start=\"438\" data-end=\"778\">The <strong data-start=\"442\" data-end=\"470\">Import Export Code (IEC)</strong> is the first and most essential requirement for any business in India that wants to start international trade. Issued by the <strong data-start=\"596\" data-end=\"643\">Directorate General of Foreign Trade (DGFT)</strong> under the <strong data-start=\"654\" data-end=\"691\">Ministry of Commerce and Industry</strong>, IEC registration enables businesses to import and export goods or services legally.</p>\r\n<p data-start=\"780\" data-end=\"1076\">Without an IEC, a business cannot conduct cross-border trade, receive international payments, or avail government export benefits. At <strong data-start=\"914\" data-end=\"935\">Rajasthan Filings</strong>, we make the entire process seamless &mdash; from application filing to final code issuance &mdash; ensuring you can begin global trade without delay.</p>\r\n<hr data-start=\"1078\" data-end=\"1081\">\r\n<h2 data-start=\"1083\" data-end=\"1119\"><strong data-start=\"1086\" data-end=\"1119\">Meaning and Importance of IEC</strong></h2>\r\n<p data-start=\"1121\" data-end=\"1387\">The Import-Export Code is a <strong data-start=\"1149\" data-end=\"1190\">10-digit unique identification number</strong> issued to Indian businesses and individuals for export or import of goods and services. It serves as a <strong data-start=\"1294\" data-end=\"1329\">primary business identification</strong> recognized by customs, banks, and government departments.</p>\r\n<p data-start=\"1389\" data-end=\"1424\"><strong data-start=\"1389\" data-end=\"1422\">Key Reasons IEC is Mandatory:</strong></p>\r\n<ul data-start=\"1425\" data-end=\"1747\">\r\n<li data-start=\"1425\" data-end=\"1480\">\r\n<p data-start=\"1427\" data-end=\"1480\">Required by customs authorities to clear shipments.</p>\r\n</li>\r\n<li data-start=\"1481\" data-end=\"1537\">\r\n<p data-start=\"1483\" data-end=\"1537\">Mandatory for receiving export payments from abroad.</p>\r\n</li>\r\n<li data-start=\"1538\" data-end=\"1619\">\r\n<p data-start=\"1540\" data-end=\"1619\">Needed to claim incentives under DGFT, Customs, or Export Promotion Councils.</p>\r\n</li>\r\n<li data-start=\"1620\" data-end=\"1683\">\r\n<p data-start=\"1622\" data-end=\"1683\">Essential for opening current accounts in foreign currency.</p>\r\n</li>\r\n<li data-start=\"1684\" data-end=\"1747\">\r\n<p data-start=\"1686\" data-end=\"1747\">Acts as a permanent business identification for global trade.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"1749\" data-end=\"1752\">\r\n<h2 data-start=\"1754\" data-end=\"1778\"><strong data-start=\"1757\" data-end=\"1778\">Who Needs an IEC?</strong></h2>\r\n<p data-start=\"1780\" data-end=\"1814\">IEC registration is required by:</p>\r\n<ul data-start=\"1815\" data-end=\"2162\">\r\n<li data-start=\"1815\" data-end=\"1866\">\r\n<p data-start=\"1817\" data-end=\"1866\">Importers buying goods or services from abroad.</p>\r\n</li>\r\n<li data-start=\"1867\" data-end=\"1921\">\r\n<p data-start=\"1869\" data-end=\"1921\">Exporters selling goods or services outside India.</p>\r\n</li>\r\n<li data-start=\"1922\" data-end=\"1979\">\r\n<p data-start=\"1924\" data-end=\"1979\">Businesses participating in international e-commerce.</p>\r\n</li>\r\n<li data-start=\"1980\" data-end=\"2047\">\r\n<p data-start=\"1982\" data-end=\"2047\">Manufacturers supplying goods to Special Economic Zones (SEZs).</p>\r\n</li>\r\n<li data-start=\"2048\" data-end=\"2105\">\r\n<p data-start=\"2050\" data-end=\"2105\">Service providers dealing with international clients.</p>\r\n</li>\r\n<li data-start=\"2106\" data-end=\"2162\">\r\n<p data-start=\"2108\" data-end=\"2162\">Individuals receiving export commission or payments.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2164\" data-end=\"2260\">Even proprietors and freelancers engaged in cross-border transactions must obtain an IEC number.</p>\r\n<hr data-start=\"2262\" data-end=\"2265\">\r\n<h2 data-start=\"2267\" data-end=\"2298\"><strong data-start=\"2270\" data-end=\"2298\">When IEC is Not Required</strong></h2>\r\n<p data-start=\"2300\" data-end=\"2327\">IEC is not required when:</p>\r\n<ul data-start=\"2328\" data-end=\"2540\">\r\n<li data-start=\"2328\" data-end=\"2406\">\r\n<p data-start=\"2330\" data-end=\"2406\">Goods or services are imported/exported for personal use (non-commercial).</p>\r\n</li>\r\n<li data-start=\"2407\" data-end=\"2474\">\r\n<p data-start=\"2409\" data-end=\"2474\">Transactions conducted by Government Departments or Ministries.</p>\r\n</li>\r\n<li data-start=\"2475\" data-end=\"2540\">\r\n<p data-start=\"2477\" data-end=\"2540\">Import or export activities restricted by DGFT notifications.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2542\" data-end=\"2629\">However, for most commercial transactions, IEC is compulsory and permanent once issued.</p>\r\n<hr data-start=\"2631\" data-end=\"2634\">\r\n<h2 data-start=\"2636\" data-end=\"2671\"><strong data-start=\"2639\" data-end=\"2671\">Benefits of IEC Registration</strong></h2>\r\n<ul data-start=\"2673\" data-end=\"3192\">\r\n<li data-start=\"2673\" data-end=\"2778\">\r\n<p data-start=\"2675\" data-end=\"2778\"><strong data-start=\"2675\" data-end=\"2707\">Global Business Recognition:</strong> Enables your business to legally participate in international trade.</p>\r\n</li>\r\n<li data-start=\"2779\" data-end=\"2868\">\r\n<p data-start=\"2781\" data-end=\"2868\"><strong data-start=\"2781\" data-end=\"2800\">Easy Expansion:</strong> Allows seamless import and export of goods or services worldwide.</p>\r\n</li>\r\n<li data-start=\"2869\" data-end=\"2952\">\r\n<p data-start=\"2871\" data-end=\"2952\"><strong data-start=\"2871\" data-end=\"2894\">Government Schemes:</strong> Access to DGFT, MEIS, SEIS, and EPC incentive programs.</p>\r\n</li>\r\n<li data-start=\"2953\" data-end=\"3042\">\r\n<p data-start=\"2955\" data-end=\"3042\"><strong data-start=\"2955\" data-end=\"2983\">Bank &amp; Customs Validity:</strong> Required for foreign transactions and customs clearance.</p>\r\n</li>\r\n<li data-start=\"3043\" data-end=\"3113\">\r\n<p data-start=\"3045\" data-end=\"3113\"><strong data-start=\"3045\" data-end=\"3067\">Lifetime Validity:</strong> One-time registration, no renewal required.</p>\r\n</li>\r\n<li data-start=\"3114\" data-end=\"3192\">\r\n<p data-start=\"3116\" data-end=\"3192\"><strong data-start=\"3116\" data-end=\"3136\">Business Growth:</strong> Builds credibility with foreign buyers and suppliers.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"3194\" data-end=\"3197\">\r\n<h2 data-start=\"3199\" data-end=\"3245\"><strong data-start=\"3202\" data-end=\"3245\">Documents Required for IEC Registration</strong></h2>\r\n<ol data-start=\"3247\" data-end=\"3689\">\r\n<li data-start=\"3247\" data-end=\"3291\">\r\n<p data-start=\"3250\" data-end=\"3291\"><strong data-start=\"3250\" data-end=\"3262\">PAN Card</strong> of business or proprietor.</p>\r\n</li>\r\n<li data-start=\"3292\" data-end=\"3351\">\r\n<p data-start=\"3295\" data-end=\"3351\"><strong data-start=\"3295\" data-end=\"3311\">Aadhaar Card</strong> of proprietor / partners / directors.</p>\r\n</li>\r\n<li data-start=\"3352\" data-end=\"3399\">\r\n<p data-start=\"3355\" data-end=\"3399\"><strong data-start=\"3355\" data-end=\"3383\">Passport-size photograph</strong> of applicant.</p>\r\n</li>\r\n<li data-start=\"3400\" data-end=\"3463\">\r\n<p data-start=\"3403\" data-end=\"3463\"><strong data-start=\"3403\" data-end=\"3419\">Bank details</strong> &ndash; cancelled cheque or banker certificate.</p>\r\n</li>\r\n<li data-start=\"3464\" data-end=\"3553\">\r\n<p data-start=\"3467\" data-end=\"3553\"><strong data-start=\"3467\" data-end=\"3484\">Address proof</strong> of business (rent agreement / ownership paper / electricity bill).</p>\r\n</li>\r\n<li data-start=\"3554\" data-end=\"3613\">\r\n<p data-start=\"3557\" data-end=\"3613\"><strong data-start=\"3557\" data-end=\"3611\">Digital Signature Certificate (if company or LLP).</strong></p>\r\n</li>\r\n<li data-start=\"3614\" data-end=\"3689\">\r\n<p data-start=\"3617\" data-end=\"3689\"><strong data-start=\"3617\" data-end=\"3647\">Email ID and mobile number</strong> linked to Aadhaar for OTP verification.</p>\r\n</li>\r\n</ol>\r\n<hr data-start=\"3691\" data-end=\"3694\">\r\n<h2 data-start=\"3696\" data-end=\"3743\"><strong data-start=\"3699\" data-end=\"3743\">Step-by-Step Process of IEC Registration</strong></h2>\r\n<p data-start=\"3745\" data-end=\"3897\">1️⃣ <strong data-start=\"3749\" data-end=\"3772\">Business Evaluation</strong><br data-start=\"3772\" data-end=\"3775\">Our experts determine your business constitution (Proprietorship / Partnership / LLP / Pvt Ltd) and verify PAN details.</p>\r\n<p data-start=\"3899\" data-end=\"4024\">2️⃣ <strong data-start=\"3903\" data-end=\"3931\">Preparation of Documents</strong><br data-start=\"3931\" data-end=\"3934\">Required documents are prepared in soft copy format according to DGFT portal standards.</p>\r\n<p data-start=\"4026\" data-end=\"4165\">3️⃣ <strong data-start=\"4030\" data-end=\"4066\">Filing Application (ANF-2A Form)</strong><br data-start=\"4066\" data-end=\"4069\">We submit your online application through the <strong data-start=\"4118\" data-end=\"4133\">DGFT portal</strong> using PAN as login credentials.</p>\r\n<p data-start=\"4167\" data-end=\"4277\">4️⃣ <strong data-start=\"4171\" data-end=\"4200\">Payment of Government Fee</strong><br data-start=\"4200\" data-end=\"4203\">The prescribed application fee is paid online via DGFT payment gateway.</p>\r\n<p data-start=\"4279\" data-end=\"4426\">5️⃣ <strong data-start=\"4283\" data-end=\"4318\">OTP Verification and Submission</strong><br data-start=\"4318\" data-end=\"4321\">Authentication is done through OTP on linked mobile and email. Details are reviewed before submission.</p>\r\n<p data-start=\"4428\" data-end=\"4569\">6️⃣ <strong data-start=\"4432\" data-end=\"4453\">IEC Code Issuance</strong><br data-start=\"4453\" data-end=\"4456\">Once approved, DGFT issues a <strong data-start=\"4488\" data-end=\"4526\">digitally signed e-IEC certificate</strong>, downloadable immediately from the portal.</p>\r\n<p data-start=\"4571\" data-end=\"4642\">⏱ <strong data-start=\"4573\" data-end=\"4586\">Timeline:</strong> Normally 1&ndash;2 working days (if all details are correct).</p>\r\n<hr data-start=\"4644\" data-end=\"4647\">\r\n<h2 data-start=\"4649\" data-end=\"4680\"><strong data-start=\"4652\" data-end=\"4680\">IEC Structure and Format</strong></h2>\r\n<p data-start=\"4682\" data-end=\"4779\">IEC is a <strong data-start=\"4691\" data-end=\"4721\">10-digit alphanumeric code</strong> unique to each business entity.<br data-start=\"4753\" data-end=\"4756\">Example: <em data-start=\"4765\" data-end=\"4777\">0512345678</em></p>\r\n<ul data-start=\"4780\" data-end=\"4895\">\r\n<li data-start=\"4780\" data-end=\"4839\">\r\n<p data-start=\"4782\" data-end=\"4839\">The first two digits represent the issuing office code.</p>\r\n</li>\r\n<li data-start=\"4840\" data-end=\"4895\">\r\n<p data-start=\"4842\" data-end=\"4895\">The remaining digits represent the business identity.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"4897\" data-end=\"4998\">Once issued, it remains valid for the lifetime of the business and does not require periodic renewal.</p>\r\n<hr data-start=\"5000\" data-end=\"5003\">\r\n<h2 data-start=\"5005\" data-end=\"5038\"><strong data-start=\"5008\" data-end=\"5038\">Post-Registration Benefits</strong></h2>\r\n<ul data-start=\"5040\" data-end=\"5389\">\r\n<li data-start=\"5040\" data-end=\"5117\">\r\n<p data-start=\"5042\" data-end=\"5117\">Can export and import goods without restrictions (subject to DGFT rules).</p>\r\n</li>\r\n<li data-start=\"5118\" data-end=\"5181\">\r\n<p data-start=\"5120\" data-end=\"5181\">Eligible to register with Export Promotion Councils (EPCs).</p>\r\n</li>\r\n<li data-start=\"5182\" data-end=\"5239\">\r\n<p data-start=\"5184\" data-end=\"5239\">Eligible for various customs and GST refund benefits.</p>\r\n</li>\r\n<li data-start=\"5240\" data-end=\"5305\">\r\n<p data-start=\"5242\" data-end=\"5305\">Can participate in international trade fairs and exhibitions.</p>\r\n</li>\r\n<li data-start=\"5306\" data-end=\"5389\">\r\n<p data-start=\"5308\" data-end=\"5389\">Enables exporters to claim benefits under <em data-start=\"5350\" data-end=\"5367\">RoDTEP, RoSCTL,</em> and <em data-start=\"5372\" data-end=\"5378\">SEIS</em> schemes.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"5391\" data-end=\"5394\">\r\n<h2 data-start=\"5396\" data-end=\"5434\"><strong data-start=\"5399\" data-end=\"5434\">Modification or Updation of IEC</strong></h2>\r\n<p data-start=\"5436\" data-end=\"5576\">Any change in business details such as address, directors, ownership, or bank account must be updated within <strong data-start=\"5545\" data-end=\"5556\">30 days</strong> on the DGFT portal.</p>\r\n<p data-start=\"5578\" data-end=\"5607\"><strong data-start=\"5578\" data-end=\"5605\">Steps for Modification:</strong></p>\r\n<ul data-start=\"5608\" data-end=\"5808\">\r\n<li data-start=\"5608\" data-end=\"5650\">\r\n<p data-start=\"5610\" data-end=\"5650\">Login to DGFT portal with credentials.</p>\r\n</li>\r\n<li data-start=\"5651\" data-end=\"5702\">\r\n<p data-start=\"5653\" data-end=\"5702\">Choose &ldquo;Amend IEC&rdquo; and update relevant details.</p>\r\n</li>\r\n<li data-start=\"5703\" data-end=\"5765\">\r\n<p data-start=\"5705\" data-end=\"5765\">Upload supporting documents (NOC, Board Resolution, etc.).</p>\r\n</li>\r\n<li data-start=\"5766\" data-end=\"5808\">\r\n<p data-start=\"5768\" data-end=\"5808\">Submit and download updated certificate.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5810\" data-end=\"5950\">Rajasthan Filings assists in all types of amendments &mdash; name change, branch addition, or director replacement &mdash; to ensure continued validity.</p>\r\n<hr data-start=\"5952\" data-end=\"5955\">\r\n<h2 data-start=\"5957\" data-end=\"6015\"><strong data-start=\"5960\" data-end=\"6015\">IEC Renewal / Annual Updation (Mandatory from 2021)</strong></h2>\r\n<p data-start=\"6017\" data-end=\"6188\">As per the DGFT Notification No. 58/2015-2020 dated 12th February 2021, all IEC holders must <strong data-start=\"6110\" data-end=\"6159\">confirm and update their IEC details annually</strong>, even if no changes occur.</p>\r\n<p data-start=\"6190\" data-end=\"6401\">Failure to update may lead to <strong data-start=\"6220\" data-end=\"6243\">deactivation of IEC</strong>. Reactivation is possible by updating details online anytime thereafter. Rajasthan Filings provides complete renewal and update support every financial year.</p>\r\n<hr data-start=\"6403\" data-end=\"6406\">\r\n<h2 data-start=\"6408\" data-end=\"6437\"><strong data-start=\"6411\" data-end=\"6437\">Common Errors to Avoid</strong></h2>\r\n<ul data-start=\"6439\" data-end=\"6689\">\r\n<li data-start=\"6439\" data-end=\"6497\">\r\n<p data-start=\"6441\" data-end=\"6497\">Mismatch between business name on PAN and application.</p>\r\n</li>\r\n<li data-start=\"6498\" data-end=\"6534\">\r\n<p data-start=\"6500\" data-end=\"6534\">Wrong bank details or IFSC code.</p>\r\n</li>\r\n<li data-start=\"6535\" data-end=\"6584\">\r\n<p data-start=\"6537\" data-end=\"6584\">Incorrect address proof or expired documents.</p>\r\n</li>\r\n<li data-start=\"6585\" data-end=\"6649\">\r\n<p data-start=\"6587\" data-end=\"6649\">Failure to digitally sign application for companies or LLPs.</p>\r\n</li>\r\n<li data-start=\"6650\" data-end=\"6689\">\r\n<p data-start=\"6652\" data-end=\"6689\">Ignoring annual update requirement.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6691\" data-end=\"6788\">Our compliance experts verify every document before submission, preventing rejections and delays.</p>\r\n<hr data-start=\"6790\" data-end=\"6793\">\r\n<h2 data-start=\"6795\" data-end=\"6830\"><strong data-start=\"6798\" data-end=\"6830\">Penalties for Non-Compliance</strong></h2>\r\n<p data-start=\"6832\" data-end=\"6895\">Operating imports or exports without a valid IEC can lead to:</p>\r\n<ul data-start=\"6896\" data-end=\"7131\">\r\n<li data-start=\"6896\" data-end=\"6940\">\r\n<p data-start=\"6898\" data-end=\"6940\">Seizure of goods by Customs authorities.</p>\r\n</li>\r\n<li data-start=\"6941\" data-end=\"6986\">\r\n<p data-start=\"6943\" data-end=\"6986\">Denial of export benefits or GST refunds.</p>\r\n</li>\r\n<li data-start=\"6987\" data-end=\"7038\">\r\n<p data-start=\"6989\" data-end=\"7038\">Delay in foreign remittance clearance by banks.</p>\r\n</li>\r\n<li data-start=\"7039\" data-end=\"7131\">\r\n<p data-start=\"7041\" data-end=\"7131\">Penalty under Section 11(2) of the Foreign Trade (Development and Regulation) Act, 1992.</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7133\" data-end=\"7136\">\r\n<h2 data-start=\"7138\" data-end=\"7165\"><strong data-start=\"7141\" data-end=\"7165\">Illustrative Example</strong></h2>\r\n<p data-start=\"7167\" data-end=\"7645\">A textile manufacturer from Rajasthan wanted to start exporting garments to Dubai. With the help of Rajasthan Filings, the firm obtained an IEC code within one day. This allowed them to register with the <strong data-start=\"7371\" data-end=\"7414\">Apparel Export Promotion Council (AEPC)</strong> and claim benefits under the <strong data-start=\"7444\" data-end=\"7461\">RoDTEP Scheme</strong>, increasing profit margins by 5%.<br data-start=\"7495\" data-end=\"7498\">The firm later used the same IEC for importing specialized fabrics, proving that a single code supports both export and import activities for life.</p>\r\n<hr data-start=\"7647\" data-end=\"7650\">\r\n<h2 data-start=\"7652\" data-end=\"7710\"><strong data-start=\"7655\" data-end=\"7710\">Advantages of Getting IEC Through Rajasthan Filings</strong></h2>\r\n<ul data-start=\"7712\" data-end=\"8083\">\r\n<li data-start=\"7712\" data-end=\"7765\">\r\n<p data-start=\"7714\" data-end=\"7765\">End-to-end online application and document filing</p>\r\n</li>\r\n<li data-start=\"7766\" data-end=\"7831\">\r\n<p data-start=\"7768\" data-end=\"7831\">Verification of business and bank details to avoid rejections</p>\r\n</li>\r\n<li data-start=\"7832\" data-end=\"7877\">\r\n<p data-start=\"7834\" data-end=\"7877\">Fast processing and same-day IEC approval</p>\r\n</li>\r\n<li data-start=\"7878\" data-end=\"7946\">\r\n<p data-start=\"7880\" data-end=\"7946\">Assistance in IEC modification, reactivation, and annual updates</p>\r\n</li>\r\n<li data-start=\"7947\" data-end=\"8023\">\r\n<p data-start=\"7949\" data-end=\"8023\">Expert guidance on export incentives, DGFT schemes, and EPC registration</p>\r\n</li>\r\n<li data-start=\"8024\" data-end=\"8083\">\r\n<p data-start=\"8026\" data-end=\"8083\">Lifetime client support for all DGFT-related compliance</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"8085\" data-end=\"8088\">\r\n<h2 data-start=\"8090\" data-end=\"8140\"><strong data-start=\"8093\" data-end=\"8140\">Why IEC is a Growth Tool for Every Business</strong></h2>\r\n<p data-start=\"8142\" data-end=\"8586\">IEC is not just a license &mdash; it is the passport for your business to enter the global market. With India expanding its export base through &ldquo;Make in India&rdquo; and &ldquo;Digital Trade Facilitation,&rdquo; every manufacturer, trader, and service provider has an opportunity to explore global buyers.<br data-start=\"8423\" data-end=\"8426\">IEC opens the door to export incentives, foreign clients, and business partnerships that can transform a small domestic operation into an international brand.</p>\r\n<hr data-start=\"8588\" data-end=\"8591\">\r\n<h2 data-start=\"8593\" data-end=\"8610\"><strong data-start=\"8596\" data-end=\"8610\">Conclusion</strong></h2>\r\n<p data-start=\"8612\" data-end=\"8819\">Obtaining an Import Export Code (IEC) is the <strong data-start=\"8657\" data-end=\"8702\">first step towards global business growth</strong>. It legitimizes your trade operations, simplifies customs procedures, and connects you to opportunities worldwide.</p>\r\n<p data-start=\"8821\" data-end=\"9051\">With Rajasthan Filings, you can complete your IEC registration online within a single day. Our team ensures accuracy, transparency, and long-term compliance so that your business can grow beyond borders confidently and lawfully.</p>\r\n<p data-start=\"9053\" data-end=\"9150\">Start your journey in international trade today with expert support from <strong data-start=\"9126\" data-end=\"9147\">Rajasthan Filings</strong>.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-25 05:28:07', '2025-11-08 00:52:02');
INSERT INTO `services` (`id`, `category_id`, `subcategory_id`, `title`, `slug`, `short_description`, `description`, `advantages`, `eligibility`, `image`, `multiple_images`, `status`, `created_at`, `updated_at`) VALUES
(25, 1, NULL, 'Trade License', 'trade-license', 'Trade License Registration', '<h1 data-start=\"422\" data-end=\"465\"><strong data-start=\"424\" data-end=\"463\">Trade License Registration in India</strong></h1>\r\n<h3 data-start=\"466\" data-end=\"567\">Legal Permission to Run Your Business within Municipal Limits &ndash; Simplified by Rajasthan Filings</h3>\r\n<p data-start=\"569\" data-end=\"770\">Every business establishment operating in India &mdash; whether small, medium, or large &mdash; is required to obtain a <strong data-start=\"677\" data-end=\"694\">Trade License</strong> from the local municipal authority before starting commercial activities.</p>\r\n<p data-start=\"772\" data-end=\"1002\">A <strong data-start=\"774\" data-end=\"791\">Trade License</strong> is a mandatory legal document that gives permission to carry on a particular trade or business at a specific location while ensuring that the business does not pose any health or safety hazards to the public.</p>\r\n<p data-start=\"1004\" data-end=\"1211\">At <strong data-start=\"1007\" data-end=\"1028\">Rajasthan Filings</strong>, we help entrepreneurs, shopkeepers, traders, and corporate offices get their trade licenses quickly and efficiently from the relevant municipal or urban local bodies across India.</p>\r\n<hr data-start=\"1213\" data-end=\"1216\">\r\n<h2 data-start=\"1218\" data-end=\"1252\"><strong data-start=\"1221\" data-end=\"1252\">Understanding Trade License</strong></h2>\r\n<p data-start=\"1254\" data-end=\"1521\">A Trade License is issued by the <strong data-start=\"1287\" data-end=\"1357\">Municipal Corporation, Municipal Council, or Local Urban Authority</strong> under the respective State&rsquo;s Municipal Acts. It certifies that the business complies with all local laws relating to public health, safety, and nuisance control.</p>\r\n<p data-start=\"1523\" data-end=\"1573\">The objective of the Trade License system is to:</p>\r\n<ul data-start=\"1574\" data-end=\"1826\">\r\n<li data-start=\"1574\" data-end=\"1631\">\r\n<p data-start=\"1576\" data-end=\"1631\">Regulate business locations and ensure proper zoning.</p>\r\n</li>\r\n<li data-start=\"1632\" data-end=\"1697\">\r\n<p data-start=\"1634\" data-end=\"1697\">Protect citizens from improper or dangerous trade activities.</p>\r\n</li>\r\n<li data-start=\"1698\" data-end=\"1759\">\r\n<p data-start=\"1700\" data-end=\"1759\">Ensure hygienic conditions and lawful business practices.</p>\r\n</li>\r\n<li data-start=\"1760\" data-end=\"1826\">\r\n<p data-start=\"1762\" data-end=\"1826\">Collect local taxes and maintain trade records for governance.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"1828\" data-end=\"1908\">Without this license, a business cannot legally operate within municipal limits.</p>\r\n<hr data-start=\"1910\" data-end=\"1913\">\r\n<h2 data-start=\"1915\" data-end=\"1947\"><strong data-start=\"1918\" data-end=\"1947\">Who Needs a Trade License</strong></h2>\r\n<p data-start=\"1949\" data-end=\"2106\">Any individual, company, or organization engaged in commercial, industrial, or professional activities within a municipal area must obtain a Trade License.</p>\r\n<p data-start=\"2108\" data-end=\"2124\">This includes:</p>\r\n<ul data-start=\"2125\" data-end=\"2439\">\r\n<li data-start=\"2125\" data-end=\"2152\">\r\n<p data-start=\"2127\" data-end=\"2152\">Shops and retail stores</p>\r\n</li>\r\n<li data-start=\"2153\" data-end=\"2187\">\r\n<p data-start=\"2155\" data-end=\"2187\">Restaurants, hotels, and caf&eacute;s</p>\r\n</li>\r\n<li data-start=\"2188\" data-end=\"2214\">\r\n<p data-start=\"2190\" data-end=\"2214\">Warehouses and godowns</p>\r\n</li>\r\n<li data-start=\"2215\" data-end=\"2253\">\r\n<p data-start=\"2217\" data-end=\"2253\">Manufacturing and processing units</p>\r\n</li>\r\n<li data-start=\"2254\" data-end=\"2296\">\r\n<p data-start=\"2256\" data-end=\"2296\">Clinics, nursing homes, and pharmacies</p>\r\n</li>\r\n<li data-start=\"2297\" data-end=\"2333\">\r\n<p data-start=\"2299\" data-end=\"2333\">Cyber caf&eacute;s and internet centres</p>\r\n</li>\r\n<li data-start=\"2334\" data-end=\"2390\">\r\n<p data-start=\"2336\" data-end=\"2390\">Service providers, contractors, and repair workshops</p>\r\n</li>\r\n<li data-start=\"2391\" data-end=\"2439\">\r\n<p data-start=\"2393\" data-end=\"2439\">Small-scale traders and local establishments</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"2441\" data-end=\"2556\">Even home-based businesses or online sellers may require a trade license if operating from a commercial location.</p>\r\n<hr data-start=\"2558\" data-end=\"2561\">\r\n<h2 data-start=\"2563\" data-end=\"2592\"><strong data-start=\"2566\" data-end=\"2592\">Types of Trade License</strong></h2>\r\n<p data-start=\"2594\" data-end=\"2668\">Depending on the nature of business, licenses are classified as follows:</p>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"2670\" data-end=\"3151\">\r\n<thead data-start=\"2670\" data-end=\"2734\">\r\n<tr data-start=\"2670\" data-end=\"2734\">\r\n<th data-start=\"2670\" data-end=\"2692\" data-col-size=\"sm\"><strong data-start=\"2672\" data-end=\"2691\">Type of License</strong></th>\r\n<th data-start=\"2692\" data-end=\"2709\" data-col-size=\"md\"><strong data-start=\"2694\" data-end=\"2708\">Issued For</strong></th>\r\n<th data-start=\"2709\" data-end=\"2734\" data-col-size=\"md\"><strong data-start=\"2711\" data-end=\"2732\">Issuing Authority</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"2801\" data-end=\"3151\">\r\n<tr data-start=\"2801\" data-end=\"2913\">\r\n<td data-start=\"2801\" data-end=\"2829\" data-col-size=\"sm\"><strong data-start=\"2803\" data-end=\"2828\">General Trade License</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2829\" data-end=\"2873\">Commercial trading and service activities</td>\r\n<td data-col-size=\"md\" data-start=\"2873\" data-end=\"2913\">Municipal Corporation / Municipality</td>\r\n</tr>\r\n<tr data-start=\"2914\" data-end=\"3035\">\r\n<td data-start=\"2914\" data-end=\"2945\" data-col-size=\"sm\"><strong data-start=\"2916\" data-end=\"2944\">Industrial Trade License</strong></td>\r\n<td data-col-size=\"md\" data-start=\"2945\" data-end=\"2981\">Manufacturing or production units</td>\r\n<td data-col-size=\"md\" data-start=\"2981\" data-end=\"3035\">Industrial Development Authority or Municipal Body</td>\r\n</tr>\r\n<tr data-start=\"3036\" data-end=\"3151\">\r\n<td data-start=\"3036\" data-end=\"3063\" data-col-size=\"sm\"><strong data-start=\"3038\" data-end=\"3062\">Health Trade License</strong></td>\r\n<td data-col-size=\"md\" data-start=\"3063\" data-end=\"3120\">Businesses dealing in food, medicine, sanitation, etc.</td>\r\n<td data-col-size=\"md\" data-start=\"3120\" data-end=\"3151\">Municipal Health Department</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"3153\" data-end=\"3303\">Each State has its own rules and fee structures, but the general purpose remains the same &mdash; to ensure the business operates safely and within the law.</p>\r\n<hr data-start=\"3305\" data-end=\"3308\">\r\n<h2 data-start=\"3310\" data-end=\"3353\"><strong data-start=\"3313\" data-end=\"3353\">Documents Required for Trade License</strong></h2>\r\n<ul data-start=\"3355\" data-end=\"3811\">\r\n<li data-start=\"3355\" data-end=\"3395\">\r\n<p data-start=\"3357\" data-end=\"3395\">PAN Card of the applicant / business</p>\r\n</li>\r\n<li data-start=\"3396\" data-end=\"3433\">\r\n<p data-start=\"3398\" data-end=\"3433\">Aadhaar Card or ID proof of owner</p>\r\n</li>\r\n<li data-start=\"3434\" data-end=\"3501\">\r\n<p data-start=\"3436\" data-end=\"3501\">Business registration certificate (GST / Udyam / Incorporation)</p>\r\n</li>\r\n<li data-start=\"3502\" data-end=\"3554\">\r\n<p data-start=\"3504\" data-end=\"3554\">Proof of ownership or rent agreement of premises</p>\r\n</li>\r\n<li data-start=\"3555\" data-end=\"3594\">\r\n<p data-start=\"3557\" data-end=\"3594\">NOC from property owner (if rented)</p>\r\n</li>\r\n<li data-start=\"3595\" data-end=\"3626\">\r\n<p data-start=\"3597\" data-end=\"3626\">Recent property tax receipt</p>\r\n</li>\r\n<li data-start=\"3627\" data-end=\"3676\">\r\n<p data-start=\"3629\" data-end=\"3676\">Layout plan or site plan of business premises</p>\r\n</li>\r\n<li data-start=\"3677\" data-end=\"3713\">\r\n<p data-start=\"3679\" data-end=\"3713\">Electricity bill or utility bill</p>\r\n</li>\r\n<li data-start=\"3714\" data-end=\"3755\">\r\n<p data-start=\"3716\" data-end=\"3755\">Passport-size photograph of applicant</p>\r\n</li>\r\n<li data-start=\"3756\" data-end=\"3811\">\r\n<p data-start=\"3758\" data-end=\"3811\">Partnership Deed or MOA &amp; AOA (for firms/companies)</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"3813\" data-end=\"3949\">Additional documents may be required based on business type &mdash; for example, FSSAI license for restaurants or Pollution NOC for factories.</p>\r\n<hr data-start=\"3951\" data-end=\"3954\">\r\n<h2 data-start=\"3956\" data-end=\"4000\"><strong data-start=\"3959\" data-end=\"4000\">Process of Trade License Registration</strong></h2>\r\n<p data-start=\"4002\" data-end=\"4201\">1️⃣ <strong data-start=\"4006\" data-end=\"4050\">Business Assessment &amp; Category Selection</strong><br data-start=\"4050\" data-end=\"4053\">Rajasthan Filings identifies your business category and determines the correct type of trade license required (General, Industrial, or Health).</p>\r\n<p data-start=\"4203\" data-end=\"4362\">2️⃣ <strong data-start=\"4207\" data-end=\"4246\">Document Preparation &amp; Verification</strong><br data-start=\"4246\" data-end=\"4249\">All identity, address, and property documents are collected and verified according to municipal regulations.</p>\r\n<p data-start=\"4364\" data-end=\"4546\">3️⃣ <strong data-start=\"4368\" data-end=\"4411\">Online / Offline Application Submission</strong><br data-start=\"4411\" data-end=\"4414\">The trade license application is filed online through the municipal portal or submitted manually at the local authority office.</p>\r\n<p data-start=\"4548\" data-end=\"4701\">4️⃣ <strong data-start=\"4552\" data-end=\"4589\">Inspection &amp; Approval by Officers</strong><br data-start=\"4589\" data-end=\"4592\">A municipal inspector may visit the business premises to verify details, hygiene, and zoning compliance.</p>\r\n<p data-start=\"4703\" data-end=\"4902\">5️⃣ <strong data-start=\"4707\" data-end=\"4727\">License Issuance</strong><br data-start=\"4727\" data-end=\"4730\">Upon successful verification, the local authority issues the <strong data-start=\"4794\" data-end=\"4823\">Trade License Certificate</strong> specifying the business name, address, nature of trade, and validity period.</p>\r\n<p data-start=\"4904\" data-end=\"4986\">⏱ <strong data-start=\"4906\" data-end=\"4919\">Timeline:</strong> Usually within 7&ndash;15 working days, depending on the jurisdiction.</p>\r\n<hr data-start=\"4988\" data-end=\"4991\">\r\n<h2 data-start=\"4993\" data-end=\"5024\"><strong data-start=\"4996\" data-end=\"5024\">Renewal of Trade License</strong></h2>\r\n<p data-start=\"5026\" data-end=\"5196\">Trade Licenses are typically valid for <strong data-start=\"5065\" data-end=\"5081\">1 to 3 years</strong>, depending on the State rules.<br data-start=\"5112\" data-end=\"5115\">Renewal must be applied for <strong data-start=\"5143\" data-end=\"5174\">15 to 30 days before expiry</strong> to avoid penalties.</p>\r\n<p data-start=\"5198\" data-end=\"5220\"><strong data-start=\"5198\" data-end=\"5218\">Renewal Process:</strong></p>\r\n<ul data-start=\"5221\" data-end=\"5453\">\r\n<li data-start=\"5221\" data-end=\"5287\">\r\n<p data-start=\"5223\" data-end=\"5287\">Submit renewal application along with existing license number.</p>\r\n</li>\r\n<li data-start=\"5288\" data-end=\"5330\">\r\n<p data-start=\"5290\" data-end=\"5330\">Pay prescribed municipal renewal fees.</p>\r\n</li>\r\n<li data-start=\"5331\" data-end=\"5417\">\r\n<p data-start=\"5333\" data-end=\"5417\">Update documents if there are changes in address, business activity, or ownership.</p>\r\n</li>\r\n<li data-start=\"5418\" data-end=\"5453\">\r\n<p data-start=\"5420\" data-end=\"5453\">Obtain the renewed certificate.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"5455\" data-end=\"5624\">Failure to renew on time can lead to cancellation or heavy fines. Rajasthan Filings tracks renewal timelines and assists with smooth continuation of licenses every year.</p>\r\n<hr data-start=\"5626\" data-end=\"5629\">\r\n<h2 data-start=\"5631\" data-end=\"5663\"><strong data-start=\"5634\" data-end=\"5663\">Modification or Surrender</strong></h2>\r\n<p data-start=\"5665\" data-end=\"5960\">If there is any change in the business name, address, trade type, or ownership, an amendment must be made to the license within the prescribed time.<br data-start=\"5813\" data-end=\"5816\">Similarly, if a business ceases to operate, the license should be formally surrendered to the municipal authority to avoid future liabilities.</p>\r\n<p data-start=\"5962\" data-end=\"6077\">Rajasthan Filings helps in modification, ownership transfer, or surrender procedures under municipal regulations.</p>\r\n<hr data-start=\"6079\" data-end=\"6082\">\r\n<h2 data-start=\"6084\" data-end=\"6116\"><strong data-start=\"6087\" data-end=\"6116\">Inspection and Compliance</strong></h2>\r\n<p data-start=\"6118\" data-end=\"6298\">Once a license is issued, businesses are expected to maintain proper compliance and hygiene standards. The municipal health department may conduct periodic inspections to ensure:</p>\r\n<ul data-start=\"6299\" data-end=\"6513\">\r\n<li data-start=\"6299\" data-end=\"6351\">\r\n<p data-start=\"6301\" data-end=\"6351\">The trade activity matches the approved license.</p>\r\n</li>\r\n<li data-start=\"6352\" data-end=\"6402\">\r\n<p data-start=\"6354\" data-end=\"6402\">The business maintains cleanliness and safety.</p>\r\n</li>\r\n<li data-start=\"6403\" data-end=\"6457\">\r\n<p data-start=\"6405\" data-end=\"6457\">There are no unauthorized alterations to premises.</p>\r\n</li>\r\n<li data-start=\"6458\" data-end=\"6513\">\r\n<p data-start=\"6460\" data-end=\"6513\">Noise, pollution, or public nuisance is controlled.</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"6515\" data-end=\"6604\">Businesses found violating these conditions may face suspension or revocation of license.</p>\r\n<hr data-start=\"6606\" data-end=\"6609\">\r\n<h2 data-start=\"6611\" data-end=\"6646\"><strong data-start=\"6614\" data-end=\"6646\">Penalties for Non-Compliance</strong></h2>\r\n<div class=\"_tableContainer_1rjym_1\">\r\n<div class=\"group _tableWrapper_1rjym_13 flex w-fit flex-col-reverse\" tabindex=\"-1\">\r\n<table class=\"w-fit min-w-(--thread-content-width)\" data-start=\"6648\" data-end=\"7100\">\r\n<thead data-start=\"6648\" data-end=\"6693\">\r\n<tr data-start=\"6648\" data-end=\"6693\">\r\n<th data-start=\"6648\" data-end=\"6664\" data-col-size=\"sm\"><strong data-start=\"6650\" data-end=\"6663\">Violation</strong></th>\r\n<th data-start=\"6664\" data-end=\"6693\" data-col-size=\"sm\"><strong data-start=\"6666\" data-end=\"6691\">Penalty / Consequence</strong></th>\r\n</tr>\r\n</thead>\r\n<tbody data-start=\"6742\" data-end=\"7100\">\r\n<tr data-start=\"6742\" data-end=\"6811\">\r\n<td data-start=\"6742\" data-end=\"6770\" data-col-size=\"sm\">Operating without license</td>\r\n<td data-col-size=\"sm\" data-start=\"6770\" data-end=\"6811\">Closure notice and fine up to ₹50,000</td>\r\n</tr>\r\n<tr data-start=\"6812\" data-end=\"6882\">\r\n<td data-start=\"6812\" data-end=\"6842\" data-col-size=\"sm\">Providing false information</td>\r\n<td data-col-size=\"sm\" data-start=\"6842\" data-end=\"6882\">Rejection or cancellation of license</td>\r\n</tr>\r\n<tr data-start=\"6883\" data-end=\"6954\">\r\n<td data-start=\"6883\" data-end=\"6911\" data-col-size=\"sm\">Non-renewal before expiry</td>\r\n<td data-col-size=\"sm\" data-start=\"6911\" data-end=\"6954\">Late fee and penalty up to ₹100 per day</td>\r\n</tr>\r\n<tr data-start=\"6955\" data-end=\"7025\">\r\n<td data-start=\"6955\" data-end=\"6990\" data-col-size=\"sm\">Operating outside permitted area</td>\r\n<td data-col-size=\"sm\" data-start=\"6990\" data-end=\"7025\">Immediate suspension of license</td>\r\n</tr>\r\n<tr data-start=\"7026\" data-end=\"7100\">\r\n<td data-start=\"7026\" data-end=\"7061\" data-col-size=\"sm\">Non-compliance with safety norms</td>\r\n<td data-col-size=\"sm\" data-start=\"7061\" data-end=\"7100\">Sealing of premises and prosecution</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n</div>\r\n<p data-start=\"7102\" data-end=\"7227\">Rajasthan Filings ensures your business stays 100% compliant with local laws, avoiding penalties and operational disruptions.</p>\r\n<hr data-start=\"7229\" data-end=\"7232\">\r\n<h2 data-start=\"7234\" data-end=\"7279\"><strong data-start=\"7237\" data-end=\"7279\">Benefits of Trade License Registration</strong></h2>\r\n<ul data-start=\"7281\" data-end=\"7648\">\r\n<li data-start=\"7281\" data-end=\"7342\">\r\n<p data-start=\"7283\" data-end=\"7342\">Legal permission to operate a business in a specific area</p>\r\n</li>\r\n<li data-start=\"7343\" data-end=\"7382\">\r\n<p data-start=\"7345\" data-end=\"7382\">Builds credibility and public trust</p>\r\n</li>\r\n<li data-start=\"7383\" data-end=\"7436\">\r\n<p data-start=\"7385\" data-end=\"7436\">Proof of compliance with municipal and local laws</p>\r\n</li>\r\n<li data-start=\"7437\" data-end=\"7498\">\r\n<p data-start=\"7439\" data-end=\"7498\">Enables participation in government tenders and approvals</p>\r\n</li>\r\n<li data-start=\"7499\" data-end=\"7555\">\r\n<p data-start=\"7501\" data-end=\"7555\">Required for bank account opening and business loans</p>\r\n</li>\r\n<li data-start=\"7556\" data-end=\"7603\">\r\n<p data-start=\"7558\" data-end=\"7603\">Ensures safety, hygiene, and accountability</p>\r\n</li>\r\n<li data-start=\"7604\" data-end=\"7648\">\r\n<p data-start=\"7606\" data-end=\"7648\">Prevents risk of closure or legal action</p>\r\n</li>\r\n</ul>\r\n<hr data-start=\"7650\" data-end=\"7653\">\r\n<h2 data-start=\"7655\" data-end=\"7699\"><strong data-start=\"7658\" data-end=\"7699\">Example: Jaipur Restaurant Case Study</strong></h2>\r\n<p data-start=\"7701\" data-end=\"8051\">A small restaurant in Jaipur operating without a trade license received a municipal notice for non-compliance. Rajasthan Filings intervened, helped prepare all documents including health and FSSAI clearances, and obtained the license within 10 days. The business now operates legally, renewed annually without issues, and even expanded its outlets.</p>\r\n<p data-start=\"8053\" data-end=\"8162\">This example shows how a valid trade license protects your investment and supports long-term business growth.</p>\r\n<hr data-start=\"8164\" data-end=\"8167\">\r\n<h2 data-start=\"8169\" data-end=\"8204\"><strong data-start=\"8172\" data-end=\"8204\">Why Choose Rajasthan Filings</strong></h2>\r\n<ul data-start=\"8206\" data-end=\"8587\">\r\n<li data-start=\"8206\" data-end=\"8263\">\r\n<p data-start=\"8208\" data-end=\"8263\">Expert team familiar with municipal laws across India</p>\r\n</li>\r\n<li data-start=\"8264\" data-end=\"8307\">\r\n<p data-start=\"8266\" data-end=\"8307\">100 % online or assisted filing process</p>\r\n</li>\r\n<li data-start=\"8308\" data-end=\"8370\">\r\n<p data-start=\"8310\" data-end=\"8370\">Support for General, Industrial, and Health Trade Licenses</p>\r\n</li>\r\n<li data-start=\"8371\" data-end=\"8428\">\r\n<p data-start=\"8373\" data-end=\"8428\">Assistance with inspections, renewals, and amendments</p>\r\n</li>\r\n<li data-start=\"8429\" data-end=\"8490\">\r\n<p data-start=\"8431\" data-end=\"8490\">Coordination with municipal officials for faster approval</p>\r\n</li>\r\n<li data-start=\"8491\" data-end=\"8533\">\r\n<p data-start=\"8493\" data-end=\"8533\">Transparent fees and document guidance</p>\r\n</li>\r\n<li data-start=\"8534\" data-end=\"8587\">\r\n<p data-start=\"8536\" data-end=\"8587\">Lifetime compliance support and renewal reminders</p>\r\n</li>\r\n</ul>\r\n<p data-start=\"8589\" data-end=\"8682\">We handle every step so you can focus on your business operations confidently and lawfully.</p>\r\n<hr data-start=\"8684\" data-end=\"8687\">\r\n<h2 data-start=\"8689\" data-end=\"8706\"><strong data-start=\"8692\" data-end=\"8706\">Conclusion</strong></h2>\r\n<p data-start=\"8708\" data-end=\"8955\">A Trade License is a fundamental requirement for every business within municipal limits. It legitimizes your operations, protects you from legal penalties, and assures customers that your establishment complies with safety and hygiene standards.</p>\r\n<p data-start=\"8957\" data-end=\"9188\">With Rajasthan Filings, obtaining or renewing your Trade License becomes effortless. Our experts handle the entire process &mdash; from application to issuance &mdash; ensuring your business runs smoothly, legally, and without interruptions.</p>', NULL, NULL, NULL, NULL, 0, '2025-10-25 05:43:10', '2025-11-08 00:52:00'),
(26, 1, NULL, 'GEM Registration', 'gem-registration', 'GeM Registration (Government e-Marketplace)', '<p data-start=\"9170\" data-end=\"9320\">account to listing products and receiving orders.</p>', 'Exposure Express\r\nPrime Billboard Services', NULL, '1762767805_gallery9.webp', '[\"1762767805_gallery3.webp\",\"1762767805_gallery7.webp\",\"1762767805_gallery2.webp\",\"1762767805_gallery1.webp\"]', 1, '2025-10-25 05:46:24', '2025-11-10 09:43:46');

