INSERT INTO `service_faqs` (`id`, `service_id`, `question`, `answer`, `status`, `created_at`, `updated_at`) VALUES
(1, 6, 'What is Business Loan Advisory?', '<p><strong>Business </strong>Loan Advisory</p>', 1, '2025-09-03 07:33:35', '2025-10-15 04:13:57'),
(3, 26, 'What is MSME/Udyam Registration?', '<p><strong>MSME/Udyam</strong> Registration</p>', 1, '2025-10-15 04:15:34', '2025-11-07 01:45:43'),
(4, 26, 'What is Online Compliance Dashboard?', '<p><strong>Compliance </strong>Dashboard</p>', 1, '2025-10-15 04:16:20', '2025-11-07 01:42:36'),
(5, 7, 'What is Income Tax Return?', '<p><strong>Income Tax </strong>Return</p>', 1, '2025-10-15 04:19:58', '2025-10-15 04:19:58'),
(6, 4, 'What is Udyam Registration?', '<p>Udyam Registration</p>', 1, '2025-10-15 04:53:36', '2025-10-15 04:53:36'),
(7, 15, 'What is TDS Return Filing?', '<p>TDS Return Filing is the process of submitting quarterly statements to the Income Tax Department showing details of tax deducted from payments such as salary, rent, interest, commission, etc.</p>', 1, '2025-10-24 07:56:08', '2025-10-24 07:56:08'),
(8, 15, 'Who is required to file TDS Returns?', '<p data-start=\"511\" data-end=\"696\">Any person or business (deductor) making payments liable for TDS &mdash; like employers, firms, companies, or government bodies &mdash; must file TDS returns every quarter using their TAN number.</p>', 1, '2025-10-24 07:56:35', '2025-10-24 07:56:35'),
(9, 15, 'What are the due dates for filing TDS Returns?', '<table>\r\n<thead>\r\n<tr>\r\n<th>Quarter</th>\r\n<th>Period</th>\r\n<th>Due Date</th>\r\n</tr>\r\n</thead>\r\n<tbody>\r\n<tr>\r\n<td>Q1</td>\r\n<td>April &ndash; June</td>\r\n<td>31st July</td>\r\n</tr>\r\n<tr>\r\n<td>Q2</td>\r\n<td>July &ndash; September</td>\r\n<td>31st October</td>\r\n</tr>\r\n<tr>\r\n<td>Q3</td>\r\n<td>October &ndash; December</td>\r\n<td>31st January</td>\r\n</tr>\r\n<tr>\r\n<td>Q4</td>\r\n<td>January &ndash; March</td>\r\n<td>31st May</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p>&nbsp;</p>', 1, '2025-10-24 07:57:09', '2025-10-24 07:57:09'),
(10, 15, 'What forms are used for filing TDS/TCS Returns?', '<ul>\r\n<li data-start=\"1040\" data-end=\"1074\">\r\n<p data-start=\"1042\" data-end=\"1074\"><strong data-start=\"1042\" data-end=\"1054\">Form 24Q</strong> &ndash; Salary payments</p>\r\n</li>\r\n<li data-start=\"1075\" data-end=\"1129\">\r\n<p data-start=\"1077\" data-end=\"1129\"><strong data-start=\"1077\" data-end=\"1089\">Form 26Q</strong> &ndash; Domestic payments other than salary</p>\r\n</li>\r\n<li data-start=\"1130\" data-end=\"1174\">\r\n<p data-start=\"1132\" data-end=\"1174\"><strong data-start=\"1132\" data-end=\"1144\">Form 27Q</strong> &ndash; Payments to non-residents</p>\r\n</li>\r\n<li data-start=\"1175\" data-end=\"1224\">\r\n<p data-start=\"1177\" data-end=\"1224\"><strong data-start=\"1177\" data-end=\"1190\">Form 27EQ</strong> &ndash; TCS (Tax Collected at Source)</p>\r\n</li>\r\n</ul>', 1, '2025-10-24 07:57:33', '2025-10-24 07:57:33'),
(11, 15, 'What happens if TDS return is not filed on time?', '<p data-start=\"1288\" data-end=\"1447\">Late filing attracts a penalty of ₹200 per day under <strong data-start=\"1341\" data-end=\"1357\">Section 234E</strong>, and higher penalties may apply under <strong data-start=\"1396\" data-end=\"1412\">Section 271H</strong> for incorrect or missed filings.</p>', 1, '2025-10-24 07:57:56', '2025-10-24 07:57:56'),
(12, 15, 'Can TDS Returns be revised after submission?', '<p data-start=\"1732\" data-end=\"1875\">Yes, if any error (like wrong PAN or challan entry) is found, a <strong data-start=\"1796\" data-end=\"1821\">TDS correction return</strong> can be filed through TRACES to rectify the mistake.</p>', 1, '2025-10-24 07:59:16', '2025-10-24 07:59:16'),
(13, 9, 'Q1. How long does it take to register a company in India?', '<p data-start=\"500\" data-end=\"716\">The process usually takes <strong data-start=\"590\" data-end=\"610\">5&ndash;7 working days</strong> after submission of complete documents. Timelines may vary based on MCA approvals and state jurisdiction.</p>', 1, '2025-10-24 15:02:28', '2025-10-24 15:02:28'),
(14, 9, 'Q2. Is physical presence required for company incorporation?', '<p data-start=\"723\" data-end=\"967\">No. The entire process is <strong data-start=\"816\" data-end=\"831\">100% online</strong>. All documents are digitally signed using a valid Digital Signature Certificate (DSC), and no personal visit to any office is required.</p>', 1, '2025-10-24 15:02:58', '2025-10-24 15:02:58'),
(15, 9, 'Q3. What is the minimum capital requirement for starting a company?', '<p data-start=\"974\" data-end=\"1196\">There is <strong data-start=\"1057\" data-end=\"1099\">no minimum paid-up capital requirement</strong> under the Companies Act, 2013. A company can even be incorporated with ₹1 as authorised capital.</p>', 1, '2025-10-24 15:03:32', '2025-10-24 15:03:32'),
(16, 9, 'Q4. Can a foreign national or NRI register a company in India?', '<p>Yes. Foreign nationals and NRIs can incorporate a company in India by complying with <strong data-start=\"1357\" data-end=\"1392\">Foreign Direct Investment (FDI)</strong> regulations and providing notarised and apostilled identity/address proofs.</p>', 1, '2025-10-24 15:05:15', '2025-10-24 15:05:15'),
(17, 9, 'Q5. What is the difference between a Private Limited Company and an LLP?', '<p data-start=\"1475\" data-end=\"1763\">A Private Limited Company offers a <strong data-start=\"1589\" data-end=\"1625\">corporate shareholding structure</strong> and higher investor confidence, whereas an <strong data-start=\"1669\" data-end=\"1676\">LLP</strong> provides flexibility and lower compliance for professional or partnership-based firms.</p>', 1, '2025-10-24 15:05:45', '2025-10-24 15:05:45'),
(18, 9, 'Q6. Can the company name be changed after incorporation?', '<p>Yes. A registered company can change its name by passing a <strong data-start=\"1892\" data-end=\"1914\">special resolution</strong> and filing <strong data-start=\"1926\" data-end=\"1941\">Form INC-24</strong> with MCA approval.</p>', 1, '2025-10-24 15:06:22', '2025-10-24 15:06:22'),
(19, 9, 'Q7. What are the mandatory post-incorporation compliances?', '<p>Key compliances include opening a current account, appointing an auditor, filing commencement of business (INC-20A), maintaining statutory registers, and filing annual returns (AOC-4 &amp; MGT-7).</p>', 1, '2025-10-24 15:06:53', '2025-10-24 15:06:53'),
(20, 9, 'Q8. Is GST registration automatically included in incorporation?', '<p>No. GST registration must be applied separately after incorporation. However, Rajasthan Filings provides <strong data-start=\"2407\" data-end=\"2428\">combined packages</strong> that include both company incorporation and GST registration.</p>', 1, '2025-10-24 15:08:04', '2025-10-24 15:08:04'),
(21, 9, 'Q9. Can one person register more than one company?', '<p data-start=\"2497\" data-end=\"2714\">Yes, a person can be a <strong data-start=\"2577\" data-end=\"2611\">director in multiple companies</strong>, provided they fulfil statutory responsibilities and maintain compliance for each entity individually.</p>', 1, '2025-10-24 15:08:35', '2025-10-24 15:08:35'),
(22, 9, 'Q10. Why should I choose Rajasthan Filings for company incorporation?', '<p>Rajasthan Filings ensures <strong data-start=\"2823\" data-end=\"2848\">end-to-end assistance</strong>, expert documentation by <strong data-start=\"2874\" data-end=\"2911\">Chartered Accountants &amp; Advocates</strong>, fast processing, and transparent communication &mdash; all handled online with complete confidentiality.</p>', 1, '2025-10-24 15:09:02', '2025-10-24 15:09:02'),
(23, 21, '1️⃣ What is the difference between a Sole Proprietorship and a Partnership Firm?', '<p>A Proprietorship is owned and managed by a single individual, while a Partnership Firm is owned by two or more persons who share profits and responsibilities as per a Partnership Deed.</p>', 1, '2025-10-25 04:13:39', '2025-10-25 04:13:39'),
(24, 21, '2️⃣ Is registration of a Partnership Firm mandatory in India?', '<p>It is not mandatory, but registration is highly recommended. A registered firm can legally enforce its rights in court, open a bank account easily, and gain better trust from clients and vendors.</p>', 1, '2025-10-25 04:14:26', '2025-10-25 04:14:26'),
(25, 21, '3️⃣ Can a Proprietorship or Partnership Firm apply for GST?', '<p>Yes. Both entities can obtain GST registration if their turnover crosses ₹20 lakh (services) or ₹40 lakh (goods). Rajasthan Filings can include GST registration along with your business setup.</p>', 1, '2025-10-25 04:14:46', '2025-10-25 04:14:46'),
(26, 21, '4️⃣ How long does it take to register a Proprietorship or Partnership Firm?', '<p>Usually <strong data-start=\"1157\" data-end=\"1180\">2 to 5 working days</strong>, depending on document readiness and department processing time.</p>', 1, '2025-10-25 04:15:09', '2025-10-25 04:15:09'),
(27, 21, '5️⃣ What is a Partnership Deed and why is it important?', '<p data-start=\"1254\" data-end=\"1536\">A Partnership Deed is a legal document that defines each partner&rsquo;s capital, duties, profit-sharing ratio, and dispute-resolution process. It serves as the foundation for smooth business operations and future reference.</p>', 1, '2025-10-25 04:15:32', '2025-10-25 04:15:32'),
(28, 21, '6️⃣ Can I use my home address as my business address?', '<p>Yes. A home or rented premises can be used with a valid <strong data-start=\"1659\" data-end=\"1693\">NOC (No Objection Certificate)</strong> from the owner and a recent electricity bill as address proof.</p>', 1, '2025-10-25 04:15:54', '2025-10-25 04:15:54'),
(29, 21, '7️⃣ What compliance is required after registration?', '<p data-start=\"1765\" data-end=\"2032\">You must maintain basic accounts, file <strong data-start=\"1862\" data-end=\"1890\">Income-Tax Returns (ITR)</strong> annually, and obtain <strong data-start=\"1912\" data-end=\"1927\">GST filings</strong> if registered. Partnership Firms should also record partner capital and profit distribution each year.</p>', 1, '2025-10-25 04:16:15', '2025-10-25 04:16:15'),
(30, 21, '8️⃣ Can I convert my Proprietorship or Partnership Firm into an LLP or Private Limited Company later?', '<p data-start=\"2039\" data-end=\"2316\">Yes. Both entities can be converted into an LLP or Private Limited Company with proper documentation. Rajasthan Filings provides full assistance for smooth conversion.</p>', 1, '2025-10-25 04:16:42', '2025-10-25 04:16:42'),
(31, 21, '9️⃣ Which licences or registrations are recommended for small businesses?', '<p data-start=\"2323\" data-end=\"2557\">Along with Udyam (MSME) registration, small businesses should consider <strong data-start=\"2474\" data-end=\"2481\">GST</strong>, <strong data-start=\"2483\" data-end=\"2507\">Shop &amp; Establishment</strong>, and <strong data-start=\"2513\" data-end=\"2522\">FSSAI</strong> (if food-related) registrations.</p>', 1, '2025-10-25 04:17:05', '2025-10-25 04:17:05'),
(32, 21, '🔟 Why should I choose Rajasthan Filings for my business registration?', '<p data-start=\"2564\" data-end=\"2660\">Because we offer:</p>\r\n<ul data-start=\"2661\" data-end=\"2885\">\r\n<li data-start=\"2661\" data-end=\"2702\">\r\n<p data-start=\"2663\" data-end=\"2702\">All-India online registration support</p>\r\n</li>\r\n<li data-start=\"2703\" data-end=\"2752\">\r\n<p data-start=\"2705\" data-end=\"2752\">Expert guidance from CA &amp; legal professionals</p>\r\n</li>\r\n<li data-start=\"2753\" data-end=\"2782\">\r\n<p data-start=\"2755\" data-end=\"2782\">Legally drafted documents</p>\r\n</li>\r\n<li data-start=\"2783\" data-end=\"2833\">\r\n<p data-start=\"2785\" data-end=\"2833\">Fast processing with transparent communication</p>\r\n</li>\r\n<li data-start=\"2834\" data-end=\"2885\">\r\n<p data-start=\"2836\" data-end=\"2885\">Lifetime advisory support for GST &amp; ITR filings</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:17:27', '2025-10-25 04:17:27'),
(33, 10, '1️⃣ What is a Shop & Establishment License?', '<p>It is a mandatory registration issued by the State Labour Department to regulate working conditions and provide legal identity to shops, offices, restaurants, and commercial establishments operating within municipal or local limits.</p>', 1, '2025-10-25 04:29:07', '2025-10-25 04:29:07'),
(34, 10, '2️⃣ Who needs to obtain this registration?', '<p data-start=\"651\" data-end=\"925\">Every business that employs people or runs from a fixed commercial place&mdash;retail shop, office, caf&eacute;, warehouse, consultancy, or service centre&mdash;must obtain the Shop &amp; Establishment License within 30 days of starting operations.</p>', 1, '2025-10-25 04:29:27', '2025-10-25 04:29:27'),
(35, 10, '3️⃣ Is it mandatory for home-based or online businesses?', '<p data-start=\"932\" data-end=\"1204\">Yes. If you work from home, operate an e-commerce business, or have a registered office for correspondence, you must still register under the Act to prove business existence and comply with local labour norms.</p>', 1, '2025-10-25 04:35:31', '2025-10-25 04:35:31'),
(36, 10, '4️⃣ Which government department issues this licence?', '<p data-start=\"1211\" data-end=\"1471\">The licence is issued by the <strong data-start=\"1299\" data-end=\"1326\">Local Labour Department</strong> or <strong data-start=\"1330\" data-end=\"1355\">Municipal Corporation</strong> of the respective state under the <strong data-start=\"1390\" data-end=\"1420\">Shops &amp; Establishments Act</strong>. Each state has its own online or offline process.</p>', 1, '2025-10-25 04:35:52', '2025-10-25 04:35:52'),
(37, 10, '5️⃣ What documents are required for registration?', '<ul data-start=\"1534\" data-end=\"1830\">\r\n<li data-start=\"1534\" data-end=\"1594\">\r\n<p data-start=\"1536\" data-end=\"1594\">PAN and Aadhaar of the proprietor / partners / directors</p>\r\n</li>\r\n<li data-start=\"1595\" data-end=\"1668\">\r\n<p data-start=\"1597\" data-end=\"1668\">Address proof of business premises (rent agreement / ownership paper)</p>\r\n</li>\r\n<li data-start=\"1669\" data-end=\"1716\">\r\n<p data-start=\"1671\" data-end=\"1716\">Electricity bill or NOC from property owner</p>\r\n</li>\r\n<li data-start=\"1717\" data-end=\"1761\">\r\n<p data-start=\"1719\" data-end=\"1761\">Passport-size photo of owner or partners</p>\r\n</li>\r\n<li data-start=\"1762\" data-end=\"1830\">\r\n<p data-start=\"1764\" data-end=\"1830\">Business details (name, nature of activity, number of employees)</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:36:10', '2025-10-25 04:36:10'),
(38, 10, '6️⃣ How long does it take to get the licence?', '<p data-start=\"1837\" data-end=\"2048\">Normally 3 to 7 working days after submission of complete documents. Some states issue instant online approvals while others require departmental verification.</p>', 1, '2025-10-25 04:36:27', '2025-10-25 04:36:27'),
(39, 10, '7️⃣ What is the validity period of the Shop & Establishment License?', '<p data-start=\"2055\" data-end=\"2285\">The licence is generally valid for 1 to 5 years, depending on the state. It must be renewed before expiry to avoid penalties or suspension of registration.</p>', 1, '2025-10-25 04:36:51', '2025-10-25 04:36:51'),
(40, 10, '8️⃣ Can this licence be used to open a business current account?', '<p>Yes. Banks accept the Shop &amp; Establishment Certificate as primary proof of business existence when opening a current account in the trade name.</p>', 1, '2025-10-25 04:37:15', '2025-10-25 04:37:15'),
(41, 10, '9️⃣ What compliance must be followed after registration?', '<p data-start=\"2513\" data-end=\"2796\">Registered establishments should display the certificate on premises, maintain attendance and salary registers, provide leaves and holidays as per the Act, and report any change in address or ownership to the department.</p>', 1, '2025-10-25 04:37:37', '2025-10-25 04:37:37'),
(42, 10, '🔟 Why should I get my licence through Rajasthan Filings?', '<p data-start=\"2803\" data-end=\"2888\">Because we provide:</p>\r\n<ul data-start=\"2889\" data-end=\"3162\">\r\n<li data-start=\"2889\" data-end=\"2933\">\r\n<p data-start=\"2891\" data-end=\"2933\">All-India online registration assistance</p>\r\n</li>\r\n<li data-start=\"2934\" data-end=\"2985\">\r\n<p data-start=\"2936\" data-end=\"2985\">Professionally verified documents by CA/CS team</p>\r\n</li>\r\n<li data-start=\"2986\" data-end=\"3043\">\r\n<p data-start=\"2988\" data-end=\"3043\">Coordination with Labour Department for fast approval</p>\r\n</li>\r\n<li data-start=\"3044\" data-end=\"3097\">\r\n<p data-start=\"3046\" data-end=\"3097\">Renewal reminders and lifetime compliance support</p>\r\n</li>\r\n<li data-start=\"3098\" data-end=\"3162\">\r\n<p data-start=\"3100\" data-end=\"3162\">Integration with other registrations (GST, Udyam, FSSAI, etc.)</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:37:55', '2025-10-25 04:37:55'),
(43, 22, '1️⃣ What is the meaning of an NGO in India?', '<p data-start=\"323\" data-end=\"675\">An NGO (Non-Governmental Organization) is a non-profit, voluntary group of individuals or institutions working for social, cultural, educational, or charitable objectives. It functions independently of government control and reinvests all income to promote its mission rather than distributing profits.</p>', 1, '2025-10-25 04:49:11', '2025-10-25 04:49:11'),
(44, 22, '3️⃣ Which form of NGO registration is best for national or large-scale operations?', '<p>A <strong data-start=\"1191\" data-end=\"1212\">Section 8 Company</strong> is most suitable for large or national NGOs because it provides stronger legal standing, corporate governance, and eligibility for CSR and foreign funding. It is regulated by the Ministry of Corporate Affairs and enjoys higher credibility with donors.</p>', 1, '2025-10-25 04:51:34', '2025-10-25 04:51:34'),
(45, 22, '4️⃣ What are 12A and 80G registrations and why are they important?', '<ul data-start=\"1544\" data-end=\"1849\">\r\n<li data-start=\"1544\" data-end=\"1628\">\r\n<p data-start=\"1546\" data-end=\"1628\"><strong data-start=\"1546\" data-end=\"1566\">12A Registration</strong> exempts the NGO&rsquo;s income from tax under the Income-Tax Act.</p>\r\n</li>\r\n<li data-start=\"1629\" data-end=\"1849\">\r\n<p data-start=\"1631\" data-end=\"1849\"><strong data-start=\"1631\" data-end=\"1652\">80G Certification</strong> allows donors to claim tax deductions on donations made to the NGO.<br data-start=\"1720\" data-end=\"1723\">Both are essential for financial transparency and donor confidence and are mandatory for receiving government and CSR funding.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:51:57', '2025-10-25 04:51:57'),
(46, 22, '5️⃣ Can an NGO in India receive foreign donations?', '<p>Yes. NGOs can receive foreign contributions only after obtaining <strong data-start=\"1978\" data-end=\"2037\">FCRA (Foreign Contribution Regulation Act) registration</strong> from the Ministry of Home Affairs. The NGO must be at least three years old, have audited accounts, and receive funds only through a designated bank account approved under FCRA 2020.</p>', 1, '2025-10-25 04:52:18', '2025-10-25 04:52:18'),
(47, 22, '6️⃣ What documents are needed for NGO registration?', '<p data-start=\"2227\" data-end=\"2324\">Generally required documents include:</p>\r\n<ul data-start=\"2325\" data-end=\"2581\">\r\n<li data-start=\"2325\" data-end=\"2358\">\r\n<p data-start=\"2327\" data-end=\"2358\">PAN &amp; Aadhaar of all founders</p>\r\n</li>\r\n<li data-start=\"2359\" data-end=\"2383\">\r\n<p data-start=\"2361\" data-end=\"2383\">Passport-size photos</p>\r\n</li>\r\n<li data-start=\"2384\" data-end=\"2434\">\r\n<p data-start=\"2386\" data-end=\"2434\">Registered office proof and NOC from the owner</p>\r\n</li>\r\n<li data-start=\"2435\" data-end=\"2489\">\r\n<p data-start=\"2437\" data-end=\"2489\">Draft Trust Deed / MOA / AOA / Rules &amp; Regulations</p>\r\n</li>\r\n<li data-start=\"2490\" data-end=\"2532\">\r\n<p data-start=\"2492\" data-end=\"2532\">Utility bill not older than two months</p>\r\n</li>\r\n<li data-start=\"2533\" data-end=\"2581\">\r\n<p data-start=\"2535\" data-end=\"2581\">Digital signatures (for Section 8 Companies)</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:52:37', '2025-10-25 04:52:37'),
(48, 22, '7️⃣ How long does it take to register an NGO in India?', '<p data-start=\"2588\" data-end=\"2689\">The timeline depends on the structure:</p>\r\n<ul data-start=\"2690\" data-end=\"2907\">\r\n<li data-start=\"2690\" data-end=\"2727\">\r\n<p data-start=\"2692\" data-end=\"2727\">Trust &ndash; about 5 to 7 working days</p>\r\n</li>\r\n<li data-start=\"2728\" data-end=\"2768\">\r\n<p data-start=\"2730\" data-end=\"2768\">Society &ndash; about 7 to 10 working days</p>\r\n</li>\r\n<li data-start=\"2769\" data-end=\"2907\">\r\n<p data-start=\"2771\" data-end=\"2907\">Section 8 Company &ndash; about 10 to 15 working days<br data-start=\"2818\" data-end=\"2821\">Rajasthan Filings handles end-to-end coordination to complete the process efficiently.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:52:55', '2025-10-25 04:52:55'),
(49, 22, '8️⃣ What compliance must a registered NGO follow every year?', '<p data-start=\"2914\" data-end=\"2993\">NGOs must:</p>\r\n<ul data-start=\"2994\" data-end=\"3273\">\r\n<li data-start=\"2994\" data-end=\"3061\">\r\n<p data-start=\"2996\" data-end=\"3061\">Maintain proper books of accounts and get them audited annually</p>\r\n</li>\r\n<li data-start=\"3062\" data-end=\"3103\">\r\n<p data-start=\"3064\" data-end=\"3103\">Hold board or governing-body meetings</p>\r\n</li>\r\n<li data-start=\"3104\" data-end=\"3153\">\r\n<p data-start=\"3106\" data-end=\"3153\">File annual returns with the Registrar or ROC</p>\r\n</li>\r\n<li data-start=\"3154\" data-end=\"3203\">\r\n<p data-start=\"3156\" data-end=\"3203\">Renew 12A, 80G, and FCRA certificates on time</p>\r\n</li>\r\n<li data-start=\"3204\" data-end=\"3273\">\r\n<p data-start=\"3206\" data-end=\"3273\">Submit activity and utilization reports to donors and authorities</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:53:14', '2025-10-25 04:53:14'),
(50, 22, '9️⃣ Can an existing Trust or Society be converted into a Section 8 Company?', '<p data-start=\"3280\" data-end=\"3620\">Yes. An existing Trust or Society can be converted into a Section 8 Company with approval from the relevant authorities and by fulfilling prescribed procedures under the Companies Act 2013. Rajasthan Filings provides complete assistance for such conversions.</p>', 1, '2025-10-25 04:53:45', '2025-10-25 04:53:45'),
(51, 22, '🔟 Why should I choose Rajasthan Filings for NGO registration?', '<p data-start=\"3627\" data-end=\"3717\">Because we provide:</p>\r\n<ul data-start=\"3718\" data-end=\"3993\">\r\n<li data-start=\"3718\" data-end=\"3766\">\r\n<p data-start=\"3720\" data-end=\"3766\">Legal drafting by expert CA / CS / Advocates</p>\r\n</li>\r\n<li data-start=\"3767\" data-end=\"3815\">\r\n<p data-start=\"3769\" data-end=\"3815\">100 % online, pan-India registration support</p>\r\n</li>\r\n<li data-start=\"3816\" data-end=\"3870\">\r\n<p data-start=\"3818\" data-end=\"3870\">Assistance in 12A, 80G, CSR, and FCRA registration</p>\r\n</li>\r\n<li data-start=\"3871\" data-end=\"3928\">\r\n<p data-start=\"3873\" data-end=\"3928\">Transparent, compliant process with lifetime guidance</p>\r\n</li>\r\n<li data-start=\"3929\" data-end=\"3993\">\r\n<p data-start=\"3931\" data-end=\"3993\">Proven track record of registering 1,000 + NGOs across India</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 04:54:03', '2025-10-25 04:54:03'),
(52, 23, '1️⃣ What is an FSSAI license and why is it mandatory?', '<p data-start=\"331\" data-end=\"739\">An FSSAI license is a legal authorization issued by the <strong data-start=\"447\" data-end=\"503\">Food Safety and Standards Authority of India (FSSAI)</strong> under the <strong data-start=\"514\" data-end=\"553\">Food Safety and Standards Act, 2006</strong>. It ensures that food products are safe for human consumption. Every food business &mdash; whether manufacturing, processing, or selling &mdash; must obtain this license before starting operations.</p>', 1, '2025-10-25 05:08:51', '2025-10-25 05:08:51'),
(53, 23, '2️⃣ Who needs to apply for an FSSAI registration or license?', '<p data-start=\"746\" data-end=\"1079\">All food business operators (FBOs), including manufacturers, distributors, transporters, storage units, restaurants, catering services, and online food sellers, are required to have an FSSAI license or registration depending on their turnover and size of operations.</p>', 1, '2025-10-25 05:09:08', '2025-10-25 05:09:08'),
(54, 23, '3️⃣ What are the types of FSSAI licenses in India?', '<p data-start=\"1086\" data-end=\"1224\">FSSAI issues three types of registrations based on business turnover and scale:</p>\r\n<ul data-start=\"1225\" data-end=\"1525\">\r\n<li data-start=\"1225\" data-end=\"1298\">\r\n<p data-start=\"1227\" data-end=\"1298\"><strong data-start=\"1227\" data-end=\"1249\">Basic Registration</strong> &ndash; for small FBOs with turnover up to ₹12 lakh.</p>\r\n</li>\r\n<li data-start=\"1299\" data-end=\"1391\">\r\n<p data-start=\"1301\" data-end=\"1391\"><strong data-start=\"1301\" data-end=\"1318\">State License</strong> &ndash; for medium-sized units with turnover between ₹12 lakh and ₹20 crore.</p>\r\n</li>\r\n<li data-start=\"1392\" data-end=\"1525\">\r\n<p data-start=\"1394\" data-end=\"1525\"><strong data-start=\"1394\" data-end=\"1413\">Central License</strong> &ndash; for large food manufacturers, exporters, or importers with turnover above ₹20 crore or interstate operations.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 05:09:29', '2025-10-25 05:09:29'),
(55, 23, '4️⃣ How long does it take to get an FSSAI license?', '<p data-start=\"1532\" data-end=\"1836\">The time required varies depending on the category and documentation. Generally, Basic and State licenses are issued within <strong data-start=\"1713\" data-end=\"1734\">5&ndash;10 working days</strong>, while Central licenses may take <strong data-start=\"1768\" data-end=\"1785\">up to 30 days</strong>, subject to inspection and departmental approvals.</p>', 1, '2025-10-25 05:09:46', '2025-10-25 05:09:46'),
(56, 23, '5️⃣ How long is the FSSAI license valid?', '<p data-start=\"1843\" data-end=\"2075\">An FSSAI license is valid for <strong data-start=\"1920\" data-end=\"1936\">1 to 5 years</strong>, as selected by the applicant at the time of registration. Businesses must renew the license before expiry to continue operations legally.</p>', 1, '2025-10-25 05:10:04', '2025-10-25 05:10:04'),
(57, 23, '6️⃣ What happens if my FSSAI license expires?', '<p data-start=\"2082\" data-end=\"2446\">If the license is not renewed before the expiry date, it becomes invalid. A late renewal attracts a penalty of <strong data-start=\"2245\" data-end=\"2261\">₹100 per day</strong>, and operating without a valid license may result in fines up to ₹5 lakh and possible closure of the business. Rajasthan Filings provides timely renewal reminders to avoid such issues.</p>', 1, '2025-10-25 05:10:21', '2025-10-25 05:10:21'),
(58, 23, '7️⃣ Can an FSSAI license be modified or upgraded?', '<p data-start=\"2453\" data-end=\"2801\">Yes. Businesses can modify or upgrade their license when there is a change in turnover, business address, food category, or operational capacity. For example, moving from Basic to State or State to Central license. Our team at Rajasthan Filings assists in modification and category upgrading.</p>', 1, '2025-10-25 05:10:40', '2025-10-25 05:10:40'),
(59, 23, '8️⃣ What documents are required for FSSAI renewal?', '<ul>\r\n<li data-start=\"2865\" data-end=\"2896\">\r\n<p data-start=\"2867\" data-end=\"2896\">Existing FSSAI license copy</p>\r\n</li>\r\n<li data-start=\"2897\" data-end=\"2946\">\r\n<p data-start=\"2899\" data-end=\"2946\">Updated turnover certificate or balance sheet</p>\r\n</li>\r\n<li data-start=\"2947\" data-end=\"2997\">\r\n<p data-start=\"2949\" data-end=\"2997\">Recent utility bill and business address proof</p>\r\n</li>\r\n<li data-start=\"2998\" data-end=\"3057\">\r\n<p data-start=\"3000\" data-end=\"3057\">Declaration Form and Form-B (for State/Central License)</p>\r\n</li>\r\n<li data-start=\"3058\" data-end=\"3118\">\r\n<p data-start=\"3060\" data-end=\"3118\">Any change details in business structure or product line</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 05:10:56', '2025-10-25 05:10:56'),
(60, 23, '9️⃣ Is inspection mandatory for all food businesses?', '<p data-start=\"3125\" data-end=\"3474\">Not for all. For small food operators under Basic Registration, inspection may not be required. However, for manufacturing units, importers, or large establishments, the Food Safety Officer may inspect premises before granting or renewing the license to verify hygiene and safety standards.</p>', 1, '2025-10-25 05:11:18', '2025-10-25 05:11:18'),
(61, 23, '🔟 Why should I apply through Rajasthan Filings for FSSAI license and renewal?', '<p data-start=\"3481\" data-end=\"3587\">Because we provide:</p>\r\n<ul data-start=\"3588\" data-end=\"3898\">\r\n<li data-start=\"3588\" data-end=\"3653\">\r\n<p data-start=\"3590\" data-end=\"3653\">Complete online filing and documentation support across India</p>\r\n</li>\r\n<li data-start=\"3654\" data-end=\"3711\">\r\n<p data-start=\"3656\" data-end=\"3711\">Category selection guidance (Basic / State / Central)</p>\r\n</li>\r\n<li data-start=\"3712\" data-end=\"3780\">\r\n<p data-start=\"3714\" data-end=\"3780\">Assistance in modification, renewal, and inspection coordination</p>\r\n</li>\r\n<li data-start=\"3781\" data-end=\"3834\">\r\n<p data-start=\"3783\" data-end=\"3834\">Experienced professionals ensuring zero rejection</p>\r\n</li>\r\n<li data-start=\"3835\" data-end=\"3898\">\r\n<p data-start=\"3837\" data-end=\"3898\">Lifetime compliance support, including annual return filing</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 05:11:38', '2025-10-25 05:11:38'),
(62, 24, '1️⃣ What is an Import-Export Code (IEC)?', '<p data-start=\"267\" data-end=\"569\">IEC is a 10-digit unique identification number issued by the <strong data-start=\"375\" data-end=\"422\">Directorate General of Foreign Trade (DGFT)</strong>, Ministry of Commerce, Government of India. It is mandatory for every individual or business that imports or exports goods or services from India.</p>', 1, '2025-10-25 05:30:52', '2025-10-25 05:30:52'),
(63, 24, '2️⃣ Who is required to obtain an IEC?', '<p data-start=\"576\" data-end=\"902\">Any person or entity engaged in international trade &mdash; including manufacturers, exporters, importers, e-commerce sellers, or service providers &mdash; must obtain an IEC before starting cross-border transactions. Even sole proprietors conducting overseas business are required to have one.</p>', 1, '2025-10-25 05:31:08', '2025-10-25 05:31:08'),
(64, 24, '3️⃣ Is IEC mandatory for all exports and imports?', '<p data-start=\"909\" data-end=\"1212\">Yes. IEC is compulsory for customs clearance of goods, international bank remittances, and participation in export-promotion schemes. However, it is not required for personal, non-commercial use or transactions conducted by government departments.</p>', 1, '2025-10-25 05:31:31', '2025-10-25 05:31:31'),
(65, 24, '4️⃣ What is the validity of an IEC?', '<p data-start=\"1219\" data-end=\"1518\">IEC is <strong data-start=\"1268\" data-end=\"1292\">valid for a lifetime</strong> once issued and does not require renewal.<br data-start=\"1334\" data-end=\"1337\">However, as per DGFT&rsquo;s latest notification, every IEC holder must <strong data-start=\"1403\" data-end=\"1441\">confirm or update details annually</strong> between April and June; otherwise, the IEC may be deactivated until updated.</p>', 1, '2025-10-25 05:31:50', '2025-10-25 05:31:50'),
(66, 24, '5️⃣ How long does it take to obtain an IEC number?', '<p>The registration process is completely online and, if all documents are correct, the IEC certificate is generally issued within <strong data-start=\"1710\" data-end=\"1737\">one to two working days</strong> from the date of application.</p>', 1, '2025-10-25 05:38:22', '2025-10-25 05:38:22'),
(67, 24, '6️⃣ Can an individual apply for an IEC?', '<p>Yes. IEC can be obtained by individuals, proprietors, and freelancers who deal in international trade. A business registration (GST or MSME) is not mandatory for applying, though it is advisable for commercial credibility.</p>', 1, '2025-10-25 05:38:42', '2025-10-25 05:38:42'),
(68, 24, '7️⃣ What documents are required to apply for IEC registration?', '<ul data-start=\"2118\" data-end=\"2380\">\r\n<li data-start=\"2118\" data-end=\"2160\">\r\n<p data-start=\"2120\" data-end=\"2160\">PAN card of the business or proprietor</p>\r\n</li>\r\n<li data-start=\"2161\" data-end=\"2194\">\r\n<p data-start=\"2163\" data-end=\"2194\">Aadhaar card of the applicant</p>\r\n</li>\r\n<li data-start=\"2195\" data-end=\"2218\">\r\n<p data-start=\"2197\" data-end=\"2218\">Passport-size photo</p>\r\n</li>\r\n<li data-start=\"2219\" data-end=\"2284\">\r\n<p data-start=\"2221\" data-end=\"2284\">Proof of business address (rent agreement / electricity bill)</p>\r\n</li>\r\n<li data-start=\"2285\" data-end=\"2325\">\r\n<p data-start=\"2287\" data-end=\"2325\">Cancelled cheque or bank certificate</p>\r\n</li>\r\n<li data-start=\"2326\" data-end=\"2380\">\r\n<p data-start=\"2328\" data-end=\"2380\">Valid email ID and mobile number linked to Aadhaar</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 05:38:59', '2025-10-25 05:38:59'),
(69, 24, '8️⃣ Can the details in an IEC be modified later?', '<p data-start=\"2387\" data-end=\"2671\">Yes. Any change in address, directors, ownership, or bank details must be updated within <strong data-start=\"2531\" data-end=\"2542\">30 days</strong> on the DGFT portal. Rajasthan Filings provides complete assistance for modification, branch addition, or reactivation of an IEC.</p>', 1, '2025-10-25 05:39:18', '2025-10-25 05:39:18'),
(70, 24, '9️⃣ What happens if I do not update my IEC annually?', '<p>If annual details are not confirmed, the IEC may be <strong data-start=\"2789\" data-end=\"2804\">deactivated</strong> by DGFT.<br data-start=\"2813\" data-end=\"2816\">Once deactivated, it cannot be used for customs clearance or bank transactions until reactivated by filing an update request online.</p>', 1, '2025-10-25 05:39:35', '2025-10-25 05:39:35'),
(71, 24, '🔟 Why should I register my IEC through Rajasthan Filings?', '<p data-start=\"2955\" data-end=\"3039\">Because we offer:</p>\r\n<ul data-start=\"3040\" data-end=\"3304\">\r\n<li data-start=\"3040\" data-end=\"3094\">\r\n<p data-start=\"3042\" data-end=\"3094\">100 % online application and documentation process</p>\r\n</li>\r\n<li data-start=\"3095\" data-end=\"3148\">\r\n<p data-start=\"3097\" data-end=\"3148\">Same-day filing with DGFT and quick code issuance</p>\r\n</li>\r\n<li data-start=\"3149\" data-end=\"3196\">\r\n<p data-start=\"3151\" data-end=\"3196\">Assistance in amendments and annual updates</p>\r\n</li>\r\n<li data-start=\"3197\" data-end=\"3244\">\r\n<p data-start=\"3199\" data-end=\"3244\">Expert CA / CS review to prevent rejections</p>\r\n</li>\r\n<li data-start=\"3245\" data-end=\"3304\">\r\n<p data-start=\"3247\" data-end=\"3304\">Lifetime customer support for export-related compliance</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 05:39:56', '2025-10-25 05:39:56'),
(72, 3, '1️⃣ What is a GST return?', '<p data-start=\"280\" data-end=\"624\">A GST return is a statement filed with the Goods and Services Tax Network (GSTN) that contains details of outward supplies, inward supplies, tax collected and paid, and input-tax credit claimed for a given period. It enables the government to assess tax liability and maintain a transparent chain of credit flow.</p>', 1, '2025-10-25 05:59:49', '2025-10-25 05:59:49'),
(73, 3, '2️⃣ Who must file GST returns?', '<p data-start=\"631\" data-end=\"928\">Every person registered under GST &mdash; including proprietorships, partnerships, LLPs, companies, and composition taxpayers &mdash; must file returns regularly, even if there is no business activity during a period. Nil returns are mandatory to keep registration active.</p>', 1, '2025-10-25 06:00:11', '2025-10-25 06:00:11'),
(74, 3, '3️⃣ What are the most commonly filed GST returns?', '<p data-start=\"935\" data-end=\"1011\">The key forms are:</p>\r\n<ul data-start=\"1012\" data-end=\"1257\">\r\n<li data-start=\"1012\" data-end=\"1052\">\r\n<p data-start=\"1014\" data-end=\"1052\"><strong data-start=\"1014\" data-end=\"1025\">GSTR-1:</strong> Outward supplies (sales)</p>\r\n</li>\r\n<li data-start=\"1053\" data-end=\"1099\">\r\n<p data-start=\"1055\" data-end=\"1099\"><strong data-start=\"1055\" data-end=\"1067\">GSTR-3B:</strong> Monthly summary &amp; tax payment</p>\r\n</li>\r\n<li data-start=\"1100\" data-end=\"1129\">\r\n<p data-start=\"1102\" data-end=\"1129\"><strong data-start=\"1102\" data-end=\"1113\">GSTR-9:</strong> Annual return</p>\r\n</li>\r\n<li data-start=\"1130\" data-end=\"1171\">\r\n<p data-start=\"1132\" data-end=\"1171\"><strong data-start=\"1132\" data-end=\"1144\">GSTR-9C:</strong> Reconciliation statement</p>\r\n</li>\r\n<li data-start=\"1172\" data-end=\"1222\">\r\n<p data-start=\"1174\" data-end=\"1222\"><strong data-start=\"1174\" data-end=\"1185\">GSTR-4:</strong> Composition dealers&rsquo; annual return</p>\r\n</li>\r\n<li data-start=\"1223\" data-end=\"1257\">\r\n<p data-start=\"1225\" data-end=\"1257\"><strong data-start=\"1225\" data-end=\"1236\">ITC-04:</strong> Job-work statement</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:00:29', '2025-10-25 06:00:29'),
(75, 3, '4️⃣ What is the due date for filing GSTR-1 and GSTR-3B?', '<ul>\r\n<li data-start=\"1326\" data-end=\"1426\">\r\n<p data-start=\"1328\" data-end=\"1426\"><strong data-start=\"1328\" data-end=\"1339\">GSTR-1:</strong> 11th of the next month (monthly) or 13th of the next month after the quarter (QRMP).</p>\r\n</li>\r\n<li data-start=\"1427\" data-end=\"1552\">\r\n<p data-start=\"1429\" data-end=\"1552\"><strong data-start=\"1429\" data-end=\"1441\">GSTR-3B:</strong> 20th of the following month for monthly filers; 22nd or 24th for quarterly filers depending on state category.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:00:46', '2025-10-25 06:00:46'),
(76, 3, '5️⃣ What happens if a GST return is filed late?', '<p data-start=\"1559\" data-end=\"1668\">Late filing attracts both <strong data-start=\"1639\" data-end=\"1666\">late fees and interest.</strong></p>\r\n<ul data-start=\"1669\" data-end=\"1878\">\r\n<li data-start=\"1669\" data-end=\"1765\">\r\n<p data-start=\"1671\" data-end=\"1765\">Late fee: ₹50 per day (₹25 CGST + ₹25 SGST) for normal returns, ₹20 per day for Nil returns.</p>\r\n</li>\r\n<li data-start=\"1766\" data-end=\"1878\">\r\n<p data-start=\"1768\" data-end=\"1878\">Interest: 18% per annum on delayed tax payment.<br data-start=\"1815\" data-end=\"1818\">Continued delay may also lead to suspension of registration.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:01:06', '2025-10-25 06:01:06'),
(77, 3, '6️⃣ Can a GST return be revised after filing?', '<p data-start=\"1885\" data-end=\"2109\">No. Once a return is filed, it cannot be revised. Any omission or error must be corrected in the next tax period before 30 November following the end of the financial year.</p>', 1, '2025-10-25 06:01:31', '2025-10-25 06:01:31'),
(78, 3, '7️⃣ What is the difference between GSTR-1 and GSTR-3B?', '<ul data-start=\"2177\" data-end=\"2410\">\r\n<li data-start=\"2177\" data-end=\"2248\">\r\n<p data-start=\"2179\" data-end=\"2248\"><strong data-start=\"2179\" data-end=\"2189\">GSTR-1</strong> reports invoice-wise outward supplies and sales details.</p>\r\n</li>\r\n<li data-start=\"2249\" data-end=\"2410\">\r\n<p data-start=\"2251\" data-end=\"2410\"><strong data-start=\"2251\" data-end=\"2262\">GSTR-3B</strong> is a self-declaration used to discharge tax liability after adjusting input-tax credit.<br data-start=\"2350\" data-end=\"2353\">Both must reconcile to ensure accuracy and avoid notices.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:01:53', '2025-10-25 06:01:53'),
(79, 3, '8️⃣ What is GSTR-9 and who needs to file it?', '<p data-start=\"2417\" data-end=\"2653\">GSTR-9 is the <strong data-start=\"2482\" data-end=\"2499\">annual return</strong> summarizing all monthly or quarterly filings for the year.<br data-start=\"2558\" data-end=\"2561\">It is mandatory for taxpayers whose aggregate turnover exceeds ₹2 crore in a financial year.</p>', 1, '2025-10-25 06:02:12', '2025-10-25 06:02:12'),
(80, 3, '9️⃣ What is GSTR-9C?', '<p data-start=\"2660\" data-end=\"2921\">GSTR-9C is a <strong data-start=\"2700\" data-end=\"2728\">reconciliation statement</strong> certified by a Chartered Accountant or Cost Accountant.<br data-start=\"2784\" data-end=\"2787\">It compares figures declared in GSTR-9 with audited financial statements and is compulsory for taxpayers with turnover above ₹5 crore.</p>', 1, '2025-10-25 06:02:29', '2025-10-25 06:02:29'),
(81, 3, '🔟 What is GSTR-4 (R-4)?', '<p data-start=\"2928\" data-end=\"3141\">GSTR-4 is the <strong data-start=\"2973\" data-end=\"3014\">annual return for composition dealers</strong>.<br data-start=\"3015\" data-end=\"3018\">It must be filed by 30 April of the following financial year, providing details of turnover, tax paid, and inward supplies.</p>', 1, '2025-10-25 06:02:56', '2025-10-25 06:02:56'),
(82, 3, '11️⃣ What is Form ITC-04 and when is it filed?', '<p data-start=\"3148\" data-end=\"3417\">ITC-04 is filed by manufacturers or principals who send goods for job-work.<br data-start=\"3276\" data-end=\"3279\">It details goods sent, received, and pending with job-workers.<br data-start=\"3341\" data-end=\"3344\">It is filed <strong data-start=\"3356\" data-end=\"3369\">quarterly</strong> by the 25th of the month following the quarter.</p>', 1, '2025-10-25 06:03:15', '2025-10-25 06:03:15'),
(83, 3, '12️⃣ What are the consequences of not filing GST returns?', '<ul data-start=\"3488\" data-end=\"3714\">\r\n<li data-start=\"3488\" data-end=\"3538\">\r\n<p data-start=\"3490\" data-end=\"3538\">Suspension or cancellation of GST registration</p>\r\n</li>\r\n<li data-start=\"3539\" data-end=\"3576\">\r\n<p data-start=\"3541\" data-end=\"3576\">Blocking of e-way bill generation</p>\r\n</li>\r\n<li data-start=\"3577\" data-end=\"3617\">\r\n<p data-start=\"3579\" data-end=\"3617\">Denial of input-tax credit to buyers</p>\r\n</li>\r\n<li data-start=\"3618\" data-end=\"3660\">\r\n<p data-start=\"3620\" data-end=\"3660\">Accumulation of interest and late fees</p>\r\n</li>\r\n<li data-start=\"3661\" data-end=\"3714\">\r\n<p data-start=\"3663\" data-end=\"3714\">Departmental assessments and recovery proceedings</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:03:33', '2025-10-25 06:03:33'),
(84, 3, '13️⃣ How is interest under GST calculated for late payment?', '<p data-start=\"3721\" data-end=\"3923\">Interest = Tax liability &times; 18 % &times; (Number of delay days &divide; 365).<br data-start=\"3850\" data-end=\"3853\">Example: ₹60 000 paid 15 days late &rarr; ₹60 000 &times; 18 % &times; 15 / 365 = ₹444.</p>', 1, '2025-10-25 06:03:54', '2025-10-25 06:03:54'),
(85, 3, '14️⃣ What documents are required for GST return filing?', '<ul>\r\n<li data-start=\"3992\" data-end=\"4023\">\r\n<p data-start=\"3994\" data-end=\"4023\">Sales and purchase invoices</p>\r\n</li>\r\n<li data-start=\"4024\" data-end=\"4050\">\r\n<p data-start=\"4026\" data-end=\"4050\">Credit and debit notes</p>\r\n</li>\r\n<li data-start=\"4051\" data-end=\"4091\">\r\n<p data-start=\"4053\" data-end=\"4091\">Bank statements (for reconciliation)</p>\r\n</li>\r\n<li data-start=\"4092\" data-end=\"4120\">\r\n<p data-start=\"4094\" data-end=\"4120\">Input-tax credit summary</p>\r\n</li>\r\n<li data-start=\"4121\" data-end=\"4145\">\r\n<p data-start=\"4123\" data-end=\"4145\">Tax payment challans</p>\r\n</li>\r\n<li data-start=\"4146\" data-end=\"4181\">\r\n<p data-start=\"4148\" data-end=\"4181\">Expense records and HSN summary</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:04:13', '2025-10-25 06:04:13'),
(86, 3, '15️⃣ Why should I choose Rajasthan Filings for GST return filing?', '<p data-start=\"4188\" data-end=\"4296\">Because Rajasthan Filings ensures:</p>\r\n<ul data-start=\"4297\" data-end=\"4558\">\r\n<li data-start=\"4297\" data-end=\"4346\">\r\n<p data-start=\"4299\" data-end=\"4346\">Accurate and timely filing of all GST returns</p>\r\n</li>\r\n<li data-start=\"4347\" data-end=\"4397\">\r\n<p data-start=\"4349\" data-end=\"4397\">Regular reconciliation and compliance tracking</p>\r\n</li>\r\n<li data-start=\"4398\" data-end=\"4450\">\r\n<p data-start=\"4400\" data-end=\"4450\">Legal-compliant computation of taxes and credits</p>\r\n</li>\r\n<li data-start=\"4451\" data-end=\"4501\">\r\n<p data-start=\"4453\" data-end=\"4501\">Updates on new GST notifications and deadlines</p>\r\n</li>\r\n<li data-start=\"4502\" data-end=\"4558\">\r\n<p data-start=\"4504\" data-end=\"4558\">Transparent and professional assistance across India</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 06:04:34', '2025-10-25 06:04:34'),
(87, 7, '1. What is an Income Tax Return (ITR)?', '<p data-start=\"514\" data-end=\"799\">An Income Tax Return (ITR) is a formal declaration of a taxpayer&rsquo;s total income, deductions, and taxes paid during a financial year. It is submitted to the Income Tax Department as a legal statement of income under the Income-tax Act, 2025.</p>', 1, '2025-10-25 08:28:27', '2025-10-25 08:28:27'),
(88, 7, '2. Who is required to file an ITR under the Income-tax Act 2025?', '<p>Every individual, firm, LLP, company, or trust whose total income exceeds the prescribed exemption limit &nbsp;must file an ITR. Companies and firms must file irrespective of profit or loss.</p>', 1, '2025-10-25 08:29:15', '2025-10-25 08:29:15'),
(89, 7, '3. What are the different types of ITR forms under the new Act?', '<p data-start=\"1080\" data-end=\"1206\">The Income-tax Act 2025 prescribes seven return forms:</p>\r\n<ul data-start=\"1207\" data-end=\"1676\">\r\n<li data-start=\"1207\" data-end=\"1258\">\r\n<p data-start=\"1209\" data-end=\"1258\">ITR-1: For salaried individuals and pensioners.</p>\r\n</li>\r\n<li data-start=\"1259\" data-end=\"1339\">\r\n<p data-start=\"1261\" data-end=\"1339\">ITR-2: For individuals and HUFs having capital gains or multiple properties.</p>\r\n</li>\r\n<li data-start=\"1340\" data-end=\"1413\">\r\n<p data-start=\"1342\" data-end=\"1413\">ITR-3: For individuals and HUFs with business or professional income.</p>\r\n</li>\r\n<li data-start=\"1414\" data-end=\"1494\">\r\n<p data-start=\"1416\" data-end=\"1494\">ITR-4: For presumptive income taxpayers under sections 44AD, 44ADA, or 44AE.</p>\r\n</li>\r\n<li data-start=\"1495\" data-end=\"1538\">\r\n<p data-start=\"1497\" data-end=\"1538\">ITR-5: For firms, LLPs, AOPs, and BOIs.</p>\r\n</li>\r\n<li data-start=\"1539\" data-end=\"1593\">\r\n<p data-start=\"1541\" data-end=\"1593\">ITR-6: For companies (except Section 8 companies).</p>\r\n</li>\r\n<li data-start=\"1594\" data-end=\"1676\">\r\n<p data-start=\"1596\" data-end=\"1676\">ITR-7: For trusts, political parties, and other institutions claiming exemption.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:29:39', '2025-10-25 08:29:39'),
(90, 7, '4. What is the due date for filing an ITR under the Income-tax Act 2025?', '<ul data-start=\"1762\" data-end=\"2056\">\r\n<li data-start=\"1762\" data-end=\"1817\">\r\n<p data-start=\"1764\" data-end=\"1817\">31 July &ndash; Individuals and HUFs not requiring audit.</p>\r\n</li>\r\n<li data-start=\"1818\" data-end=\"1884\">\r\n<p data-start=\"1820\" data-end=\"1884\">31 October &ndash; Businesses, firms, and companies requiring audit.</p>\r\n</li>\r\n<li data-start=\"1885\" data-end=\"1941\">\r\n<p data-start=\"1887\" data-end=\"1941\">30 November &ndash; Entities involved in transfer pricing.</p>\r\n</li>\r\n<li data-start=\"1942\" data-end=\"1994\">\r\n<p data-start=\"1944\" data-end=\"1994\">31 March (next AY) &ndash; Belated or revised returns.</p>\r\n</li>\r\n<li data-start=\"1995\" data-end=\"2056\">\r\n<p data-start=\"1997\" data-end=\"2056\">Within 24 months &ndash; Updated ITR (ITR-U) with additional tax.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:30:01', '2025-10-25 08:30:01'),
(91, 7, '6. What are the penalties for filing a late ITR?', '<p data-start=\"2340\" data-end=\"2427\">Under Section 234F of the Act:</p>\r\n<ul data-start=\"2428\" data-end=\"2602\">\r\n<li data-start=\"2428\" data-end=\"2467\">\r\n<p data-start=\"2430\" data-end=\"2467\">₹1,000 penalty if income &le; ₹5 lakh.</p>\r\n</li>\r\n<li data-start=\"2468\" data-end=\"2602\">\r\n<p data-start=\"2470\" data-end=\"2602\">₹5,000 penalty if income &gt; ₹5 lakh.<br data-start=\"2505\" data-end=\"2508\">Additionally, 1% interest per month applies on unpaid tax under Sections 234A, 234B, and 234C.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:30:53', '2025-10-25 08:30:53'),
(92, 7, '7. What happens if I do not file my ITR at all?', '<p data-start=\"2609\" data-end=\"2695\">Failure to file may result in:</p>\r\n<ul data-start=\"2696\" data-end=\"2855\">\r\n<li data-start=\"2696\" data-end=\"2742\">\r\n<p data-start=\"2698\" data-end=\"2742\">Loss of refund and carry-forward benefits.</p>\r\n</li>\r\n<li data-start=\"2743\" data-end=\"2800\">\r\n<p data-start=\"2745\" data-end=\"2800\">Penalty of 50% to 200% of tax due under Section 270A.</p>\r\n</li>\r\n<li data-start=\"2801\" data-end=\"2855\">\r\n<p data-start=\"2803\" data-end=\"2855\">Prosecution under Section 276CC for willful default</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:31:13', '2025-10-25 08:31:13');
INSERT INTO `service_faqs` (`id`, `service_id`, `question`, `answer`, `status`, `created_at`, `updated_at`) VALUES
(93, 7, '8. What is the difference between Revised ITR and Updated ITR?', '<ul data-start=\"2931\" data-end=\"3176\">\r\n<li data-start=\"2931\" data-end=\"3058\">\r\n<p data-start=\"2933\" data-end=\"3058\">Revised ITR (Section 139(5)): For correcting errors in the original return before 31 March of the relevant assessment year.</p>\r\n</li>\r\n<li data-start=\"3059\" data-end=\"3176\">\r\n<p data-start=\"3061\" data-end=\"3176\">Updated ITR (Section 139(8A)): For voluntary income disclosure within 24 months, with an additional 25% or 50% tax.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:31:30', '2025-10-25 08:31:30'),
(94, 7, '9. What is the time limit for verifying a filed ITR?', '<p data-start=\"3183\" data-end=\"3323\">An ITR must be verified within 30 days of filing. Verification options include:</p>\r\n<ul data-start=\"3324\" data-end=\"3440\">\r\n<li data-start=\"3324\" data-end=\"3363\">\r\n<p data-start=\"3326\" data-end=\"3363\">Digital Signature Certificate (DSC)</p>\r\n</li>\r\n<li data-start=\"3364\" data-end=\"3385\">\r\n<p data-start=\"3366\" data-end=\"3385\">Aadhaar-based OTP</p>\r\n</li>\r\n<li data-start=\"3386\" data-end=\"3440\">\r\n<p data-start=\"3388\" data-end=\"3440\">Electronic Verification Code (EVC) via Net Banking</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:31:51', '2025-10-25 08:31:51'),
(95, 7, '10. How can I check the status of my income tax refund?', '<p data-start=\"3447\" data-end=\"3701\">Refunds can be tracked through the e-filing portal under the &ldquo;Refund Status&rdquo; tab. Refunds are credited directly to the pre-validated bank account within 7&ndash;15 working days of return processing.</p>', 1, '2025-10-25 08:32:10', '2025-10-25 08:32:10'),
(96, 7, '11. Is e-verification mandatory for all taxpayers?', '<p data-start=\"3708\" data-end=\"3916\">Yes. All returns filed electronically must be verified through DSC, Aadhaar OTP, or EVC for them to be considered valid under the Income-tax Act, 2025.</p>', 1, '2025-10-25 08:32:27', '2025-10-25 08:32:27'),
(97, 7, '12. What documents are required to file an ITR?', '<ul>\r\n<li data-start=\"3977\" data-end=\"4013\">\r\n<p data-start=\"3979\" data-end=\"4013\">Form 16 or 16A (TDS certificate)</p>\r\n</li>\r\n<li data-start=\"4014\" data-end=\"4041\">\r\n<p data-start=\"4016\" data-end=\"4041\">Form 26AS, AIS, and TIS</p>\r\n</li>\r\n<li data-start=\"4042\" data-end=\"4061\">\r\n<p data-start=\"4044\" data-end=\"4061\">Bank statements</p>\r\n</li>\r\n<li data-start=\"4062\" data-end=\"4105\">\r\n<p data-start=\"4064\" data-end=\"4105\">Investment proofs (80C, 80D, 80G, etc.)</p>\r\n</li>\r\n<li data-start=\"4106\" data-end=\"4146\">\r\n<p data-start=\"4108\" data-end=\"4146\">Capital gains and property documents</p>\r\n</li>\r\n<li data-start=\"4147\" data-end=\"4190\">\r\n<p data-start=\"4149\" data-end=\"4190\">Business books of account (if applicable)</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:32:47', '2025-10-25 08:32:47'),
(98, 7, '13. What is AIS and TIS, and why are they important?', '<p data-start=\"4197\" data-end=\"4513\">AIS (Annual Information Statement) and TIS (Taxpayer Information Summary) display all transactions reported to the tax department by third parties&mdash;such as banks, employers, and registrars. Your ITR must reconcile with AIS/TIS to avoid notices or mismatches.</p>', 1, '2025-10-25 08:33:11', '2025-10-25 08:33:11'),
(99, 7, '14. Can I carry forward business or capital losses?', '<p data-start=\"4520\" data-end=\"4716\">Yes, but only if the ITR is filed before the due date. Delayed filing results in forfeiture of this right under the provisions of the Act.</p>', 1, '2025-10-25 08:33:31', '2025-10-25 08:33:31'),
(100, 7, '15. What is a faceless assessment?', '<p data-start=\"4723\" data-end=\"4976\">A faceless assessment is a digital scrutiny system where all communications, hearings, and orders occur online. It ensures transparency, removes personal interaction, and reduces the scope for discretion or bias.</p>', 1, '2025-10-25 08:33:55', '2025-10-25 08:33:55'),
(101, 7, '16. What are the penalties for under-reporting or misreporting of income?', '<ul>\r\n<li data-start=\"5063\" data-end=\"5103\">\r\n<p data-start=\"5065\" data-end=\"5103\">Under-reporting: 50% of the tax due.</p>\r\n</li>\r\n<li data-start=\"5104\" data-end=\"5221\">\r\n<p data-start=\"5106\" data-end=\"5221\">Misreporting (intentional concealment): 200% of the tax due.<br data-start=\"5166\" data-end=\"5169\">These may attract prosecution for severe violations.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:34:16', '2025-10-25 08:34:16'),
(102, 7, '18. What is the difference between an intimation and an assessment?', '<ul>\r\n<li data-start=\"5538\" data-end=\"5619\">\r\n<p data-start=\"5540\" data-end=\"5619\">Intimation (Section 143(1)): Auto-processed summary showing refund or demand.</p>\r\n</li>\r\n<li data-start=\"5620\" data-end=\"5711\">\r\n<p data-start=\"5622\" data-end=\"5711\">Assessment (Section 143(3)): Detailed scrutiny by the department based on selected cases.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:34:41', '2025-10-25 08:34:41'),
(103, 7, '19. Can I correct my ITR after submission?', '<p data-start=\"5718\" data-end=\"5982\">Yes. You may file a Revised Return under Section 139(5) before 31 March of the relevant AY. If the time limit has expired, you can still disclose income by filing an Updated ITR within 24 months with additional tax.</p>', 1, '2025-10-25 08:35:00', '2025-10-25 08:35:00'),
(104, 7, '20. Why should I choose Rajasthan Filings for ITR filing?', '<p data-start=\"5985\" data-end=\"6076\">Rajasthan Filings offers:</p>\r\n<ul data-start=\"6077\" data-end=\"6318\">\r\n<li data-start=\"6077\" data-end=\"6124\">\r\n<p data-start=\"6079\" data-end=\"6124\">Complete filing support for ITR-1 to ITR-7.</p>\r\n</li>\r\n<li data-start=\"6125\" data-end=\"6163\">\r\n<p data-start=\"6127\" data-end=\"6163\">Accurate AIS / TIS reconciliation.</p>\r\n</li>\r\n<li data-start=\"6164\" data-end=\"6224\">\r\n<p data-start=\"6166\" data-end=\"6224\">Guidance on Revised and Updated ITRs under the 2025 law.</p>\r\n</li>\r\n<li data-start=\"6225\" data-end=\"6270\">\r\n<p data-start=\"6227\" data-end=\"6270\">Audit and faceless-assessment assistance.</p>\r\n</li>\r\n<li data-start=\"6271\" data-end=\"6318\">\r\n<p data-start=\"6273\" data-end=\"6318\">Transparent process and nationwide service.</p>\r\n</li>\r\n</ul>', 1, '2025-10-25 08:36:49', '2025-10-25 08:36:49');

